window.__DOCS_SEARCH__ = [[{"i":"#","p":["Nitrite is a serverless, embedded, and self-contained NoSQL database. It is an open-source project that provides a simple API for persistent data storage. Nitrite database is designed to be lightweight, fast, and easy to use."]},{"l":"Welcome to Nitrite Database","p":["NOsql Object (NO2 a.k.a Nitrite) is a serverless, embedded, and self-contained NoSQL database. It is an open-source project that provides a simple API for persistent data storage. Nitrite database is designed to be lightweight, fast, and easy to use. Currently, it is available in Java, Kotlin, Flutter, and Rust.","Nitrite database can be used in various scenarios where a lightweight, embedded, and serverless NoSQL database is required. Some of the use cases for Nitrite database are:","Mobile and desktop applications","IoT devices and sensors","Web applications and APIs","Prototyping and testing","Data caching and synchronization","Data analysis and reporting","Nitrite database is designed to be simple and easy to use, making it a good choice for small to medium-sized projects that require a fast and reliable data storage solution."]},{"l":"✨ Features","p":["Embedded, serverless","Simple API","Document-oriented","Schemaless document collection and object repository","Extensible storage engines","Indexing and full-text search","Vector similarity search (ANN) & RAG store (Rust SDK only)","Simple query API","In-memory and file-based store","Transaction support","Schema migration support","Encryption support"]},{"l":"⛔ What Nitrite is not","p":["Nitrite is not an RDBMS. It is also not a distributed NoSQL database like MongoDB or Cassandra. It does not have any server for external application to connect to."]},{"l":"\uD83D\uDE80 Getting Started","p":["Nitrite database is currently available in Java, Kotlin, Flutter, and Rust. Please visit the respective language page for getting started guidance and repository links. Feature availability can differ slightly by SDK, so each language guide documents its supported modules and capabilities."]},{"l":"\uD83D\uDCDD License","p":["Nitrite database is an open-source project released under the terms of the Apache License, Version 2.0."]},{"l":"\uD83E\uDD1D Support","p":["Give a ⭐️ if this project helped you! Please consider donating to support the development and maintenance."]},{"l":"\uD83D\uDC9A Contributing","p":["Contributions, issues and feature requests are welcome. Feel free to open a discussion thread here."]},{"l":"\uD83C\uDF9E️ Showcase","p":["If you are using Nitrite database in your project, please let us know. We will be happy to showcase your project here."]}],[{"i":"#","p":["This guide will help you get started with Nitrite database. It will show you how to create a database, create a collection, insert documents, and query documents in Java."]},{"l":"Getting Started in Java","p":["To get started with Nitrite database, you need to add the Nitrite BOM to your project. The BOM will help you to manage the dependencies. Details of the BOM can be found here.","To add the BOM to your project, follow the steps below:"]},{"l":"Add dependency","p":["Add Nitrite dependency to your project:"]},{"l":"Maven","p":["Add the nitrite dependency to your pom.xml file:"]},{"i":"maven-code-1","c":["<dependencyManagement>\n    <dependencies>\n        <dependency>\n            <groupId>org.dizitart</groupId>\n            <artifactId>nitrite-bom</artifactId>\n            <version>[latest version]</version>\n            <scope>import</scope>\n            <type>pom</type>\n        </dependency>\n    </dependencies>\n</dependencyManagement>\n\n<dependencies>\n    <dependency>\n        <groupId>org.dizitart</groupId>\n        <artifactId>nitrite</artifactId>\n    </dependency>\n</dependencies>"]},{"l":"Gradle","p":["Add the nitrite dependency to your build.gradle file:","The latest released version of Nitrite can be found here."]},{"i":"gradle-code-1","c":["dependencies {\n    implementation platform('org.dizitart:nitrite-bom:[latest version]')\n    implementation 'org.dizitart:nitrite'\n}"]},{"l":"Snapshot builds","p":["Snapshot builds are available from Sonatype.","To use snapshot builds, you need to add the following repository to your pom.xml file:","Or, if you are using Gradle, add the following repository to your build.gradle file:","You need Java 11 or above to use Nitrite database."]},{"i":"snapshot-builds-code-1","c":["<repositories>\n    <repository>\n        <id>sonatype-snapshot</id>\n        <url>https://oss.sonatype.org/content/repositories/snapshots/</url>\n        <releases>\n            <enabled>false</enabled>\n        </releases>\n        <snapshots>\n            <enabled>true</enabled>\n        </snapshots>\n    </repository>\n</repositories>"]},{"i":"snapshot-builds-code-2","c":["repositories {\n    mavenCentral()\n    maven {\n        url 'https://oss.sonatype.org/content/repositories/snapshots/'\n    }\n}"]},{"l":"Upgrade from 3.x","p":["If you are upgrading from 3.x, please note that there are lots of breaking changes in the API. The whole library is re-written from scratch. It is recommended to go through this guide before upgrading.","You need to use the MVStore as your storage module to upgrade from 3.x. The RocksDB module is not backward compatible.","Nitrite will try to migrate your existing database to the latest version on the provided you are using the MVStore module. If you are using the RocksDB module, you need to migrate your database manually. However, it is recommended to take a backup of your database before upgrading."]}],[{"l":"Nitrite Database","p":["Nitrite database is a serverless, embedded, and self-contained Java NoSQL database. It is an open-source project that provides a simple API for persistent data storage. Nitrite database is designed to be lightweight, fast, and easy to use."]},{"l":"Creating a Database","p":["Nitrite database can be created in-memory or on-disk. By default, Nitrite database is created in-memory. To create a database on-disk, you need to add a storage module dependency to your project. More details about storage modules can be found here.","To create a database, you need to use NitriteBuilder class. To get an instance of NitriteBuilder, you need to call builder() method on Nitrite class."]},{"i":"creating-a-database-code-1","c":["NitriteBuilder builder = Nitrite.builder();"]},{"l":"In-memory Database","p":["If you don't load any on-disk storage module, then Nitrite will create an in-memory database. The below code snippet shows how to create a database in-memory."]},{"i":"in-memory-database-code-1","c":["Nitrite db = Nitrite.builder()\n    .openOrCreate();"]},{"l":"On-disk Database","p":["The below code snippet shows how to create a database on-disk."]},{"l":"MVStore Backed Database","p":["More details about MVStore configuration can be found here."]},{"i":"mvstore-backed-database-code-1","c":["MVStoreModule storeModule = MVStoreModule.withConfig()\n    .filePath(\"/path/to/my.db\")\n    .build();\n\nNitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate();"]},{"l":"RocksDB Backed Database","p":["More details about RocksDB configuration can be found here."]},{"i":"rocksdb-backed-database-code-1","c":["RocksDBModule storeModule = RocksDBModule.withConfig()\n    .filePath(\"/path/to/my.db\")\n    .build();\n\nNitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate();"]},{"l":"NitriteBuilder","p":["NitriteBuilder provides a fluent API to configure and create a Nitrite database instance."]},{"l":"Open or Create a Database","p":["To open or create a database, you need to call openOrCreate() method on NitriteBuilder instance. This method returns a Nitrite instance.","If no StoreModule is configured, then Nitrite will create an in-memory database. If a StoreModule is configured, then Nitrite will create a file-based database. If the database file does not exist, then Nitrite will create a new database file. If the database file already exists, then Nitrite will open the existing database file."]},{"i":"open-or-create-a-database-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate();"]},{"l":"Securing a Database","p":["To secure a database, you need to call openOrCreate() method with username and password on NitriteBuilder instance. This method returns a Nitrite instance with the given username and password.","If you are using a file-based database, then you need to use the same username and password to open the database again. Otherwise, you will get a NitriteSecurityException.","Both username and password must be provided or both must be null."]},{"i":"securing-a-database-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate(\"user\", \"password\");"]},{"l":"Registering an EntityConverter","p":["Nitrite database uses a mapper to map Java entities to Nitrite documents and vice-versa. By default, Nitrite uses SimpleNitriteMapper as its mapper. This mapper uses EntityConverters to map Java entities to Nitrite documents and vice-versa. To register an EntityConverter, you need to call registerEntityConverter() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","More on EntityConverter can be found here."]},{"i":"registering-an-entityconverter-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .registerEntityConverter(new ProductConverter())\n    .registerEntityConverter(new ProductIdConverter())\n    .registerEntityConverter(new ManufacturerConverter())\n    .openOrCreate();"]},{"l":"Loading a Module","p":["Nitrite database is modular in nature. It provides various modules to extend its functionality. To load a module, you need to call loadModule() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance."]},{"l":"Loading a Storage Module"},{"i":"loading-a-storage-module-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate();"]},{"l":"Loading a Jackson Based Mapper Module","p":["More on the Nitrite's module system can be found here."]},{"i":"loading-a-jackson-based-mapper-module-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(new JacksonMapperModule())\n    .openOrCreate();"]},{"l":"Adding Migration Steps","p":["Nitrite database supports schema migration. To configure a migration step, you need to call addMigrations() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","More on the schema migration can be found here."]},{"i":"adding-migration-steps-code-1","c":["Migration migration = new Migration(Constants.INITIAL_SCHEMA_VERSION, 2) {\n    @Override\n    public void migrate(InstructionSet instruction) {\n        instruction.forDatabase()\n            .addUser(\"test-user\", \"test-password\");\n\n        instruction.forRepository(OldClass.class, \"demo1\")\n            .renameRepository(\"new\", null)\n            .changeDataType(\"empId\", (TypeConverter<String, Long>) Long::parseLong)\n            .changeIdField(Fields.withNames(\"uuid\"), Fields.withNames(\"empId\"))\n            .deleteField(\"uuid\")\n            .renameField(\"lastName\", \"familyName\")\n            .addField(\"fullName\", document -> document.get(\"firstName\", String.class) + \" \"\n                + document.get(\"familyName\", String.class))\n            .dropIndex(\"firstName\")\n            .dropIndex(\"literature.text\")\n            .changeDataType(\"literature.ratings\", (TypeConverter<Float, Integer>) Math::round);\n    }\n};\n\nNitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .addMigrations(migration)\n    .openOrCreate();"]},{"l":"Current Schema Version","p":["To configure the current schema version, you need to call schemaVersion() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","By default, the initial schema version is set to 1."]},{"i":"current-schema-version-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .schemaVersion(2)\n    .openOrCreate();"]},{"l":"Field Separator Character","p":["To configure the field separator character, you need to call fieldSeparator() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","It is used to separate field names in a nested document. For example, if a document has a field address which is a nested document, then the field street of the nested document can be accessed using address.street syntax.","The default field separator character is set to .."]},{"i":"field-separator-character-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .fieldSeparator('.')\n    .openOrCreate();"]},{"l":"Disable Repository Type Validation","p":["To disable repository type validation, you need to call disableRepositoryTypeValidation() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","Repository type validation is a feature in Nitrite that ensures the type of the objects stored in the repository can be converted to and from the document. By default, the repository type validation is enabled. If you disable it, and if you try to store an object that cannot be converted to a document, Nitrite will throw an exception during the operation."]},{"i":"disable-repository-type-validation-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .disableRepositoryTypeValidation()\n    .openOrCreate();"]}],[{"l":"Document","p":["Document is the basic unit of data in Nitrite database. It is a JSON like field-value pairs. The field is always a String and value can be anything including null. Document is schema-less, which means you can store any kind of data in a document.","Nitrite document supports nested document. That means, a value of a field can be another document. This allows you to create complex data structure."]},{"l":"Document Structure","p":["Nitrite document has the following structure."]},{"i":"document-structure-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"address\": {\n        \"street\": \"123 Main Street\",\n        \"city\": \"New York\",\n        \"state\": \"NY\",\n        \"zip\": \"10001\"\n    },\n    \"phone\": [\n        \"212-555-1234\",\n        \"646-555-4567\"\n    ]\n}"]},{"l":"Document Field","p":["Document field is always a String. It can be any valid string. The field cannot be null or empty string.","Below fields are reserved and cannot be used as key in a document.","_id : The unique identifier of a document. This field is auto-generated by Nitrite database during insertion.","_revision : The revision number of a document. This field is auto-generated by Nitrite database during insertion and update.","_source : The source collection name of a document.","_modified : The last modified timestamp of a document. This field is auto-generated by Nitrite database during insertion and update."]},{"l":"Document Value","p":["Document value can be any valid Java object. It can be null or any primitive type. It can also be a collection or an array. It can also be a nested document."]},{"l":"Document Identifier","p":["It is a unique identifier of a document. It is auto-generated by Nitrite database during insertion. It is a NitriteId and is stored as a String in the document."]},{"l":"NitriteId","p":["NitriteId is a unique identifier across the Nitrite database. Each document in a nitrite collection is associated with a NitriteId.","During insertion if a unique String value representing a 64-bit integer is supplied in the _id field of the document, then the value of the _id field will be used to generate the NitriteId. Otherwise, a new NitriteId will be generated and will be used in the _id field of the document.","The value of the NitriteId is a String representation of a 64-bit integer. The id generation is based on Twitter Snowflake algorithm. The id is composed of:","41 bits for time in milliseconds","10 bits for a machine id","12 bits for a sequence number","1 unused sign bit","The id is not guaranteed to be monotonically increasing. The id is sortable and the timestamp is stored in the id itself."]},{"l":"Retrieving a NitriteId from a Document","p":["The id can be retrieved from a document using Document.getId() method. If the document does not have an id, then it will create a new NitriteId and will set it in the document and will return the id. If the document already has an id, then it will return the id."]},{"i":"retrieving-a-nitriteid-from-a-document-code-1","c":["Document document = Document.createDocument(\"firstName\", \"John\");\n\nNitriteId id = document.getId();"]},{"l":"Field Separator","p":["To access a field of a nested document, or an element of an array field, you need to use the field separator.","Field separator is configurable. You can change the field separator character by calling NitriteBuilder.fieldSeparator() method.","Nitrite uses . as field separator by default."]},{"i":"field-separator-code-1","c":["Nitrite db = Nitrite.builder()\n    .fieldSeparator('.')\n    .openOrCreate();"]},{"l":"Nested Document","p":["To specify or access a field of a nested document, you need to use the field separator character. That means, if a document has a field address which is a nested document, then the field street of the nested document can be accessed using address.street syntax."]},{"l":"Array Field","p":["To specify or access an element of an array field, you need to use the index of the element. For example, if a document has a field phone which is an array, then the first element of the array can be accessed using phone.0 syntax."]},{"l":"Creating a Document","p":["To create a document, you need to use Document.createDocument() method."]},{"l":"Creating an Empty Document"},{"i":"creating-an-empty-document-code-1","c":["Document document = Document.createDocument();"]},{"l":"Creating a Document with Initial Field-value Pair"},{"i":"creating-a-document-with-initial-field-value-pair-code-1","c":["Document document = Document.createDocument(\"firstName\", \"John\");"]},{"l":"Creating a Document with a Map"},{"i":"creating-a-document-with-a-map-code-1","c":["Map<String, Object> map = new HashMap<>();\nmap.put(\"firstName\", \"John\");\nmap.put(\"lastName\", \"Doe\");\n\nDocument document = Document.createDocument(map);"]},{"l":"Updating a Document","p":["To update a document, you need to use Document.put() method. This method takes two parameters, the field name and the value. If the field already exists in the document, then the value will be updated. If the field does not exist, then it will be created."]},{"i":"updating-a-document-code-1","c":["Document document = Document.createDocument(\"firstName\", \"John\");\n\ndocument.put(\"lastName\", \"Doe\");"]},{"l":"Retrieving a Value from Document","p":["To retrieve a value from document, you need to use Document.get() method. This method takes one parameter, the field name. If the field exists in the document, then the value will be returned. If the field does not exist, then it will return null.","To retrieve a value from a nested document, use the field separator character.","To retrieve an element from an array field, use the index of the element."]},{"i":"retrieving-a-value-from-document-code-1","c":["Document document = Document.createDocument(\"firstName\", \"John\");\n\nString firstName = document.get(\"firstName\");"]},{"i":"retrieving-a-value-from-document-code-2","c":["Document document = Document.createDocument(\"firstName\", \"John\")\n    .put(\"address\", Document.createDocument(\"street\", \"123 Main Street\"));\n\nString street = document.get(\"address.street\", String.class);\n// or\nString street = (String) document.get(\"address.street\");"]},{"i":"retrieving-a-value-from-document-code-3","c":["Document document = Document.createDocument(\"firstName\", \"John\")\n    .put(\"phone\", new String[] { \"212-555-1234\", \"646-555-4567\" });\n\nString phone = document.get(\"phone.0\", String.class);\n// or\nString phone = (String) document.get(\"phone.0\");"]},{"l":"Removing a Field from Document","p":["To remove a field from document, you need to use Document.remove() method. This method takes one parameter, the field name. If the field exists in the document, then it will be removed. If the field does not exist, then it will do nothing.","To remove a field from a nested document, use the field separator character.","To remove an element from an array field, use the index of the element."]},{"i":"removing-a-field-from-document-code-1","c":["Document document = Document.createDocument(\"firstName\", \"John\");\n\ndocument.remove(\"firstName\");"]},{"i":"removing-a-field-from-document-code-2","c":["Document document = Document.createDocument(\"firstName\", \"John\")\n    .put(\"address\", Document.createDocument(\"street\", \"123 Main Street\"));\n\ndocument.remove(\"address.street\");"]},{"i":"removing-a-field-from-document-code-3","c":["Document document = Document.createDocument(\"firstName\", \"John\")\n    .put(\"phone\", new String[] { \"212-555-1234\", \"646-555-4567\" });\n\ndocument.remove(\"phone.0\");"]},{"l":"Checking If a Field Exists in Document","p":["To check if a field exists in a document, you need to use Document.containsField() method. This method takes one parameter, the field name. If the field exists in the document, then it will return true. If the field does not exist, then it will return false.","To check if a field exists in a nested document, use the field separator character.","It cannot check if an element exists in an array field."]},{"i":"checking-if-a-field-exists-in-document-code-1","c":["Document document = Document.createDocument(\"firstName\", \"John\");\n\nboolean hasFirstName = document.containsField(\"firstName\");"]},{"i":"checking-if-a-field-exists-in-document-code-2","c":["Document document = Document.createDocument(\"firstName\", \"John\")\n    .put(\"address\", Document.createDocument(\"street\", \"123 Main Street\"));\n\nboolean hasStreet = document.containsField(\"address.street\");"]}],[{"l":"Introduction","p":["NitriteCollection represents a named document collection stored in a Nitrite database. It persists documents in a Nitrite database. It is similar to a table in relational database or a collection in MongoDB.","Each document in a collection is associated with a unique NitriteId. It exposes a set of methods to perform CRUD operations on documents. It also supports indexing and querying. It also supports event based notification on document changes.","NitriteCollection is thread-safe and supports concurrent read and write operations."]},{"l":"Creating a Collection","p":["A NitriteCollection can be created using Nitrite class. You need to call getCollection() method on Nitrite class to get an instance of a NitriteCollection.","If the collection does not exist, then it will be created automatically. If a collection with the same name already exists, then it will return the existing collection."]},{"i":"creating-a-collection-code-1","c":["Nitrite db = Nitrite.builder()\n    .openOrCreate();\n\nNitriteCollection collection = db.getCollection(\"myCollection\");"]},{"l":"Limitations on Collection Name","p":["A collection name cannot be null or empty string. It cannot contains any of the following characters:","| (pipe)",": (colon)","+ (plus)","The name also cannot be any of the following reserved words:","$nitrite_users","$nitrite_index_meta","$nitrite_index","$nitrite_meta_map","$nitrite_store_info","$nitrite_catalog"]}],[{"l":"Write Operations"},{"l":"Inserting Documents","p":["Documents can be inserted into a collection using insert() method. It takes one or multiple Document objects as input parameter. It returns a WriteResult object.","If the document has a NitriteId already in it's _id field, then it will be used as a unique key to identify the document in the collection. Otherwise, a new NitriteId will be generated and inserted into the document.","If any of the field is already indexed in the collection, then the index will be updated accordingly.","This operation will notify all the registered CollectionEventListener with EventType.Insert event."]},{"l":"Inserting a Single Document"},{"i":"inserting-a-single-document-code-1","c":["Document doc = Document.createDocument(\"firstName\", \"John\")\n    .put(\"lastName\", \"Doe\")\n    .put(\"age\", 30)\n    .put(\"data\", new byte[] { 1, 2, 3, 4, 5 });\n\nWriteResult result = collection.insert(doc);"]},{"l":"Inserting Multiple Documents"},{"i":"inserting-multiple-documents-code-1","c":["Document doc1 = Document.createDocument(\"firstName\", \"John\")\n    .put(\"lastName\", \"Doe\")\n    .put(\"age\", 30)\n    .put(\"data\", new byte[] { 1, 2, 3, 4, 5 });\n\nDocument doc2 = Document.createDocument(\"firstName\", \"Jane\")\n    .put(\"lastName\", \"Doe\")\n    .put(\"age\", 25)\n    .put(\"data\", new byte[] { 1, 2, 3, 4, 5 });\n\nWriteResult result = collection.insert(doc1, doc2);"]},{"l":"Error Scenarios","p":["If the document is null, then it will throw a ValidationException.","If the document contains invalid value in it's _id field, then it will throw a InvalidIdException.","If there is another document with the same _id value in the collection, then it will throw a UniqueConstraintException.","If a field of the document is unique indexed and it's value violates the index constraint, then it will throw a UniqueConstraintException."]},{"l":"WriteResult","p":["WriteResult contains the result of a write operation. It contains the following information:","Number of documents affected by the write operation. You can get this value using getAffectedCount() method.","List of NitriteId of the documents affected by the write operation. The WriteResults implements IterableNitriteId interface. So you can iterate over the WriteResult to get the NitriteId of the documents affected by the write operation."]},{"l":"Updating Documents","p":["Documents can be updated in a collection using update() method. There are several overloaded version of update() method. You can update a single document or multiple documents at a time. You can also update a document using a filter.","This operation will notify all the registered CollectionEventListener with EventType.Update event."]},{"l":"Updating a Single Document","p":["You can update a single document using update() method. It takes a Document object as input parameter. It returns a WriteResult object. The document must contain a valid NitriteId in it's _id field. The document must not be null.","If the document does not contain a valid NitriteId in it's _id field, then it will throw a NotIdentifiableException."]},{"i":"updating-a-single-document-code-1","c":["Document doc = Document.createDocument(\"_id\", existingDoc.getId())\n    .put(\"age\", 30);\n\nWriteResult result = collection.update(doc);"]},{"l":"Upserting a Single Document","p":["You can upsert a single document using update() method. It takes a Document object as the first input parameter. It takes a boolean value as the second input parameter. If the second input parameter is true, then it will insert the document if it does not exist in the collection. Otherwise, it will update the document if it exists in the collection. It returns a WriteResult object. The document must not be null."]},{"i":"upserting-a-single-document-code-1","c":["Document doc = Document.createDocument(\"_id\", existingDoc.getId())\n    .put(\"lastName\", \"Doe\")\n    .put(\"age\", 30)\n    .put(\"data\", new byte[] { 1, 2, 3, 4, 5 });\n\nWriteResult result = collection.update(doc, true);"]},{"l":"Updating Using a Filter","p":["You can update multiple documents using a filter. It takes a Filter object as the first input parameter. It takes a Document object as the second input parameter. It returns a WriteResult object. The document must not be null or empty.","If the filter result matches multiple documents, then all the documents will be updated."]},{"i":"updating-using-a-filter-code-1","c":["Document update = Document.createDocument(\"_id\", existingDoc.getId())\n    .put(\"firstName\", \"Jane\");\n\nWriteResult result = collection.update(where(\"firstName\").eq(\"John\"), update);"]},{"l":"Updating Using a Filter and Options","p":["You can update multiple documents using a filter and options. It takes a Filter object as the first input parameter. It takes a Document object as the second input parameter. It takes a UpdateOptions object as the third input parameter. It returns a WriteResult object. The document must not be null or empty."]},{"l":"UpdateOptions","p":["UpdateOptions is a class that contains several options for update operation. It has the following options:","insertIfAbsent: If this option is true, then it will insert the document if it does not exist in the collection. Otherwise, it will update the document if it exists in the collection.","justOnce: If this option is true, then it will update only the first document matched by the filter. Otherwise, it will update all the documents matched by the filter."]},{"i":"updateoptions-code-1","c":["Document update = Document.createDocument(\"_id\", existingDoc.getId())\n    .put(\"firstName\", \"Jane\");\n\nUpdateOptions updateOptions = new UpdateOptions();\nupdateOptions.insertIfAbsent(true);\nupdateOptions.justOnce(true);\n\nWriteResult result = collection.update(where(\"firstName\").eq(\"John\"), update, updateOptions);"]},{"l":"Removing Documents","p":["Documents can be removed from a collection using remove() method. There are several overloaded version of remove() method. You can remove a single document or multiple documents at a time using a filter.","This operation will notify all the registered CollectionEventListener with EventType.Remove event."]},{"l":"Removing a Single Document","p":["You can remove a single document using remove() method. It takes a Document object as input parameter. It returns a WriteResult object. The document must contain a valid NitriteId in it's _id field. The document must not be null.","If the document does not contain a valid NitriteId in it's _id field, then it will throw a NotIdentifiableException."]},{"i":"removing-a-single-document-code-1","c":["Document doc = Document.createDocument(\"_id\", existingDoc.getId());\n\nWriteResult result = collection.remove(doc);"]},{"l":"Removing Using a Filter","p":["You can remove multiple documents using a filter. It takes a Filter object as the input parameter. It returns a WriteResult object.","If the filter result matches multiple documents, then all the documents will be removed."]},{"i":"removing-using-a-filter-code-1","c":["WriteResult result = collection.remove(where(\"firstName\").eq(\"John\"));"]},{"l":"Removing Using a Filter and Options","p":["You can remove multiple documents using a filter and options. It takes a Filter object as the first input parameter. It takes a boolean value as the second input parameter. If the second input parameter is true, then it will remove only the first document matched by the filter. Otherwise, it will remove all the documents matched by the filter. It returns a WriteResult object."]},{"i":"removing-using-a-filter-and-options-code-1","c":["WriteResult result = collection.remove(where(\"firstName\").eq(\"John\"), true);"]}],[{"l":"Read Operations"},{"l":"Find Operations","p":["You can search documents in a collection using find() method. There are several overloaded version of find() method using a filter or find options or both. You can also search a document using it's NitriteId."]},{"l":"Filters","p":["Nitrite uses filters to find documents in a collection. A filter is a simple expression which evaluates to true or false. More information about filters can be found here."]},{"l":"Find All Documents","p":["You can find all documents in a collection by calling find(). It returns a DocumentCursor object."]},{"i":"find-all-documents-code-1","c":["DocumentCursor cursor = collection.find();"]},{"l":"Finding a Document Using NitriteId","p":["You can find a document using it's NitriteId by calling getById(). It takes a NitriteId as input parameter. It returns a Document object if the document is found. Otherwise, it returns null."]},{"i":"finding-a-document-using-nitriteid-code-1","c":["Document doc = collection.getById(someNitriteId);"]},{"l":"Finding a Document Using a Filter","p":["You can find a document using a filter. It takes a Filter object as input parameter. It returns a DocumentCursor object.","If there is an index on the field specified in the filter, this operation will use the index to find the document. Otherwise, it will scan the entire collection to find the document."]},{"i":"finding-a-document-using-a-filter-code-1","c":["DocumentCursor cursor = collection.find(where(\"firstName\").eq(\"John\"));"]},{"l":"Finding a Document Using a Filter and Options","p":["You can find a document using a filter and options. It takes a Filter object as the first input parameter. It takes a FindOptions object as the second input parameter. It returns a DocumentCursor object."]},{"l":"FindOptions","p":["FindOptions is a class that contains several options for find operation. It has the following options:","limit: It specifies the maximum number of documents to be returned by the find operation.","skip: It specifies the number of documents to be skipped from the beginning of the result set.","orderBy: It specifies a collection of fields to be sorted by, along with sort order for each field. The sort order can be SortOrder.Ascending or SortOrder.Descending.","collator: It specifies a collator to be used for sorting. If this option is not specified, then the default collator will be used.","distinct: It specifies if the find operation should return distinct documents. If this option is true, then it will return only the distinct documents. Otherwise, it will return all the documents matched by the filter."]},{"i":"findoptions-code-1","c":["FindOptions findOptions = new FindOptions();\nfindOptions.skip(10).limit(10).thenOrderBy(\"firstName\", SortOrder.Descending).withDistinct(true);\n\nDocumentCursor cursor = collection.find(where(\"firstName\").eq(\"John\"), findOptions);"]},{"l":"DocumentCursor","p":["DocumentCursor represents a result set of a find operation. It provides methods to iterate over the result of a find operation and retrieve the documents. It also provides methods like projection, join etc. to get the desired result."]},{"l":"Iterating over Documents","p":["The DocumentCursor extends Iterable interface. So, you can iterate over the documents using for-each loop.","A DocumentCursor is a lazy iterable. It does not load all the documents in memory at once. It loads the documents in memory as needed. So, it is memory efficient."]},{"i":"iterating-over-documents-code-1","c":["DocumentCursor cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nfor (Document doc : cursor) {\n    // do something with the document\n}"]},{"l":"Getting the Documents","p":["You can get the documents at once using toList() and toSet() methods. It returns a List and Set of documents respectively."]},{"i":"getting-the-documents-code-1","c":["DocumentCursor cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nList<Document> documents = cursor.toList();\nSet<Document> documents = cursor.toSet();"]},{"l":"Getting the First Document","p":["You can get the first document using firstOrNull() method. It returns the first document if the cursor has any document. Otherwise, it returns null."]},{"i":"getting-the-first-document-code-1","c":["DocumentCursor cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nDocument doc = cursor.firstOrNull();"]},{"l":"Getting the Size of the Result Set","p":["You can get the size of the result set using size() method. It returns the number of documents in the result set."]},{"i":"getting-the-size-of-the-result-set-code-1","c":["DocumentCursor cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nlong size = cursor.size();"]},{"l":"Projection","p":["You can project the result set using project() method. It takes a Document as the only input parameter. It returns a RecordStreamDocument object.","The document must contain only the fields that needs to be projected. The field values must be null or a nested document. The condition holds true for nested documents as well.","Let's say you have a document like this:","And you want to project only lastName and address.street fields. Then you can do it like this:","The result set will contain only lastName and address.street fields."]},{"i":"projection-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"address\": {\n        \"street\": \"123 Main Street\",\n        \"city\": \"New York\"\n    }\n}"]},{"i":"projection-code-2","c":["DocumentCursor cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nDocument projection = Document.createDocument(\"lastName\", null).put(\"address\", createDocument(\"street\", null));\n\nRecordStream<Document> projectedStream = cursor.project(projection);"]},{"i":"projection-code-3","c":["{\n    \"lastName\": \"Doe\",\n    \"address\": {\n        \"street\": \"123 Main Street\"\n    }\n}"]},{"l":"Join","p":["You can join two cursors using join() method. It takes a DocumentCursor as the first input parameter. It takes a Lookup as the second input parameter. It returns a RecordStream object.","The join operation is similar to SQL left outer join operation. It takes two cursors and a lookup object. The lookup object contains the join condition.","Let's say you have two collections users and orders. The users collection contains the following documents:","And the orders collection contains the following documents:","Now, you want to join these two collections on userId field. Then you can do it like this:","The result set will contain the following documents:"]},{"i":"join-code-1","c":["{\n    \"userId\": 1,\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\"\n}"]},{"i":"join-code-2","c":["{\n    \"userId\": 2,\n    \"firstName\": \"Jane\",\n    \"lastName\": \"Doe\"\n}"]},{"i":"join-code-3","c":["{\n    \"orderId\": 1,\n    \"userId\": 1,\n    \"orderDate\": \"2018-01-01\"\n}"]},{"i":"join-code-4","c":["{\n    \"orderId\": 2,\n    \"userId\": 1,\n    \"orderDate\": \"2018-01-02\"\n}"]},{"i":"join-code-5","c":["{\n    \"orderId\": 3,\n    \"userId\": 2,\n    \"orderDate\": \"2018-01-03\"\n}"]},{"i":"join-code-6","c":["{\n    \"orderId\": 4,\n    \"userId\": 2,\n    \"orderDate\": \"2018-01-04\"\n}"]},{"i":"join-code-7","c":["DocumentCursor users = db.getCollection(\"users\").find();\nDocumentCursor orders = db.getCollection(\"orders\").find();\n\nLookup lookup = new Lookup();\nlookup.setLocalField(\"userId\");\nlookup.setForeignField(\"userId\");\nlookup.setTargetField(\"orders\");\n\nRecordStream<Document> joinedStream = users.join(orders, lookup);"]},{"i":"join-code-8","c":["{\n    \"userId\": 1,\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"orders\": [\n        {\n            \"orderId\": 1,\n            \"userId\": 1,\n            \"orderDate\": \"2018-01-01\"\n        },\n        {\n            \"orderId\": 2,\n            \"userId\": 1,\n            \"orderDate\": \"2018-01-02\"\n        }\n    ]\n}"]},{"i":"join-code-9","c":["{\n    \"userId\": 2,\n    \"firstName\": \"Jane\",\n    \"lastName\": \"Doe\",\n    \"orders\": [\n        {\n            \"orderId\": 3,\n            \"userId\": 2,\n            \"orderDate\": \"2018-01-03\"\n        },\n        {\n            \"orderId\": 4,\n            \"userId\": 2,\n            \"orderDate\": \"2018-01-04\"\n        }\n    ]\n}"]},{"l":"FindPlan","p":["FindPlan is a class that contains the execution plan of a find operation. It has the following properties:","byIdFilter: It contains the filter for finding a document using NitriteId.","indexScanFilter: It contains the filter for finding a document using index.","collectionScanFilter: It contains the filter for finding a document using full scan.","indexDescriptor: It contains the index descriptor for finding a document using index.","indexScanOrder: It contains the sort order for finding a document using index.","blockingSortOrder: It contains the sort order for finding a document using full scan.","skip: It contains the number of documents to be skipped from the beginning of the result set.","limit: It contains the maximum number of documents to be returned by the find operation.","distinct: It specifies if the find operation returns distinct documents.","collator: It specifies a collator to be used for sorting.","subPlans: It contains the sub plans for finding a document using or filter.","You can get the execution plan of a find operation using getFindPlan() method. It returns a FindPlan object."]},{"i":"findplan-code-1","c":["DocumentCursor cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nFindPlan findPlan = cursor.getFindPlan();"]}],[{"l":"Indexing","p":["Indexing is a way to optimize the performance of a database by minimizing the number of disk accesses required when a query is processed. It is a data structure technique which is used to quickly locate and access the data in a database.","Nitrite supports indexing on a collection. It supports indexing on a single field or multiple fields. It also supports full-text indexing."]},{"l":"Index Types","p":["Nitrite supports the following types of index out of the box:","Unique Index","Non-Unique Index","Full-text Index"]},{"l":"Unique Index","p":["A unique index ensures that the indexed field contains unique value. It does not allow duplicate value in the indexed field. It also ensures that the indexed field is not null."]},{"l":"Non-unique Index","p":["A non-unique index does not ensure that the indexed field contains unique value. It allows duplicate value in the indexed field."]},{"l":"Full-text Index","p":["A full-text index is used to search text content in a document. It is useful when you want to search text content in a document. It is also useful when you want to search text content in a document in a language other than English.","Document's _id field is always indexed.","Indexing on non-comparable value is not supported."]},{"l":"Custom Index","p":["You can also create your own custom index. You need to implement NitriteIndexer interface to create your own custom index. NitriteIndexer is a NitritePlugin, so you need to register it using loadModule() method while opening a database. During index creation you need to pass the type of the custom index in IndexOptions object.","One of such custom index implementation can be found in spatial module. It provides spatial indexing on a collection. More on spatial indexing can be found here."]},{"l":"Creating an Index","p":["You can create an index on a collection using createIndex() method. There are several overloaded version of createIndex() method. You can create an index on a single field or multiple fields.","You cannot create a new index on a field or a set of fields which is already indexed with a different type of index.","For example, if you have a unique index on firstName field, then you cannot create a non-unique index on firstName field. But you can create a unique index on firstName and lastName fields. Similarly, if you have a unique index on firstName and lastName fields, then you cannot create a non-unique index on firstName and lastName fields. But you can create two indexes on firstName and lastName fields separately."]},{"l":"Creating a Unique Index","p":["You can create a unique index on a single field or multiple fields. It takes the name of the fields on which the index will be created as input parameter."]},{"i":"creating-a-unique-index-code-1","c":["// create a unique index on a single field\ncollection.createIndex(\"firstName\");\n\n// create a unique index on multiple fields\ncollection.createIndex(\"firstName\", \"lastName\");"]},{"l":"Creating a Non-unique Index","p":["You can create a non-unique index on a single field or multiple fields by passing the index type as IndexType.NON_UNIQUE in IndexOptions object and the name of the fields on which the index will be created as input parameters."]},{"i":"creating-a-non-unique-index-code-1","c":["// create a non-unique index on a single field\ncollection.createIndex(IndexOptions.indexOptions(IndexType.NON_UNIQUE), \"firstName\");\n\n// create a non-unique index on multiple fields\ncollection.createIndex(IndexOptions.indexOptions(IndexType.NON_UNIQUE), \"firstName\", \"lastName\");"]},{"l":"Creating a Full-text Index","p":["You can create a full-text index on a single field by passing the index type as IndexType.FULL_TEXT in IndexOptions object and the name of the field on which the index will be created as input parameters.","Full-text index is not supported on multiple fields."]},{"i":"creating-a-full-text-index-code-1","c":["// create a full-text index on a single field\ncollection.createIndex(IndexOptions.indexOptions(IndexType.FULL_TEXT), \"firstName\");"]},{"l":"Creating Index on Array Field","p":["Nitrite supports creating index on array field. It will create index on each element of the array. For example, if you have a document like this:","You can create index on phones field like this:"]},{"i":"creating-index-on-array-field-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"age\": 30,\n    \"address\": \"123 Street\",\n    \"phones\": [\"1234567890\", \"0987654321\"]\n}"]},{"i":"creating-index-on-array-field-code-2","c":["// create unique index on array field\ncollection.createIndex(\"phones\");\n\n// create non-unique index on array field\ncollection.createIndex(IndexOptions.indexOptions(IndexType.NON_UNIQUE), \"phones\");"]},{"l":"Creating Index on Nested Field","p":["You can create index on nested field. For example, if you have a document like this:","You can create a unique index on street field like this:","You cannot create index on nested field if the parent field is an array."]},{"i":"creating-index-on-nested-field-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"age\": 30,\n    \"phones\": [\"1234567890\", \"0987654321\"],\n    \"address\": {\n        \"street\": \"123 Street\",\n        \"city\": \"New York\",\n        \"state\": \"NY\",\n        \"zip\": \"10021\"\n    }\n}"]},{"i":"creating-index-on-nested-field-code-2","c":["// create unique index on nested field\ncollection.createIndex(\"address.street\");"]},{"l":"Rebuilding an Index","p":["You can rebuild an index on a collection using rebuildIndex() method. It takes the name of the fields on which the index will be rebuilt as input parameter."]},{"i":"rebuilding-an-index-code-1","c":["// rebuild an index on a single field\ncollection.rebuildIndex(\"firstName\");\n\n// rebuild an index on multiple fields\ncollection.rebuildIndex(\"firstName\", \"lastName\");"]},{"l":"Dropping an Index","p":["You can drop an index on a collection using dropIndex() method. It takes the name of the fields on which the index will be dropped as input parameter."]},{"i":"dropping-an-index-code-1","c":["// drop an index on a single field\ncollection.dropIndex(\"firstName\");\n\n// drop an index on multiple fields\ncollection.dropIndex(\"firstName\", \"lastName\");"]},{"l":"Dropping All Indexes","p":["You can drop all indexes on a collection using dropAllIndices() method."]},{"i":"dropping-all-indexes-code-1","c":["collection.dropAllIndices();"]},{"l":"Getting All Indexes","p":["You can get all indexes on a collection using listIndices() method. It returns a Collection of IndexDescriptor object."]},{"i":"getting-all-indexes-code-1","c":["Collection<IndexDescriptor> indexes = collection.listIndices();"]},{"l":"IndexDescriptor","p":["IndexDescriptor is a simple class which contains the following information about an index:","collectionName: The name of the collection on which the index is created.","indexType: The type of the index.","fields: A Fields object containing the name of the fields on which the index is created."]},{"l":"Checking If an Index Exists","p":["You can check if an index exists on a collection using hasIndex() method. It takes the name of the fields on which the index will be checked as input parameter."]},{"i":"checking-if-an-index-exists-code-1","c":["// check if an index exists on a single field\nboolean exists = collection.hasIndex(\"firstName\");\n\n// check if an index exists on multiple fields\nboolean exists = collection.hasIndex(\"firstName\", \"lastName\");"]},{"l":"Error Scenarios","p":["The following error scenarios are possible while creating an index:","If another index of any type is already created on the collection on the same field(s), then it will throw IndexingException.","If a unique index is created on a field and the field contains duplicate value, then it will throw UniqueConstraintException.","If a full-text index is created on multiple fields, then it will throw IndexingException.","If a full-text index is created on a field which is not a String, then it will throw IndexingException.","If you try to drop an index which does not exist, then it will throw IndexingException.","If you try to rebuild an index which does not exist, then it will throw IndexingException."]}],[{"l":"Other Operations"},{"l":"Size of a Collection","p":["You can get the size of a collection using size() method. It returns the number of documents in the collection."]},{"i":"size-of-a-collection-code-1","c":["long size = collection.size();"]},{"l":"Clearing a Collection","p":["You can clear all the documents from a collection using clear() method. It removes all the documents from the collection and index entries from the indexes. It does not drop the collection."]},{"i":"clearing-a-collection-code-1","c":["collection.clear();"]},{"l":"Dropping a Collection","p":["You can drop a collection using drop() method. It removes all the documents from the collection and index entries from the indexes. It also drops all the indexes associated with the collection. It also removes the collection from the database.","You can call isDropped() method to check if the collection is dropped or not.","Any further operation on a dropped collection will throw NitriteIOException."]},{"i":"dropping-a-collection-code-1","c":["collection.drop();"]},{"i":"dropping-a-collection-code-2","c":["boolean isDropped = collection.isDropped();"]},{"l":"Closing a Collection","p":["You can close a collection using close() method. Any further operation on a closed collection will throw NitriteIOException.","After closing a collection, you must re-open it via Nitrite.getCollection() method to perform any operation on it.","You can call isOpen() method to check if the collection is closed or not."]},{"i":"closing-a-collection-code-1","c":["collection.close();"]},{"i":"closing-a-collection-code-2","c":["boolean isOpen = collection.isOpen();"]},{"l":"Event Listener","p":["You can register an event listener on a collection to get notified on document changes. The event listener must implement CollectionEventListener interface. It will receive CollectionEventInfo whenever a document is inserted, updated or removed from the collection.","You can also remove an event listener from a collection."]},{"i":"event-listener-code-1","c":["collection.subscribe(eventInfo -> {\n    // do something\n});"]},{"i":"event-listener-code-2","c":["collection.unsubscribe(listener);"]},{"l":"CollectionEventInfo","p":["CollectionEventInfo contains the following information:","item - the document which is inserted, updated or removed.","originator - the name of the collection on which the event is fired.","eventType - the type of the event. It can be any of the following:","EventType.Insert","EventType.Update","EventType.Remove","EventType.IndexStart","EventType.IndexEnd","timestamp - the timestamp of the event."]},{"l":"Attributes","p":["Attributes is a metadata information associated with a collection.","You can get/set attributes on a collection. The attributes are stored in the database and can be retrieved later. The attributes are stored in a special map named $nitrite_meta_map."]},{"i":"attributes-code-1","c":["// get the attributes\nAttributes attributes = collection.getAttributes();\nattributes.set(\"key\", \"value\");\n\n// save the attributes\ncollection.setAttributes(attributes);\n\n// get the attributes\nattributes = collection.getAttributes();\n\n// get the value of a key\nString value = attributes.get(\"key\");"]},{"l":"Processors","p":["Processors are used to process documents before writing them into or after reading them from a collection.","Processors are useful when you want to add some additional information in a document or transform any field before inserting or updating it in a collection. Processors are also useful when you want to validate a document before inserting or updating it in a collection.","Processors are registered on a collection. A collection can have multiple processors. Processors are executed in the order they are registered."]},{"l":"Registering a Processor","p":["You can register a processor on a collection using addProcessor() method. It takes a Processor as input parameter."]},{"i":"registering-a-processor-code-1","c":["public class MyProcessor implements Processor {\n    @Override\n    public Document processBeforeWrite(Document document) {\n        // encrypt the secret value\n        document.put(\"secretValue\", encrypt(document.get(\"secretValue\")));\n        return document;\n    }\n\n    @Override\n    public Document processAfterRead(Document document) {\n        // decrypt the secret value\n        document.put(\"secretValue\", decrypt(document.get(\"secretValue\")));\n        return document;\n    }\n}\n\n// create a processor\nMyProcessor processor = new MyProcessor();\n\n// process existing documents, if the collection is not empty\nprocessor.process(collection);\n\n// register the processor\ncollection.addProcessor(processor);"]},{"l":"Available Processors","p":["Nitrite provides a StringFieldEncryptionProcessor which can be used to encrypt a field before writing it into a collection and decrypt a field after reading it from a collection.","More on this is described in Support."]}],[{"l":"Introduction","p":["ObjectRepository provides a simple and type-safe API for storing and retrieving Java objects in a Nitrite database. It is built on top of NitriteCollection and provides a similar API for CRUD operations. It also supports indexing and querying. It also supports event based notification on object changes.","ObjectRepository is thread-safe and supports concurrent read and write operations."]},{"l":"Creating a Repository","p":["An ObjectRepository can be created using Nitrite class. You need to call getRepository() method on Nitrite class to get an instance of an ObjectRepository. If the repository does not exist, then it will be created automatically. If a repository with the same name already exists, then it will return the existing repository.","There are several overloaded methods available to create a repository. You can pass a class type or an EntityDecorator along with an optional string key to create a repository."]},{"l":"Creating a Repository with Class Type","p":["You can create a ObjectRepository by passing a class type to getRepository() method."]},{"i":"creating-a-repository-with-class-type-code-1","c":["Nitrite db = Nitrite.builder()\n    .openOrCreate();\n\nObjectRepository<Employee> repository = db.getRepository(Employee.class);"]},{"l":"Creating a Repository with Class Type and Key","p":["You can create a keyed ObjectRepository by passing a class type and a key to getRepository() method.","One typical use case of this keyed repository is to create a repository for each user in a multi-user application. The key can be the user name or user id. This will ensure that each user will have a separate repository for storing objects."]},{"i":"creating-a-repository-with-class-type-and-key-code-1","c":["Nitrite db = Nitrite.builder()\n    .openOrCreate();\n\nObjectRepository<Employee> repository = db.getRepository(Employee.class, \"myKey\");"]},{"l":"Creating a Repository with EntityDecorator","p":["A ObjectRepository can be created using EntityDecorator. This is useful when you cannot modify the object class to add annotations.","More details about EntityDecorator can be found here."]},{"i":"creating-a-repository-with-entitydecorator-code-1","c":["Nitrite db = Nitrite.builder()\n    .openOrCreate();\n\nObjectRepository<Employee> repository = db.getRepository(new EmployeeDecorator());"]},{"l":"Creating a Repository with EntityDecorator and Key","p":["A keyed ObjectRepository can be created using EntityDecorator and a key. This is useful when you cannot modify the object class to add annotations.","More details about EntityDecorator can be found here."]},{"i":"creating-a-repository-with-entitydecorator-and-key-code-1","c":["Nitrite db = Nitrite.builder()\n    .openOrCreate();\n\nObjectRepository<Employee> repository = db.getRepository(new EmployeeDecorator(), \"myKey\");"]}],[{"l":"Entity","p":["An entity is a Java object that can be stored in a Nitrite database. An entity can be a simple POJO or a complex object with nested objects. Every entity in an ObjectRepository is actually converted to a Document before storing in the underlying NitriteCollection. When an entity is converted to a Document, the fields of the entity are mapped to the fields of the Document. While retrieving an entity from the ObjectRepository, the Document is converted back to the entity.","Nitrite uses a NitriteMapper implementation to convert an entity to a Document and vice versa. By default, Nitrite uses an EntityConverter based implementation of NitriteMapper to convert an entity to a Document. You can also provide your own implementation of NitriteMapper to convert an entity to a Document.","More on NitriteMapper can be found here."]},{"l":"Annotations","p":["Nitrite uses annotations to define an entity. There are several annotations available to define an entity. These annotations are:","@Entity","@Id","@Index","@Indices","@InheritIndices","In case you cannot modify the entity class to add annotations, you can use EntityDecorator to add metadata to an entity. More on EntityDecorator can be found here."]},{"i":"entity-1","l":"@Entity","p":["@Entity annotation is used to mark a class as an entity. It is a class level annotation and takes optional value and indices parameters.","The value parameter is used to specify the name of the NitriteCollection in which the entity will be stored as a Document. If the value parameter is not specified, then the name of the collection will be the name of the class. The indices parameter is used to specify the indices on the repository."],"c":["@Entity public class Employee { @Id private Long empId; private String firstName; private String lastName; private Address address; private List<String> phoneNumbers; private Map<String, String> properties; // getters and setters }","@Entity(value = \"employees\", indices = { @Index(fields = \"firstName\", type = IndexType.NON_UNIQUE), @Index(fields = \"lastName\", type = IndexType.NON_UNIQUE), @Index(fields = { \"address.city\", \"firstName\" }), }) public class Employee { @Id private Long empId; private String firstName; private String lastName; private Address address; private List<String> phoneNumbers; private Map<String, String> properties; // getters and setters }"]},{"l":"@Id","p":["@Id annotation is used to mark a field as the unique identifier of the entity. It is a field level annotation and takes optional fieldName parameter. The fieldName parameter is used to specify the name of the field in the document. If the fieldName parameter is not specified, then the name of the field in the class will be used as the name of the field in the document."],"c":["@Entity public class Employee { @Id private Long empId; private String firstName; private String lastName; private Address address; private List<String> phoneNumbers; private Map<String, String> properties; // getters and setters }","@Entity public class Employee { @Id(fieldName = \"empId\") private Long empId; private String firstName; private String lastName; private Address address; private List<String> phoneNumbers; private Map<String, String> properties; // getters and setters }"]},{"l":"Embedded Id","p":["Nitrite also supports embedded id. The embedded id is used when the entity has a composite primary key. The @Id annotation can also be used to mark a field as an embedded id. In case of embedded id, the field should be marked with @Id annotation and the fieldName and embeddedFields parameters should be specified. The fieldName parameter is used to specify the name of the field in the document. The embeddedFields parameter is used to specify the name of the fields in the embedded object.","The above @Id annotation will create a unique compound index on the fields - emp_Id.uniqueId and emp_Id.companyId."]},{"i":"embedded-id-code-1","c":["@Entity\npublic class Employee {\n    @Id(fieldName = \"emp_Id\", embeddedFields = { \"uniqueId\", \"companyId\" })\n    private EmployeeId empId;\n    private String firstName;\n    private String lastName;\n    private Address address;\n    private List<String> phoneNumbers;\n    private Map<String, String> properties;\n    // getters and setters\n}\n\npublic class EmployeeId {\n    private Long uniqueId;\n    private String companyId;\n    // getters and setters\n}"]},{"l":"Data Type","p":["The data type of the field marked with @Id annotation can be either Comparable or NitriteId. If the data type is Comparable, then the value of the field should be unique. If the data type is NitriteId, then the value of the field will be generated by Nitrite. But in the case of embedded id, the data type of the embedded fields can only be Comparable, it can't be NitriteId."]},{"l":"@Index","p":["@Index annotation is used to declare an index on an entity field. It is a class level annotation and takes mandatory fields parameter and optional type parameter. The fields parameter is used to specify the names of the fields in the document to be indexed. The type parameter is used to specify the type of the index. If the type parameter is not specified, then the type of the index will be IndexType.UNIQUE."]},{"i":"index-code-1","c":["@Entity(value = \"employees\", indices = {\n    @Index(fields = \"firstName\", type = IndexType.NON_UNIQUE),\n    @Index(fields = \"lastName\", type = IndexType.NON_UNIQUE),\n    @Index(fields = { \"address.city\", \"firstName\" }),\n})\npublic class Employee {\n    @Id\n    private Long empId;\n    private String firstName;\n    private String lastName;\n    private Address address;\n    private List<String> phoneNumbers;\n    private Map<String, String> properties;\n    // getters and setters\n}"]},{"l":"@Indices","p":["@Indices annotation is used declare multiple indices on an entity. It is a class level annotation and takes mandatory value parameter. The value parameter is used to specify the list of @Index annotations."]},{"i":"indices-code-1","c":["@Indices({\n    @Index(fields = \"firstName\", type = IndexType.NON_UNIQUE),\n    @Index(fields = \"address.streetName\", type = IndexType.FULL_TEXT)\n})\npublic class Employee {\n    @Id\n    private Long empId;\n    private String firstName;\n    private String lastName;\n    private Address address;\n    private List<String> phoneNumbers;\n    private Map<String, String> properties;\n    // getters and setters\n}"]},{"l":"@InheritIndices","p":["@InheritIndices annotation is used to inherit the indices from the parent class. It is a class level annotation and takes no parameter.","If the @InheritIndices annotation is not specified, then the indices will not be inherited from the parent class."]},{"i":"inheritindices-code-1","c":["@Entity\n@Indices({\n    @Index(fields = \"firstName\", type = IndexType.NON_UNIQUE),\n    @Index(fields = \"address.streetName\", type = IndexType.FULL_TEXT)\n})\npublic class Employee {\n    @Id\n    private Long empId;\n    private String firstName;\n    private String lastName;\n    private Address address;\n    private List<String> phoneNumbers;\n    private Map<String, String> properties;\n    // getters and setters\n}\n\n@Entity\n@InheritIndices\n@Index(fields = \"department\", type = IndexType.NON_UNIQUE),\npublic class Manager extends Employee {\n    private String department;\n    // getters and setters\n}"]},{"l":"EntityDecorator","p":["EntityDecorator is used to add metadata to an entity. If you cannot modify the entity class to add annotations, then you can use EntityDecorator to add metadata to an entity. You can use EntityDecorator to add id, indices and collection name for an entity.","While creating or opening a repository, you can pass an instance of EntityDecorator to the getRepository() method on Nitrite class. Nitrite will extract the metadata from the EntityDecorator instance and use it to create the repository.","To write an EntityDecorator for an entity, you need to implement the EntityDecorator interface. Let's take an example of a Product entity.","The Product entity has an embedded id ProductId and two indices on a nested object Manufacturer. To write an EntityDecorator for the Product entity, you need to implement the EntityDecorator interface as follows.","which is equivalent to the following entity class."]},{"i":"entitydecorator-code-1","c":["Nitrite db = Nitrite.builder()\n    .openOrCreate();\n\nObjectRepository<Product> repository = db.getRepository(new ProductDecorator());"]},{"i":"entitydecorator-code-2","c":["public class Product {\n    private ProductId productId;\n    private Manufacturer manufacturer;\n    private String productName;\n    private Double price;\n    // getters and setters\n}\n\npublic class ProductId {\n    private String uniqueId;\n    private String productCode;\n    // getters and setters\n}\n\npublic class Manufacturer {\n    private String name;\n    private String uniqueId;\n    // getters and setters\n}"]},{"i":"entitydecorator-code-3","c":["public class ProductDecorator implements EntityDecorator<Product> {\n    @Override\n    public Class<Product> getEntityType() {\n        return Product.class;\n    }\n\n    @Override\n    public EntityId getIdField() {\n        return new EntityId(\"productId\", \"uniqueId\", \"productCode\");\n    }\n\n    @Override\n    public List<EntityIndex> getIndexFields() {\n        return Arrays.asList(\n            new EntityIndex(IndexType.NON_UNIQUE, \"manufacturer.name\"),\n            new EntityIndex(IndexType.UNIQUE, \"productName\", \"manufacturer.uniqueId\")\n        );\n    }\n\n    @Override\n    public String getEntityName() {\n        return \"product\";\n    }\n}"]},{"i":"entitydecorator-code-4","c":["@Entity(value = \"product\", indices = {\n    @Index(fields = \"manufacturer.name\", type = IndexType.NON_UNIQUE),\n    @Index(fields = { \"productName\", \"manufacturer.uniqueId\" }, type = IndexType.UNIQUE)\n})\npublic class Product {\n    @Id(fieldName = \"productId\", embeddedFields = { \"uniqueId\", \"productCode\" })\n    private ProductId productId;\n    private Manufacturer manufacturer;\n    private String productName;\n    private Double price;\n}"]},{"l":"EntityId","p":["EntityId is used to specify the id field of an entity. It takes mandatory fieldName parameter and optional embeddedFields parameter in case of embedded id. The fieldName parameter is used to specify the name of the field in the document. The embeddedFields parameter is used to specify the name of the fields in the embedded object.","Here productId is the name of the field in the document and uniqueId and productCode are the names of the fields in the embedded object. This will create a unique compound index on the fields - productId.uniqueId and productId.productCode."]},{"i":"entityid-code-1","c":["@Override\npublic EntityId getIdField() {\n    return new EntityId(\"productId\", \"uniqueId\", \"productCode\");\n}"]},{"l":"EntityIndex","p":["EntityIndex is used to specify the indices on an entity. It takes mandatory type parameter and fields parameter. The type parameter is used to specify the type of the index. The fields parameter is used to specify the name of the fields in the document to be indexed.","Here manufacturer.name is the name of the field in the document and productName and manufacturer.uniqueId are the names of the fields in the document. This will create a non-unique index on the field manufacturer.name and a unique compound index on the fields - productName and manufacturer.uniqueId."]},{"i":"entityindex-code-1","c":["@Override\npublic List<EntityIndex> getIndexFields() {\n    return Arrays.asList(\n        new EntityIndex(IndexType.NON_UNIQUE, \"manufacturer.name\"),\n        new EntityIndex(IndexType.UNIQUE, \"productName\", \"manufacturer.uniqueId\")\n    );\n}"]},{"l":"Entity Name","p":["Entity name is used to specify the name of the collection in which the entity will be stored. It takes no parameter.","Here product is the name of the NitriteCollection in which the product document will be stored."]},{"i":"entity-name-code-1","c":["@Override\npublic String getEntityName() {\n    return \"product\";\n}"]}],[{"l":"NitriteMapper","p":["NitriteMapper is a simple and lightweight object mapper which can be used to map Java objects to Nitrite documents and vice-versa. Nitrite uses a NitriteMapper implementation to map Java entities to Nitrite documents and vice-versa while storing and retrieving objects from an ObjectRepository."]},{"l":"SimpleNitriteMapper","p":["Nitrite provides a default NitriteMapper implementation called SimpleNitriteMapper. This is a simple and lightweight mapper which uses EntityConverter to map a Java object to Nitrite documents and vice-versa. This mapper is suitable for most of the use cases."]},{"l":"EntityConverter","p":["EntityConverter is a simple interface which provides methods to convert a Java object to Nitrite document and vice-versa. For each class, you need to provide an implementation of EntityConverter and register it with SimpleNitriteMapper. SimpleNitriteMapper will use this converter to map the object to Nitrite document and vice-versa.","Let's take an example of Product class.","To map this to Nitrite document, we need to provide an implementation of EntityConverter for each class. Let's take a look at the converter for Product class.","Similarly, we need to provide converter for ProductId and Manufacturer class.","Once the converters are ready, we need to register them with registerEntityConverter() method on NitriteBuilder instance.","we can also register the converters with SimpleNitriteMapper instance and then pass the instance to loadModule() method.","NitriteMapper is a NitritePlugin. So, you need to load it using loadModule() method on NitriteBuilder. More on Nitrite's module system can be found here.","If you have used the registerEntityConverter() method on NitriteBuilder instance, Nitrite will only use SimpleNitriteMapper to map the entities. It will ignore any other NitriteMapper implementation you have provided using loadModule() method."]},{"i":"entityconverter-code-1","c":["public class Product {\n    private ProductId productId;\n    private Manufacturer manufacturer;\n    private String productName;\n    private Double price;\n    // getter and setter\n}\n\npublic class ProductId {\n    private String uniqueId;\n    private String productCode;\n    // getter and setter\n}\n\npublic class Manufacturer {\n    private String name;\n    private String address;\n    private Integer uniqueId;\n    // getter and setter\n}"]},{"i":"entityconverter-code-2","c":["public class ProductConverter implements EntityConverter<Product> {\n    @Override\n    public Class<Product> getEntityType() {\n        return Product.class;\n    }\n\n    @Override\n    public Document toDocument(Product entity, NitriteMapper nitriteMapper) {\n        Document productId = (Document) nitriteMapper.tryConvert(entity.getProductId(), Document.class);\n        Document manufacturer = (Document) nitriteMapper.tryConvert(entity.getManufacturer(), Document.class);\n\n        return Document.createDocument()\n            .put(\"productId\", productId)\n            .put(\"manufacturer\", manufacturer)\n            .put(\"productName\", entity.getProductName())\n            .put(\"price\", entity.getPrice());\n    }\n\n    @Override\n    public Product fromDocument(Document document, NitriteMapper nitriteMapper) {\n        Product entity = new Product();\n        ProductId productId = (ProductId) nitriteMapper.tryConvert(document.get(\"productId\", Document.class), ProductId.class);\n        Manufacturer manufacturer = (Manufacturer) nitriteMapper.tryConvert(document.get(\"manufacturer\", Document.class),\n            Manufacturer.class);\n        entity.setProductId(productId);\n        entity.setManufacturer(manufacturer);\n        entity.setProductName(document.get(\"productName\", String.class));\n        entity.setPrice(document.get(\"price\", Double.class));\n        return entity;\n    }\n}"]},{"i":"entityconverter-code-3","c":["public class ProductIdConverter implements EntityConverter<ProductId> {\n    @Override\n    public Class<ProductId> getEntityType() {\n        return ProductId.class;\n    }\n\n    @Override\n    public Document toDocument(ProductId entity, NitriteMapper nitriteMapper) {\n        return Document.createDocument(\"uniqueId\", entity.getUniqueId())\n            .put(\"productCode\", entity.getProductCode());\n    }\n\n    @Override\n    public ProductId fromDocument(Document document, NitriteMapper nitriteMapper) {\n        ProductId entity = new ProductId();\n        entity.setUniqueId(document.get(\"uniqueId\", String.class));\n        entity.setProductCode(document.get(\"productCode\", String.class));\n        return entity;\n    }\n}\n\npublic class ManufacturerConverter implements EntityConverter<Manufacturer> {\n    @Override\n    public Class<Manufacturer> getEntityType() {\n        return Manufacturer.class;\n    }\n\n    @Override\n    public Document toDocument(Manufacturer entity, NitriteMapper nitriteMapper) {\n        return Document.createDocument(\"name\", entity.getName())\n            .put(\"address\", entity.getAddress())\n            .put(\"uniqueId\", entity.getUniqueId());\n    }\n\n    @Override\n    public Manufacturer fromDocument(Document document, NitriteMapper nitriteMapper) {\n        Manufacturer manufacturer = new Manufacturer();\n        manufacturer.setName(document.get(\"name\", String.class));\n        manufacturer.setAddress(document.get(\"address\", String.class));\n        manufacturer.setUniqueId(document.get(\"uniqueId\", Integer.class));\n        return manufacturer;\n    }\n}"]},{"i":"entityconverter-code-4","c":["Nitrite db = Nitrite.builder()\n    .registerEntityConverter(new ProductConverter())\n    .registerEntityConverter(new ProductIdConverter())\n    .registerEntityConverter(new ManufacturerConverter())\n    .openOrCreate();"]},{"i":"entityconverter-code-5","c":["NitriteMapper nitriteMapper = new SimpleNitriteMapper();\nnitriteMapper.registerEntityConverter(new ProductConverter());\nnitriteMapper.registerEntityConverter(new ProductIdConverter());\nnitriteMapper.registerEntityConverter(new ManufacturerConverter());\n\nNitrite db = Nitrite.builder()\n    .loadModule(module(nitriteMapper))\n    .openOrCreate();"]},{"l":"JacksonMapper","p":["Nitrite also provides a Jackson based mapper called JacksonMapper. This mapper uses Jackson's ObjectMapper to map Java entities to Nitrite documents and vice-versa. Here you don't need to provide any EntityConverter. Jackson will use its own ObjectMapper to map the entities.","More on this mapper can be found here."]},{"l":"Custom NitriteMapper","p":["Apart from SimpleNitriteMapper and JacksonMapper, you can also provide your own implementation of NitriteMapper. You need to implement NitriteMapper interface and provide your own implementation. Once the implementation is ready, you need to load it using loadModule() method on NitriteBuilder while building the database."]},{"i":"custom-nitritemapper-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(module(new CustomNitriteMapper()))\n    .openOrCreate();"]}],[{"l":"Write Operations"},{"l":"Inserting Entities","p":["Entities can be inserted into a repository using insert() method. It takes one or multiple Java entities as input parameter. It returns a WriteResult object.","If the entity has a NitriteId field, then the field value would be populated with a new NitriteId before inserting into the repository.","If any of the field is already indexed in the repository, then the index will be updated accordingly.","This operation will notify all the registered CollectionEventListener with EventType.Insert event."]},{"l":"Inserting a Single Entity"},{"i":"inserting-a-single-entity-code-1","c":["Product product = new Product();\nproduct.setProductId(new ProductId(1));\nproduct.setProductName(\"Apple iPhone 6\");\nproduct.setPrice(600.0);\n\nWriteResult result = productRepository.insert(product);"]},{"l":"Inserting Multiple Entities"},{"i":"inserting-multiple-entities-code-1","c":["Product product1 = new Product();\nproduct1.setProductId(new ProductId(1));\nproduct1.setProductName(\"Apple iPhone 6\");\nproduct1.setPrice(600.0);\n\nProduct product2 = new Product();\nproduct2.setProductId(new ProductId(2));\nproduct2.setProductName(\"Apple iPhone 6 Plus\");\nproduct2.setPrice(700.0);\n\nWriteResult result = productRepository.insert(product1, product2);"]},{"l":"Error Scenarios","p":["If the entity is null, then it will throw a ValidationException.","If a field of the entity is unique indexed and it's value violates the index constraint, then it will throw a UniqueConstraintException."]},{"l":"WriteResult","p":["More information about WriteResult can be found here."]},{"l":"Updating Entities","p":["Entities can be updated in a repository using update() method. There are several overloaded methods available for updating entities. All of them returns a WriteResult object.","This operation will notify all the registered CollectionEventListener with EventType.Update event."]},{"l":"Updating a Single Entity","p":["You can update a single entity using update() method. It takes a Java entity as input parameter. It returns a WriteResult object.","The entity must have a valid id field marked with @Id annotation. In case an EntityDecorator is used, the getIdField() method must return a valid non-null EntityId object. Otherwise, it will throw a NotIdentifiableException."]},{"i":"updating-a-single-entity-code-1","c":["Product product = new Product();\nproduct.setProductId(new ProductId(1));\nproduct.setProductName(\"Apple iPhone 6\");\nproduct.setPrice(600.0);\n\nWriteResult result = productRepository.insert(product);\n\nproduct.setPrice(700.0);\nresult = productRepository.update(product);"]},{"l":"Upserting a Single Entity","p":["You can upsert a single entity using update() method. It takes a Java entity as first input parameter. It takes a boolean value as second input parameter. If the second input parameter is true, then it will insert the entity if it does not exist in the repository. Otherwise, it will update the entity if it exists in the repository. It returns a WriteResult object."]},{"i":"upserting-a-single-entity-code-1","c":["Product product = new Product();\nproduct.setProductId(new ProductId(1));\nproduct.setProductName(\"Apple iPhone 6\");\nproduct.setPrice(600.0);\n\nWriteResult result = productRepository.update(product, true);"]},{"l":"Updating Using a Filter","p":["You can update multiple entities using a filter. It takes a Filter object as first input parameter. It takes a Java entity as second input parameter. It returns a WriteResult object. The entity must not be null.","If the filter result matches multiple entities, then all the entities will be updated."]},{"i":"updating-using-a-filter-code-1","c":["Product product = new Product();\nproduct.setProductId(new ProductId(1));\nproduct.setProductName(\"Apple iPhone 6\");\nproduct.setPrice(600.0);\n\nWriteResult result = productRepository.update(where(\"productName\").eq(\"Apple iPhone 6\"), product);"]},{"l":"Updating Using a Filter and Options","p":["You can update multiple entities using a filter and options. It takes a Filter object as first input parameter. It takes a Java entity as second input parameter. It takes a UpdateOptions object as third input parameter. It returns a WriteResult object. The entity must not be null."]},{"l":"UpdateOptions","p":["More information about UpdateOptions can be found here."]},{"i":"updateoptions-code-1","c":["Product product = new Product();\nproduct.setProductId(new ProductId(1));\nproduct.setProductName(\"Apple iPhone 6\");\nproduct.setPrice(600.0);\n\nUpdateOptions updateOptions = new UpdateOptions();\nupdateOptions.insertIfAbsent(true);\n\nWriteResult result = productRepository.update(where(\"productName\").eq(\"Apple iPhone 6\"), product, updateOptions);"]},{"l":"Updating Using a Filter and Document","p":["You can update multiple entities using a filter and document. It takes a Filter object as first input parameter. It takes a Document object as second input parameter. It returns a WriteResult object. The document must not be null or empty.","If the filter result matches multiple entities, then all the entities will be updated. The document must contain only the fields that needs to be updated.","The document should not contain _id field."]},{"i":"updating-using-a-filter-and-document-code-1","c":["Document update = Document.createDocument(\"price\", 700.0);\n\nWriteResult result = productRepository.update(where(\"productName\").eq(\"Apple iPhone 6\"), update);"]},{"l":"Updating Using a Filter, Document and Options","p":["You can update multiple entities using a filter, document and options. It takes a Filter object as first input parameter. It takes a Document object as second input parameter. It takes a boolean value as third input parameter. If the third input parameter is true, then it will only update the first entity matched by the filter. Otherwise, it will update all the entities matched by the filter. It returns a WriteResult object. The document must not be null or empty.","The document must contain only the fields that needs to be updated.","The document should not contain _id field."]},{"i":"updating-using-a-filter-document-and-options-code-1","c":["Document update = Document.createDocument(\"price\", 700.0);\n\nWriteResult result = productRepository.update(where(\"productName\").eq(\"Apple iPhone 6\"), update, false);"]},{"l":"Removing Entities","p":["Entities can be removed from a repository using remove() method. There are several overloaded methods available for removing entities. All of them returns a WriteResult object.","This operation will notify all the registered CollectionEventListener with EventType.Remove event."]},{"l":"Removing a Single Entity","p":["You can remove a single entity using remove() method. It takes a Java entity as input parameter. It returns a WriteResult object.","The entity must have a valid id field marked with @Id annotation. In case an EntityDecorator is used, the getIdField() method must return a valid non-null EntityId object. Otherwise, it will throw a NotIdentifiableException."]},{"i":"removing-a-single-entity-code-1","c":["Product product = new Product();\nproduct.setProductId(new ProductId(1));\nproduct.setProductName(\"Apple iPhone 6\");\nproduct.setPrice(600.0);\n\nWriteResult result = productRepository.insert(product);\n\nresult = productRepository.remove(product);"]},{"l":"Removing Using a Filter","p":["You can remove multiple entities using a filter. It takes a Filter object as input parameter. It returns a WriteResult object.","If the filter result matches multiple entities, then all the entities will be removed."]},{"i":"removing-using-a-filter-code-1","c":["WriteResult result = productRepository.remove(where(\"productName\").eq(\"Apple iPhone 6\"));"]},{"l":"Removing Using a Filter and Options","p":["You can remove multiple entities using a filter and options. It takes a Filter object as first input parameter. It takes a boolean value as second input parameter. If the second input parameter is true, then it will remove only the first entity matched by the filter. Otherwise, it will remove all the entities matched by the filter. It returns a WriteResult object."]},{"i":"removing-using-a-filter-and-options-code-1","c":["WriteResult result = productRepository.remove(where(\"productName\").eq(\"Apple iPhone 6\"), false);"]}],[{"l":"Read Operations"},{"l":"Find Operations","p":["You can search entities in a repository using find() method. There are several overloaded version of find() method using a filter or find options or both. You can also search an entity using it's id."]},{"l":"Filters","p":["Nitrite uses filters to find entities in a repository. A filter is a simple expression which evaluates to true or false. More information about filters can be found here."]},{"l":"Find All Entities","p":["You can find all entities in a repository by calling find(). It returns a Cursor object."]},{"i":"find-all-entities-code-1","c":["Cursor<Product> cursor = productRepository.find();"]},{"l":"Finding an Entity Using Id","p":["You can find an entity using it's id by calling getById(). It takes an id as input parameter. It returns an entity if the entity is found. Otherwise, it returns null."]},{"i":"finding-an-entity-using-id-code-1","c":["Product product = productRepository.getById(new ProductId(1));"]},{"l":"Finding an Entity Using a Filter","p":["You can find an entity using a filter. It takes a Filter object as input parameter. It returns a Cursor object.","If there is an index on the field specified in the filter, this operation will use the index to find the entity. Otherwise, it will scan the entire repository to find the entity."]},{"i":"finding-an-entity-using-a-filter-code-1","c":["Cursor<Product> cursor = productRepository.find(where(\"productName\").eq(\"Apple iPhone 6\"));"]},{"l":"Finding an Entity Using a Filter and Options","p":["You can find an entity using a filter and options. It takes a Filter object as the first input parameter. It takes a FindOptions object as the second input parameter. It returns a Cursor object."]},{"l":"FindOptions","p":["More information about FindOptions can be found here."]},{"l":"Cursor","p":["Cursor represents a result set of a find operation. It provides methods to iterate over the result of a find operation and retrieve the entities. It also provides methods like projection, join etc. to get the desired result."]},{"l":"Iterating over Entities","p":["The Cursor extends Iterable interface. So, you can iterate over the entities using for-each loop.","A Cursor is a lazy iterable. It will not load all the entities in memory at once. It will load the entities in memory as needed. So, it is memory efficient."]},{"i":"iterating-over-entities-code-1","c":["Cursor<Product> cursor = productRepository.find();\n\nfor (Product product : cursor) {\n    // do something with the product\n}"]},{"l":"Getting the Entities","p":["You can get the entities from the cursor at once using toList() and toSet() method. It returns a List and Set of entities respectively."]},{"i":"getting-the-entities-code-1","c":["Cursor<Product> cursor = productRepository.find();\n\nList<Product> products = cursor.toList();\nSet<Product> productSet = cursor.toSet();"]},{"l":"Getting the First Entity","p":["You can get the first entity from the cursor using firstOrNull() method. It returns the first entity if the cursor is not empty. Otherwise, it returns null."]},{"i":"getting-the-first-entity-code-1","c":["Cursor<Product> cursor = productRepository.find();\n\nProduct product = cursor.firstOrNull();"]},{"l":"Getting the Size of the Cursor","p":["You can get the size of the cursor using size() method. It returns the number of entities in the cursor."]},{"i":"getting-the-size-of-the-cursor-code-1","c":["Cursor<Product> cursor = productRepository.find();\n\nlong size = cursor.size();"]},{"l":"Projection","p":["You can project the cursor using project() method. It takes another entity type as input parameter. It returns a Cursor object of the projected entity.","The projected entity must contain only the fields that needs to be projected.","Let's say you have an entity like this:","And you want to project only lastName and address.street fields. Then you can define a new entity like this:","And then you can project the cursor like this:"]},{"i":"projection-code-1","c":["public class User {\n    private String firstName;\n    private String lastName;\n    private Address address;\n}\n\npublic class Address {\n    private String street;\n    private String city;\n}"]},{"i":"projection-code-2","c":["public class UserProjection {\n    private String lastName;\n    private StreetAddress address;\n}\n\npublic class StreetAddress {\n    private String street;\n}"]},{"i":"projection-code-3","c":["Cursor<User> cursor = userRepository.find(where(\"firstName\").eq(\"John\"));\n\nRecordStream<UserProjection> projectedStream = cursor.project(UserProjection.class);"]},{"l":"Join","p":["You can join two cursors using join() method. It takes another cursor as the first input parameter. It takes a Lookup as the second input parameter and type of the join as the third input parameter. It returns a RecordStream object.","The join operation is similar to SQL left outer join operation. It takes two cursors and a lookup object. The lookup object contains the join condition.","Let's say you have two entities like this:","And you want to join these two entities using userId field. Then you can define a new entity like this:","And then you can join the cursors like this:"]},{"i":"join-code-1","c":["public class User {\n    private String userId;\n    private String firstName;\n    private String lastName;\n}\n\npublic class Order {\n    private String orderId;\n    private String userId;\n    private String productName;\n}"]},{"i":"join-code-2","c":["public class UserOrder {\n    private String userId;\n    private String firstName;\n    private String lastName;\n    private List<Order> orders;\n}"]},{"i":"join-code-3","c":["Cursor<User> userCursor = userRepository.find();\nCursor<Order> orderCursor = orderRepository.find();\n\nLookup lookup = new Lookup();\nlookup.setLocalField(\"userId\");\nlookup.setForeignField(\"userId\");\nlookup.setTargetField(\"orders\");\n\nRecordStream<UserOrder> joinedStream = userCursor.join(orderCursor, lookup, UserOrder.class);"]},{"l":"FindPlan","p":["You can get the FindPlan of a cursor using getFindPlan() method. It returns a FindPlan object.","More information about FindPlan can be found here."]},{"i":"findplan-code-1","c":["Cursor<Product> cursor = productRepository.find(where(\"productName\").eq(\"Apple iPhone 6\"));\n\nFindPlan findPlan = cursor.getFindPlan();"]}],[{"l":"Indexing","p":["Indexing is a way to optimize the performance of a database by minimizing the number of disk accesses required when a query is processed. It is a data structure technique which is used to quickly locate and access the data in a database.","Nitrite supports indexing on a repository. It supports indexing on a single field or multiple fields. It also supports full-text indexing.","Indexes for an entity can be defined using various annotations like @Id, @Index, @Indices etc. More information about annotations can be found here. It can also be managed using various methods of ObjectRepository interface."]},{"l":"Index Types","p":["Nitrite supports the following types of index out of the box:","Unique Index","Non-Unique Index","Full-text Index"]},{"l":"Unique Index","p":["A unique index ensures that the indexed field contains unique value. It does not allow duplicate value in the indexed field. It also ensures that the indexed field is not null."]},{"l":"Non-unique Index","p":["A non-unique index does not ensure that the indexed field contains unique value. It allows duplicate value in the indexed field."]},{"l":"Full-text Index","p":["A full-text index is used to search text content in an entity. It is useful when you want to search text content in an entity. It is also useful when you want to search text content in an entity in a language other than English.","Indexing on non-comparable value is not supported."]},{"l":"Custom Index","p":["You can also create your own custom index. More information about custom index can be found here."]},{"l":"Creating an Index","p":["You can define indexes for an entity using annotations. You can also create indexes using ObjectRepository interface.","You cannot create a new index on a field or a set of fields which is already indexed with a different type of index.","For example, if you have a unique index on firstName field, then you cannot create a non-unique index on firstName field. But you can create a unique index on firstName and lastName fields. Similarly, if you have a unique index on firstName and lastName fields, then you cannot create a non-unique index on firstName and lastName fields. But you can create two indexes on firstName and lastName fields separately."]},{"l":"Creating a Unique Index","p":["You can create a unique index on a single field or multiple fields. It takes the name of the fields on which the index will be created as input parameter."]},{"l":"Using Annotations","p":["You can create a unique index on a single field or multiple fields using annotations. You can use @Id annotation to create a unique index on a single field. You can use @Index annotation to create a unique index on multiple fields."]},{"i":"using-annotations-code-1","c":["@Indices(\n    @Index(value = \"productName\", type = IndexType.UNIQUE)\n    @Index(value = {\"category\", \"manufacturer\"}, type = IndexType.UNIQUE)\n)\npublic class Product {\n    @Id\n    private String productId;\n    private String productName;\n    private Double price;\n    private String category;\n    private String manufacturer;\n    // getter/setter\n}"]},{"l":"Using ObjectRepository","p":["You can create a unique index on a single field or multiple fields using createIndex() method. It takes the name of the fields on which the index will be created as input parameter."]},{"i":"using-objectrepository-code-1","c":["productRepository.createIndex(\"productName\");\nproductRepository.createIndex(\"category\", \"manufacturer\");"]},{"l":"Creating a Non-unique Index","p":["You can create a non-unique index on a single field or multiple fields by passing the index type as IndexType.NON_UNIQUE."]},{"i":"using-annotations-1","l":"Using Annotations","p":["You can create a non-unique index on a single field or multiple fields using annotations. You can use @Index annotation to create a non-unique index on multiple fields."]},{"i":"using-annotations-1-code-1","c":["@Indices(\n    @Index(value = \"productName\", type = IndexType.NON_UNIQUE)\n    @Index(value = {\"category\", \"price\"}, type = IndexType.NON_UNIQUE)\n)\npublic class Product {\n    @Id\n    private String productId;\n    private String productName;\n    private Double price;\n    private String category;\n    private String manufacturer;\n    // getter/setter\n}"]},{"i":"using-objectrepository-1","l":"Using ObjectRepository","p":["You can create a non-unique index on a single field or multiple fields using createIndex() method. It takes the name of the fields on which the index will be created as input parameter and the index type as IndexType.NON_UNIQUE."]},{"i":"using-objectrepository-1-code-1","c":["productRepository.createIndex(IndexOptions.indexOptions(IndexType.NON_UNIQUE), \"productName\");\nproductRepository.createIndex(IndexOptions.indexOptions(IndexType.NON_UNIQUE), \"category\", \"price\");"]},{"l":"Creating a Full-text Index","p":["You can create a full-text index on a single field by passing the index type as IndexType.FULL_TEXT."]},{"i":"using-annotations-2","l":"Using Annotations","p":["You can create a full-text index on a single field using annotations. You can use @Index annotation to create a full-text index on a single field."]},{"i":"using-annotations-2-code-1","c":["@Indices(\n    @Index(value = \"description\", type = IndexType.FULL_TEXT)\n)\npublic class Product {\n    @Id\n    private String productId;\n    private String productName;\n    private Double price;\n    private String category;\n    private String manufacturer;\n    private String description;\n    // getter/setter\n}"]},{"i":"using-objectrepository-2","l":"Using ObjectRepository","p":["You can create a full-text index on a single field using createIndex() method. It takes the name of the fields on which the index will be created as input parameter and the index type as IndexType.FULL_TEXT.","Full-text index is not supported on multiple fields."]},{"i":"using-objectrepository-2-code-1","c":["productRepository.createIndex(IndexOptions.indexOptions(IndexType.FULL_TEXT), \"description\");"]},{"l":"Creating Index on Array Field","p":["Nitrite supports creating index on array field. It will create index on each element of the array. For example, if you have an entity like this:","You can create index on tags field like this:"]},{"i":"creating-index-on-array-field-code-1","c":["public class Product {\n    @Id\n    private String productId;\n    private String productName;\n    private Double price;\n    private String category;\n    private String manufacturer;\n    private String[] tags;\n    // getter/setter\n}"]},{"i":"creating-index-on-array-field-code-2","c":["productRepository.createIndex(IndexOptions.indexOptions(IndexType.NON_UNIQUE), \"tags\");"]},{"l":"Creating Index on Embedded Field","p":["Nitrite supports creating index on embedded field. For example, if you have entities like this:","You can create index on name of Manufacturer entity via annotation like this:","Or you can create index on name of Manufacturer entity via ObjectRepository like this:","You cannot create index on nested field if the parent field is an array."]},{"i":"creating-index-on-embedded-field-code-1","c":["public class Product {\n    @Id\n    private String productId;\n    private String productName;\n    private Double price;\n    private String category;\n    private Manufacturer manufacturer;\n    // getter/setter\n}\n\npublic class Manufacturer {\n    private String name;\n    private String address;\n    // getter/setter\n}"]},{"i":"creating-index-on-embedded-field-code-2","c":["@Indices(\n    @Index(value = \"manufacturer.name\", type = IndexType.UNIQUE)\n)\npublic class Product {\n    @Id\n    private String productId;\n    private String productName;\n    private Double price;\n    private String category;\n    private Manufacturer manufacturer;\n    // getter/setter\n}"]},{"i":"creating-index-on-embedded-field-code-3","c":["productRepository.createIndex(\"manufacturer.name\");"]},{"l":"Rebuilding an Index","p":["You can rebuild an index on a repository using rebuildIndex() method. It takes the name of the fields on which the index will be rebuilt as input parameter."]},{"i":"rebuilding-an-index-code-1","c":["// rebuild an index on a single field\nproductRepository.rebuildIndex(\"productName\");\n\n// rebuild an index on multiple fields\nproductRepository.rebuildIndex(\"category\", \"manufacturer.name\");"]},{"l":"Dropping an Index","p":["You can drop an index on a repository using dropIndex() method. It takes the name of the fields on which the index will be dropped as input parameter."]},{"i":"dropping-an-index-code-1","c":["// drop an index on a single field\nproductRepository.dropIndex(\"productName\");\n\n// drop an index on multiple fields\nproductRepository.dropIndex(\"category\", \"manufacturer.name\");"]},{"l":"Dropping All Indexes","p":["You can drop all indexes on a repository using dropAllIndices() method."]},{"i":"dropping-all-indexes-code-1","c":["productRepository.dropAllIndices();"]},{"l":"Getting All Indexes","p":["You can get all indexes on a repository using listIndices() method. It returns a Collection of IndexDescriptor object."]},{"i":"getting-all-indexes-code-1","c":["Collection<IndexDescriptor> indexes = productRepository.listIndices();"]},{"l":"IndexDescriptor","p":["IndexDescriptor is a simple class which contains the following information about an index:","collectionName: The name of the collection on which the index is created.","indexType: The type of the index.","fields: A Fields object containing the name of the fields on which the index is created."]},{"l":"Checking If an Index Exists","p":["You can check if an index exists on a repository using hasIndex() method. It takes the name of the fields on which the index will be checked as input parameter."]},{"i":"checking-if-an-index-exists-code-1","c":["// check if an index exists on a single field\nboolean exists = productRepository.hasIndex(\"productName\");\n\n// check if an index exists on multiple fields\nboolean exists = productRepository.hasIndex(\"category\", \"manufacturer.name\");"]},{"l":"Error Scenarios","p":["The following error scenarios are possible while creating an index:","If another index of any type is already created on the repository on the same field(s), then it will throw IndexingException.","If a unique index is created on a field and the field contains duplicate value, then it will throw UniqueConstraintException.","If a full-text index is created on multiple fields, then it will throw IndexingException.","If a full-text index is created on a field which is not a String, then it will throw IndexingException.","If you try to drop an index which does not exist, then it will throw IndexingException.","If you try to rebuild an index which does not exist, then it will throw IndexingException."]}],[{"l":"Other Operations"},{"l":"Size of a Repository","p":["You can get the size of a repository using size() method. It returns the number of entities in the repository."]},{"i":"size-of-a-repository-code-1","c":["long size = productRepository.size();"]},{"l":"Clearing a Repository","p":["You can clear all the entities from a repository using clear() method. It removes all the entities from the repository and index entries from the indexes. It does not drop the repository."]},{"i":"clearing-a-repository-code-1","c":["productRepository.clear();"]},{"l":"Dropping a Repository","p":["You can drop a repository using drop() method. It removes all the entities from the repository and index entries from the indexes. It also drops all the indexes associated with the repository. It also removes the repository from the database.","You can call isDropped() method to check if the repository is dropped or not.","Any further operation on a dropped repository will throw NitriteIOException."]},{"i":"dropping-a-repository-code-1","c":["productRepository.drop();"]},{"i":"dropping-a-repository-code-2","c":["boolean isDropped = productRepository.isDropped();"]},{"l":"Closing a Repository","p":["You can close a repository using close() method. Any further operation on a closed repository will throw NitriteIOException.","After closing a repository, you must re-open it via Nitrite.getRepository() method to perform any operation on it.","You can call isOpen() method to check if the repository is closed or not."]},{"i":"closing-a-repository-code-1","c":["productRepository.close();"]},{"i":"closing-a-repository-code-2","c":["boolean isOpen = productRepository.isOpen();"]},{"l":"Event Listener","p":["You can register an event listener on a repository to get notified on entity changes. The event listener must implement CollectionEventListener interface. It will receive CollectionEventInfo whenever an entity is inserted, updated or removed from the repository.","You can also remove an event listener from a collection."]},{"i":"event-listener-code-1","c":["productRepository.subscribe(eventInfo -> {\n    // do something with the eventInfo\n});"]},{"i":"event-listener-code-2","c":["productRepository.unsubscribe(listener);"]},{"l":"CollectionEventInfo","p":["More on CollectionEventInfo can be found here."]},{"l":"Attributes","p":["Attributes is a metadata information associated with a repository.","You can get/set attributes on a repository. The attributes are stored in the database and can be retrieved later. The attributes are stored in a special map named $nitrite_meta_map."]},{"i":"attributes-code-1","c":["// get the attributes\nAttributes attributes = productRepository.getAttributes();\nattributes.set(\"key\", \"value\");\n\n// save the attributes\nproductRepository.setAttributes(attributes);\n\n// get the attributes\nattributes = productRepository.getAttributes();\n\n// get the value of a key\nString value = attributes.get(\"key\");"]},{"l":"Processors","p":["Processor can be used to process the underlying documents of a repository. More on processors can be found here."]},{"l":"Registering a Processor","p":["You can register a processor on a repository using addProcessor() method. It takes a Processor as input parameter."]},{"i":"registering-a-processor-code-1","c":["// create a processor\nMyProcessor processor = new MyProcessor();\n\n// process existing entities\nprocessor.process(productRepository);\n\n// register the processor\nproductRepository.addProcessor(processor);"]},{"l":"Available Processors","p":["Nitrite provides a StringFieldEncryptionProcessor which can be used to encrypt a field before writing it into a repository and decrypt a field after reading it from a repository.","More on this is described in Support."]}],[{"l":"Filters","p":["Filters are used to specify the criteria used to select documents from a collection or repository. It provides a way to specify conditions that the documents must meet to be included in the result set. Filters are used in conjunction with the find method. The find method returns all documents in a collection that match the specified filtering criteria.","Each filtering criteria is based on a field in the document. If the field is indexed, the find operation takes advantage of the index to speed up the operation. If the field is not indexed, the find operation scans the entire collection to find matching documents."]},{"l":"Fluent API","p":["Nitrite provides a fluent API to create filters via FluentFilter class. It provides a static where method that creates a new FluentFilter instance with the specified field name. Here's an example:","In this example, the FluentFilter.where method is used to create a filter that matches documents where the name field equals John. The filter is then passed to the find method to retrieve the matching documents.","For spatial filters, use the SpatialFluentFilter class for the fluent API. It provides a static where method that creates a new SpatialFluentFilter instance with the specified field name. Here's an example:","More on spatial module can be found here."]},{"i":"fluent-api-code-1","c":["// create a filter for the field 'name'\nFluentFilter filter = FluentFilter.where(\"name\").eq(\"John\");\nDocumentCursor cursor = collection.find(filter);"]},{"i":"fluent-api-code-2","c":["// create a filter for the field 'location'\nSpatialFilter filter = SpatialFluentFilter.where(\"location\").near(coordinate, 1000);\nDocumentCursor cursor = collection.find(filter);"]},{"l":"Usage","p":["Filters are used with the find method of NitriteCollection or ObjectRepository to retrieve documents or entities that match the filter. Here's an example:","In this example, the where and eq methods are used to create an equality filter that matches documents where the name field equals \"John\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"usage-code-1","c":["// find all documents where the field 'name' equals 'John'\nDocumentCursor cursor = collection.find(where(\"name\").eq(\"John\"));"]},{"l":"Types of Filters","p":["Nitrite filters can be grouped into the following categories:","Comparison filters","Logical filters","Array filters","Evaluation filters","Spatial filters"]},{"l":"Comparison Filters","p":["Comparison filters are used to compare a field with a value. The following comparison filters are supported:","Equality (eq): Matches all documents where the value of the field equals the specified value.","Inequality (notEq): Matches all documents where the value of the field is not equal to the specified value.","Greater than (gt): Matches all documents where the value of the field is greater than the specified value.","Greater than or equal to (gte): Matches all documents where the value of the field is greater than or equal to the specified value.","Less than (lt): Matches all documents where the value of the field is less than the specified value.","Less than or equal to (lte): Matches all documents where the value of the field is less than or equal to the specified value.","In (in): Matches all documents where the value of the field equals any value in the specified array.","Not in (notIn): Matches all documents where the value of the field does not equal any value in the specified array.","Between (between): Matches all documents where the value of the field is between the specified values.","All (all): Matches all documents in the collection."]},{"l":"Equality Filter","p":["The equality filter is used to match documents where the value of a field equals the specified value. The following example shows how to use the equality filter:","In this example, the where() and eq() methods are used to create an equality filter that matches documents where the name field equals \"John\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"equality-filter-code-1","c":["// find all documents where the field 'name' equals 'John'\ncollection.find(where(\"name\").eq(\"John\"));"]},{"l":"Inequality Filter","p":["The inequality filter is used to match documents where the value of a field is not equal to the specified value. The following example shows how to use the inequality filter:","In this example, the where() and notEq() methods are used to create an inequality filter that matches documents where the name field does not equal \"John\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"inequality-filter-code-1","c":["// find all documents where the field 'name' does not equal 'John'\ncollection.find(where(\"name\").notEq(\"John\"));"]},{"l":"Greater Than Filter","p":["The greater than filter is used to match documents where the value of a field is greater than the specified value. The following example shows how to use the greater than filter:","In this example, the where() and gt() methods are used to create a greater than filter that matches documents where the age field is greater than 18. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"greater-than-filter-code-1","c":["// find all documents where the field 'age' is greater than 18\ncollection.find(where(\"age\").gt(18));"]},{"l":"Greater Than or Equal To Filter","p":["The greater than or equal to filter is used to match documents where the value of a field is greater than or equal to the specified value. The following example shows how to use the greater than or equal to filter:","In this example, the where() and gte() methods are used to create a greater than or equal to filter that matches documents where the age field is greater than or equal to 18. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"greater-than-or-equal-to-filter-code-1","c":["// find all documents where the field 'age' is greater than or equal to 18\ncollection.find(where(\"age\").gte(18));"]},{"l":"Less Than Filter","p":["The less than filter is used to match documents where the value of a field is less than the specified value. The following example shows how to use the less than filter:","In this example, the where() and lt() methods are used to create a less than filter that matches documents where the age field is less than 18. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"less-than-filter-code-1","c":["// find all documents where the field 'age' is less than 18\ncollection.find(where(\"age\").lt(18));"]},{"l":"Less Than or Equal To Filter","p":["The less than or equal to filter is used to match documents where the value of a field is less than or equal to the specified value. The following example shows how to use the less than or equal to filter:","In this example, the where() and lte() methods are used to create a less than or equal to filter that matches documents where the age field is less than or equal to 18. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"less-than-or-equal-to-filter-code-1","c":["// find all documents where the field 'age' is less than or equal to 18\ncollection.find(where(\"age\").lte(18));"]},{"l":"In Filter","p":["The in filter is used to match documents where the value of a field equals any value in the specified array. The following example shows how to use the in filter:","In this example, the where() and in() methods are used to create an in filter that matches documents where the name field equals \"John\" or \"Jane\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"in-filter-code-1","c":["// find all documents where the field 'name' equals 'John' or 'Jane'\ncollection.find(where(\"name\").in(\"John\", \"Jane\"));"]},{"l":"Not In Filter","p":["The not in filter is used to match documents where the value of a field does not equal any value in the specified array. The following example shows how to use the not in filter:","In this example, the where() and notIn() methods are used to create a not in filter that matches documents where the name field does not equal \"John\" or \"Jane\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"not-in-filter-code-1","c":["// find all documents where the field 'name' does not equal 'John' or 'Jane'\ncollection.find(where(\"name\").notIn(\"John\", \"Jane\"));"]},{"l":"Between Filter","p":["The between filter is used to match documents where the value of a field is between the specified values. The following example shows how to use the between filter:","In this example, the where() and between() methods are used to create a between filter that matches documents where the age field is between 18 and 30. The filter is then passed to the find method to retrieve the matching documents.","There are three overloaded versions of the between filter. The first version takes two parameters, the lower and upper bounds of the range. The second version takes an additional boolean parameter that indicates whether both the lower and upper bounds are inclusive or exclusive. The third version takes two additional boolean parameters that indicate whether the lower and upper bounds are inclusive or exclusive. The following example shows how to use the second version of the between filter:","In this example, the where() and between() methods are used to create a between filter that matches documents where the age field is between 18 and 30. Both the lower and upper bounds are inclusive. The filter is then passed to the find method to retrieve the matching documents.","The following example shows how to use the third version of the between filter:","In this example, the where() and between() methods are used to create a between filter that matches documents where the age field is between 18 and 30. The lower bound is inclusive and the upper bound is exclusive. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"between-filter-code-1","c":["// find all documents where the field 'age' is between 18 and 30\ncollection.find(where(\"age\").between(18, 30));"]},{"i":"between-filter-code-2","c":["// find all documents where the field 'age' is between 18 and 30\n// both the lower and upper bounds are inclusive\ncollection.find(where(\"age\").between(18, 30, true));"]},{"i":"between-filter-code-3","c":["// find all documents where the field 'age' is between 18 and 30\n// the lower bound is inclusive and the upper bound is exclusive\ncollection.find(where(\"age\").between(18, 30, true, false));"]},{"l":"All Filter","p":["The all filter is used to match all documents in the collection. The following example shows how to use the all filter:","In this example, the Filter.ALL constant is used to create an all filter that matches all documents in the collection. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"all-filter-code-1","c":["// find all documents in the collection\ncollection.find(Filter.ALL);"]},{"l":"Logical Filters","p":["Logical filters are used to combine multiple filters into a single filter. The following logical filters are supported:","And (and): Matches all documents that satisfy all the specified filters.","Or (or): Matches all documents that satisfy at least one of the specified filters.","Not (not): Matches all documents that do not satisfy the specified filter."]},{"l":"And Filter","p":["The and filter is used to match documents that satisfy all the specified filters. The following example shows how to use the and filter:","In this example, the where() and eq() methods are used to create an equality filter that matches documents where the name field equals \"John\". The where() and gt() methods are used to create a greater than filter that matches documents where the age field is greater than 18. The two filters are then combined using the and() method to create an and filter that matches documents where the name field equals \"John\" and the age field is greater than 18. The filter is then passed to the find method to retrieve the matching documents.","The and() method can be used to combine any number of filters. The following example shows how to combine three filters:","The static Filter.and() method can also be used to combine multiple filters into a single filter. The following example shows how to combine two filters into a single filter:","In this example, the and() method is used to combine three filters into a single filter. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"and-filter-code-1","c":["// find all documents where the field 'name' equals 'John' and the field 'age' is greater than 18\ncollection.find(where(\"name\").eq(\"John\").and(where(\"age\").gt(18)));"]},{"i":"and-filter-code-2","c":["// find all documents where the field 'name' equals 'John' and the field 'age' is greater than 18 and less than 30\ncollection.find(where(\"name\").eq(\"John\").and(where(\"age\").gt(18)).and(where(\"age\").lt(30)));"]},{"i":"and-filter-code-3","c":["// find all documents where the field 'name' equals 'John' and the field 'age' is greater than 18\n// and the field 'age' is less than 30\ncollection.find(and(where(\"name\").eq(\"John\"), where(\"age\").gt(18),where(\"age\").lt(30)));"]},{"l":"Or Filter","p":["The or filter is used to match documents that satisfy at least one of the specified filters. The following example shows how to use the or filter:","In this example, the where() and eq() methods are used to create an equality filter that matches documents where the name field equals \"John\". The where() and gt() methods are used to create a greater than filter that matches documents where the age field is greater than 18. The two filters are then combined using the or() method to create an or filter that matches documents where the name field equals \"John\" or the age field is greater than 18. The filter is then passed to the find method to retrieve the matching documents.","The or() method can be used to combine any number of filters. The following example shows how to combine three filters:","The static Filter.or() method can also be used to combine multiple filters into a single filter. The following example shows how to combine two filters into a single filter:","In this example, the or() method is used to combine three filters into a single filter. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"or-filter-code-1","c":["// find all documents where the field 'name' equals 'John' or the field 'age' is greater than 18\ncollection.find(where(\"name\").eq(\"John\").or(where(\"age\").gt(18)));"]},{"i":"or-filter-code-2","c":["// find all documents where the field 'name' equals 'John' or the field 'age' is greater than 18 or less than 30\ncollection.find(where(\"name\").eq(\"John\").or(where(\"age\").gt(18)).or(where(\"age\").lt(30)));"]},{"i":"or-filter-code-3","c":["// find all documents where the field 'name' equals 'John' or the field 'age' is greater than 18\n// or the field 'age' is less than 30\ncollection.find(or(where(\"name\").eq(\"John\"), where(\"age\").gt(18), where(\"age\").lt(30)));"]},{"l":"Not Filter","p":["The not filter is used to match documents that do not satisfy the specified filter. The following example shows how to use the not filter:","In this example, the where() and eq() methods are used to create an equality filter that matches documents where the name field equals \"John\". The not() method is then used to create a not filter that matches documents where the name field does not equal \"John\". The filter is then passed to the find method to retrieve the matching documents.","The not() method can be used to negate any filter. The following example shows how to negate a greater than filter:"]},{"i":"not-filter-code-1","c":["// find all documents where the field 'name' does not equal 'John'\ncollection.find(where(\"name\").eq(\"John\").not());"]},{"i":"not-filter-code-2","c":["// find all documents where the field 'age' is not greater than 18\ncollection.find(where(\"age\").gt(18).not());"]},{"l":"Array Filters","p":["Array filters are used to match documents based on the values in an array field. The following array filters are supported:","Element match (elemMatch): Matches all documents where the array field contains at least one element that matches the specified filter."]},{"l":"Element Match Filter","p":["The element match filter is used to match documents where the array field contains at least one element that matches the specified filter. The following example shows how to use the element match filter:","Let's say we have a collection that contains documents with the following structure:","The following example shows how to use the element match filter to find all documents where the addresses field contains at least one element that matches the filter where the city field equals \"New York\":","In this example, the where() and elemMatch() methods are used to create an element match filter that matches documents where the addresses field contains at least one element that matches the filter where the city field equals \"New York\". The filter is then passed to the find method to retrieve the matching documents.","The elemMatch filter can be used to search an array of elements for a specific value. The following example shows how to use the elemMatch filter to find all documents where the data field contains at least one element that is greater than 2 or less than equal to 5:","The static FluentFilter.$ is used to create a filter for the current element in the array. The $.gt(2).or($.lte(5)) filter is used to match documents where the data field contains at least one element that is greater than 2 or less than equal to 5. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"element-match-filter-code-1","c":["{\n  \"name\": \"John\",\n  \"addresses\": [\n    {\n      \"city\": \"New York\",\n      \"state\": \"NY\"\n    },\n    {\n      \"city\": \"Los Angeles\",\n      \"state\": \"CA\"\n    }\n  ]\n}"]},{"i":"element-match-filter-code-2","c":["// find all documents where the field 'addresses' contains at least one element that matches the filter\n// where the field 'city' equals 'New York'\ncollection.find(where(\"addresses\").elemMatch(where(\"city\").eq(\"New York\")));"]},{"i":"element-match-filter-code-3","c":["// find all documents where the field 'data' contains at least one element that is greater than 2 or less than equal to 5\ncollection.find(where(\"data\").elemMatch($.gt(2).or($.lte(5))));"]},{"l":"Evaluation Filters","p":["Evaluation filters are used to match documents based on evaluating the value of any field in a document. The following evaluation filters are supported:","Text (text): Matches all documents which contain a specified full-text search expression.","Regex (regex): Matches all documents where values contain a specified regular expression."]},{"l":"Text Filter","p":["The text filter is used to match documents which contain a specified full-text search expression. The following example shows how to use the text filter:","In this example, the where() and text() methods are used to create a text filter that matches documents where the name field contains the word \"John\". The filter is then passed to the find method to retrieve the matching documents.","The text filter supports glob patterns. The following example shows how to use the text filter with glob patterns:","The text filter can only be used with a field that has a full-text index."]},{"i":"text-filter-code-1","c":["// find all documents where the field 'name' contains the word 'John'\ncollection.find(where(\"name\").text(\"John\"));"]},{"i":"text-filter-code-2","c":["// find all documents where the field 'name' starts with the word 'Jo'\ncollection.find(where(\"name\").text(\"Jo*\"));\n\n// find all documents where the field 'name' ends with the word 'hn'\ncollection.find(where(\"name\").text(\"*hn\"));\n\n// find all documents where the field 'name' contains the word 'oh'\ncollection.find(where(\"name\").text(\"*oh*\"));"]},{"l":"Regex Filter","p":["The regex filter is used to match documents where values contain a specified regular expression. The following example shows how to use the regex filter:","In this example, the where() and regex() methods are used to create a regex filter that matches documents where the name field matches the regular expression \"John.*\". The filter is then passed to the find method to retrieve the matching documents.","This filter scans the entire collection to find matching documents. It cannot take advantage of an index."]},{"i":"regex-filter-code-1","c":["// find all documents where the field 'name' matches the regular expression 'John.*'\ncollection.find(where(\"name\").regex(\"John.*\"));"]},{"l":"Spatial Filters","p":["Spatial filters are used to match documents based on the values in a spatial field. The following spatial filters are supported:","Near (near): Matches all documents where the spatial field is within the specified distance from the specified point.","Within (within): Matches all documents where the spatial field is within the specified shape.","Intersects (intersects): Matches all documents where the spatial field intersects the specified shape.","To use spatial filters, you need create a spatial index on the field, which needs the nitrite-spatial module to be loaded. More on this can be found here.","Spatial filters can only be used with a field that has a spatial index."]},{"l":"Near Filter","p":["The near filter is used to match documents where the value of the spatial field is near the specified point. The following example shows how to use the near filter:","In this example, the where() and near() methods are used to create a near filter that matches documents where the location field is within 1000 meters of the point (40.730610, -73.935242). The filter is then passed to the find method to retrieve the matching documents."]},{"i":"near-filter-code-1","c":["// find all documents where the field 'location' is within 1000 meters of the point (40.730610, -73.935242)\nWKTReader reader = new WKTReader();\nPoint search = (Point) reader.read(\"POINT (40.730610, -73.935242)\");\nCoordinate coordinate = search.getCoordinate();\n\ncollection.find(where(\"location\").near(coordinate, 1000));"]},{"l":"Within Filter","p":["The within filter is used to match documents where the value of the spatial field is within the specified shape. The following example shows how to use the within filter:","In this example, the where() and within() methods are used to create a within filter that matches documents where the location field is within the polygon ((0 0, 0 3, 3 3, 3 0, 0 0)). The filter is then passed to the find method to retrieve the matching documents."]},{"i":"within-filter-code-1","c":["// find all documents where the field 'location' is within the polygon ((0 0, 0 3, 3 3, 3 0, 0 0))\nWKTReader reader = new WKTReader();\nGeometry search = reader.read(\"POLYGON ((0 0, 0 3, 3 3, 3 0, 0 0))\");\n\ncollection.find(where(\"location\").within(search));"]},{"l":"Intersects Filter","p":["The intersects filter is used to match documents where the value of the spatial field intersects the specified shape. The following example shows how to use the intersects filter:","In this example, the where() and intersects() methods are used to create an intersects filter that matches documents where the location field intersects the polygon ((0 0, 0 3, 3 3, 3 0, 0 0)). The filter is then passed to the find method to retrieve the matching documents."]},{"i":"intersects-filter-code-1","c":["// find all documents where the field 'location' intersects the polygon ((0 0, 0 3, 3 3, 3 0, 0 0))\nWKTReader reader = new WKTReader();\nGeometry search = reader.read(\"POLYGON ((0 0, 0 3, 3 3, 3 0, 0 0))\");\n\ncollection.find(where(\"location\").intersects(search));"]}],[{"l":"Transaction","p":["A transaction is a single logical unit of work which accesses and possibly modifies the contents of a database. Transactions access data using read and write operations.","Nitrite supports transactional operations on its collections and repositories. A transaction can be committed or rolled back. Once a transaction is committed, all the changes are persisted to the disk. If a transaction is rolled back, all the changes are discarded."]},{"l":"Transaction on NitriteCollection","p":["A transaction can be started from a session using the Session.beginTransaction() method. To start a transactional operation on a NitriteCollection, the Transaction.getCollection() method can be used. All the operations performed on the collection will be part of the transaction.","Transaction is a closeable resource. It is recommended to use it with try-with-resource block.","Any find operations performed inside a transaction will return all the documents including the uncommitted ones.","Any find operations performed outside a transaction will return only the committed documents."]},{"i":"transaction-on-nitritecollection-code-1","c":["// start a transaction\nTransaction transaction = session.beginTransaction();\n\n// get a collection\nNitriteCollection collection = transaction.getCollection(\"test\");\n\n// perform operations on the collection\ncollection.insert(doc1);\n\n// commit the transaction\ntransaction.commit();"]},{"i":"transaction-on-nitritecollection-code-2","c":["try (Session session = db.createSession()) {\n    try (Transaction transaction = session.beginTransaction()) {\n        NitriteCollection collection = transaction.getCollection(\"test\");\n        collection.insert(doc1);\n        transaction.commit();\n    }\n}"]},{"l":"Auto-commit Operations","p":["Certain operations are auto-committed in Nitrite. Those operations are not part of a transaction and cannot be rolled back. The following operations are auto-committed:","NitriteCollection.createIndex()","NitriteCollection.rebuildIndex()","NitriteCollection.dropIndex()","NitriteCollection.dropAllIndices()","NitriteCollection.drop()","NitriteCollection.clear()","NitriteCollection.close()"]},{"l":"Transaction on ObjectRepository","p":["A transaction can be started from a session using the Session.beginTransaction() method. To start a transactional operation on a ObjectRepository, the Transaction.getRepository() method can be used. All the operations performed on the repository will be part of the transaction.","Transaction is a closeable resource. It is recommended to use it with try-with-resource block.","Any find operations performed inside a transaction will return all the entities including the uncommitted ones.","Any find operations performed outside a transaction will return only the committed entities."]},{"i":"transaction-on-objectrepository-code-1","c":["// start a transaction\nTransaction transaction = session.beginTransaction();\n\n// get a repository\nObjectRepository<Employee> repository = transaction.getRepository(Employee.class);\n\n// perform operations on the repository\nrepository.insert(employee);\n\n// commit the transaction\ntransaction.commit();"]},{"i":"transaction-on-objectrepository-code-2","c":["try (Session session = db.createSession()) {\n    try (Transaction transaction = session.beginTransaction()) {\n        ObjectRepository<Employee> repository = transaction.getRepository(Employee.class);\n        repository.insert(employee);\n        transaction.commit();\n    }\n}"]},{"i":"auto-commit-operations-1","l":"Auto-commit Operations","p":["Certain operations are auto-committed in Nitrite. Those operations are not part of a transaction and cannot be rolled back. The following operations are auto-committed:","ObjectRepository.createIndex()","ObjectRepository.rebuildIndex()","ObjectRepository.dropIndex()","ObjectRepository.dropAllIndices()","ObjectRepository.drop()","ObjectRepository.clear()","ObjectRepository.close()"]},{"l":"Session","p":["A session represents a transactional context for a Nitrite database. Session is used to create a new transaction. A session should be closed after use to release any resources held by it. If a session is closed and the transaction is not committed, all opened transactions will be rolled back."]},{"l":"Create a Session","p":["A session can be created using the Nitrite.createSession() method. Multiple sessions can be created for a Nitrite database."]},{"i":"create-a-session-code-1","c":["// create a session\nSession session = db.createSession();"]},{"l":"Close a Session","p":["A session can be closed using the Session.close() method. If a session is closed and the transaction is not committed, all opened transactions will be rolled back."]},{"i":"close-a-session-code-1","c":["// close a session\nsession.close();"]},{"l":"Checking Session State","p":["The current state of a session can be checked using the Session.checkState() method. If the session is not active, it will throw an TransactionException."]},{"i":"checking-session-state-code-1","c":["// check session state\nsession.checkState();"]},{"l":"Managing Transactions","p":["A transaction can be started using the Session.beginTransaction() method.","A transaction can be committed using the Transaction.commit() method. If a transaction is committed, all the changes are persisted to the disk.","A transaction can be rolled back using the Transaction.rollback() method. If a transaction is rolled back, all the changes are discarded.","A transaction can be closed using the Transaction.close() method. If a transaction is closed and the transaction is not committed, all opened transactions will be rolled back."]},{"i":"managing-transactions-code-1","c":["// start a transaction\nTransaction transaction = session.beginTransaction();"]},{"i":"managing-transactions-code-2","c":["// commit a transaction\ntransaction.commit();"]},{"i":"managing-transactions-code-3","c":["// rollback a transaction\ntransaction.rollback();"]},{"i":"managing-transactions-code-4","c":["// close a transaction\ntransaction.close();"]},{"l":"Querying Transaction State","p":["The current state of a transaction can be retrieved using the Transaction.getState() method. It returns an enum of type TransactionState.","The following states are available:","TransactionState.Active - The transaction is active.","TransactionState.Committed - The transaction is committed.","TransactionState.PartiallyCommitted - The transaction is partially committed.","TransactionState.Closed - The transaction is closed.","TransactionState.Failed - The transaction is failed.","TransactionState.Aborted - The transaction is aborted."]},{"i":"querying-transaction-state-code-1","c":["// get transaction state\nTransactionState state = transaction.getState();"]}],[{"l":"Schema Migration","p":["A migration is a set of changes to the schema that can be applied to a database. Migrations are used to keep the database schema up to date with the codebase. It contains a queue of instructions that are executed in order to update the database schema from one version to the next.","The migration is executed only once for a specific schema version. If you want to execute the migration again, you need to change the schema version of the database.","For example, if you have a database with the schema version 1 and you want to update it to version 2, you need to apply the migration steps from version 1 and version 2.","The migration instructions are executed in the order they are added to the migration. The order of the instructions is important. For example, if you want to rename a field, you need to add the renameField instruction before the deleteField instruction. Otherwise, the deleteField instruction will fail.","Once a migration is applied to a database, it cannot be reverted. If you want to revert a migration, you need to create a new migration that will revert the changes.","Nitrite provides a set of instructions that can be used to update the database schema. These instructions can be grouped into three categories:","Database Instruction","Collection Instruction","Repository Instruction"]},{"i":"schema-migration-code-1","c":["// Create a migration\n\nMigration migration = new Migration(1, 2) {\n    @Override\n    public void migrate(InstructionSet instruction) {\n        instruction.forDatabase()\n            .addUser(\"test-user\", \"test-password\");\n\n        instruction.forRepository(OldClass.class, \"demo1\")\n            .renameRepository(\"new\", null)\n            .changeDataType(\"empId\", (TypeConverter<String, Long>) Long::parseLong)\n            .changeIdField(Fields.withNames(\"uuid\"), Fields.withNames(\"empId\"))\n            .deleteField(\"uuid\")\n            .renameField(\"lastName\", \"familyName\")\n            .addField(\"fullName\", document -> document.get(\"firstName\", String.class) + \" \"\n                + document.get(\"familyName\", String.class))\n            .dropIndex(\"firstName\")\n            .dropIndex(\"literature.text\")\n            .changeDataType(\"literature.ratings\", (TypeConverter<Float, Integer>) Math::round);\n    }\n};\n\n// Apply the migration\nNitrite db = Nitrite.builder()\n    .loadModule(storeModule)\n    .schemaVersion(1)\n    .addMigrations(migration)\n    .openOrCreate(\"test-user\", \"test-password\");"]},{"l":"Database Instruction","p":["Database instructions are used to perform operations on the database. The following instructions are available:"]},{"l":"Add User","p":["Adds an instruction to set a user authentication to the database. The user will be used to open the database.","Nitrite database supports only one user authentication per database. If you try to add a new user when there is already a user authentication present, the migration will fail throwing a NitriteSecurityException."]},{"i":"add-user-code-1","c":["instruction.forDatabase()\n    .addUser(\"test-user\", \"test-password\");"]},{"l":"Change Password","p":["Adds an instruction to change the password for the user authentication to the database.","The user authentication must be present in the database. If you try to change the password for a user that does not exist, the migration will fail throwing a NitriteSecurityException.","If you try to change the password for a user with a wrong password, the migration will also fail throwing a NitriteSecurityException."]},{"i":"change-password-code-1","c":["instruction.forDatabase()\n    .changePassword(\"test-user\", \"test-password\", \"new-password\");"]},{"l":"Drop Collection","p":["Adds an instruction to drop a NitriteCollection from the database."]},{"i":"drop-collection-code-1","c":["instruction.forDatabase()\n    .dropCollection(\"collection-name\");"]},{"l":"Drop Repository","p":["Adds an instruction to drop a ObjectRepository from the database. There are several ways to drop a repository:"]},{"l":"Drop by Class"},{"i":"drop-by-class-code-1","c":["instruction.forDatabase()\n    .dropRepository(OldClass.class);"]},{"l":"Drop by Class and Key Name"},{"i":"drop-by-class-and-key-name-code-1","c":["instruction.forDatabase()\n    .dropRepository(OldClass.class, \"demo1\");"]},{"l":"Drop by EntityDecorator"},{"i":"drop-by-entitydecorator-code-1","c":["instruction.forDatabase()\n    .dropRepository(new OldClassEntityDecorator<OldClass>());"]},{"l":"Drop by EntityDecorator and Key Name"},{"i":"drop-by-entitydecorator-and-key-name-code-1","c":["instruction.forDatabase()\n    .dropRepository(new OldClassEntityDecorator<OldClass>(), \"demo1\");"]},{"l":"Drop by Repository Type Name"},{"i":"drop-by-repository-type-name-code-1","c":["instruction.forDatabase()\n    .dropRepository(\"com.example.OldClass\");"]},{"l":"Drop by Repository Type Name and Key Name"},{"i":"drop-by-repository-type-name-and-key-name-code-1","c":["instruction.forDatabase()\n    .dropRepository(\"com.example.OldClass\", \"demo1\");"]},{"l":"Custom Instruction","p":["Adds a custom instruction to perform a user defined operation on the database. The custom instruction is a callback that takes a Nitrite instance as an argument. The callback can be used to perform any operation on the database."]},{"i":"custom-instruction-code-1","c":["instruction.forDatabase()\n    .customInstruction(nitrite -> {\n        // do something with the database\n    });"]},{"l":"Collection Instruction","p":["Collection instructions are used to perform operations on a NitriteCollection. The following instructions are available:"]},{"l":"Rename Collection","p":["Adds an instruction to rename a NitriteCollection."]},{"i":"rename-collection-code-1","c":["instruction.forCollection(\"collection-name\")\n    .rename(\"new-collection-name\");"]},{"l":"Add Field","p":["Adds an instruction to add new field to the documents of a NitriteCollection."]},{"l":"Add Field with Null Value","p":["The new field will be added to all the documents of the collection. The value of the new field will be null."]},{"i":"add-field-with-null-value-code-1","c":["instruction.forCollection(\"collection-name\")\n    .addField(\"new-field\");"]},{"l":"Add Field with Default Value","p":["The new field will be added to all the documents of the collection. The value of the new field will be new-value."]},{"i":"add-field-with-default-value-code-1","c":["instruction.forCollection(\"collection-name\")\n    .addField(\"new-field\", \"new-value\");"]},{"l":"Add Field with Generator","p":["The new field will be added to all the documents of the collection. The value of the new field will be the value returned by the Generator."]},{"i":"add-field-with-generator-code-1","c":["instruction.forCollection(\"collection-name\")\n    .addField(\"new-field\", document -> {\n        // do something with the document\n        return \"new-value\";\n    });"]},{"l":"Generator","p":["A Generator is a functional interface that takes a Document as input and returns a value. The value returned by the Generator will be used as the value of the new field."]},{"i":"generator-code-1","c":["Generator<String> generator = document -> {\n    // do something with the document\n    return \"new-value\";\n};"]},{"l":"Rename Field","p":["Adds an instruction to rename a field of the documents of a NitriteCollection."]},{"i":"rename-field-code-1","c":["instruction.forCollection(\"collection-name\")\n    .renameField(\"old-field\", \"new-field\");"]},{"l":"Delete Field","p":["Adds an instruction to delete a field from the documents of a NitriteCollection."]},{"i":"delete-field-code-1","c":["instruction.forCollection(\"collection-name\")\n    .deleteField(\"field-name\");"]},{"l":"Drop Index","p":["Adds an instruction to drop an index from a NitriteCollection.","The drop index instruction can be used to drop a single field index or a compound index."]},{"i":"drop-index-code-1","c":["instruction.forCollection(\"collection-name\")\n    .dropIndex(\"field-name-1\", \"field-name-2\");"]},{"l":"Drop All Indexes","p":["Adds an instruction to drop all the indexes from a NitriteCollection."]},{"i":"drop-all-indexes-code-1","c":["instruction.forCollection(\"collection-name\")\n    .dropAllIndices();"]},{"l":"Create Index","p":["Adds an instruction to create an index on a NitriteCollection.","The create index instruction can be used to create a single field index or a compound index."]},{"i":"create-index-code-1","c":["instruction.forCollection(\"collection-name\")\n    .createIndex(IndexType.NON_UNIQUE, \"field-name-1\", \"field-name-2\");"]},{"l":"Repository Instruction","p":["Repository instructions are used to perform operations on a ObjectRepository. The following instructions are available:"]},{"l":"Rename Repository","p":["Adds an instruction to rename a ObjectRepository."]},{"i":"rename-repository-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .renameRepository(\"com.example.NewClass\", null);"]},{"i":"add-field-1","l":"Add Field","p":["Adds an instruction to add new field to the entity of a ObjectRepository."]},{"i":"add-field-with-null-value-1","l":"Add Field with Null Value","p":["The new field will be added to all the entities of the repository. The value of the new field will be null."]},{"i":"add-field-with-null-value-1-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .addField(\"new-field\");"]},{"i":"add-field-with-default-value-1","l":"Add Field with Default Value","p":["The new field will be added to all the entities of the repository. The value of the new field will be 0."]},{"i":"add-field-with-default-value-1-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .addField(\"new-field\", 0);"]},{"l":"Add Field with Generator Function","p":["The new field will be added to all the entities of the repository. The value of the new field will be the value returned by the Generator function.","More information about the Generator can be found here."]},{"i":"add-field-with-generator-function-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .addField(\"new-field\", document -> {\n        // do something with the document\n        return \"new-value\";\n    });"]},{"i":"rename-field-1","l":"Rename Field","p":["Adds an instruction to rename a field of the entity of a ObjectRepository."]},{"i":"rename-field-1-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .renameField(\"old-field\", \"new-field\");"]},{"i":"delete-field-1","l":"Delete Field","p":["Adds an instruction to delete a field from the entity of a ObjectRepository."]},{"i":"delete-field-1-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .deleteField(\"field-name\");"]},{"l":"Change Data Type","p":["Adds an instruction to change the data type of a field of the entity of a ObjectRepository."]},{"i":"change-data-type-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .changeDataType(\"field-name\", (TypeConverter<String, Long>) Long::parseLong);"]},{"l":"Type Converter","p":["A TypeConverter is a functional interface that takes a value of one type as input and returns a value of another type. The value returned by the TypeConverter will be used as the value of the new field."]},{"i":"type-converter-code-1","c":["// convert String to Long\nTypeConverter<String, Long> converter = Long::parseLong;\n\n// convert Float to Integer\nTypeConverter<Float, Integer> converter = Math::round;"]},{"l":"Change Id Field","p":["Adds an instruction to change the id field of the entity of a ObjectRepository."]},{"i":"change-id-field-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .changeIdField(Fields.withNames(\"uuid\"), Fields.withNames(\"empId\"));"]},{"i":"drop-index-1","l":"Drop Index","p":["Adds an instruction to drop an index from a ObjectRepository.","The drop index instruction can be used to drop a single field index or a compound index."]},{"i":"drop-index-1-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .dropIndex(\"field-name-1\", \"field-name-2\");"]},{"i":"drop-all-indexes-1","l":"Drop All Indexes","p":["Adds an instruction to drop all the indexes from a ObjectRepository."]},{"i":"drop-all-indexes-1-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .dropAllIndices();"]},{"i":"create-index-1","l":"Create Index","p":["Adds an instruction to create an index on a ObjectRepository.","The create index instruction can be used to create a single field index or a compound index."]},{"i":"create-index-1-code-1","c":["instruction.forRepository(OldClass.class, \"demo1\")\n    .createIndex(IndexType.NON_UNIQUE, \"field-name-1\", \"field-name-2\");"]}],[{"l":"Module System","p":["Nitrite is a modular database engine. The core functionality of Nitrite is provided by the nitrite module. The nitrite module is the only mandatory module for Nitrite. All other modules are optional and can be added to the project as per the requirement.","Nitrite's module system is built on top of NitritePlugin and NitriteModule interfaces. A module is a collection of plugins. While opening a database, all the modules must be loaded. Each module then load and initialize all the plugins it contains.","The nitrite module provides default implementation of all the interfaces. For example, the nitrite module provides in-memory storage implementation. If you want to use on-disk storage, you need to add a storage module to your project.","The main advantage of Nitrite's module system is that it allows you to extend the functionality of Nitrite without adding all the dependencies at once in your project. You only need to add dependencies that you want to use. This helps to keep the application size small.","You can write your own module and plugin and add it to the project. The module system also allows you to replace the default implementation of any plugin. For example, if you want to use a different storage engine, you can write your own storage module and add it to the project."]},{"l":"NitriteModule","p":["The NitriteModule interface is the base interface for all the modules. It encapsulates a set of plugins. A module must be loaded before opening a database.","To create a module, you need to implement the NitriteModule interface. The NitriteModule interface has a single method plugins() which returns a set of plugins."]},{"i":"nitritemodule-code-1","c":["MyModule module = new MyModule();\nNitrite db = Nitrite.builder()\n    .loadModule(module)\n    .openOrCreate(\"user\", \"password\");"]},{"i":"nitritemodule-code-2","c":["public class MyModule implements NitriteModule {\n    @Override\n    public Set<NitritePlugin> plugins() {\n        // return a set of plugins\n    }\n}"]},{"l":"Dynamic Module","p":["A dynamic module can be created using the static module() method of the NitriteModule interface. A dynamic module is a module which is not loaded from a jar file. It is created at runtime.","A dynamic module is useful when you want to create a module from a set of plugins at runtime."]},{"i":"dynamic-module-code-1","c":["NitriteModule module = NitriteModule.module(new MyPlugin1(), new MyPlugin2());\nNitrite db = Nitrite.builder()\n    .loadModule(module)\n    .openOrCreate(\"user\", \"password\");"]},{"l":"Available Modules","p":["The following modules are available from Nitrite.","Storage Module","Jackson Module","Spatial Module"]},{"l":"NitritePlugin","p":["The NitritePlugin interface is the base interface for all the plugins. A plugin is a single unit of functionality. A plugin must be loaded via a NitriteModule before opening a database."]},{"i":"nitriteplugin-code-1","c":["MyPlugin plugin = new MyPlugin();\nMyModule module = new MyModule(plugin);\nNitrite db = Nitrite.builder()\n    .loadModule(module)\n    .openOrCreate(\"user\", \"password\");"]},{"l":"Initializing Plugin","p":["A plugin can be initialized by implementing the initialize() method of the NitritePlugin interface. The initialize() method is called by the module when the plugin is loaded."]},{"i":"initializing-plugin-code-1","c":["public class MyPlugin implements NitritePlugin {\n    @Override\n    public void initialize(NitriteConfig nitriteConfig) {\n        // initialize the plugin\n    }\n}"]},{"l":"Closing Plugin","p":["A NitritePlugin is a closable resource. The close method is called by the Nitrite when the plugin is unloaded to release any resources held by the plugin."]},{"i":"closing-plugin-code-1","c":["public class MyPlugin implements NitritePlugin {\n    @Override\n    public void close() {\n        // close the plugin\n    }\n}"]},{"l":"Available Plugins","p":["Following are the available plugins in Nitrite which can be used to extend the functionality of Nitrite:","NitriteStore - A plugin to provide storage functionality.","NitriteMapper - A plugin to provide object mapping functionality.","NitriteIndexer - A plugin to provide indexing functionality.","EntityConverter - A plugin to provide entity conversion functionality.","You can implement any of the above plugins to extend the functionality of Nitrite."]},{"l":"NitriteStore","p":["The NitriteStore interface is the base interface for all the storage plugins. A storage plugin is responsible for storing and retrieving data from the underlying storage. The NitriteStore interface extends the NitritePlugin interface.","A reference implementation of the NitriteStore interface can be found here."]},{"i":"nitritestore-code-1","c":["public class MyStore implements NitriteStore {\n    // implement the methods\n}"]},{"l":"NitriteMapper","p":["The NitriteMapper interface is the base interface for all the object mapping plugins. A mapper plugin is responsible for mapping an object to a document and vice-versa. The NitriteMapper interface extends the NitritePlugin interface.","JacksonMapper is one of the available mapper plugins in Nitrite. It uses Jackson to map an object to a document and vice-versa. You can find more information about JacksonMapper here."]},{"i":"nitritemapper-code-1","c":["public class CustomNitriteMapper implements NitriteMapper {\n    // implement the methods\n}"]},{"l":"NitriteIndexer","p":["The NitriteIndexer interface is the base interface for all the indexing plugins. An indexer plugin is responsible for indexing a document. The NitriteIndexer interface extends the NitritePlugin interface.","While creating a new index, Nitrite uses the getIndexType() method of the NitriteIndexer interface to determine the type of the index. The getIndexType() method returns a string which represents the type of the index. So when you create a new index, you need to pass the same string to the IndexOptions.indexType."]},{"i":"nitriteindexer-code-1","c":["public class CustomIndexer implements NitriteIndexer {\n    public static final String INDEX_TYPE = \"custom\";\n\n    @Override\n    public String getIndexType() {\n        // get the index type\n        return INDEX_TYPE;\n    }\n\n    // implement the methods\n}"]},{"i":"nitriteindexer-code-2","c":["collection.createIndex(indexOptions(CustomIndexer.INDEX_TYPE), \"firstName\");"]},{"l":"EntityConverter","p":["An EntityConverter is a plugin which is responsible for converting an object to a document and vice-versa. The EntityConverter interface extends the NitritePlugin interface.","If Nitrite is using the default SimpleNitriteMapper, then all EntityConverters from all the loaded modules are automatically registered with the mapper. If you are using a custom mapper, then you need to register the EntityConverter with the mapper manually.","One of the available EntityConverter in Nitrite is GeometryConverter from the spatial module. It is responsible for converting a Geometry object of JTS to a document and vice-versa. Once you load the spatial module, the GeometryConverter is automatically registered with the mapper. You can find more information about GeometryConverter here.","If you want to load multiple EntityConverters, while opening the database, you can also create a dynamic module and load it instead of using the NitriteBuilder.registerEntityConverter() method multiple times."]},{"i":"entityconverter-code-1","c":["NitriteModule module = NitriteModule.module(new MyOtherConverter(), new MyConverter());\n\nNitrite db = Nitrite.builder()\n    .loadModule(module)\n    .openOrCreate(\"user\", \"password\");"]},{"l":"Nitrite Bill of Materials","p":["The nitrite-bom is a bill of materials (BOM) for Nitrite. It is a pom file that contains the version of all the modules. It is useful when you want to use multiple modules in your project and want to keep the version of all the modules in sync."]},{"l":"Maven","p":["Add the nitrite dependency to your pom.xml file:"]},{"i":"maven-code-1","c":["<dependencyManagement>\n    <dependencies>\n        <dependency>\n            <groupId>org.dizitart</groupId>\n            <artifactId>nitrite-bom</artifactId>\n            <version>[latest version]</version>\n            <scope>import</scope>\n            <type>pom</type>\n        </dependency>\n    </dependencies>\n</dependencyManagement>\n\n<dependencies>\n    <dependency>\n        <groupId>org.dizitart</groupId>\n        <artifactId>nitrite</artifactId>\n    </dependency>\n\n    <!-- add other modules here -->\n    <dependency>\n        <groupId>org.dizitart</groupId>\n        <artifactId>nitrite-spatial</artifactId>\n    </dependency>\n    <dependency>\n        <groupId>org.dizitart</groupId>\n        <artifactId>nitrite-jackson-mapper</artifactId>\n    </dependency>\n</dependencies>"]},{"l":"Gradle","p":["Add the nitrite dependency to your build.gradle file:"]},{"i":"gradle-code-1","c":["dependencies {\n    implementation platform('org.dizitart:nitrite-bom:[latest version]')\n    implementation 'org.dizitart:nitrite'\n\n    // add other modules here\n    implementation 'org.dizitart:nitrite-spatial'\n    implementation 'org.dizitart:nitrite-jackson-mapper'\n}"]}],[{"l":"Storage Module","p":["Nitrite provides a default storage module which is in-memory. It means all the data is stored in memory and is volatile. Once the application is closed, all the data is lost. If you want to persist the data, you want to use on-disk storage, you need to add a storage module to your project. There are choices of storage modules available for Nitrite. You can choose any one of them as per your requirement.","MVStore Module","RocksDB Module","You can also write your own storage module and add it to the project. More details about writing your own storage module is available here."]}],[{"l":"MVStore Modules","p":["Nitrite provides a persistent storage module based on MVStore. MVStore is a pure Java key-value store database. It is a single file based database. It is very fast and lightweight."]},{"l":"Adding MVStore Module","p":["Add MVStore module to your project:"]},{"l":"Maven","p":["Add the MVStore dependency to your pom.xml file:"]},{"i":"maven-code-1","c":["<dependency>\n    <groupId>org.dizitart</groupId>\n    <artifactId>nitrite-mvstore-adapter</artifactId>\n</dependency>"]},{"l":"Gradle","p":["Add the MVStore dependency to your build.gradle file:"]},{"i":"gradle-code-1","c":["dependencies {\n    implementation 'org.dizitart:nitrite-mvstore-adapter'\n}"]},{"l":"Using MVStore Module","p":["To use MVStore as your persistent storage, you need to load the MVStoreModule while opening the database. You can also configure the module as per your requirement.","Once the module is loaded, you can use the database as usual. All the data will be persisted in the file you specified."]},{"i":"using-mvstore-module-code-1","c":["// configure the module\nMVStoreModule storeModule = MVStoreModule.withConfig()\n            .filePath(filePath)\n            .compress(true)\n            .build();\n\nNitrite db = Nitrite.builder()\n            .loadModule(storeModule)\n            .openOrCreate();"]},{"l":"Configuring MVStore Module","p":["You can configure the MVStore module as per your requirement. The following configuration options are available:","filePath - the file path where the database will be stored.","autoCommitBufferSize - the size of the buffer used for auto-commit. When the buffer is full, the changes are automatically committed to the database. The default buffer size is 1024.","encryptionKey - the encryption key used to encrypt the database. If not specified, the database will not be encrypted.","readOnly - if set to true, the database will be opened in read-only mode. The default value is false.","compress - if set to true, the database will be compressed. The default value is false.","compressHigh - if set to true, the database will be compressed using high compression. The default value is false. It may result in slower read and write performance but smaller file size on disk.","autoCommit - if set to true, all changes will be committed immediately. If set to false, changes will be buffered until the buffer is full or Nitrite.commit() is called. The default value is true.","recoveryMode - if set to true, the database will be opened in recovery mode. The default value is false.","cacheSize - the cache size in MB. The default value is 16 MB.","cacheConcurrency - the read cache concurrency used by MVStore. Default is 16 segments.","pageSplitSize - the amount of memory a MVStore page should contain at most, in bytes, before it is split. The default is 16 KB.","fileStore - the file store used by MVStore.","Nitrite provides a builder pattern to configure the module. You can use the MVStoreModule.withConfig() method to get the builder instance. The builder has a build() method which returns the configured module."]},{"i":"configuring-mvstore-module-code-1","c":["MVStoreModule storeModule = MVStoreModule.withConfig()\n            .filePath(filePath)\n            .compress(true)\n            .build();"]},{"l":"Upgrading from 3.x","p":["If you are upgrading from Nitrite 3.x, you need to use the MVStore module as your storage module if you want to automatically upgrade your database. Any other storage module will not be able to upgrade your database automatically; you need to write your own upgrade logic.","Nitrite 3.x uses MVStore version 1.4.x. Nitrite 4.x uses MVStore version 2.2.x. The MVStore version 2.2.x is not backward compatible with version 1.4.x. So, Nitrite 4.x will try to upgrade your database automatically when you open it for the first time on a . If the upgrade fails, you need to write your own upgrade logic. However, it is recommended to take a backup of your database before upgrading."]}],[{"l":"RocksDB Module","p":["Nitrite provides a persistent storage module based on RocksDB. RocksDB is a persistent key-value store for fast storage. It is based on a log-structured merge-tree (LSM tree) data structure. It is very fast and lightweight. Nitrite uses the JNI wrapper of RocksDB.","RocksDB's column family feature is used to store the data of each collection."]},{"l":"Adding RocksDB Module","p":["Add RocksDB module to your project:"]},{"l":"Maven","p":["Add the RocksDB dependency to your pom.xml file:"]},{"i":"maven-code-1","c":["<dependency>\n    <groupId>org.dizitart</groupId>\n    <artifactId>nitrite-rocksdb-adapter</artifactId>\n</dependency>"]},{"l":"Gradle","p":["Add the RocksDB dependency to your build.gradle file:"]},{"i":"gradle-code-1","c":["dependencies {\n    implementation 'org.dizitart:nitrite-rocksdb-adapter'\n}"]},{"l":"Using RocksDB Module","p":["To use RocksDB as your persistent storage, you need to load the RocksDBModule while opening the database. You can also configure the module as per your requirement.","Once the module is loaded, you can use the database as usual. All the data will be persisted in the file you specified."]},{"i":"using-rocksdb-module-code-1","c":["// configure the module\nRocksDBModule storeModule = RocksDBModule.withConfig()\n            .filePath(filePath)\n            .build();\n\nNitrite db = Nitrite.builder()\n            .loadModule(storeModule)\n            .openOrCreate();"]},{"l":"Configuring RocksDB Module","p":["You can configure the RocksDB module as per your requirement. The following configuration options are available:","filePath - the file path where the database will be stored.","options - the RocksDB's Options object. You can configure RocksDB as per your requirement. The default value is null.","dbOptions - the RocksDB's DBOptions object. You can configure RocksDB as per your requirement. The default value is null.","columnFamilyOptions - the RocksDB's ColumnFamilyOptions object. You can configure RocksDB as per your requirement. The default value is null.","objectFormatter - the ObjectFormatter to be used to serialize/deserialize objects. The default implementation is KryoObjectFormatter which is based on Kryo serializer."]},{"l":"Object Serialization","p":["RocksDB is a key-value store database. It stores data in byte array format. To store objects in RocksDB, Nitrite uses a serializer. Nitrite uses ObjectFormatter to serialize/deserialize objects. The default implementation is KryoObjectFormatter which is based on Kryo serializer. You can also provide your own implementation of ObjectFormatter to serialize/deserialize objects."]},{"l":"Implementing ObjectFormatter","p":["To implement your own ObjectFormatter, you need to implement the ObjectFormatter interface.","Once you have implemented the ObjectFormatter, you can use it while configuring the RocksDB module.","Normally, you don't need to implement your own ObjectFormatter. The default implementation is good enough for most of the use cases."]},{"i":"implementing-objectformatter-code-1","c":["public class MyObjectFormatter implements ObjectFormatter {\n    @Override\n    public <T> byte[] encode(T object) {\n        // your implementation\n    }\n\n    @Override\n    public <T> byte[] encodeKey(T object) {\n        // your implementation\n    }\n\n    @Override\n    public <T> T decode(byte[] bytes, Class<T> type) {\n        // your implementation\n    }\n\n    @Override\n    public <T> T decodeKey(byte[] bytes, Class<T> type) {\n        // your implementation\n    }\n}"]},{"i":"implementing-objectformatter-code-2","c":["// configure the module\nRocksDBModule storeModule = RocksDBModule.withConfig()\n            .filePath(filePath)\n            .objectFormatter(new MyObjectFormatter())\n            .build();\n\nNitrite db = Nitrite.builder()\n            .loadModule(storeModule)\n            .openOrCreate();"]},{"l":"Limitations","p":["RocksDB JNI does not support RTree, so RocksDB storage adapter does not provide any RTree backed NitriteRTree implementation. Though there is a workaround implementation of NitriteRTree using RocksDB, it is not recommended to use it in production. It is only for testing purpose. Hence, RocksDB storage adapter is not recommended for spatial data indexing.","If you want to use spatial data indexing, you can use Spatial Module with MVStore storage adapter. MVStore storage adapter provides RTree backed NitriteRTree implementation."]}],[{"l":"Custom Storage Modules","p":["The beauty of Nitrite is that it is highly extensible. You can write your own storage module and use it with Nitrite. Nitrite provides a simple interface StoreModule to write your own storage module."]},{"l":"StoreModule Interface","p":["To write a custom storage module, you need to implement the StoreModule interface. The interface has only one method getStore() which returns an implementation of NitriteStore interface.","Optionally, you can also implement the StoreConfig interface to provide configuration options for your storage module."]},{"l":"NitriteStore Interface","p":["The NitriteStore is the storage abstraction layer for Nitrite. It provides the basic operations required by Nitrite to store and retrieve data. A NitriteStore is responsible for managing NitriteMap and NitriteRTree instances which are the main building blocks of database collections."]},{"l":"StoreConfig Interface","p":["The StoreConfig interface provides configuration options for your storage module. You can use this interface to provide configuration options for your storage module."]},{"l":"NitriteMap Interface","p":["The NitriteMap interface is the abstraction layer for Nitrite's key-value store. It provides the basic operations required by a collection to store and retrieve data. A NitriteMap is responsible for managing NitriteId and Document instances which are the main unit of data storage in Nitrite."]},{"l":"NitriteRTree Interface","p":["The NitriteRTree interface is the abstraction layer for Nitrite's R-Tree. It provides the basic operations required by a spatial index to store and retrieve data."]},{"l":"Example","p":["Let's write a simple storage module which stores data in a Map object. The module will be a simple in-memory storage module. The module will be configured with a Map object and will use it to store data."]},{"l":"Store Module","p":["The following code snippet shows the implementation of the storage module."]},{"i":"store-module-code-1","c":["public class InMemoryStoreModule implements StoreModule {\n\n    @Setter(AccessLevel.PACKAGE)\n    private InMemoryConfig storeConfig;\n\n    public InMemoryStoreModule() {\n        this.storeConfig = new InMemoryConfig();\n    }\n\n    public static InMemoryModuleBuilder withConfig() {\n        return new InMemoryModuleBuilder();\n    }\n\n    @Override\n    public NitriteStore<?> getStore() {\n        InMemoryStore store = new InMemoryStore();\n        store.setStoreConfig(storeConfig);\n        return store;\n    }\n\n    @Override\n    public Set<NitritePlugin> plugins() {\n        return setOf(getStore());\n    }\n}"]},{"l":"Store Config","p":["The following code snippet shows the implementation of the store configuration.","And the builder class for the configuration."]},{"i":"store-config-code-1","c":["@Accessors(fluent = true)\npublic class InMemoryConfig implements StoreConfig {\n    @Getter\n    @Setter(AccessLevel.PACKAGE)\n    private Set<StoreEventListener> eventListeners;\n\n    public InMemoryConfig() {\n        this.eventListeners = new HashSet<>();\n    }\n\n    @Override\n    public final String filePath() {\n        return null;\n    }\n\n    @Override\n    public Boolean isReadOnly() {\n        return false;\n    }\n\n    @Override\n    public void addStoreEventListener(StoreEventListener listener) {\n        eventListeners.add(listener);\n    }\n}"]},{"i":"store-config-code-2","c":["@Getter\n@Accessors(fluent = true)\npublic class InMemoryModuleBuilder {\n    private final Set<StoreEventListener> eventListeners;\n    private final InMemoryConfig dbConfig;\n\n    public InMemoryModuleBuilder() {\n        dbConfig = new InMemoryConfig();\n        eventListeners = new HashSet<>();\n    }\n\n    public InMemoryModuleBuilder addStoreEventListener(StoreEventListener listener) {\n        eventListeners.add(listener);\n        return this;\n    }\n\n    public InMemoryStoreModule build() {\n        InMemoryStoreModule module = new InMemoryStoreModule();\n        dbConfig.eventListeners(eventListeners());\n        module.setStoreConfig(dbConfig);\n        return module;\n    }\n}"]},{"l":"Nitrite Store","p":["The following code snippet shows the implementation of the NitriteStore interface."]},{"i":"nitrite-store-code-1","c":["public final class InMemoryStore extends AbstractNitriteStore<InMemoryConfig> {\n    private final Map<String, NitriteMap<?, ?>> nitriteMapRegistry;\n    private final Map<String, NitriteRTree<?, ?>> nitriteRTreeMapRegistry;\n    private volatile boolean closed = false;\n\n    public InMemoryStore() {\n        super();\n        this.nitriteMapRegistry = new ConcurrentHashMap<>();\n        this.nitriteRTreeMapRegistry = new ConcurrentHashMap<>();\n    }\n\n    @Override\n    public void openOrCreate() {\n        initEventBus();\n        alert(StoreEvents.Opened);\n    }\n\n    @Override\n    public boolean isClosed() {\n        return closed;\n    }\n\n    @Override\n    public boolean hasUnsavedChanges() {\n        return false;\n    }\n\n    @Override\n    public boolean isReadOnly() {\n        return false;\n    }\n\n    @Override\n    public void commit() {\n        alert(StoreEvents.Commit);\n    }\n\n    @Override\n    public void close() {\n        closed = true;\n        Consumer<Map.Entry<?, ?>> closeConsumer = entry -> {\n            if (entry.getValue() instanceof AutoCloseable) {\n                try {\n                    ((AutoCloseable) entry.getValue()).close();\n                } catch (Exception e) {\n                    throw new RuntimeException(e);\n                }\n            }\n        };\n\n        nitriteMapRegistry.entrySet().forEach(closeConsumer);\n        nitriteRTreeMapRegistry.entrySet().forEach(closeConsumer);\n\n        nitriteMapRegistry.clear();\n        nitriteRTreeMapRegistry.clear();\n        super.close();\n    }\n\n    @Override\n    public boolean hasMap(String mapName) {\n        return nitriteMapRegistry.containsKey(mapName) || nitriteRTreeMapRegistry.containsKey(mapName);\n    }\n\n    @Override\n    @SuppressWarnings(\"unchecked\")\n    public <Key, Value> NitriteMap<Key, Value> openMap(String mapName, Class<?> keyType, Class<?> valueType) {\n        if (nitriteMapRegistry.containsKey(mapName)) {\n            NitriteMap<Key, Value> nitriteMap = (NitriteMap<Key, Value>) nitriteMapRegistry.get(mapName);\n            if (nitriteMap.isClosed()) {\n                nitriteMapRegistry.remove(mapName);\n            } else {\n                return nitriteMap;\n            }\n        }\n\n        NitriteMap<Key, Value> nitriteMap = new InMemoryMap<>(mapName, this);\n        nitriteMapRegistry.put(mapName, nitriteMap);\n        return nitriteMap;\n    }\n\n    @Override\n    @SuppressWarnings(\"unchecked\")\n    public <Key extends BoundingBox, Value> NitriteRTree<Key, Value> openRTree(String rTreeName,\n                                                                               Class<?> keyType,\n                                                                               Class<?> valueType) {\n        if (nitriteRTreeMapRegistry.containsKey(rTreeName)) {\n            return (InMemoryRTree<Key, Value>) nitriteRTreeMapRegistry.get(rTreeName);\n        }\n\n        NitriteRTree<Key, Value> rTree = new InMemoryRTree<>(rTreeName, this);\n        nitriteRTreeMapRegistry.put(rTreeName, rTree);\n\n        return rTree;\n    }\n\n    @Override\n    public void closeMap(String mapName) {\n        nitriteMapRegistry.remove(mapName);\n    }\n\n    @Override\n    public void closeRTree(String rTreeName) {\n        nitriteRTreeMapRegistry.remove(rTreeName);\n    }\n\n    @Override\n    public void removeMap(String mapName) {\n        if (nitriteMapRegistry.containsKey(mapName)) {\n            NitriteMap<?, ?> nitriteMap = nitriteMapRegistry.get(mapName);\n            if (!nitriteMap.isClosed() && !nitriteMap.isDropped()) {\n                nitriteMap.clear();\n                nitriteMap.close();\n            }\n            nitriteMapRegistry.remove(mapName);\n            getCatalog().remove(mapName);\n        }\n    }\n\n    @Override\n    public void removeRTree(String rTreeName) {\n        if (nitriteRTreeMapRegistry.containsKey(rTreeName)) {\n            NitriteRTree<?, ?> rTree = nitriteRTreeMapRegistry.get(rTreeName);\n            rTree.close();\n            nitriteRTreeMapRegistry.remove(rTreeName);\n            getCatalog().remove(rTreeName);\n        }\n    }\n\n    @Override\n    public String getStoreVersion() {\n        return \"InMemory/\" + NITRITE_VERSION;\n    }\n\n    private void initEventBus() {\n        if (getStoreConfig().eventListeners() != null) {\n            for (StoreEventListener eventListener : getStoreConfig().eventListeners()) {\n                subscribe(eventListener);\n            }\n        }\n    }\n}"]},{"l":"Nitrite Map","p":["The following code snippet shows the implementation of the NitriteMap interface."]},{"i":"nitrite-map-code-1","c":["public class InMemoryMap<Key, Value> implements NitriteMap<Key, Value> {\n    private final NavigableMap<Key, Value> backingMap;\n    private final NitriteStore<?> nitriteStore;\n    private final String mapName;\n    private final AtomicBoolean droppedFlag;\n    private final AtomicBoolean closedFlag;\n\n    public InMemoryMap(String mapName, NitriteStore<?> nitriteStore) {\n        this.mapName = mapName;\n        this.nitriteStore = nitriteStore;\n        this.backingMap = new ConcurrentSkipListMap<>((o1, o2) ->\n            Comparables.compare((Comparable<?>) o1, (Comparable<?>) o2));\n\n        this.closedFlag = new AtomicBoolean(false);\n        this.droppedFlag = new AtomicBoolean(false);\n    }\n\n    @Override\n    public boolean containsKey(Key key) {\n        checkOpened();\n        return backingMap.containsKey(key);\n    }\n\n    @Override\n    public Value get(Key key) {\n        checkOpened();\n        return backingMap.get(key);\n    }\n\n    @Override\n    public NitriteStore<?> getStore() {\n        return nitriteStore;\n    }\n\n    @Override\n    public String getName() {\n        return mapName;\n    }\n\n    @Override\n    public RecordStream<Value> values() {\n        checkOpened();\n        return RecordStream.fromIterable(backingMap.values());\n    }\n\n    @Override\n    public Value remove(Key key) {\n        checkOpened();\n        Value value = backingMap.remove(key);\n        updateLastModifiedTime();\n        return value;\n    }\n\n    @Override\n    public RecordStream<Key> keys() {\n        checkOpened();\n        return RecordStream.fromIterable(backingMap.keySet());\n    }\n\n    @Override\n    public void put(Key key, Value value) {\n        checkOpened();\n        notNull(value, \"value cannot be null\");\n        backingMap.put(key, value);\n        updateLastModifiedTime();\n    }\n\n    @Override\n    public long size() {\n        checkOpened();\n        return backingMap.size();\n    }\n\n    @Override\n    public Value putIfAbsent(Key key, Value value) {\n        checkOpened();\n        notNull(value, \"value cannot be null\");\n\n        Value v = get(key);\n        if (v == null) {\n            put(key, value);\n            updateLastModifiedTime();\n        }\n        return v;\n    }\n\n    @Override\n    public RecordStream<Pair<Key, Value>> entries() {\n        checkOpened();\n        return getStream(backingMap);\n    }\n\n    @Override\n    public RecordStream<Pair<Key, Value>> reversedEntries() {\n        checkOpened();\n        return getStream(backingMap.descendingMap());\n    }\n\n    @Override\n    public Key higherKey(Key key) {\n        checkOpened();\n        if (key == null) {\n            return null;\n        }\n        return backingMap.higherKey(key);\n    }\n\n    @Override\n    public Key ceilingKey(Key key) {\n        checkOpened();\n        if (key == null) {\n            return null;\n        }\n        return backingMap.ceilingKey(key);\n    }\n\n    @Override\n    public Key lowerKey(Key key) {\n        checkOpened();\n        if (key == null) {\n            return null;\n        }\n        return backingMap.lowerKey(key);\n    }\n\n    @Override\n    public Key floorKey(Key key) {\n        checkOpened();\n        if (key == null) {\n            return null;\n        }\n        return backingMap.floorKey(key);\n    }\n\n    @Override\n    public boolean isEmpty() {\n        checkOpened();\n        return backingMap.isEmpty();\n    }\n\n    @Override\n    public void drop() {\n        if (!droppedFlag.get()) {\n            backingMap.clear();\n            getStore().removeMap(mapName);\n            droppedFlag.compareAndSet(false, true);\n            closedFlag.compareAndSet(false, true);\n        }\n    }\n\n    @Override\n    public boolean isDropped() {\n        return droppedFlag.get();\n    }\n\n    @Override\n    public void close() {\n        closedFlag.compareAndSet(false, true);\n        getStore().closeMap(mapName);\n    }\n\n    @Override\n    public boolean isClosed() {\n        return closedFlag.get();\n    }\n\n    @Override\n    public void clear() {\n        checkOpened();\n        backingMap.clear();\n        getStore().closeMap(mapName);\n        updateLastModifiedTime();\n    }\n\n    private RecordStream<Pair<Key, Value>> getStream(NavigableMap<Key, Value> primaryMap) {\n        return RecordStream.fromIterable(() -> new Iterator<Pair<Key, Value>>() {\n            private final Iterator<Map.Entry<Key, Value>> entryIterator =\n                primaryMap.entrySet().iterator();\n            @Override\n            public boolean hasNext() {\n                return entryIterator.hasNext();\n            }\n\n            @Override\n            public Pair<Key, Value> next() {\n                Map.Entry<Key, Value> entry = entryIterator.next();\n                return new Pair<>(entry.getKey(), entry.getValue());\n            }\n        });\n    }\n\n    private void checkOpened() {\n        if (closedFlag.get()) {\n            throw new InvalidOperationException(\"Map \" + mapName + \" is closed\");\n        }\n\n        if (droppedFlag.get()) {\n            throw new InvalidOperationException(\"Map \" + mapName + \" is dropped\");\n        }\n    }\n}"]},{"l":"Nitrite RTree","p":["The following code snippet shows the implementation of the NitriteRTree interface."]},{"i":"nitrite-rtree-code-1","c":["public class InMemoryRTree<Key extends BoundingBox, Value> implements NitriteRTree<Key, Value> {\n    private final Map<SpatialKey, Key> backingMap;\n    private final AtomicBoolean droppedFlag;\n    private final AtomicBoolean closedFlag;\n    private final String mapName;\n    private final NitriteStore<?> nitriteStore;\n\n    public InMemoryRTree(String mapName, NitriteStore<?> nitriteStore) {\n        this.backingMap = new ConcurrentHashMap<>();\n        this.closedFlag = new AtomicBoolean(false);\n        this.droppedFlag = new AtomicBoolean(false);\n        this.mapName = mapName;\n        this.nitriteStore = nitriteStore;\n    }\n\n    @Override\n    public void add(Key key, NitriteId nitriteId) {\n        checkOpened();\n        if (nitriteId != null && nitriteId.getIdValue() != null) {\n            SpatialKey spatialKey = getKey(key, Long.parseLong(nitriteId.getIdValue()));\n            backingMap.put(spatialKey, key);\n        }\n    }\n\n    @Override\n    public void remove(Key key, NitriteId nitriteId) {\n        checkOpened();\n        if (nitriteId != null && nitriteId.getIdValue() != null) {\n            SpatialKey spatialKey = getKey(key, Long.parseLong(nitriteId.getIdValue()));\n            backingMap.remove(spatialKey);\n        }\n    }\n\n    @Override\n    public RecordStream<NitriteId> findIntersectingKeys(Key key) {\n        checkOpened();\n        SpatialKey spatialKey = getKey(key, 0L);\n        Set<NitriteId> set = new HashSet<>();\n\n        for (SpatialKey sk : backingMap.keySet()) {\n            if (isOverlap(sk, spatialKey)) {\n                set.add(NitriteId.createId(Long.toString(sk.getId())));\n            }\n        }\n\n        return RecordStream.fromIterable(set);\n    }\n\n    @Override\n    public RecordStream<NitriteId> findContainedKeys(Key key) {\n        checkOpened();\n        SpatialKey spatialKey = getKey(key, 0L);\n        Set<NitriteId> set = new HashSet<>();\n\n        for (SpatialKey sk : backingMap.keySet()) {\n            if (isInside(sk, spatialKey)) {\n                set.add(NitriteId.createId(Long.toString(sk.getId())));\n            }\n        }\n\n        return RecordStream.fromIterable(set);\n    }\n\n    @Override\n    public long size() {\n        checkOpened();\n        return backingMap.size();\n    }\n\n    @Override\n    public void close() {\n        closedFlag.compareAndSet(false, true);\n    }\n\n    @Override\n    public void clear() {\n        checkOpened();\n        backingMap.clear();\n    }\n\n    @Override\n    public void drop() {\n        checkOpened();\n        droppedFlag.compareAndSet(false, true);\n        backingMap.clear();\n        nitriteStore.removeRTree(mapName);\n    }\n\n    private SpatialKey getKey(Key key, long id) {\n        return new SpatialKey(id, key.getMinX(),\n            key.getMaxX(), key.getMinY(), key.getMaxY());\n    }\n\n    private boolean isOverlap(SpatialKey a, SpatialKey b) {\n        if (a.isNull() || b.isNull()) {\n            return false;\n        }\n        for (int i = 0; i < 2; i++) {\n            if (a.max(i) < b.min(i) || a.min(i) > b.max(i)) {\n                return false;\n            }\n        }\n        return true;\n    }\n\n    private boolean isInside(SpatialKey a, SpatialKey b) {\n        if (a.isNull() || b.isNull()) {\n            return false;\n        }\n        for (int i = 0; i < 2; i++) {\n            if (a.min(i) <= b.min(i) || a.max(i) >= b.max(i)) {\n                return false;\n            }\n        }\n        return true;\n    }\n\n    private void checkOpened() {\n        if (closedFlag.get()) {\n            throw new InvalidOperationException(\"RTreeMap is closed\");\n        }\n\n        if (droppedFlag.get()) {\n            throw new InvalidOperationException(\"RTreeMap is dropped\");\n        }\n    }\n}"]}],[{"l":"Spatial Module","p":["Nitrite Spatial module provides support for spatial queries. The module uses JTS library for spatial operations."]},{"l":"Adding Spatial Module","p":["Add Spatial module to your project:"]},{"l":"Maven","p":["Add the Spatial dependency to your pom.xml file:"]},{"i":"maven-code-1","c":["<dependency>\n    <groupId>org.dizitart</groupId>\n    <artifactId>nitrite-spatial</artifactId>\n</dependency>"]},{"l":"Gradle","p":["Add the Spatial dependency to your build.gradle file:"]},{"i":"gradle-code-1","c":["dependencies {\n    implementation 'org.dizitart:nitrite-spatial'\n}"]},{"l":"Using Spatial Module","p":["To use Spatial module, you need to load the SpatialModule while opening the database.","If Nitrite is using the default SimpleNitriteMapper, then the SpatialModule will automatically register the GeometryConverter with the mapper. If you are using your own custom mapper, then you need to register the GeometryConverter with the mapper."]},{"i":"using-spatial-module-code-1","c":["Nitrite db = Nitrite.builder()\n            .loadModule(new SpatialModule())\n            .openOrCreate();"]},{"l":"GeometryConverter","p":["GeometryConverter is an EntityConverter which is used to convert Geometry object of JTS to Document and vice-versa. It is used to store the Geometry object in the database."]},{"l":"Using Spatial Modules with Jackson","p":["If you are using Jackson module for serialization, you need to register the GeometryModule with Jackson as well.","The GeometryModule is required to serialize the Geometry object of JTS via Jackson."]},{"i":"using-spatial-modules-with-jackson-code-1","c":["Nitrite db = Nitrite.builder()\n            .loadModule(new SpatialModule())\n            .loadModule(new JacksonMapperModule(new GeometryModule()))\n            .openOrCreate();"]},{"l":"Spatial Index","p":["Spatial module uses R-Tree index to store the spatial data.","To create a spatial index, you need to pass the index type as SpatialIndexer.SPATIAL_INDEX while creating the index.","Spatial index is not supported on multiple fields."]},{"i":"spatial-index-code-1","c":["collection.createIndex(IndexOptions.indexOptions(SpatialIndexer.SPATIAL_INDEX), \"location\");"]},{"l":"Spatial Filter","p":["Spatial module supports several filters to query spatial data. To know more about filters, please refer to Spatial Filters."]}],[{"l":"Jackson Mapper Module","p":["Nitrite provides a Jackson mapper module to convert Java objects to Document and vice-versa. The module is useful when you don't want to use the EntityConverter interface to map Java objects to Document and vice-versa."]},{"l":"Adding Jackson Mapper Module","p":["Add the Jackson mapper module to your project:"]},{"l":"Maven","p":["Add the Jackson mapper module dependency to your pom.xml file:"]},{"i":"maven-code-1","c":["<dependency>\n    <groupId>org.dizitart</groupId>\n    <artifactId>nitrite-jackson-mapper</artifactId>\n</dependency>"]},{"l":"Gradle","p":["Add the Jackson mapper module dependency to your build.gradle file:"]},{"i":"gradle-code-1","c":["dependencies {\n    implementation 'org.dizitart:nitrite-jackson-mapper'\n}"]},{"l":"Using Jackson Mapper Module","p":["To use Jackson mapper module, you need to load the JacksonMapperModule while opening the database."]},{"i":"using-jackson-mapper-module-code-1","c":["Nitrite db = Nitrite.builder()\n            .loadModule(new JacksonMapperModule())\n            .openOrCreate();"]},{"l":"Using Custom Jackson Modules","p":["If you want to register any custom Jackson module, you can do so by passing the module to JacksonMapperModule constructor.","If you want to register multiple modules, you can do so by passing an array of modules to JacksonMapperModule constructor.","And here is an example of a custom Jackson module."]},{"i":"using-custom-jackson-modules-code-1","c":["Nitrite db = Nitrite.builder()\n            .loadModule(new JacksonMapperModule(new MyCustomModule()))\n            .openOrCreate();"]},{"i":"using-custom-jackson-modules-code-2","c":["Nitrite db = Nitrite.builder()\n            .loadModule(new JacksonMapperModule(new MyCustomModule(), new MyAnotherCustomModule()))\n            .openOrCreate();"]},{"i":"using-custom-jackson-modules-code-3","c":["public class MyCustomModule extends SimpleModule {\n\n    @Override\n    public void setupModule(SetupContext context) {\n        addSerializer(MyCustomType.class, new MyCustomTypeSerializer());\n        addDeserializer(MyCustomType.class, new MyCustomTypeDeserializer());\n        super.setupModule(context);\n    }\n}"]},{"l":"Customizing ObjectMapper","p":["If you want to customize the ObjectMapper used by the Jackson mapper module, you can do so by extending the JacksonMapper class and overriding the getObjectMapper() method.","Now, you can use this custom mapper while building the database."]},{"i":"customizing-objectmapper-code-1","c":["public class MyCustomJacksonMapper extends JacksonMapper {\n    @Override\n    public ObjectMapper getObjectMapper() {\n        ObjectMapper objectMapper = super.getObjectMapper();\n        objectMapper.setSerializationInclusion(JsonInclude.Include.NON_NULL);\n        return objectMapper;\n    }\n}"]},{"i":"customizing-objectmapper-code-2","c":["Nitrite db = Nitrite.builder()\n            .loadModule(NitriteModule.module(new MyCustomJacksonMapper()))\n            .openOrCreate();"]}],[{"l":"Usage","p":["Nitrite provides some additional functionalities via nitrite-support library. You can use the library to enable encryption, import/export database, and database recovery."]},{"l":"Adding nitrite-support","p":["Add the nitrite-support dependency to your project:"]},{"l":"Maven","p":["Add the nitrite-support dependency to your pom.xml file:"]},{"i":"maven-code-1","c":["<dependency>\n    <groupId>org.dizitart</groupId>\n    <artifactId>nitrite-support</artifactId>\n</dependency>"]},{"l":"Gradle","p":["Add the nitrite-support dependency to your build.gradle file:"]},{"i":"gradle-code-1","c":["dependencies {\n    implementation 'org.dizitart:nitrite-support'\n}"]}],[{"l":"Import/Export","p":["Nitrite provides import/export functionality via nitrite-support library. You can import/export your database to/from a file in JSON format. You can choose to import/export the entire database or a specific collection."]},{"l":"Exporting Database","p":["To export the entire database in JSON format, you can use the Exporter class of nitrite-support library. You can construct an instance of Exporter from an ExportOptions instance using Exporter.withOptions() method. The ExportOptions class provides various options to configure the export process.","The exportTo() method can take a File or a String or an OutputStream or a Writer as an argument. If you pass a File or a String argument, the exporter will create a FileOutputStream and write the exported data to the file. If you pass an OutputStream or a Writer argument, the exporter will write the exported data to the stream or writer.","The database must be in closed state before exporting."]},{"i":"exporting-database-code-1","c":["// create an exporter with export options\nExporter exporter = new Exporter(exportOptions);\n\n// export the database to a file\nexporter.exportTo(dataFile);"]},{"l":"Export Options","p":["collections - the list of collections to export. The rules for specifying the collection names are as follows:","exportData - whether to export data or not. It's an optional field, if not provided, it will be set to true.","exportIndices - whether to export indices or not. It's an optional field, if not provided, it will be set to true.","If a non-empty list is specified, only the collections in the list will be exported.","If a non-empty list is specified, only the repositories in the list will be exported.","If a non-empty map is specified, only the keyed repositories in the map will be exported.","If an empty list is specified, no collection will be exported.","If an empty list is specified, no repository will be exported.","If an empty map is specified, no keyed repository will be exported.","If null is specified, all collections will be exported.","If null is specified, all keyed repositories will be exported.","If null is specified, all repositories will be exported.","jsonFactory - the JsonFactory instance to use for export. It is used to create the JsonGenerator instance for export. It's an optional field, if not provided, a default one will be used.","keyedRepositories - the map of keyed repositories to export. The rules for specifying the keyed repository names are as follows:","nitriteFactory - the NitriteFactory instance to use for export. It is used to create the Nitrite instance for export. It's a mandatory field.","repositories - the list of repositories to export. The rules for specifying the repository names are as follows:","The ExportOptions class provides various options to configure the export process. You can set the following options:"]},{"l":"Example","p":["First create a method to create a Nitrite instance, which will be used as the nitriteFactory.","Then create the ExportOptions instance and configure it.","Then create the Exporter instance and export the database.","The test.json file will contain the exported data."]},{"i":"example-code-1","c":["public Nitrite createDb(String filePath) {\n    // create a MVStore based file store\n    MVStoreModule storeModule = MVStoreModule.withConfig()\n        .filePath(filePath)\n        .build();\n\n    // create an instance of nitrite database\n    return Nitrite.builder()\n        .loadModule(storeModule)\n        .registerEntityConverter(new Employee.EmployeeConverter())\n        .registerEntityConverter(new Company.CompanyConverter())\n        .registerEntityConverter(new Note.NoteConverter())\n        .openOrCreate();\n}"]},{"i":"example-code-2","c":["// create export options\nExportOptions exportOptions = new ExportOptions();\n// set the nitrite factory\nexportOptions.setNitriteFactory(() -> createDb(\"test.db\"));\n// set the collections to export\nexportOptions.setCollections(List.of(\"first\"));\n// set the repositories to export\nexportOptions.setRepositories(List.of(\"org.dizitart.no2.support.data.Employee\", \"org.dizitart.no2.support.data.Company\"));\n// set the keyed repositories to export\nexportOptions.setKeyedRepositories(Map.of(\"key\", Set.of(\"org.dizitart.no2.support.data.Employee\")));"]},{"i":"example-code-3","c":["// create an exporter with export options\nExporter exporter = Exporter.withOptions(exportOptions);\nexporter.exportTo(\"test.json\");"]},{"l":"Importing Database","p":["To import the entire database from an exported JSON data, you can use the Importer class of nitrite-support library. You can construct an instance of Importer from an ImportOptions instance using Importer.withOptions() method. The ImportOptions class provides various options to configure the import process.","The importFrom() method can take a File or a String or an InputStream or a Reader as an argument. If you pass a File or a String argument, the importer will create a FileInputStream and read the exported data from the file. If you pass an InputStream or a Reader argument, the importer will read the exported data from the stream or reader.","The database must be in closed state before importing."]},{"i":"importing-database-code-1","c":["// create an importer with import options\nImporter importer = new Importer(importOptions);\n\n// import the database from a file\nimporter.importFrom(dataFile);"]},{"l":"Import Options","p":["The ImportOptions class provides various options to configure the import process. You can set the following options:","nitriteFactory - the NitriteFactory instance to use for import. It is used to create the Nitrite instance for import. It's a mandatory field.","jsonFactory - the JsonFactory instance to use for import. It is used to create the JsonParser instance for import. It's an optional field, if not provided, a default one will be used."]},{"i":"example-1","l":"Example","p":["First create a ImportOptions instance and configure it using the createDb() method from the previous example.","Then create the Importer instance and import the database.","The new-test.db file will contain the imported data. You can open the database and use it."]},{"i":"example-1-code-1","c":["// create import options\nImportOptions importOptions = new ImportOptions();\n// set the nitrite factory\nimportOptions.setNitriteFactory(() -> createDb(\"new-test.db\"));"]},{"i":"example-1-code-2","c":["// create an importer with import options\nImporter importer = Importer.withOptions(importOptions);\nimporter.importFrom(\"test.json\");"]}],[{"l":"Encryption","p":["Nitrite provides encryption support via nitrite-support module. You can encrypt your data using a password. Nitrite provides an Encryptor interface to encrypt and decrypt data. Nitrite also provides an AES based implementation of Encryptor interface, which uses AES/GCM/NoPadding algorithm to encrypt and decrypt data."]},{"l":"Using Encryption","p":["To use encryption, you can either use the AES implementation of Encryptor interface or you can create your own implementation of Encryptor interface."]},{"l":"Using AES Encryptor","p":["To use AES based encryption you need to use the AESEncryptor class. The class takes a password as a parameter in its constructor.","There is another constructor also which takes a password along with the algorithm, tag length, IV length, and salt length.","You can use the encryptor to encrypt and decrypt data."]},{"i":"using-aes-encryptor-code-1","c":["// create an AES encryptor with a password\nEncryptor encryptor = new AESEncryptor(\"my-password\");"]},{"i":"using-aes-encryptor-code-2","c":["// create an AES encryptor with a password and algorithm parameters\n\n// algo: AES/CBC/PKCS5Padding\n// tag length: 128\n// IV length: 12\n// salt length: 16\n\nEncryptor encryptor = new AESEncryptor(\"my-password\", \"AES/CBC/PKCS5Padding\", 128, 12, 16);"]},{"i":"using-aes-encryptor-code-3","c":["// encrypt a string\nString encrypted = encryptor.encrypt(\"my-data\".getBytes(StandardCharsets.UTF_8));\n\n// decrypt the string\nString decrypted = encryptor.decrypt(encrypted);"]},{"l":"Using Custom Encryptor","p":["If you want to use your own encryption algorithm, you can do so by implementing the Encryptor interface. The interface has two methods encrypt and decrypt. You can implement these methods to encrypt and decrypt data."]},{"i":"using-custom-encryptor-code-1","c":["public class MyEncryptor implements Encryptor {\n    @Override\n    public String encrypt(byte[] plainText) {\n        // implement your encryption logic\n    }\n\n    @Override\n    public String decrypt(String encryptedText) {\n        // implement your decryption logic\n    }\n}"]},{"l":"Field Level Encryption","p":["Nitrite provides field level encryption support. You can encrypt a field of a document using a password. Nitrite provides a StringFieldEncryptionProcessor utility class to encrypt and decrypt a field of a document. It is a Processor implementation. It uses the Encryptor interface to encrypt and decrypt data."]},{"l":"Using Field Encryption","p":["To use field encryption, you need to create an instance of StringFieldEncryptionProcessor class. The class takes either an Encryptor instance or a password as a parameter in its constructor.","If you provide the password, the class will create an instance of AESEncryptor class using the password. If you provide an Encryptor instance, the class will use the provided Encryptor instance.","You can also use the AESEncryptor class to create an instance of StringFieldEncryptionProcessor class.","The encrypted data is a base64 encoded string of the encrypted bytes."]},{"i":"using-field-encryption-code-1","c":["// create an instance of StringFieldEncryptionProcessor using a password\nStringFieldEncryptionProcessor processor = new StringFieldEncryptionProcessor(\"my-password\");\n\n// add fields to encrypt\nprocessor.addFields(\"field1\", \"field2\");\n\n// use the processor\ncollection.addProcessor(processor);\n\n// use the collection\ncollection.insert(doc);"]},{"i":"using-field-encryption-code-2","c":["// create an instance of AESEncryptor\nEncryptor encryptor = new AESEncryptor(\"my-password\");\n\n// create an instance of StringFieldEncryptionProcessor using the encryptor\nStringFieldEncryptionProcessor processor = new StringFieldEncryptionProcessor(encryptor);\n\n// add fields to encrypt\nprocessor.addFields(\"field1\", \"field2\");\n\n// use the processor\ncollection.addProcessor(processor);\n\n// use the collection\ncollection.insert(doc);"]}],[{"i":"#","p":["This guide will help you get started with Nitrite database. It will show you how to create a database, create a collection, insert documents, and query documents in Kotlin."]},{"l":"Getting Started in Kotlin","p":["Nitrite's Kotlin SDK is a wrapper around the Java SDK. It provides some Kotlin friendly extensions for some of the Java API to work with Nitrite database. The Kotlin SDK is available as a separate module named potassium-nitrite (KNO2). In this guide, we will discuss the Kotlin specific API only. For rest of the API, please refer to the Java SDK. So it is highly recommended to go through the Java SDK guide first.","To get started with Nitrite database, you need to add the Nitrite BOM to your project. The BOM will help you to manage the dependencies. Details of the BOM can be found here.","To add the BOM to your project, follow the steps below:"]},{"l":"Add dependency","p":["To enable Kotlin support, you need to add the potassium-nitrite library to your project. It will automatically add the nitrite library as a dependency along with nitrite-spatial and nitrite-jackson-mapper libraries."]},{"l":"Maven","p":["Add the nitrite dependency to your pom.xml file:"]},{"i":"maven-code-1","c":["<dependencyManagement>\n    <dependencies>\n        <dependency>\n            <groupId>org.dizitart</groupId>\n            <artifactId>nitrite-bom</artifactId>\n            <version>[latest version]</version>\n            <scope>import</scope>\n            <type>pom</type>\n        </dependency>\n    </dependencies>\n</dependencyManagement>\n\n<dependencies>\n    <dependency>\n        <groupId>org.dizitart</groupId>\n        <artifactId>potassium-nitrite</artifactId>\n    </dependency>\n</dependencies>"]},{"l":"Gradle","p":["Add the nitrite dependency to your build.gradle file:","The latest released version of Nitrite can be found here."]},{"i":"gradle-code-1","c":["dependencies {\n    implementation platform('org.dizitart:nitrite-bom:[latest version]')\n    implementation 'org.dizitart:potassium-nitrite'\n}"]},{"l":"Snapshot builds","p":["Snapshot builds are available from Sonatype.","To use snapshot builds, you need to add the snapshot repository to your pom.xml or build.gradle file:"]},{"i":"maven-1","l":"Maven"},{"i":"maven-1-code-1","c":["<repositories>\n    <repository>\n        <id>sonatype-snapshot</id>\n        <url>https://oss.sonatype.org/content/repositories/snapshots/</url>\n        <releases>\n            <enabled>false</enabled>\n        </releases>\n        <snapshots>\n            <enabled>true</enabled>\n        </snapshots>\n    </repository>\n</repositories>"]},{"i":"gradle-1","l":"Gradle","p":["Nitrite's Kotlin SDK is not as lean as the Java SDK. It has a lot of dependencies. If you are using Kotlin in your project, it is recommended to use the Kotlin SDK. Otherwise, you can use the Java SDK with Kotlin as well."]},{"i":"gradle-1-code-1","c":["repositories {\n    maven {\n        url \"https://oss.sonatype.org/content/repositories/snapshots/\"\n    }\n}"]},{"l":"Upgrade from 3.x","p":["If you are upgrading from 3.x, please note that there are lots of breaking changes in the API. The whole library is re-written from scratch. It is recommended to go through this guide before upgrading.","You need to use the MVStore as your storage module to upgrade from 3.x. The RocksDB module is not backward compatible.","Nitrite will try to migrate your existing database to the latest version on the provided you are using the MVStore module. If you are using the RocksDB module, you need to migrate your database manually. However, it is recommended to take a backup of your database before upgrading."]}],[{"l":"Nitrite Database","p":["Nitrite database is a serverless, embedded, and self-contained Java NoSQL database. It is an open-source project that provides a simple API for persistent data storage. Nitrite database is designed to be lightweight, fast, and easy to use."]},{"l":"Creating a Database","p":["Nitrite database can be created in-memory or on-disk. By default, Nitrite database is created in-memory. To create a database on-disk, you need to add a storage module dependency to your project. More details about storage modules can be found here.","To create a database, you need to use nitrite() function. It is a builder function that returns an instance of Nitrite."]},{"i":"creating-a-database-code-1","c":["var db = nitrite {\n    // database configuration\n}"]},{"l":"In-memory Database","p":["If you don't load any on-disk storage module, then Nitrite will create an in-memory database. The below code snippet shows how to create a database in-memory."]},{"i":"in-memory-database-code-1","c":["var db = nitrite()"]},{"l":"On-disk Database","p":["The below code snippet shows how to create a database on-disk."]},{"l":"MVStore Backed Database","p":["More details about MVStore configuration can be found here."]},{"i":"mvstore-backed-database-code-1","c":["val storeModule = MVStoreModule.withConfig()\n    .filePath(\"/path/to/my.db\")\n    .build()\n\nvar db = nitrite {\n    loadModule(storeModule)\n}"]},{"l":"RocksDB Backed Database","p":["More details about RocksDB configuration can be found here."]},{"i":"rocksdb-backed-database-code-1","c":["val storeModule = RocksDBModule.withConfig()\n    .filePath(\"/path/to/my.db\")\n    .build()\n\nvar db = nitrite {\n    loadModule(storeModule)\n}"]},{"l":"Securing a Database","p":["To secure a database, you need to pass a username and password to the nitrite() function. The below code snippet shows how to secure a database.","If you are using a file-based database, then you need to use the same username and password to open the database again. Otherwise, you will get a NitriteSecurityException.","Both username and password must be provided or both must be null."]},{"i":"securing-a-database-code-1","c":["var db = nitrite(\"user\", \"password\") {\n    // database configuration\n}"]},{"l":"Registering an EntityConverter","p":["Nitrite database uses a mapper to map Kotlin/Java entities to Nitrite documents and vice-versa. By default, Nitrite uses SimpleNitriteMapper as its mapper. This mapper uses EntityConverters to map entities to Nitrite documents and vice-versa. To register an EntityConverter, you need to call registerEntityConverter() method on Builder instance.","More details about EntityConverter can be found here."]},{"i":"registering-an-entityconverter-code-1","c":["var db = nitrite {\n    registerEntityConverter(MyEntityConverter())\n}"]},{"l":"Loading a Nitrite Module","p":["Nitrite database is modular in nature. It provides a set of modules to extend its functionality. To load a module, you need to call loadModule() method on Builder instance.","More details about Nitrite modules can be found here."]},{"i":"loading-a-nitrite-module-code-1","c":["var db = nitrite {\n    loadModule(MyModule())\n}"]},{"l":"Loading a Storage Module","p":["More details about storage modules can be found here."]},{"i":"loading-a-storage-module-code-1","c":["var db = nitrite {\n    loadModule(MVStoreModule.withConfig()\n        .filePath(\"/path/to/my.db\")\n        .build())\n}"]},{"l":"Adding Migration Steps","p":["Nitrite database supports migration from one version to another. To add a migration step, you need to call addMigration() method on Builder instance.","More details about schema migration can be found here."]},{"i":"adding-migration-steps-code-1","c":["var db = nitrite {\n    addMigration(object : Migration(Constants.INITIAL_SCHEMA_VERSION, 2) {\n        override fun migrate(instruction: InstructionSet) {\n            instruction.forDatabase()\n                .dropCollection(\"test\")\n        }\n    })\n    loadModule(MVStoreModule(fileName))\n    schemaVersion = 2\n}"]},{"l":"Current Schema Version","p":["To configure the current schema version, you need to set the schemaVersion property on Builder instance.","By default, the initial schema version is set to 1."]},{"i":"current-schema-version-code-1","c":["var db = nitrite {\n    schemaVersion = 2\n}"]},{"l":"Field Separator Character","p":["Nitrite database uses . as the field separator character. It is used to separate nested fields in a document. For example, if you have a document like below:","Then you can access the firstName field like below:","And you can access the street field like below:","To configure the field separator character, you need to set the fieldSeparator property on Builder instance.","By default, the field separator character is set to .."]},{"i":"field-separator-character-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"address\": {\n        \"street\": \"123 Main Street\",\n        \"city\": \"New York\",\n        \"state\": \"NY\",\n        \"zip\": \"10001\"\n    }\n}"]},{"i":"field-separator-character-code-2","c":["val firstName = document[\"firstName\"]"]},{"i":"field-separator-character-code-3","c":["val street = document[\"address.street\"]"]},{"i":"field-separator-character-code-4","c":["var db = nitrite {\n    fieldSeparator = '.'\n}"]},{"l":"Disable Repository Type Validation","p":["Nitrite database has a feature called repository type validation. It ensures the type of the objects stored in the repository can be converted to and from the document. By default, the repository type validation is enabled. If you disable it, and if you try to store an object that cannot be converted to a document, Nitrite will throw an exception during the operation.","To disable repository type validation, you need to set the enableRepositoryValidation property to false on Builder instance."]},{"i":"disable-repository-type-validation-code-1","c":["var db = nitrite {\n    enableRepositoryValidation = false\n}"]}],[{"l":"Document","p":["Document is the basic unit of data in Nitrite database. It is a JSON like field-value pairs. The field is always a String and value can be anything including null. Document is schema-less, which means you can store any kind of data in a document.","Nitrite document supports nested document. That means, a value of a field can be another document. This allows you to create complex data structure.","More details on document can be found here."]},{"l":"Kotlin API for Document","p":["Potassium Nitrite provides a set of extension functions to make document manipulation easier."]},{"l":"Create a Document","p":["To create a document, you can use the documentOf function. It takes a vararg of PairString, Any? and returns a Document.","To create a nested document, you can use the documentOf function recursively.","To create an empty document, you can use the emptyDocument function."]},{"i":"create-a-document-code-1","c":["val document = documentOf(\"firstName\" to \"John\", \"lastName\" to \"Doe\")"]},{"i":"create-a-document-code-2","c":["val document = documentOf(\n    \"firstName\" to \"John\",\n    \"lastName\" to \"Doe\",\n    \"address\" to documentOf(\n        \"street\" to \"123 Main Street\",\n        \"city\" to \"New York\",\n        \"state\" to \"NY\",\n        \"zip\" to \"10001\"\n    ),\n    \"phone\" to listOf(\"212-555-1234\", \"646-555-4567\")\n)"]},{"i":"create-a-document-code-3","c":["val document = emptyDocument()"]},{"l":"Get a Field Value","p":["To get a field value from a document, you can use the index operator [] on the document. It takes a String as the field name and returns the value of the field."]},{"i":"get-a-field-value-code-1","c":["val firstName = document[\"firstName\"]"]},{"l":"Checking If a Document is Empty","p":["To check if a document is empty, you can use the isEmpty function. It takes no argument and returns a Boolean.","Conversely, to check if a document is not empty, you can use the isNotEmpty function. It takes no argument and returns a Boolean."]},{"i":"checking-if-a-document-is-empty-code-1","c":["val isEmpty = document.isEmpty()"]},{"i":"checking-if-a-document-is-empty-code-2","c":["val isNotEmpty = document.isNotEmpty()"]}],[{"l":"Nitrite Collection","p":["NitriteCollection represents a named document collection stored in a Nitrite database. It persists documents in a Nitrite database. It is similar to a table in relational database or a collection in MongoDB.","More details on collection can be found here."]},{"l":"Kotlin API for NitriteCollection","p":["Potassium Nitrite provides a higher-order function to make collection manipulation easier."]},{"i":"kotlin-api-for-nitritecollection-code-1","c":["db.getCollection(\"myCollection\") {\n    // do something with collection\n    insert(documentOf(\"firstName\" to \"John\", \"lastName\" to \"Doe\"))\n    createIndex(\"firstName\")\n}"]}],[{"l":"Object Repository","p":["ObjectRepository provides a simple and type-safe API for storing and retrieving Kotlin/Java objects in a Nitrite database. It is built on top of NitriteCollection and provides a similar API for CRUD operations. It also supports indexing and querying. It also supports event based notification on object changes.","More details on repository can be found here."]},{"l":"Kotlin API for ObjectRepository","p":["Potassium Nitrite provides some higher-order functions to make repository manipulation easier."]},{"l":"Creating a Repository with Class Type","p":["You can create a ObjectRepository by passing a class type to getRepository() method."]},{"i":"creating-a-repository-with-class-type-code-1","c":["val repository = db.getRepository<Employee>() {\n    // do something with repository\n    insert(Employee(\"John\", \"Doe\"))\n    createIndex(\"firstName\")\n}"]},{"l":"Creating a Repository with Class Type and Key","p":["You can create a keyed ObjectRepository by passing a class type and a key to getRepository() method.","One typical use case of this keyed repository is to create a repository for each user in a multi-user application. The key can be the user name or user id. This will ensure that each user will have a separate repository for storing objects."]},{"i":"creating-a-repository-with-class-type-and-key-code-1","c":["val repository = db.getRepository<Employee>(\"myKey\") {\n    // do something with repository\n    insert(Employee(\"John\", \"Doe\"))\n    createIndex(\"firstName\")\n}"]},{"l":"Creating a Repository with EntityDecorator","p":["A ObjectRepository can be created using EntityDecorator. This is useful when you cannot modify the object class to add annotations.","More details about EntityDecorator can be found here."]},{"i":"creating-a-repository-with-entitydecorator-code-1","c":["val repository = db.getRepository(EmployeeDecorator()) {\n    // do something with repository\n    insert(Employee(\"John\", \"Doe\"))\n    createIndex(\"firstName\")\n}"]},{"l":"Creating a Repository with EntityDecorator and Key","p":["A keyed ObjectRepository can be created using EntityDecorator and a key. This is useful when you cannot modify the object class to add annotations.","More details about EntityDecorator can be found here."]},{"i":"creating-a-repository-with-entitydecorator-and-key-code-1","c":["val repository = db.getRepository(EmployeeDecorator(), \"myKey\") {\n    // do something with repository\n    insert(Employee(\"John\", \"Doe\"))\n    createIndex(\"firstName\")\n}"]},{"l":"NitriteMapper","p":["Nitrite provides a mapper interface called NitriteMapper. It is used to map Java objects to Nitrite documents and vice-versa. More details on NitriteMapper can be found here.","Apart from the SimpleNitriteMapper, Potassium Nitrite also provides two additional mappers:","KNO2JacksonMapper","KotlinXSerializationMapper"]},{"l":"Jackson Mapper","p":["Potassium Nitrite extends the JacksonMapper to provide KNO2JacksonMapper. This class overrides the getObjectMapper() method to register some Kotlin specific Jackson modules as follows:","KotlinModule","JavaTimeModule","Jdk8Module","GeometryModule","It also disables the SerializationFeature.WRITE_DATES_AS_TIMESTAMPS feature. The constructor of KNO2JacksonMapper takes a vararg of com.fasterxml.jackson.databind.Module to register additional Jackson modules.","To use the KNO2JacksonMapper instead of the default SimpleNitriteMapper you need to load it while opening the database."]},{"i":"jackson-mapper-code-1","c":["val db = nitrite {\n    loadModule(module(KNO2JacksonMapper()))\n}"]},{"l":"KotlinX Serialization Mapper","p":["Potassium Nitrite also provides a KotlinX Serialization based mapper called KotlinXSerializationMapper. KotlinX Serialization is used to convert Java/Kotlin objects to Document and vice-versa.","To use the KotlinXSerializationMapper instead of the default SimpleNitriteMapper you need to load it while opening the database."]},{"i":"kotlinx-serialization-mapper-code-1","c":["val db = nitrite {\n    loadModule(module(KotlinXSerializationMapper()))\n}"]}],[{"l":"Filters","p":["Filters are used to specify the criteria used to select documents from a collection or repository. It provides a way to specify conditions that the documents must meet to be included in the result set. Filters are used in conjunction with the find method. The find method returns all documents in a collection that match the specified filtering criteria.","More details on filters can be found here."]},{"l":"Kotlin API for Filters","p":["Potassium Nitrite provides a set of infix functions to make filter usage more like operators. It also provides a set of extension functions for KProperty so that you can use property name instead of string in case of entity class."]},{"l":"Comparison Operators","p":["Comparison operators are used to compare two expressions. More details on comparison operators can be found here."]},{"l":"Equal To","p":["To check if a field value is equal to a value, you can use the eq function.","Similarly, you can use the eq function with KProperty.","More details on eq function can be found here."]},{"i":"equal-to-code-1","c":["val filter = (\"firstName\" eq \"John\")"]},{"i":"equal-to-code-2","c":["val filter = (Employee::firstName eq \"John\")"]},{"l":"Not Equal To","p":["To check if a field value is not equal to a value, you can use the notEq function.","Similarly, you can use the notEq function with KProperty.","More details on notEq function can be found here."]},{"i":"not-equal-to-code-1","c":["val filter = (\"firstName\" notEq \"John\")"]},{"i":"not-equal-to-code-2","c":["val filter = (Employee::firstName notEq \"John\")"]},{"l":"Greater Than","p":["To check if a field value is greater than a value, you can use the gt function.","Similarly, you can use the gt function with KProperty.","More details on gt function can be found here."]},{"i":"greater-than-code-1","c":["val filter = (\"age\" gt 18)"]},{"i":"greater-than-code-2","c":["val filter = (Employee::age gt 18)"]},{"l":"Greater Than or Equal To","p":["To check if a field value is greater than or equal to a value, you can use the gte function.","Similarly, you can use the gte function with KProperty.","More details on gte function can be found here."]},{"i":"greater-than-or-equal-to-code-1","c":["val filter = (\"age\" gte 18)"]},{"i":"greater-than-or-equal-to-code-2","c":["val filter = (Employee::age gte 18)"]},{"l":"Less Than","p":["To check if a field value is less than a value, you can use the lt function.","Similarly, you can use the lt function with KProperty.","More details on lt function can be found here."]},{"i":"less-than-code-1","c":["val filter = (\"age\" lt 18)"]},{"i":"less-than-code-2","c":["val filter = (Employee::age lt 18)"]},{"l":"Less Than or Equal To","p":["To check if a field value is less than or equal to a value, you can use the lte function.","Similarly, you can use the lte function with KProperty.","More details on lte function can be found here."]},{"i":"less-than-or-equal-to-code-1","c":["val filter = (\"age\" lte 18)"]},{"i":"less-than-or-equal-to-code-2","c":["val filter = (Employee::age lte 18)"]},{"l":"Within","p":["To check if a field value is in a list of values, you can use the within function.","Similarly, you can use the within function with KProperty.","You can also use it with range.","More details on within function can be found here."]},{"i":"within-code-1","c":["val filter = (\"firstName\" within arrayOf(\"John\", \"Jane\"))"]},{"i":"within-code-2","c":["val filter = (Employee::firstName within listOf(\"John\", \"Jane\"))"]},{"i":"within-code-3","c":["val filter = (\"age\" within (18..65))"]},{"l":"Not Within","p":["To check if a field value is not in a list of values, you can use the notWithin function.","Similarly, you can use the notWithin function with KProperty.","You can also use it with range.","More details on notWithin function can be found here."]},{"i":"not-within-code-1","c":["val filter = (\"firstName\" notWithin arrayOf(\"John\", \"Jane\"))"]},{"i":"not-within-code-2","c":["val filter = (Employee::firstName notWithin listOf(\"John\", \"Jane\"))"]},{"i":"not-within-code-3","c":["val filter = (\"age\" notWithin (18..65))"]},{"l":"Between","p":["To check if a field value is between two values, you can use the between function. More details on between function can be found here."]},{"i":"between-code-1","c":["val filter = (\"age\".between(18, 65))\n\n// or\nval filter = (\"age\".between (18, 65, true, true))"]},{"l":"Logical Filters","p":["Logical operators are used to combine two or more expressions. More details on logical operators can be found here."]},{"l":"And","p":["To combine two or more expressions with AND operator, you can use the and function.","Similarly, you can use the and function with KProperty.","More details on and function can be found here."]},{"i":"and-code-1","c":["val filter = ((\"firstName\" eq \"John\") and (\"lastName\" eq \"Doe\"))"]},{"i":"and-code-2","c":["val filter = ((Employee::firstName eq \"John\") and (Employee::lastName eq \"Doe\"))"]},{"l":"Or","p":["To combine two or more expressions with OR operator, you can use the or function.","Similarly, you can use the or function with KProperty.","More details on or function can be found here."]},{"i":"or-code-1","c":["val filter = ((\"firstName\" eq \"John\") or (\"lastName\" eq \"Doe\"))"]},{"i":"or-code-2","c":["val filter = ((Employee::firstName eq \"John\") or (Employee::lastName eq \"Doe\"))"]},{"l":"Array Filters","p":["Array filters are used to match documents based on the values in an array field. More details on array filters can be found here."]},{"l":"Element Match","p":["To check if an array field contains at least one element that matches the specified filter, you can use the elemMatch function.","Similarly, you can use the elemMatch function with KProperty.","More details on elemMatch function can be found here."]},{"i":"element-match-code-1","c":["val filter = (\"phone\" elemMatch (\"$\" eq \"212-555-1234\"))"]},{"i":"element-match-code-2","c":["val filter = (Employee::phone elemMatch (\"$\" eq \"212-555-1234\"))"]},{"l":"Evaluation Filters","p":["Evaluation filters are used to match documents based on evaluating the value of any field in a document. More details on evaluation filters can be found here."]},{"l":"Regex","p":["To check if a field value matches a regular expression, you can use the regex function.","Similarly, you can use the regex function with KProperty.","More details on regex function can be found here."]},{"i":"regex-code-1","c":["val filter = (\"firstName\" regex \"^J.*\")"]},{"i":"regex-code-2","c":["val filter = (Employee::firstName regex \"^J.*\")"]},{"l":"Text","p":["The text filter is used to match documents which contain a specified full-text search expression.","Similarly, you can use the text function with KProperty.","More details on text function can be found here."]},{"i":"text-code-1","c":["val filter = (\"notes\" text \"John*\")"]},{"i":"text-code-2","c":["val filter = (Employee::notes text \"John*\")"]},{"l":"Spatial Filters","p":["Spatial filters are used to match documents based on their geometric shape. More details on spatial filters can be found here."]},{"l":"Near","p":["To check if a field value is near to a point, you can use the near function.","Similarly, you can use the near function with KProperty.","More details on near function can be found here."]},{"i":"near-code-1","c":["val filter = (\"location\".near(reader.read(\"POINT (490 490)\") as Point, 20.0))"]},{"i":"near-code-2","c":["val filter = (Employee::location.near(reader.read(\"POINT (490 490)\") as Point, 20.0))"]},{"i":"within-1","l":"Within","p":["To check if a field value is within a specified shape, you can use the within function.","Similarly, you can use the within function with KProperty.","More details on within function can be found here."]},{"i":"within-1-code-1","c":["val filter = (\"location\" within reader.read(\"POLYGON ((0 0, 0 1000, 1000 1000, 1000 0, 0 0))\") as Polygon)"]},{"i":"within-1-code-2","c":["val filter = (Employee::location within reader.read(\"POLYGON ((0 0, 0 1000, 1000 1000, 1000 0, 0 0))\") as Polygon)"]},{"l":"Intersects","p":["The intersects filter is used to match documents where the value of the spatial field intersects the specified shape.","Similarly, you can use the intersects function with KProperty.","More details on intersects function can be found here."]},{"i":"intersects-code-1","c":["val filter = (\"location\" intersects reader.read(\"POLYGON ((0 0, 0 1000, 1000 1000, 1000 0, 0 0))\") as Polygon)"]},{"i":"intersects-code-2","c":["val filter = (Employee::location intersects reader.read(\"POLYGON ((0 0, 0 1000, 1000 1000, 1000 0, 0 0))\") as Polygon)"]}],[{"l":"Transaction","p":["Nitrite supports transactional operations on its collections and repositories. A transaction can be committed or rolled back. Once a transaction is committed, all the changes are persisted to the disk. If a transaction is rolled back, all the changes are discarded.","More information about Nitrite transactions can be found here."]},{"l":"Kotlin API for Transaction","p":["Potassium Nitrite provides a set of builder functions for Session and Transaction to make transaction usage more like natural to Kotlin."]},{"l":"Session","p":["A session represents a transactional context for a Nitrite database. Session is used to create a new transaction. More details on session can be found here."]},{"l":"Kotlin API for Session","p":["To create a new session, you can use the session() extension function on Nitrite.","Session will be automatically closed once the block is executed."]},{"i":"kotlin-api-for-session-code-1","c":["val session = db.session {\n    // perform transactional operations\n}"]},{"i":"transaction-1","l":"Transaction","p":["A transaction is a single logical unit of work which accesses and possibly modifies the contents of a database. Transactions access data using read and write operations. More details on transaction can be found here."]},{"i":"kotlin-api-for-transaction-1","l":"Kotlin API for Transaction","p":["To start a transaction, you can use the tx() extension function on Session.","Transaction will be automatically closed once the block is executed."]},{"i":"kotlin-api-for-transaction-1-code-1","c":["db.session {\n    tx {\n        // perform transactional operations\n        val collection = getCollection(\"test\")\n        collection.insert(doc1)\n\n        // commit the transaction\n        commit()\n    }\n}"]}],[{"l":"Potassium Nitrite Module","p":["Nitrite is a modular database engine, so is Potassium Nitrite. All Nitrite modules are compatible with Potassium Nitrite as well. More details about Nitrite modules can be found here.","Potassium Nitrite provides a single module KNO2Module to load all plugins it provides. You can load the module while opening the database.","This module loads the following plugins:","KNO2JacksonMapper - A Jackson based mapper for Potassium Nitrite.","SpatialIndexer - A spatial index plugin for Nitrite.","Visit the respective pages to know more about the plugins."]},{"i":"potassium-nitrite-module-code-1","c":["val db = nitrite {\n    loadModule(KNO2Module())\n}"]}],[{"i":"#","p":["This guide walks through the Rust Nitrite crates, opening a database, working with collections, and creating typed repositories."]},{"l":"Getting Started in Rust","p":["Nitrite for Rust is organized as a small crate ecosystem. The core nitrite crate provides collections, repositories, indexes, filters, transactions, and migrations. Companion crates add derive macros, persistent storage, spatial indexing, and full-text search."]},{"l":"Add dependencies","p":["The core setup is the nitrite crate plus nitrite-derive if you want typed repositories.","Nitrite's published crates currently use Rust edition 2021. Optional capabilities are split into separate crates:","Use only the crates you need:","nitrite for the core document database API.","nitrite-derive for Convertible and NitriteEntity derive macros.","nitrite-fjall-adapter for persistent Fjall-backed storage.","nitrite-spatial for spatial indexes and geospatial filters.","nitrite-tantivy-fts for Tantivy-backed full-text search."]},{"i":"add-dependencies-code-1","c":["[dependencies]\nnitrite = \"0.4\"\nnitrite-derive = \"0.4\""]},{"i":"add-dependencies-code-2","c":["[dependencies]\nnitrite = \"0.4\"\nnitrite-derive = \"0.4\"\nnitrite-fjall-adapter = \"0.4\"\nnitrite-spatial = \"0.4\"\nnitrite-tantivy-fts = \"0.4\""]},{"l":"Open a database","p":["If you do not load a storage module, Nitrite starts with the built-in in-memory store.","The builder entry point is Nitrite::builder(). The returned NitriteBuilder lets you configure:","a custom field separator for nested document paths","the target schema version","migrations","additional modules such as Fjall, spatial indexing, or full-text search"]},{"i":"open-a-database-code-1","c":["use nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Work with a collection","p":["Collections store schemaless Document values. The doc! macro is the shortest way to build them.","Collections are the best fit when:","the document shape is flexible or evolves frequently","you want to work directly with Document values","you are building tooling, migrations, or mixed-schema ingestion flows"]},{"i":"work-with-a-collection-code-1","c":["use nitrite::doc;\nuse nitrite::filter::field;\nuse nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");\n\nlet collection = db.collection(\"users\").expect(\"missing collection\");\n\ncollection.insert(doc! {\n    \"name\": \"John Doe\",\n    \"age\": 30,\n    \"active\": true\n}).expect(\"insert failed\");\n\nlet mut cursor = collection\n    .find(field(\"name\").eq(\"John Doe\"))\n    .expect(\"query failed\");\n\nif let Some(Ok(document)) = cursor.first() {\n    println!(\"matched document: {:?}\", document);\n}"]},{"l":"Work with a typed repository","p":["Repositories wrap a backing collection and map documents to Rust types. A repository type must implement both Convertible and NitriteEntity. In practice that usually means deriving both macros and providing an entity ID.","Use a repository when:","you want compile-time type safety around stored entities","your domain type has a stable identifier and index definition","you want projection, joins, or keyed repositories for a typed model"]},{"i":"work-with-a-typed-repository-code-1","c":["use nitrite::filter::field;\nuse nitrite::nitrite::Nitrite;\nuse nitrite::repository::ObjectRepository;\nuse nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(id(field = \"id\"))]\nstruct User {\n    id: i64,\n    name: String,\n    email: String,\n}\n\nlet db = Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");\n\nlet repo: ObjectRepository<User> = db.repository().expect(\"repository open failed\");\n\nrepo.insert(User {\n    id: 1,\n    name: \"Alice\".to_string(),\n    email: \"alice@example.com\".to_string(),\n}).expect(\"insert failed\");\n\nlet user = repo.get_by_id(&1).expect(\"read failed\");\nlet mut users = repo.find(field(\"name\").eq(\"Alice\")).expect(\"query failed\");\n\nif let Some(Ok(found)) = users.first() {\n    println!(\"found user: {}\", found.email);\n}\n\nassert!(user.is_some());"]},{"l":"Add persistence or optional modules","p":["The core crate loads an in-memory store automatically. File-based persistence and advanced indexes are added as modules.","Spatial and full-text modules are loaded through the same builder API. See Module System, Storage Modules, Spatial Module, and Full-Text Search."]},{"i":"add-persistence-or-optional-modules-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_fjall_adapter::FjallModule;\n\nlet storage = FjallModule::with_config()\n    .db_path(\"./data/nitrite\")\n    .build();\n\nlet db = Nitrite::builder()\n    .load_module(storage)\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Next steps","p":["Use Nitrite Database for builder options, database lifecycle, and persistence choices.","Use Document for document structure, nested fields, and reserved fields.","Use Nitrite Collection for schemaless collection operations.","Use Object Repository for entity mapping and typed CRUD.","Use Transaction and Schema Migration when you need coordinated writes and controlled schema evolution."]}],[{"l":"Nitrite Database","p":["Nitrite is an embedded, serverless database. In the Rust SDK, the database handle is the Nitrite type and the entry point for configuration is Nitrite::builder()."]},{"l":"Creating a database"},{"l":"In-memory database","p":["If you do not register a store module, Nitrite auto-loads its built-in in-memory store.","This mode is useful for tests, short-lived tools, and workloads where persistence is not required."]},{"i":"in-memory-database-code-1","c":["use nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Fjall-backed database","p":["Persistent storage is currently provided through the nitrite-fjall-adapter crate.","More on the persistent store options is available in Storage Modules and Fjall Module."]},{"i":"fjall-backed-database-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_fjall_adapter::FjallModule;\n\nlet storage = FjallModule::with_config()\n    .db_path(\"./data/nitrite\")\n    .build();\n\nlet db = Nitrite::builder()\n    .load_module(storage)\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"NitriteBuilder","p":["NitriteBuilder is the Rust SDK's configuration surface. It lets you build a database instance incrementally and applies validation when open_or_create() is called."]},{"l":"Open or create","p":["open_or_create(username, password) accepts optional credentials.","The credential rules are strict:","either provide both username and password","or provide neither","if credentials are provided and the database has no users yet, Nitrite creates the first user during authentication"]},{"i":"open-or-create-code-1","c":["use nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .open_or_create(Some(\"app-user\"), Some(\"secret-passphrase\"))\n    .expect(\"failed to open database\");"]},{"l":"Field separator","p":["Nested document paths use . by default. You can change that with field_separator().","This affects document field addressing for operations such as Document::get() and filter paths. See Document for nested field examples."]},{"i":"field-separator-code-1","c":["use nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .field_separator(\"::\")\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Loading modules","p":["Modules extend the core engine with store implementations and specialized indexers."]},{"i":"loading-modules-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_fjall_adapter::FjallModule;\nuse nitrite_spatial::SpatialModule;\n\nlet db = Nitrite::builder()\n    .load_module(\n        FjallModule::with_config()\n            .db_path(\"./data/nitrite\")\n            .build(),\n    )\n    .load_module(SpatialModule)\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Schema version and migrations","p":["The builder tracks a schema version and accepts registered migrations.","See Schema Migration for the available database, collection, and repository instruction builders."]},{"i":"schema-version-and-migrations-code-1","c":["use nitrite::common::Value;\nuse nitrite::migration::Migration;\nuse nitrite::nitrite::Nitrite;\n\nlet migration = Migration::new(1, 2, |instruction| {\n    instruction\n        .for_collection(\"users\")\n        .add_field(\"status\", Some(Value::String(\"active\".to_string())), None)\n        .create_index(\"NON_UNIQUE\", &[\"status\"]);\n    Ok(())\n});\n\nlet db = Nitrite::builder()\n    .schema_version(2)\n    .add_migration(migration)\n    .open_or_create(None, None)\n    .expect(\"failed to open migrated database\");"]},{"l":"Working with database handles","p":["Once the database is open, the Nitrite handle is the main gateway to collections and repositories.","Useful database-level operations include:","collection(name) to get or create a named document collection","repository::T() and keyed_repository::T(key) for typed access","has_collection(name), has_repository::T(), and has_keyed_repository::T(key) for discovery","destroy_collection(name), destroy_repository::T(), and destroy_keyed_repository::T(key) for cleanup","commit() to flush pending changes to the underlying store","close() to shut the database down cleanly and flush module-managed buffered work such as Tantivy FTS batches","On the current 0.4 line, a clean close() is also what drains a Fjall-backed database to a consistent reopen point, so prefer closing explicitly instead of relying on process teardown.","In the repository examples above, User is any type that implements Default, Convertible, and NitriteEntity."]},{"i":"working-with-database-handles-code-1","c":["use nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");\n\nlet collection = db.collection(\"users\").expect(\"collection open failed\");\nlet repo = db.repository::<User>().expect(\"repository open failed\");\nlet keyed = db.keyed_repository::<User>(\"tenant-a\").expect(\"keyed repository open failed\");\n\ndb.commit().expect(\"commit failed\");\ndb.close().expect(\"close failed\");"]}],[{"l":"Document","p":["Document is Nitrite's schemaless record type. It stores string keys and Value entries, supports nested documents and arrays, and uses a lock-free persistent map internally so cloning is cheap."]},{"l":"Create documents","p":["You can create a document explicitly with Document::new() or use the doc! macro for inline literals."]},{"i":"create-documents-code-1","c":["use nitrite::collection::Document;\nuse nitrite::doc;\n\nlet mut manual = Document::new();\nmanual.put(\"name\", \"Alice\").expect(\"put failed\");\nmanual.put(\"age\", 30_i64).expect(\"put failed\");\n\nlet inline = doc! {\n    \"name\": \"Bob\",\n    \"age\": 28,\n    \"active\": true\n};"]},{"l":"Nested fields and arrays","p":["By default, Nitrite uses . as the nested field separator. That means address.city targets the city field inside an embedded address document.","If a field does not exist, get() returns Value::Null instead of failing.","If you configure a different separator through NitriteBuilder::field_separator(), the same rule applies with the new delimiter."]},{"i":"nested-fields-and-arrays-code-1","c":["use nitrite::common::Value;\nuse nitrite::doc;\n\nlet document = doc! {\n    \"name\": \"Warehouse A\",\n    \"address\": {\n        \"city\": \"Berlin\",\n        \"zip\": 10115\n    },\n    \"tags\": [\"inventory\", \"primary\"]\n};\n\nassert_eq!(\n    document.get(\"address.city\").expect(\"lookup failed\"),\n    Value::String(\"Berlin\".to_string())\n);\nassert_eq!(\n    document.get(\"tags.0\").expect(\"lookup failed\"),\n    Value::String(\"inventory\".to_string())\n);"]},{"i":"nested-fields-and-arrays-code-2","c":["use nitrite::common::Value;\nuse nitrite::doc;\n\nlet document = doc! { \"name\": \"Alice\" };\nlet missing = document.get(\"profile.timezone\").expect(\"lookup failed\");\n\nassert!(matches!(missing, Value::Null));"]},{"l":"Updating fields","p":["put() inserts a new value or overwrites an existing one.","This is the same document shape that collection updates consume."]},{"i":"updating-fields-code-1","c":["use nitrite::collection::Document;\n\nlet mut document = Document::new();\ndocument.put(\"status\", \"draft\").expect(\"put failed\");\ndocument.put(\"status\", \"published\").expect(\"put failed\");\ndocument.put(\"author.name\", \"Nitrite Team\").expect(\"put failed\");"]},{"l":"Reserved fields","p":["Nitrite manages a small set of reserved metadata fields on every stored document:","_id","_revision","_source","_modified","The _id field is special. It is a NitriteId and is generated automatically when needed.","You cannot assign _id to an arbitrary non-NitriteId value through put()."]},{"i":"reserved-fields-code-1","c":["use nitrite::doc;\n\nlet mut document = doc! { \"name\": \"Alice\" };\nlet id = document.id().expect(\"id generation failed\");\n\nprintln!(\"document id: {}\", id);"]},{"l":"Iteration and conversion","p":["Documents can be iterated key by key, passed through processors, and converted to Value::Document for repository mapping. In most collection code you will work with them directly, while typed repositories use the same document representation behind the scenes.","If you need compile-time mapping instead of raw document access, move to Object Repository."]}],[{"l":"Introduction","p":["A NitriteCollection stores schemaless Document values under a logical name. Collections are the most direct way to use Nitrite: you work with documents, filters, indexes, processors, and events without adding an entity layer."]},{"l":"Get or create a collection","p":["Nitrite::collection(name) returns a named collection and creates it if it does not already exist.","Collection names must be valid and cannot collide with repository-backed collection names."]},{"i":"get-or-create-a-collection-code-1","c":["use nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");\n\nlet collection = db.collection(\"users\").expect(\"collection open failed\");"]},{"l":"What collections are good at","p":["Collections are a good fit when:","the stored shape is flexible","you are ingesting heterogeneous records","you want to work with Document directly","you are writing utilities, scripts, or migrations where a typed entity model adds little value","If your domain model is stable and strongly typed, use Object Repository instead."]},{"l":"Documents, IDs, and metadata","p":["Every collection stores Document values. Nitrite manages a few reserved fields automatically, including the internal _id field, revision metadata, and modification timestamps.","The inserted document receives a NitriteId if it did not already have one."]},{"i":"documents-ids-and-metadata-code-1","c":["use nitrite::doc;\n\nlet collection = db.collection(\"users\").expect(\"collection open failed\");\ncollection.insert(doc! {\n    \"name\": \"Alice\",\n    \"email\": \"alice@example.com\"\n}).expect(\"insert failed\");"]},{"l":"Core collection capabilities","p":["NitriteCollection combines two kinds of behavior:","document CRUD through methods such as insert, update, remove, find, and get_by_id","persistent-collection capabilities such as indexing, processors, attributes, and event subscriptions","The remaining pages in this section cover those capabilities in detail:","Read Operations","Write Operations","Indexing","Other Operations"]}],[{"l":"Write Operations","p":["Collections support inserts, batch inserts, document updates, and removals. All write operations return a WriteResult containing the affected NitriteId values."]},{"l":"Insert documents","p":["Use insert() for a single document and insert_many() for a batch."]},{"i":"insert-documents-code-1","c":["use nitrite::doc;\n\nlet collection = db.collection(\"users\").expect(\"collection open failed\");\n\ncollection.insert(doc! {\n    \"name\": \"Alice\",\n    \"email\": \"alice@example.com\"\n}).expect(\"insert failed\");\n\ncollection.insert_many(vec![\n    doc! { \"name\": \"Bob\" },\n    doc! { \"name\": \"Carol\" },\n]).expect(\"batch insert failed\");"]},{"l":"Update matching documents","p":["Use update() for the default behavior or update_with_options() for more control.","UpdateOptions controls two behaviors:","insert_if_absent to insert a new document when no match exists","just_once to stop after the first matching document","The helper constructors are insert_if_absent() and just_once()."]},{"i":"update-matching-documents-code-1","c":["use nitrite::collection::just_once;\nuse nitrite::doc;\nuse nitrite::filter::field;\n\nlet patch = doc! { \"status\": \"inactive\" };\nlet options = just_once();\n\ncollection.update_with_options(\n    field(\"email\").eq(\"alice@example.com\"),\n    &patch,\n    &options,\n).expect(\"update failed\");"]},{"l":"Update one document by identity or ID","p":["If you already have the full document, update_one() uses the document's _id. If you already know the NitriteId, update_by_id() is the most direct update path.","update_by_id() is an O(1) lookup by internal identifier and is the most efficient update route when you already have the ID."]},{"i":"update-one-document-by-identity-or-id-code-1","c":["let mut document = collection\n    .find(nitrite::filter::field(\"name\").eq(\"Alice\"))\n    .expect(\"query failed\")\n    .first()\n    .transpose()\n    .expect(\"cursor failed\")\n    .expect(\"document missing\");\n\nlet id = document.id().expect(\"missing id\");\ndocument.put(\"status\", \"active\").expect(\"put failed\");\n\ncollection.update_by_id(&id, &document, false).expect(\"update by id failed\");"]},{"l":"Remove documents","p":["Collections support both filtered removal and single-document removal.","The just_once flag on remove() behaves the same way as it does for updates: true removes the first match only."]},{"i":"remove-documents-code-1","c":["use nitrite::filter::field;\n\ncollection.remove(field(\"status\").eq(\"inactive\"), false)\n    .expect(\"remove failed\");\n\ncollection.remove_one(&document).expect(\"remove one failed\");"]},{"l":"Practical write patterns","p":["Two common collection write patterns are:","use find(...).iter_with_id() and then update_by_id() when you need efficient bulk rewrites","use update_with_options(..., insert_if_absent()) when you want collection-level upsert behavior","If you want write operations against strongly typed entities instead of raw documents, move to Object Repository write operations."]}],[{"l":"Read Operations","p":["Collections return DocumentCursor values for query results. In the current 0.4 line, the common find() cursor is streaming: it yields documents lazily and reset() rebuilds the query instead of replaying a cached snapshot. For a stable collection the observable results are the same; if the underlying data changes before reset(), the cursor reflects the current state."]},{"l":"Query with filters","p":["Use find(filter) for the common case.","To scan everything, use nitrite::filter::all()."]},{"i":"query-with-filters-code-1","c":["use nitrite::filter::field;\n\nlet collection = db.collection(\"users\").expect(\"collection open failed\");\nlet mut cursor = collection\n    .find(field(\"active\").eq(true))\n    .expect(\"query failed\");\n\nif let Some(Ok(document)) = cursor.first() {\n    println!(\"first active user: {:?}\", document);\n}"]},{"l":"Sorting, pagination, and distinct queries","p":["find_with_options() accepts a FindOptions value.","When a query is fully covered by an index, size() can answer from the index metadata without materializing every matching document. Indexed bounded range filters also use bounded scans in the current 0.4 line, so narrow range queries stay narrow instead of scanning from one side and post-filtering.","Sorting is correct for both directions and is independent of whether an index covers the query. SortOrder::Ascending and SortOrder::Descending apply to the field you sort on — including descending sorts over an indexed field, which is the common \"newest first\" pattern (for example order_by(received_at, SortOrder::Descending)). Numeric sorts order by value, so negative and large integers sort correctly.","There are also convenience constructors:","order_by(field, sort_order)","skip_by(count)","limit_to(count)","distinct()"]},{"i":"sorting-pagination-and-distinct-queries-code-1","c":["use nitrite::collection::FindOptions;\nuse nitrite::common::SortOrder;\nuse nitrite::filter::field;\n\nlet options = FindOptions::new()\n    .sort_by(\"age\".to_string(), SortOrder::Descending)\n    .skip(10)\n    .limit(20);\n\nlet mut cursor = collection\n    .find_with_options(field(\"active\").eq(true), &options)\n    .expect(\"query failed\");\n\nprintln!(\"page size: {}\", cursor.size());"]},{"l":"Read by internal ID","p":["If you already have a NitriteId, get_by_id() is the most direct path.","This is an O(1) lookup against the document's internal identifier."]},{"i":"read-by-internal-id-code-1","c":["let maybe_document = collection.get_by_id(&id).expect(\"lookup failed\");"]},{"l":"Cursor helpers","p":["DocumentCursor exposes a few helpers that are useful in tooling and update flows:","first() to fetch the first matching document","size() to count the result set, with a fast path for fully index-covered queries","reset() to restart iteration; streaming cursors rerun the query, while rewindable cursors replay cached rows","iter_with_id() to stream (NitriteId, Document) pairs","iter_with_id() is especially useful when you plan to feed the IDs into update_by_id() later."]},{"i":"cursor-helpers-code-1","c":["let mut cursor = collection.find(nitrite::filter::all()).expect(\"query failed\");\n\nfor row in cursor.iter_with_id() {\n    let (id, document) = row.expect(\"cursor row failed\");\n    println!(\"{} -> {:?}\", id, document);\n}"]},{"l":"Joins and projections","p":["Document cursors can join documents as a post-query step.","Use joins sparingly for read-model shaping. For projection-oriented typed read pipelines, the repository cursor API is usually a better fit."]},{"i":"joins-and-projections-code-1","c":["use nitrite::common::Lookup;\nuse nitrite::doc;\n\nlet mut users = db.collection(\"users\").expect(\"collection open failed\")\n    .find(nitrite::filter::all())\n    .expect(\"query failed\");\n\nlet mut teams = db.collection(\"teams\").expect(\"collection open failed\")\n    .find(nitrite::filter::all())\n    .expect(\"query failed\");\n\nlet lookup = Lookup::new(\"team_id\", \"id\", \"team\");\nlet mut joined = users.join(&mut teams, &lookup).expect(\"join failed\");\nlet _ = joined.next();"]}],[{"l":"Indexing","p":["Indexes accelerate collection queries at the cost of additional write-time maintenance. The core Rust SDK supports unique, non-unique, and core full-text indexes through IndexOptions helpers."]},{"l":"Create indexes"},{"i":"create-indexes-code-1","c":["use nitrite::index::{full_text_index, non_unique_index, unique_index};\n\nlet collection = db.collection(\"users\").expect(\"collection open failed\");\n\ncollection.create_index(vec![\"email\"], &unique_index())\n    .expect(\"unique index failed\");\ncollection.create_index(vec![\"department\"], &non_unique_index())\n    .expect(\"non-unique index failed\");\ncollection.create_index(vec![\"bio\"], &full_text_index())\n    .expect(\"full-text index failed\");"]},{"l":"Compound indexes","p":["Pass more than one field name to create a compound index.","Compound indexes are useful when your most selective queries combine the same fields repeatedly."]},{"i":"compound-indexes-code-1","c":["use nitrite::index::non_unique_index;\n\ncollection.create_index(vec![\"last_name\", \"first_name\"], &non_unique_index())\n    .expect(\"compound index failed\");"]},{"l":"Write performance and low-cardinality fields","p":["Since 0.4.0, non-unique indexes (simple and compound) store one composite (value…, id) row per entry instead of a single growing array of ids per value. Each insert and removal is an O(1) point write, and per-insert memory is flat.","This matters most for low-cardinality fields — ones where many documents share the same value, such as a status, category, account, or folder id. Previously, bulk-loading such a field was O(n²) in time and O(n) in per-insert memory because every insert rewrote an ever-growing id array; it is now linear. You can index these fields freely without paying a quadratic write penalty:","Equality lookups on a non-unique field are prefix range scans (O(matches)), and range/sorted scans are exact — see Read Operations and Filters.","The non-unique/compound index layout (and the Fjall key encoding) changed in 0.4.0. Indexes built by 0.3.x are not readable by 0.4.x; rebuild them on upgrade — see Schema Migration. Indexes are derived data, so rebuild_index(...) (or recreating the database) is all that is required."]},{"i":"write-performance-and-low-cardinality-fields-code-1","c":["use nitrite::index::non_unique_index;\n\n// Low-cardinality, high-volume fields — cheap to keep indexed in 0.4.\ncollection.create_index(vec![\"account_id\"], &non_unique_index())\n    .expect(\"account index failed\");\ncollection.create_index(vec![\"folder_id\"], &non_unique_index())\n    .expect(\"folder index failed\");"]},{"l":"Inspect and maintain indexes","p":["Persistent collections expose several maintenance methods:","has_index(field_names)","list_indexes()","is_indexing(field_names)","rebuild_index(field_names)","drop_index(field_names)","drop_all_indexes()"]},{"i":"inspect-and-maintain-indexes-code-1","c":["let has_email_index = collection.has_index(vec![\"email\"]).expect(\"has_index failed\");\nlet descriptors = collection.list_indexes().expect(\"list_indexes failed\");\n\nif has_email_index {\n    collection.rebuild_index(vec![\"email\"]).expect(\"rebuild failed\");\n}\n\nprintln!(\"index count: {}\", descriptors.len());"]},{"l":"Choosing an index type","p":["Use the core types like this:","unique_index() for fields such as email addresses or external IDs","non_unique_index() for category, status, and other repeated values","full_text_index() for lightweight text-searchable fields inside the core engine","Specialized modules add their own index types:","nitrite_spatial::spatial_index() for spatial fields","nitrite_tantivy_fts::fts_index() for Tantivy-backed full-text search","Those module-specific indexes are covered in the modules section."]}],[{"l":"Other Operations","p":["Collections also expose metadata, lifecycle, event, and processing hooks through the shared PersistentCollection interface."]},{"l":"Collection events","p":["You can subscribe to collection events such as insert, update, remove, and index lifecycle notifications."]},{"i":"collection-events-code-1","c":["use nitrite::collection::{CollectionEventInfo, CollectionEventListener, CollectionEvents};\n\nlet subscriber = collection.subscribe(CollectionEventListener::new(\n    |event: CollectionEventInfo| {\n        match event.event_type() {\n            CollectionEvents::Insert => println!(\"insert event from {}\", event.originator()),\n            CollectionEvents::Update => println!(\"update event\"),\n            CollectionEvents::Remove => println!(\"remove event\"),\n            CollectionEvents::IndexStart | CollectionEvents::IndexEnd => {}\n        }\n        Ok(())\n    },\n)).expect(\"subscribe failed\");\n\nif let Some(handle) = subscriber {\n    collection.unsubscribe(handle).expect(\"unsubscribe failed\");\n}"]},{"l":"Processors","p":["Processors transform documents before writes and after reads. They are useful for enrichment, normalization, or field redaction."]},{"i":"processors-code-1","c":["use nitrite::collection::Document;\nuse nitrite::common::{Processor, ProcessorProvider};\nuse nitrite::errors::NitriteResult;\n\nstruct AuditProcessor;\n\nimpl ProcessorProvider for AuditProcessor {\n    fn name(&self) -> String {\n        \"audit-processor\".to_string()\n    }\n\n    fn process_before_write(&self, mut doc: Document) -> NitriteResult<Document> {\n        doc.put(\"updated_at\", 1_725_000_000_i64)?;\n        Ok(doc)\n    }\n\n    fn process_after_read(&self, doc: Document) -> NitriteResult<Document> {\n        Ok(doc)\n    }\n}\n\ncollection.add_processor(Processor::new(AuditProcessor))\n    .expect(\"processor registration failed\");"]},{"l":"Attributes","p":["Collections can store custom metadata through Attributes."]},{"i":"attributes-code-1","c":["use nitrite::common::{Attributes, Value};\n\nlet mut attributes = Attributes::new_for_collection(\"users\");\nattributes.put(\"retention_policy\", Value::String(\"90-days\".to_string()));\n\ncollection.set_attributes(attributes).expect(\"set attributes failed\");\n\nlet stored = collection.attributes().expect(\"attributes failed\");\nassert!(stored.is_some());"]},{"l":"Lifecycle and maintenance","p":["NitriteCollection also exposes administrative methods that are useful for maintenance flows.","size()","clear()","is_open()","is_dropped()","close()","dispose()","store()","Use dispose() with care: it is intended for permanently discarding the collection state, not just closing a handle."]},{"i":"lifecycle-and-maintenance-code-1","c":["let size = collection.size().expect(\"size failed\");\nlet open = collection.is_open().expect(\"is_open failed\");\n\nprintln!(\"collection size: {}, open: {}\", size, open);"]}],[{"l":"Introduction","p":["An ObjectRepositoryT is Nitrite's typed persistence API. It stores Rust values as documents internally, but exposes typed CRUD and query operations at the call site."]},{"l":"Repository requirements","p":["Repository entities must implement:","Default","ConvertibleOutput = T","NitriteEntity","Send + Sync","In most applications, you satisfy those requirements with the derive macros from nitrite-derive."]},{"i":"repository-requirements-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite::repository::ObjectRepository;\nuse nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(id(field = \"id\"))]\nstruct User {\n    id: i64,\n    name: String,\n    email: String,\n}\n\nlet db = Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");\n\nlet repo: ObjectRepository<User> = db.repository().expect(\"repository open failed\");"]},{"l":"Keyed repositories","p":["The Rust SDK also supports keyed repositories. They let you keep multiple repository namespaces for the same entity type.","This is useful for patterns such as tenant partitioning, soft archives, or environment-specific datasets that still share the same entity definition."]},{"i":"keyed-repositories-code-1","c":["let live: ObjectRepository<User> = db.repository().expect(\"repository open failed\");\nlet archived: ObjectRepository<User> = db.keyed_repository(\"archived\")\n    .expect(\"keyed repository open failed\");"]},{"l":"Repositories are backed by collections","p":["Every repository is backed by a Nitrite collection. That means repositories inherit collection capabilities such as:","indexes","processors","attributes","event listeners","lifecycle and maintenance operations","If you need to drop down to raw document access, use document_collection() on the repository."]},{"l":"When to choose a repository","p":["Use a repository when:","your data has a stable Rust type","you want type-safe reads and writes","you want entity IDs and indexes declared next to the model","you need typed cursor helpers such as projection","Use a collection instead when the data shape is still fluid or when you intentionally want raw document access."]}],[{"l":"Entity","p":["NitriteEntity supplies repository metadata: the entity name, the repository ID definition, and any declared indexes. In day-to-day Rust code this is usually derived, not implemented by hand."]},{"l":"A basic entity","p":["This gives Nitrite enough metadata to:","name the repository","build an ID filter for get_by_id() and update_one()","attach any declared indexes"]},{"i":"a-basic-entity-code-1","c":["use nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(id(field = \"id\"))]\nstruct User {\n    id: i64,\n    name: String,\n    email: String,\n}"]},{"l":"Custom entity names","p":["You can override the repository entity name with name = ...."]},{"i":"custom-entity-names-code-1","c":["#[derive(Default, Convertible, NitriteEntity)]\n#[entity(name = \"users\", id(field = \"id\"))]\nstruct User {\n    id: i64,\n    name: String,\n}"]},{"l":"Embedded and compound IDs","p":["Entity IDs can be defined on nested value objects through embedded_fields.","When Nitrite builds ID filters for this entity, it addresses the encoded nested fields under the configured field separator."]},{"i":"embedded-and-compound-ids-code-1","c":["use nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible)]\nstruct BookId {\n    author: String,\n    isbn: String,\n}\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(id(field = \"book_id\", embedded_fields = \"author, isbn\"))]\nstruct Book {\n    book_id: BookId,\n    title: String,\n}"]},{"l":"Declaring indexes on the entity","p":["Indexes can live beside the entity definition.","This keeps repository metadata close to the domain type and avoids repeating index definitions at every call site."]},{"i":"declaring-indexes-on-the-entity-code-1","c":["use nitrite::collection::NitriteId;\nuse nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(\n    id(field = \"id\"),\n    index(type = \"unique\", fields = \"isbn\"),\n    index(type = \"non-unique\", fields = \"author, year\")\n)]\nstruct Book {\n    id: NitriteId,\n    title: String,\n    author: String,\n    isbn: String,\n    year: i32,\n}"]},{"l":"NitriteId support","p":["If you want Nitrite to manage entity identifiers automatically, use NitriteId as the ID field type.","The runtime trait behind the derive macro exposes this metadata through entity_name(), entity_indexes(), and entity_id()."]},{"i":"nitriteid-support-code-1","c":["use nitrite::collection::NitriteId;\nuse nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(id(field = \"id\"))]\nstruct Order {\n    id: NitriteId,\n    total_cents: i64,\n}"]}],[{"l":"Object Mapping","p":["Rust Nitrite does not use the Java or Flutter NitriteMapper model. Instead, object mapping is part of the type contract: repositories require entities to implement Convertible, and repository metadata comes from NitriteEntity."]},{"l":"The core mapping trait","p":["Convertible has two responsibilities:","to_value() converts a Rust value into Nitrite's Value","from_value() reconstructs the Rust value from Value","For repository entities, to_value() normally returns Value::Document(...)."]},{"l":"Prefer derive macros","p":["For straightforward structs, derive Convertible and NitriteEntity together.","This is the recommended default because it keeps mapping boilerplate out of the application layer."]},{"i":"prefer-derive-macros-code-1","c":["use nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(id(field = \"id\"))]\nstruct Product {\n    id: i64,\n    sku: String,\n    price_cents: i64,\n}"]},{"l":"Manual Convertible implementations","p":["If you need custom field transformations, manual validation, or an intentionally different persisted shape, implement Convertible yourself."]},{"i":"manual-convertible-implementations-code-1","c":["use nitrite::collection::Document;\nuse nitrite::common::{Convertible, Value};\nuse nitrite::errors::{ErrorKind, NitriteError, NitriteResult};\n\n#[derive(Default)]\nstruct Product {\n    sku: String,\n    price_cents: i64,\n}\n\nimpl Convertible for Product {\n    type Output = Product;\n\n    fn to_value(&self) -> NitriteResult<Value> {\n        let mut doc = Document::new();\n        doc.put(\"sku\", self.sku.clone())?;\n        doc.put(\"price_cents\", self.price_cents)?;\n        Ok(Value::Document(doc))\n    }\n\n    fn from_value(value: &Value) -> NitriteResult<Self::Output> {\n        let doc = match value {\n            Value::Document(document) => document,\n            _ => {\n                return Err(NitriteError::new(\n                    \"expected document value\",\n                    ErrorKind::ObjectMappingError,\n                ));\n            }\n        };\n\n        let sku = match doc.get(\"sku\")? {\n            Value::String(text) => text,\n            _ => {\n                return Err(NitriteError::new(\n                    \"expected string sku\",\n                    ErrorKind::ObjectMappingError,\n                ));\n            }\n        };\n        let price_cents = match doc.get(\"price_cents\")? {\n            Value::I64(value) => value,\n            _ => {\n                return Err(NitriteError::new(\n                    \"expected i64 price_cents\",\n                    ErrorKind::ObjectMappingError,\n                ));\n            }\n        };\n\n        Ok(Product { sku, price_cents })\n    }\n}"]},{"l":"Mapping nested values","p":["Convertible is implemented for many standard Rust and Nitrite value types, so nested fields, vectors, sets, maps, options, boxed values, and tuples can participate in mapping without extra glue code.","That makes the derive macros the best option for most repository models. Reach for a manual implementation only when the persisted document shape should differ from the in-memory struct."]}],[{"l":"Write Operations","p":["Repository writes follow the same lifecycle as collection writes, but accept typed entities instead of raw Document values."]},{"l":"Insert entities"},{"i":"insert-entities-code-1","c":["repo.insert(User {\n    id: 1,\n    name: \"Alice\".to_string(),\n    email: \"alice@example.com\".to_string(),\n}).expect(\"insert failed\");\n\nrepo.insert_many(vec![\n    User {\n        id: 2,\n        name: \"Bob\".to_string(),\n        email: \"bob@example.com\".to_string(),\n    },\n    User {\n        id: 3,\n        name: \"Carol\".to_string(),\n        email: \"carol@example.com\".to_string(),\n    },\n]).expect(\"batch insert failed\");"]},{"l":"Update by filter","p":["Use update() for the default behavior or update_with_options() when you want insert-if-absent or just-once semantics."]},{"i":"update-by-filter-code-1","c":["use nitrite::collection::just_once;\nuse nitrite::filter::field;\n\nlet options = just_once();\nlet updated = User {\n    id: 1,\n    name: \"Alice\".to_string(),\n    email: \"alice@new-domain.example\".to_string(),\n};\n\nrepo.update_with_options(\n    field(\"email\").eq(\"alice@example.com\"),\n    updated,\n    &options,\n).expect(\"update failed\");"]},{"l":"Update by entity ID","p":["update_one() derives the unique lookup filter from the entity's configured ID metadata.","If you already have the internal NitriteId, update_by_nitrite_id() is the most direct update path."]},{"i":"update-by-entity-id-code-1","c":["repo.update_one(User {\n    id: 1,\n    name: \"Alice\".to_string(),\n    email: \"alice@example.com\".to_string(),\n}, false).expect(\"update_one failed\");"]},{"i":"update-by-entity-id-code-2","c":["use nitrite::filter::all;\n\nlet mut cursor = repo.find(all()).expect(\"query failed\");\n\nfor row in cursor.iter_with_id() {\n    let (id, mut user) = row.expect(\"cursor row failed\");\n    user.name = user.name.to_uppercase();\n    repo.update_by_nitrite_id(&id, user, false)\n        .expect(\"update_by_nitrite_id failed\");\n}"]},{"l":"Partial raw-document updates","p":["If you need to patch repository data with a raw Document, use update_document().","This is useful when the update payload does not naturally map to a full entity instance."]},{"i":"partial-raw-document-updates-code-1","c":["use nitrite::doc;\nuse nitrite::filter::field;\n\nlet patch = doc! { \"status\": \"inactive\" };\nrepo.update_document(field(\"id\").eq(1), &patch, true)\n    .expect(\"update_document failed\");"]},{"l":"Remove entities","p":["Use remove_one() for a specific entity or remove() for filtered deletion.","remove_one() uses the entity's ID metadata. The non-ID fields in the example above are ignored for the lookup."]},{"i":"remove-entities-code-1","c":["use nitrite::filter::field;\n\nrepo.remove(field(\"status\").eq(\"inactive\"), false)\n    .expect(\"remove failed\");\n\nrepo.remove_one(User {\n    id: 3,\n    name: String::new(),\n    email: String::new(),\n}).expect(\"remove_one failed\");"]}],[{"l":"Read Operations","p":["Repository reads are the typed equivalent of collection reads. The result cursor converts each matching document back into your entity type lazily. In the current 0.4 line, the underlying find() cursor is streaming, so reset() reruns the query instead of replaying a cached snapshot."]},{"l":"Read by ID","p":["Use get_by_id() when you already know the repository ID value.","The ID type must match the entity's configured NitriteEntity::Id type."]},{"i":"read-by-id-code-1","c":["let maybe_user = repo.get_by_id(&1).expect(\"lookup failed\");\nassert!(maybe_user.is_some());"]},{"l":"Query with filters","p":["find() accepts the same core Filter values that collections use."]},{"i":"query-with-filters-code-1","c":["use nitrite::filter::field;\n\nlet mut users = repo.find(field(\"name\").eq(\"Alice\"))\n    .expect(\"query failed\");\n\nif let Some(Ok(user)) = users.first() {\n    println!(\"{}\", user.email);\n}"]},{"l":"Sorting and pagination","p":["find_with_options() uses FindOptions exactly like collection queries do.","As with collection cursors, fully index-covered repository queries can answer size() without materializing every entity."]},{"i":"sorting-and-pagination-code-1","c":["use nitrite::collection::FindOptions;\nuse nitrite::common::SortOrder;\nuse nitrite::filter::all;\n\nlet options = FindOptions::new()\n    .sort_by(\"name\".to_string(), SortOrder::Ascending)\n    .skip(20)\n    .limit(20);\n\nlet mut page = repo.find_with_options(all(), &options)\n    .expect(\"query failed\");\n\nprintln!(\"page size: {}\", page.size());"]},{"l":"Cursor helpers","p":["ObjectCursorT adds a few repository-specific conveniences:","first() to fetch the first entity","size() to count the result set, with a fast path for fully index-covered queries","reset() to restart iteration; streaming cursors rerun the query, while rewindable cursors replay cached rows","iter_with_id() to stream (NitriteId, T) pairs","project::P() to map each result to a projection type","If you need cursor composition across two result sets, ObjectCursorT also exposes join() with a Lookup."]},{"i":"cursor-helpers-code-1","c":["use nitrite::filter::all;\nuse nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\nstruct UserSummary {\n    name: String,\n    email: String,\n}\n\nlet mut cursor = repo.find(all()).expect(\"query failed\");\nlet mut projected = cursor.project::<UserSummary>()\n    .expect(\"projection failed\");\n\nif let Some(Ok(summary)) = projected.next() {\n    println!(\"{} <{}>\", summary.name, summary.email);\n}"]},{"l":"Drop to raw documents when needed","p":["If a read flow needs raw documents instead of typed entities, use document_collection() and switch to the collection cursor API."]},{"i":"drop-to-raw-documents-when-needed-code-1","c":["let collection = repo.document_collection();\nlet mut docs = collection.find(nitrite::filter::all())\n    .expect(\"query failed\");\nlet _ = docs.next();"]}],[{"l":"Indexing","p":["Repositories can be indexed in two ways:","declare indexes on the entity with #[entity(index(...))]","create and maintain indexes dynamically through the repository handle"]},{"l":"Entity-declared indexes","p":["The derive macro is the cleanest option when the index shape is part of the domain model."]},{"i":"entity-declared-indexes-code-1","c":["use nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(\n    id(field = \"id\"),\n    index(type = \"unique\", fields = \"isbn\"),\n    index(type = \"non-unique\", fields = \"author, year\")\n)]\nstruct Book {\n    id: i64,\n    title: String,\n    author: String,\n    isbn: String,\n    year: i32,\n}"]},{"l":"Runtime index management","p":["Repositories also implement PersistentCollection, so you can manage indexes through the repository handle.","Compound indexes work the same way as they do on collections."]},{"i":"runtime-index-management-code-1","c":["use nitrite::index::{full_text_index, non_unique_index, unique_index};\n\nrepo.create_index(vec![\"email\"], &unique_index())\n    .expect(\"unique index failed\");\nrepo.create_index(vec![\"department\"], &non_unique_index())\n    .expect(\"non-unique index failed\");\nrepo.create_index(vec![\"bio\"], &full_text_index())\n    .expect(\"full-text index failed\");"]},{"i":"runtime-index-management-code-2","c":["repo.create_index(vec![\"last_name\", \"first_name\"], &non_unique_index())\n    .expect(\"compound index failed\");"]},{"l":"Inspect and maintain repository indexes","p":["The same maintenance operations available on collections are available on repositories:","has_index(field_names)","list_indexes()","is_indexing(field_names)","rebuild_index(field_names)","drop_index(field_names)","drop_all_indexes()","Use entity-declared indexes for the stable baseline and runtime index calls when indexing needs to remain operationally configurable."]}],[{"l":"Other Operations","p":["Repositories inherit the same persistent-collection services as collections and also expose repository-specific helpers such as document_collection()."]},{"l":"Work with the backing collection","p":["document_collection() gives you the raw collection behind the repository.","This is useful when a typed workflow needs to drop down to raw document inspection or low-level maintenance."]},{"i":"work-with-the-backing-collection-code-1","c":["let collection = repo.document_collection();\nlet size = collection.size().expect(\"size failed\");\nprintln!(\"raw collection size: {}\", size);"]},{"l":"Events, processors, and attributes","p":["Because repositories implement PersistentCollection, you can attach the same hooks you would use on a collection."]},{"i":"events-processors-and-attributes-code-1","c":["use nitrite::collection::CollectionEventListener;\nuse nitrite::common::{Attributes, Processor, ProcessorProvider, Value};\nuse nitrite::errors::NitriteResult;\n\nrepo.subscribe(CollectionEventListener::new(|event| {\n    println!(\"repository event: {:?}\", event.event_type());\n    Ok(())\n})).expect(\"subscribe failed\");\n\nstruct TouchProcessor;\n\nimpl ProcessorProvider for TouchProcessor {\n    fn name(&self) -> String {\n        \"touch-processor\".to_string()\n    }\n\n    fn process_before_write(\n        &self,\n        mut doc: nitrite::collection::Document,\n    ) -> NitriteResult<nitrite::collection::Document> {\n        doc.put(\"touched\", true)?;\n        Ok(doc)\n    }\n\n    fn process_after_read(\n        &self,\n        doc: nitrite::collection::Document,\n    ) -> NitriteResult<nitrite::collection::Document> {\n        Ok(doc)\n    }\n}\n\nrepo.add_processor(Processor::new(TouchProcessor))\n    .expect(\"processor registration failed\");\n\nlet mut attributes = Attributes::new_for_collection(\"User\");\nattributes.put(\"stream\", Value::String(\"primary\".to_string()));\nrepo.set_attributes(attributes).expect(\"set attributes failed\");"]},{"l":"Lifecycle and maintenance","p":["Repositories also expose collection-like maintenance operations:","size()","clear()","is_open()","close()","dispose()","store()","Use clear() when you want to keep the repository structure but remove its data. Use disposal and destruction APIs only when the repository itself should be discarded."]},{"l":"Destroy repositories from the database handle","p":["Repository destruction happens at the database level.","That keeps repository lifecycle consistent whether the handle was typed or keyed."]},{"i":"destroy-repositories-from-the-database-handle-code-1","c":["db.destroy_repository::<User>().expect(\"destroy_repository failed\");\ndb.destroy_keyed_repository::<User>(\"archived\")\n    .expect(\"destroy_keyed_repository failed\");"]}],[{"l":"Filters","p":["The Rust SDK exposes a fluent filter DSL through field(...). Filters can be combined, negated, and reused across collections and repositories."]},{"l":"Equality and comparison filters","p":["Start with field(name) and finish with a comparison operator."]},{"i":"equality-and-comparison-filters-code-1","c":["use nitrite::filter::field;\n\nlet by_name = field(\"name\").eq(\"Alice\");\nlet not_deleted = field(\"deleted\").ne(true);\nlet adults = field(\"age\").gte(18);\nlet seniors = field(\"age\").gt(64);\nlet before_cutoff = field(\"score\").lt(50);\nlet at_most = field(\"priority\").lte(3);"]},{"l":"Range filters","p":["Nitrite provides three range helpers depending on how explicit you want the bound rules to be.","On indexed fields in the current 0.4 line, bounded ranges such as between(...) and paired gte(...)/lte(...) filters use bounded index scans instead of a broad one-sided scan plus a post-filter.","Range results are also exact across every comparable type. Since 0.4.0 the persistent (Fjall) store encodes keys so byte order matches value order, so integer and floating-point ranges — including negative and large values such as nanosecond timestamps — return precisely the matching set. (Earlier releases could mis-order numeric keys on disk, for example returning the wrong rows for field(seq).between(100, 199, true, true).)"]},{"i":"range-filters-code-1","c":["use nitrite::filter::field;\n\nlet inclusive = field(\"age\").between_optional_inclusive(18, 65);\nlet same_rule = field(\"age\").between_inclusive(18, 65, true);\nlet custom = field(\"price\").between(10, 20, true, false);"]},{"l":"Text, regex, and array filters","p":["Core filters cover substring matching, regex matching, membership, and array element matching."]},{"i":"text-regex-and-array-filters-code-1","c":["use nitrite::filter::field;\n\nlet contains = field(\"address\").text(\"street\");\nlet contains_ignore_case = field(\"address\").text_case_insensitive(\"main street\");\nlet regex = field(\"email\").text_regex(\".*@example\\\\.com$\");\nlet roles = field(\"role\").in_array(vec![\"admin\", \"editor\"]);\nlet excluded = field(\"status\").not_in_array(vec![\"archived\", \"deleted\"]);\nlet matching_tags = field(\"tags\").elem_match(field(\"name\").eq(\"database\"));"]},{"l":"Logical composition","p":["You can compose filters either as methods on Filter or with the top-level helpers."]},{"i":"logical-composition-code-1","c":["use nitrite::filter::{all, and, field, not, or};\n\nlet active_adults = field(\"active\")\n    .eq(true)\n    .and(field(\"age\").gte(18));\n\nlet privileged = or(vec![\n    field(\"role\").eq(\"admin\"),\n    field(\"role\").eq(\"moderator\"),\n]);\n\nlet visible = and(vec![active_adults, not(field(\"deleted\").eq(true)), privileged]);\nlet everything = all();"]},{"l":"Match by document ID","p":["If you already have a NitriteId, you can query directly by internal document identifier.","This is mostly useful in collection-level workflows. Repository-level code usually prefers get_by_id() or update_by_nitrite_id()."]},{"i":"match-by-document-id-code-1","c":["use nitrite::collection::NitriteId;\nuse nitrite::filter::by_id;\n\nlet id = NitriteId::new();\nlet filter = by_id(id);"]},{"l":"Using filters with collections and repositories","p":["The same Filter values work with both collection and repository query APIs."]},{"i":"using-filters-with-collections-and-repositories-code-1","c":["use nitrite::filter::field;\n\nlet filter = field(\"name\").eq(\"Alice\");\n\nlet documents = collection.find(filter.clone()).expect(\"collection query failed\");\nlet users = repository.find(filter).expect(\"repository query failed\");"]},{"l":"Specialized filters from modules","p":["The core filter module covers general document queries. Optional modules add dedicated fluent APIs for richer index types:","nitrite_spatial::spatial_field(location) for spatial intersections, containment, and nearest-neighbor queries","nitrite_tantivy_fts::fts_field(content) for Tantivy-backed full-text search","Those module-specific filters are documented in Spatial Module and Full-Text Search."]}],[{"l":"Transaction","p":["Nitrite transactions are session-based. A Session owns one or more NitriteTransaction instances, and each transaction provides isolated collection and repository views until you commit or roll back."]},{"l":"Execute work with with_session","p":["Nitrite::with_session() is the simplest way to run transactional work.","This keeps transaction setup local to the database handle and ensures the session is cleaned up when the closure ends."]},{"i":"execute-work-with-with_session-code-1","c":["use nitrite::doc;\nuse nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");\n\ndb.with_session(|session| {\n    let tx = session.begin_transaction()?;\n\n    let users = tx.collection(\"users\")?;\n    let audit_log = tx.collection(\"audit_log\")?;\n\n    users.insert(doc! {\n        \"name\": \"Alice\",\n        \"active\": true\n    })?;\n\n    audit_log.insert(doc! {\n        \"event\": \"user-created\",\n        \"user\": \"Alice\"\n    })?;\n\n    tx.commit()\n}).expect(\"transaction failed\");"]},{"l":"Session model","p":["A Session is the parent transactional context. It has:","an ID","an active/closed lifecycle","a registry of active transactions","When a session closes, any uncommitted transactions are rolled back.","That matters in two situations:","if you call rollback() explicitly","if your with_session() closure returns an error before commit() runs"]},{"l":"Transactional collections and repositories","p":["Inside a transaction, you access data through the transaction handle instead of the root database handle.","NitriteTransaction supports:","collection(name)","repository::T()","keyed_repository::T(key)","commit()","rollback()"]},{"i":"transactional-collections-and-repositories-code-1","c":["use nitrite::filter::field;\nuse nitrite::repository::ObjectRepository;\nuse nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Default, Convertible, NitriteEntity)]\n#[entity(id(field = \"id\"))]\nstruct Account {\n    id: i64,\n    owner: String,\n    balance: i64,\n}\n\nlet db = nitrite::nitrite::Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");\n\ndb.with_session(|session| {\n    let tx = session.begin_transaction()?;\n    let repo: ObjectRepository<Account> = tx.repository()?;\n\n    let mut accounts = repo.find(field(\"owner\").eq(\"Alice\"))?;\n    let current = accounts.first().transpose()?;\n\n    if let Some(mut account) = current {\n        account.balance += 100;\n        repo.update_one(account, false)?;\n    }\n\n    tx.commit()\n}).expect(\"transaction failed\");"]},{"l":"Commit and rollback semantics","p":["Nitrite's transaction implementation coordinates multi-collection and multi-repository work through a dedicated transaction store and a two-phase commit flow.","In practice, that means:","reads inside the transaction see the transactional view","writes are isolated until commit succeeds","rollback discards uncommitted changes across all touched collections and repositories in that transaction","If you need an explicit abort path, call rollback() directly."]},{"i":"commit-and-rollback-semantics-code-1","c":["db.with_session(|session| {\n    let tx = session.begin_transaction()?;\n    let collection = tx.collection(\"jobs\")?;\n\n    collection.insert(nitrite::doc! { \"state\": \"running\" })?;\n\n    let should_abort = true;\n    if should_abort {\n        tx.rollback()?;\n        return Ok(());\n    }\n\n    tx.commit()\n}).expect(\"transaction failed\");"]},{"l":"Crash-atomic writes on Fjall","p":["On a Fjall-backed database in the current 0.4 line, a logical write now lands in one atomic store transaction. That includes:","a transaction commit() across all touched collections and repositories","a single insert, update, or remove together with its index updates","After an unclean stop, Nitrite recovers to either the state before that logical write or the state after it. You do not get a persisted data row without its index entries, or the reverse."]},{"l":"When to use transactions","p":["Use a transaction when a sequence of writes must succeed or fail as a unit, especially when:","more than one collection is involved","you are updating multiple repositories together","you want predictable rollback behavior on validation or business-rule failures"]}],[{"l":"Schema Migration","p":["Nitrite for Rust supports versioned schema evolution through Migration and InstructionSet. Migrations are registered on the builder and run when the stored schema version differs from the version you request with schema_version().","These Migration/InstructionSet tools are for your schema changes (renaming fields, adding defaults, re-typing values). They are independent of the engine's own on-disk format. The next section covers the one-time storage-format change introduced by the 0.4.0 engine upgrade."]},{"l":"Upgrading from 0.3.x to 0.4.x","p":["0.4.0 changes the engine's on-disk storage format, so a database written by 0.3.x cannot be opened directly by 0.4.x. Two things changed:","Index layout. Non-unique simple and compound indexes now store one composite (field-values…, id) row per entry instead of a single array (or nested map) of ids per value. This is what makes inserts O(1) and removes the old O(n²) bulk-load cost on low-cardinality fields.","Key encoding (nitrite-fjall-adapter). Keys are now serialized with an order-preserving codec so the store's byte order matches value order, which is what makes integer/float range and ascending/descending sorted index scans exact.","Indexes are derived data, so recovering is straightforward — choose whichever fits your deployment:","Re-create the database from your source of truth (simplest for caches and re-syncable data such as an email client's mailbox).","Rebuild indexes on first open with 0.4.x if you keep the data partitions:","There is no automatic in-place converter for 0.3.x databases; plan the rebuild as part of your upgrade. No application API changed — create_index, filters, find, and order_by are source-compatible; only the on-disk format and the (now correct) numeric ordering behavior differ."],"c":["// After opening the 0.4.x database, rebuild each index you rely on. collection.rebuild_index(vec![\"account_id\"]).expect(\"rebuild failed\"); collection.rebuild_index(vec![\"folder_id\"]).expect(\"rebuild failed\");"]},{"l":"Define a migration","p":["Use Migration::new(from_version, to_version, |instruction| { ... }) to define the transition.","Register the migration when opening the database:"]},{"i":"define-a-migration-code-1","c":["use nitrite::common::Value;\nuse nitrite::migration::Migration;\n\nlet migration = Migration::new(1, 2, |instruction| {\n    instruction\n        .for_collection(\"users\")\n        .rename_field(\"last_name\", \"family_name\")\n        .add_field(\"status\", Some(Value::String(\"active\".to_string())), None)\n        .create_index(\"NON_UNIQUE\", &[\"status\"]);\n\n    Ok(())\n});"]},{"i":"define-a-migration-code-2","c":["use nitrite::nitrite::Nitrite;\n\nlet db = Nitrite::builder()\n    .schema_version(2)\n    .add_migration(migration)\n    .open_or_create(None, None)\n    .expect(\"failed to open migrated database\");"]},{"l":"Migration scopes","p":["InstructionSet exposes three builders, each grounded to a specific migration scope."]},{"l":"Database instructions","p":["for_database() is used for database-wide changes such as:","add_user(username, password)","change_password(username, old_password, new_password)","drop_collection(name)","drop_repository(entity_name, key)","custom_instruction(...)"]},{"l":"Collection instructions","p":["for_collection(name) works on raw document collections and supports:","rename(new_name)","add_field(field_name, default_value, generator)","rename_field(old_name, new_name)","delete_field(field_name)","drop_index(field_names)","drop_all_indices()","create_index(index_type, field_names)"]},{"l":"Repository instructions","p":["for_repository(entity_name, key) targets typed repositories and adds repository-specific operations:","rename_repository(new_entity_name, new_key)","add_field(field_name, default_value, generator)","rename_field(old_name, new_name)","delete_field(field_name)","change_data_type(field_name, converter)","change_id_field(old_field_names, new_field_names)","drop_index(field_names)","drop_all_indices()","create_index(index_type, field_names)"]},{"l":"Generated values during migration","p":["Collection and repository add_field() calls can use either a static Value or a generator closure that receives the current Document."]},{"i":"generated-values-during-migration-code-1","c":["use nitrite::common::Value;\nuse nitrite::migration::Migration;\n\nlet migration = Migration::new(2, 3, |instruction| {\n    instruction\n        .for_repository(\"User\", None)\n        .add_field(\"display_name\", None, Some(|doc| {\n            let first = match doc.get(\"first_name\")? {\n                Value::String(value) => value,\n                _ => String::new(),\n            };\n            let last = match doc.get(\"family_name\")? {\n                Value::String(value) => value,\n                _ => String::new(),\n            };\n\n            Ok(Value::String(format!(\"{} {}\", first, last).trim().to_string()))\n        }));\n\n    Ok(())\n});"]},{"l":"Choosing index types","p":["Migration builders take index types as string identifiers. For the core engine, the relevant values are:","UNIQUE","NON_UNIQUE","FULL_TEXT","Specialized modules may add their own index type strings. For example, the Tantivy FTS and spatial modules each provide their own index options and matching filters."]},{"l":"Practical guidance","p":["advance schema_version() only when you have a matching migration path","keep each migration focused on one version transition","prefer collection instructions for document-shape cleanup and repository instructions for entity-centric changes","test migrations against a copy of real data before promoting them into production flows"]}],[{"l":"Module System","p":["Nitrite for Rust is modular by design. Modules are how storage engines and specialized indexers are added to the core engine."]},{"l":"Core concepts","p":["The module system is centered on three public types:","NitriteModule for module registration","NitritePluginProvider for plugin lifecycle (initialize(), close(), as_plugin())","PluginRegistrar for registering stores and indexers during module loading","At runtime, the plugin manager keeps registries of store and indexer plugins."]},{"l":"What the core engine loads automatically","p":["When no custom module overrides them, the core plugin manager auto-loads:","the built-in in-memory store","the unique indexer","the non-unique indexer","the core full-text indexer","That is why a plain Nitrite::builder().open_or_create(None, None) works without any extra setup."]},{"l":"Loading modules","p":["Modules are added through NitriteBuilder::load_module()."]},{"i":"loading-modules-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_fjall_adapter::FjallModule;\nuse nitrite_spatial::SpatialModule;\nuse nitrite_tantivy_fts::TantivyFtsModule;\n\nlet db = Nitrite::builder()\n    .load_module(\n        FjallModule::with_config()\n            .db_path(\"./data/nitrite\")\n            .build(),\n    )\n    .load_module(SpatialModule)\n    .load_module(TantivyFtsModule::default())\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"How custom modules register functionality","p":["A custom module implements NitriteModule and uses PluginRegistrar inside load().","For storage modules, see Storage Modules and Custom Storage Modules."]},{"i":"how-custom-modules-register-functionality-code-1","c":["use nitrite::common::{NitriteModule, NitritePlugin, PluginRegistrar};\nuse nitrite::errors::NitriteResult;\n\nstruct MyModule;\n\nimpl NitriteModule for MyModule {\n    fn plugins(&self) -> NitriteResult<Vec<NitritePlugin>> {\n        Ok(vec![])\n    }\n\n    fn load(&self, _plugin_registrar: &PluginRegistrar) -> NitriteResult<()> {\n        // Register a store or indexer plugin here.\n        Ok(())\n    }\n}"]},{"l":"Choosing between core and optional modules","p":["Use the core engine alone when you need:","in-memory storage","unique or non-unique indexing","core document and repository APIs","Add modules when you need:","on-disk persistence with Fjall","spatial indexes and geospatial filters","Tantivy-backed full-text search"]}],[{"l":"Storage Module","p":["Nitrite for Rust always has a store backend. If you do not register one explicitly, the plugin manager loads the built-in in-memory store. If you need persistence, add a store module.","The supported store paths in the current Rust codebase are:","built-in in-memory storage with no extra crate","persistent Fjall-backed storage via nitrite-fjall-adapter","custom stores built on the public store traits","Fjall Module","Custom Storage Modules"]},{"l":"In-memory by default","p":["This path requires no additional dependency and is ideal for tests and ephemeral workloads."]},{"i":"in-memory-by-default-code-1","c":["let db = nitrite::nitrite::Nitrite::builder()\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Add persistence when needed","p":["As soon as you need a file-backed store, register a store module through load_module() before opening the database."]}],[{"l":"Fjall Module","p":["nitrite-fjall-adapter is the persistent store module in the current Rust Nitrite ecosystem. It uses Fjall as an embedded LSM-tree backend."]},{"l":"Add the dependency"},{"i":"add-the-dependency-code-1","c":["[dependencies]\nnitrite = \"0.4\"\nnitrite-fjall-adapter = \"0.4\""]},{"l":"Basic configuration","p":["db_path() is the essential setting because it tells Fjall where to store the database files."]},{"i":"basic-configuration-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_fjall_adapter::FjallModule;\n\nlet module = FjallModule::with_config()\n    .db_path(\"./data/nitrite\")\n    .build();\n\nlet db = Nitrite::builder()\n    .load_module(module)\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Durability modes","p":["In the current 0.4 line, Fjall defaults to Durability::Periodic. Commits are buffered to the OS and fsynced by a background timer within the configured fsync_frequency() window, which is 1000 ms by default. That keeps acknowledged writes safe across a process crash while trading a bounded power-loss window for much better throughput than fsyncing every commit.","If you want every commit fsynced before it returns, opt into Durability::OnCommit explicitly:"]},{"i":"durability-modes-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_fjall_adapter::{Durability, FjallModule};\n\nlet module = FjallModule::with_config()\n    .db_path(\"./data/nitrite\")\n    .durability(Durability::OnCommit)\n    .build();\n\nlet db = Nitrite::builder()\n    .load_module(module)\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Presets","p":["The builder ships with three presets for common operating modes.","Use them as starting points, then override specific settings if needed."]},{"i":"presets-code-1","c":["use nitrite_fjall_adapter::FjallModule;\n\nlet production = FjallModule::with_config()\n    .production_preset()\n    .db_path(\"./data/prod\")\n    .build();\n\nlet throughput = FjallModule::with_config()\n    .high_throughput_preset()\n    .db_path(\"./data/bulk\")\n    .build();\n\nlet low_memory = FjallModule::with_config()\n    .low_memory_preset()\n    .db_path(\"./data/dev\")\n    .build();"]},{"l":"Tuning knobs","p":["The builder exposes a broad set of Fjall tuning parameters. The most relevant operational controls are:","block_cache_capacity(...)","blob_cache_capacity(...)","max_write_buffer_size(...)","max_memtable_size(...)","flush_workers(...)","compaction_workers(...)","manual_journal_persist(...)","fsync_frequency(...)","durability(...)","compression_type(...)","kv_separated(...)","Example:","For most applications, start with production_preset() and tune only after measuring your workload. If you stay on Durability::Periodic, fsync_frequency(...) controls the background fsync interval."]},{"i":"tuning-knobs-code-1","c":["use nitrite_fjall_adapter::FjallModule;\n\nlet module = FjallModule::with_config()\n    .db_path(\"./data/nitrite\")\n    .block_cache_capacity(256 * 1024 * 1024)\n    .blob_cache_capacity(64 * 1024 * 1024)\n    .max_write_buffer_size(128 * 1024 * 1024)\n    .flush_workers(4)\n    .compaction_workers(2)\n    .build();"]},{"l":"On-disk key ordering","p":["Fjall is an LSM-tree that keeps keys sorted by their raw bytes. Since 0.4.0, the adapter serializes keys with an order-preserving codec so that byte order matches Nitrite's value ordering. This makes indexed range filters (between, gte/lte) and sorted index scans exact for every comparable type — including negative and large integers (for example nanosecond timestamps order correctly, beyond f64 precision) — instead of the byte-order artifacts the previous encoding produced.","This is a transparent change to your code, but it does change the on-disk format.","A database written by 0.3.x cannot be opened by 0.4.x as-is: both the key encoding and the non-unique/compound index layout changed. Rebuild the database (or drop and re-create its indexes) on upgrade. See Schema Migration."]}],[{"l":"Custom Storage Modules","p":["Nitrite's storage layer is public and extensible. If Fjall is not the right persistence strategy for your application, you can build a custom store module."]},{"l":"Storage extension points","p":["At the module boundary, custom storage is expressed through StoreModule.","In practice, a custom storage integration has two layers:","a store provider implementing NitriteStoreProvider","a module implementing NitriteModule and StoreModule"]},{"i":"storage-extension-points-code-1","c":["use nitrite::errors::NitriteResult;\nuse nitrite::store::{NitriteStore, StoreModule};\nuse nitrite::NitriteModule;\n\npub trait StoreModule: NitriteModule {\n    fn get_store(&self) -> NitriteResult<NitriteStore>;\n}"]},{"l":"What a store provider is responsible for","p":["NitriteStoreProvider is the low-level contract. A custom store must handle:","opening or creating the physical store","returning collection and repository registries","opening maps","committing and compacting persisted state","publishing store events","closing cleanly","Because NitriteStoreProvider extends NitritePluginProvider, it also participates in plugin initialization and shutdown."]},{"l":"Registering the store through a module","p":["The module wrapper is responsible for registering the custom store with the plugin registrar.","The store field in that example is typically constructed with NitriteStore::new(my_provider) where my_provider is your NitriteStoreProvider implementation."]},{"i":"registering-the-store-through-a-module-code-1","c":["use nitrite::common::{NitriteModule, NitritePlugin, PluginRegistrar};\nuse nitrite::errors::NitriteResult;\nuse nitrite::store::{NitriteStore, StoreModule};\n\n#[derive(Clone)]\nstruct MyStoreModule {\n    store: NitriteStore,\n}\n\nimpl NitriteModule for MyStoreModule {\n    fn plugins(&self) -> NitriteResult<Vec<NitritePlugin>> {\n        Ok(vec![self.store.as_plugin()])\n    }\n\n    fn load(&self, plugin_registrar: &PluginRegistrar) -> NitriteResult<()> {\n        plugin_registrar.register_store_plugin(self.store.clone())\n    }\n}\n\nimpl StoreModule for MyStoreModule {\n    fn get_store(&self) -> NitriteResult<NitriteStore> {\n        Ok(self.store.clone())\n    }\n}"]},{"l":"When to build a custom store","p":["Build a custom store only when you need behavior the current ecosystem does not provide, such as:","a different persistence engine","a specialized durability model","platform-specific storage constraints","custom observability or operational hooks at the storage layer"]}],[{"l":"Vector Store (ANN / RAG)","p":["The nitrite-vector crate turns Nitrite into an embedded vector database. It adds approximate-nearest-neighbour (ANN) indexes and a fluent kNN query builder, plus a higher-level RagStore for retrieval-augmented-generation (RAG) workloads — store text + embedding + metadata, search by similarity, and combine the result with ordinary Nitrite metadata filters.","Embeddings are provided by the caller (bring-your-own vectors, like sqlite-vec / usearch / lance); this crate stores and searches vectors, it does not generate them."]},{"l":"Two backends","p":["You choose a backend per database. Both expose the exact same query API.","Backend","Storage","Best for","Durability","HNSW (default)","in-memory graph, persisted to Nitrite's KV store","indexes that fit in RAM","per-write, atomic with the DB","DiskANN","memory-mapped flat file + PQ codes in RAM","indexes larger than RAM (e.g. mobile)","flush-on-close (rebuildable)","HNSW — an in-memory Malkov–Yashunin graph, written through to the store on every change (crash-safe). Fastest when everything fits in memory.","DiskANN — a disk-resident Vamana graph with full vectors in a memory-mapped file and product-quantized (PQ) codes resident in RAM for fast traversal, followed by an exact re-rank from the on-disk vectors. Resident memory is bounded by the OS page cache (cold pages are reclaimed under pressure — the index cannot OOM from its vector data), so it serves indexes much larger than RAM."]},{"l":"Add the dependency"},{"i":"add-the-dependency-code-1","c":["[dependencies]\nnitrite = \"0.4.2\"\nnitrite-vector = \"0.4.2\"\n# a storage backend (also where the DiskANN files live):\nnitrite-fjall-adapter = \"0.4.2\""]},{"l":"Load the module","p":["The module is configured through VectorModule::builder(dim, metric).","The first argument is the embedding dimension. This walkthrough uses 3 so the vectors are readable; real embeddings are typically 384–1536-dimensional."],"c":["use nitrite::nitrite::Nitrite; use nitrite_vector::{VectorModule, Metric}; let db = Nitrite::builder() .load_module(VectorModule::builder(3, Metric::Cosine).build()) .open_or_create(None, None) .expect(\"failed to open database\");","use nitrite::nitrite::Nitrite; use nitrite_vector::{VectorModule, IndexBackend, Precision, Metric}; use nitrite_fjall_adapter::FjallModule; let module = VectorModule::builder(384, Metric::Cosine) .backend(IndexBackend::DiskAnn) .precision(Precision::F16) // stored-vector precision .degree(64) // Vamana out-degree R .search_beam(100) // default query search width .pq_subvectors(16) // PQ bytes per code .pq_train_threshold(10_000) // train PQ once this many vectors exist .cache_bytes(128 * 1024 * 1024) // advisory (OS page cache bounds RAM) .build(); let db = Nitrite::builder() .load_module(FjallModule::with_config().db_path(\"./data\").build()) .load_module(module) .open_or_create(None, None) .expect(\"failed to open database\");"]},{"l":"Create a vector index","p":["Create the index on the document field that holds the embedding array."]},{"i":"create-a-vector-index-code-1","c":["use nitrite_vector::vector_index_options;\n\nlet collection = db.collection(\"docs\").expect(\"collection open failed\");\ncollection.create_index(vec![\"embedding\"], &vector_index_options())\n    .expect(\"vector index failed\");"]},{"l":"Insert vectors","p":["The embedding is a normal numeric array field on the document."]},{"i":"insert-vectors-code-1","c":["use nitrite::doc;\n\ncollection.insert(doc! { \"title\": \"fox\",  \"embedding\": [1.0, 0.0, 0.0] })\n    .expect(\"insert failed\");\ncollection.insert(doc! { \"title\": \"wolf\", \"embedding\": [0.9, 0.1, 0.0] })\n    .expect(\"insert failed\");"]},{"l":"Query with vector_field","p":["The fluent entry point is vector_field(name).nearest(query, k).","Results come back through the normal DocumentCursor, ordered nearest-first, so they compose with projections, joins, and the rest of the collection API."]},{"i":"query-with-vector_field-code-1","c":["use nitrite_vector::vector_field;\n\nlet filter = vector_field(\"embedding\")\n    .nearest(vec![1.0, 0.0, 0.0], 5)   // query vector, k\n    .ef(64)                            // optional: search width (recall vs latency)\n    .min_score(0.5)                    // optional: similarity cutoff\n    .build();\n\nlet mut nearest = collection.find(filter).expect(\"vector query failed\");\nlet _ = nearest.next();"]},{"l":"RAG store","p":["RagStore is a thin, convenient layer over a collection. It stores a text field, an embedding field, and any metadata you pass; it does kNN and combines the result with ordinary Nitrite filters, returning documents with similarity scores.","RagStore also exposes add_many, get, len, is_empty, and collection()."]},{"i":"rag-store-code-1","c":["use nitrite_vector::{RagStore, Metric};\nuse nitrite::doc;\nuse nitrite::filter::field;\n\n// The db must be built with a VectorModule using the same metric.\nlet store = RagStore::create(&db, \"kb\", Metric::Cosine).expect(\"rag store failed\");\n\nlet id = store\n    .add(\"the quick brown fox\", embedding, doc! { \"source\": \"wiki\" })\n    .expect(\"add failed\");\n\nlet hits = store\n    .search(query_vector, 5)                 // top-5\n    .filter(field(\"source\").eq(\"wiki\"))      // combine with metadata\n    .min_score(0.75)                         // drop dissimilar hits\n    .ef(128)                                 // search width\n    .run()                                   // Vec<SearchHit { id, text, score, document }>\n    .expect(\"search failed\");\n\nfor hit in &hits {\n    println!(\"{} (score {:.3})\", hit.text, hit.score);\n}\n\nstore.delete(&id).expect(\"delete failed\");"]},{"l":"Distance metrics","p":["Choose the metric when you build the module: Metric::Cosine, Metric::Euclidean (L2), or Metric::Dot. Cosine vectors are L2-normalized on insert. Similarity scores are metric-aware (higher = more similar); min_score uses that scale."]},{"l":"Configuration reference","p":["1.2","10 000","100","1000","16","200","64","64 MiB","advisory RAM budget (see Durability)","alpha","Backend","background delete-consolidation trigger; 0 = manual","both","build search width","build_beam","cache_bytes","consolidate_threshold","construction search width L","Default","default query search width","default query search width L","degree","DiskANN","ef_construction","ef_search","Every knob is on VectorModule::builder(dim, metric). Resolved parameters are persisted in the index header, so a reopened index keeps its settings.","F32","F32 / F16 / I8 stored-vector encoding","graph connectivity M","Hnsw","Hnsw or DiskAnn","Knob","m","Meaning","Per-query, .ef(n) on the fluent filter overrides ef_search (HNSW) or search_beam (DiskANN) — turn it up for higher recall, down for lower latency.","PQ bytes per code; 0 = exact traversal","pq_subvectors","pq_train_threshold","precision","RobustPrune diversity slack (≥ 1.0)","search_beam","train PQ once N vectors are indexed","Vamana out-degree R"]},{"l":"Precision","p":["Precision selects the stored-vector codec, trading size for exactness:","Bytes/dim","Notes","F32","4","exact (default)","F16","2","IEEE half; ~exact for normalized embeddings","I8","1","per-vector scalar quantization; ~4× smaller, approximate","For DiskANN, PQ codes only guide traversal; the final ranking is always an exact re-rank against the stored vectors at the chosen precision."]},{"l":"Deletes & consolidation (DiskANN)","p":["A delete is correct immediately: the freed slot is held aside (never reused until cleaned), and stale in-edges resolve to a dead sentinel that queries skip.","Once consolidate_threshold deletes accumulate, a background thread (single-flight, chunked so queries interleave) runs a FreshDiskANN-style pass: it drops references to deleted nodes, reconnects through their surviving neighbors, re-prunes to degree, and reclaims the slots.","Closing the database runs a final synchronous consolidation so the persisted state is clean. You can also trigger it manually via DiskAnnIndex::consolidate()."]},{"l":"Persistence & durability","p":["Backend","Storage","Durability","HNSW","Nitrite NitriteMap (e.g. fjall)","per-write, atomic with the DB","DiskANN","memory-mapped flat file + sidecar next to the DB","flush-on-close","The DiskANN index is derived data (rebuildable from the documents), so a crash before flush costs at most a reindex — the documents themselves are always safe in the main store. Use the HNSW backend if you need per-write index durability.","cache_bytes is advisory for DiskANN: because the store is memory-mapped, the OS page cache bounds resident memory and reclaims cold pages under pressure, so the index cannot OOM from its vector data."]},{"l":"Performance","p":["~0.10 ms","~0.19 ms","~0.4 ms / vector inserted","~12 ns","~4.6× faster than single-threaded","Allocation-free vector decode into reused buffers.","ANN is float-heavy; always benchmark and deploy --release. A debug build is roughly an order of magnitude slower.","Build throughput","DiskANN query (k=10, PQ + exact re-rank)","DiskANN, 128 queries across 8 threads","Distance kernel (128-dim, SIMD)","Fast integer hashing (rustc-hash) on the query hot path.","HNSW ≥ 0.95, DiskANN + PQ ≥ 0.90","HNSW query (k=10)","Indicative release-build numbers on a 10-core laptop, 384-dim embeddings, 2k index:","Lock-free per-query read view (DiskANN) — one lock per query, not per node, so concurrent queries scale instead of contending.","Numbers vary with dataset, dimension, recall target, and hardware. Run the benchmarks yourself:","Operation","Portable SIMD distance kernels (wide f32x8) — pure Rust, no C dependency, so it cross-compiles cleanly to ARM NEON for mobile.","Recall vs brute force","Result","The crate is tuned to approach hand-optimized ANN libraries:"]},{"i":"performance-code-1","c":["cargo bench -p nitrite_vector"]},{"l":"How it compares","p":["nitrite-vector is embedded / in-process, so the fair comparison is other in-process libraries, not networked databases:","Category","Examples","Query latency includes","In-process (fair)","usearch, hnswlib, FAISS-HNSW, sqlite-vec, LanceDB","just the index lookup","Client–server","Qdrant, Milvus, Weaviate, Pinecone, pgvector","index + network + serialization","Against networked vector DBs, any in-process index avoids the network tax (often several milliseconds of round-trip and serialization per query).","Against in-process libraries, the distance kernels and query concurrency are in the same class; on AVX-512 servers a hand-tuned kernel can still be faster (the portable SIMD targets AVX2 / NEON).","The DiskANN backend adds something most embedded libraries don't: it serves indexes larger than RAM at roughly sub-millisecond query latency, at the cost of SSD reads and flush-on-close durability.","Treat these as same-class-as-embedded-ANN-libraries, not a head-to-head benchmark win."]},{"l":"When to use which backend","p":["HNSW — the index fits comfortably in RAM and you want the fastest queries and per-write durability. This is the default.","DiskANN — the index is (or will grow) larger than RAM, e.g. large on-device corpora on mobile, and you can accept flush-on-close durability for a derived index.","For small text-matching needs, the Full-Text Search module or the core field(...).text(...) filters may be all you need — reach for the vector store when you have embeddings and want semantic / kNN search."]}],[{"l":"Spatial Module","p":["The nitrite-spatial crate adds spatial indexes and spatial filter builders for geometry-aware queries."]},{"l":"Add the dependency"},{"i":"add-the-dependency-code-1","c":["[dependencies]\nnitrite = \"0.4\"\nnitrite-spatial = \"0.4\""]},{"l":"Load the module"},{"i":"load-the-module-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_spatial::SpatialModule;\n\nlet db = Nitrite::builder()\n    .load_module(SpatialModule)\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"l":"Create a spatial index"},{"i":"create-a-spatial-index-code-1","c":["use nitrite_spatial::spatial_index;\n\nlet collection = db.collection(\"locations\").expect(\"collection open failed\");\ncollection.create_index(vec![\"location\"], &spatial_index())\n    .expect(\"spatial index failed\");"]},{"l":"Query with spatial filters","p":["The fluent entry point is spatial_field(name).","Available spatial operations include:","intersects(...)","within(...)","near(...)","geo_near(...)","knearest(...)","The module also exports geometry helpers such as Geometry, Point, GeoPoint, Coordinate, and parsing helpers for WKT and GeoJSON."]},{"i":"query-with-spatial-filters-code-1","c":["use nitrite_spatial::{spatial_field, GeoPoint, Geometry};\n\nlet bbox = Geometry::envelope(-74.0, 40.7, -73.9, 40.9);\nlet mut within_city = collection.find(\n    spatial_field(\"location\").within(bbox)\n).expect(\"spatial query failed\");\n\nlet origin = GeoPoint::new(45.0, -93.265).expect(\"invalid point\");\nlet mut nearby = collection.find(\n    spatial_field(\"location\")\n        .geo_near(origin, 5_000.0)\n        .expect(\"invalid geo_near query\")\n).expect(\"spatial query failed\");\n\nlet _ = within_city.next();\nlet _ = nearby.next();"]}],[{"l":"Full-Text Search","p":["The nitrite-tantivy-fts crate adds Tantivy-backed full-text indexing and a dedicated full-text query DSL."]},{"l":"Add the dependency"},{"i":"add-the-dependency-code-1","c":["[dependencies]\nnitrite = \"0.4\"\nnitrite-tantivy-fts = \"0.4\""]},{"l":"Load the module","p":["The simplest configuration uses TantivyFtsModule::default().","You can also build a tuned module configuration."]},{"i":"load-the-module-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_tantivy_fts::TantivyFtsModule;\n\nlet db = Nitrite::builder()\n    .load_module(TantivyFtsModule::default())\n    .open_or_create(None, None)\n    .expect(\"failed to open database\");"]},{"i":"load-the-module-code-2","c":["use nitrite_tantivy_fts::TantivyFtsModule;\n\nlet module = TantivyFtsModule::with_config()\n    .index_writer_heap_size(100 * 1024 * 1024)\n    .num_threads(4)\n    .build();"]},{"l":"Create an FTS index"},{"i":"create-an-fts-index-code-1","c":["use nitrite_tantivy_fts::fts_index;\n\nlet collection = db.collection(\"articles\").expect(\"collection open failed\");\ncollection.create_index(vec![\"content\"], &fts_index())\n    .expect(\"fts index failed\");"]},{"l":"Query with fts_field","p":["matches() uses Tantivy's query parser, so it supports multi-term searches, required terms with +, excluded terms with -, and boolean operators. contains() and text() are aliases for matches()."]},{"i":"query-with-fts_field-code-1","c":["use nitrite_tantivy_fts::fts_field;\n\nlet mut matches = collection.find(\n    fts_field(\"content\").matches(\"+rust +database\")\n).expect(\"fts query failed\");\n\nlet mut exact_phrase = collection.find(\n    fts_field(\"content\").phrase(\"embedded database\")\n).expect(\"fts phrase query failed\");\n\nlet _ = matches.next();\nlet _ = exact_phrase.next();"]},{"l":"Batch commit behavior","p":["In the current 0.4 line, full-text writes and deletes are buffered and committed on the next search or on db.close() instead of once per document. Searches still observe their own writes because Nitrite commits the dirty batch and reloads the Tantivy reader before executing the query.","For bulk indexing this is much faster than committing every document individually. A clean close flushes any remaining FTS batch; an unclean crash can lose only the uncommitted derived index batch, which Nitrite can rebuild."]},{"l":"When to use this module","p":["The core crate already supports field(...).text(...) filters and the core full_text_index() helper. Use the Tantivy module when you want a dedicated search index and query parser rather than the core text-matching path."]}],[{"l":"Usage","p":["Unlike the Java and Flutter SDKs, the Rust SDK does not have a separate nitrite-support package. Instead, functionality is split into focused crates."]},{"l":"Core installation","p":["For most applications, start with the core crate and the derive macros.","Equivalent Cargo.toml entries look like this:"]},{"i":"core-installation-code-1","c":["cargo add nitrite\ncargo add nitrite-derive"]},{"i":"core-installation-code-2","c":["[dependencies]\nnitrite = \"0.4\"\nnitrite-derive = \"0.4\""]},{"l":"Optional crates","p":["Add only the modules you need."]},{"i":"optional-crates-code-1","c":["cargo add nitrite-fjall-adapter\ncargo add nitrite-spatial\ncargo add nitrite-tantivy-fts"]},{"i":"optional-crates-code-2","c":["[dependencies]\nnitrite = \"0.4\"\nnitrite-derive = \"0.4\"\nnitrite-fjall-adapter = \"0.4\"\nnitrite-spatial = \"0.4\"\nnitrite-tantivy-fts = \"0.4\""]},{"l":"One naming detail to remember","p":["Cargo dependency names use hyphens, while Rust import paths use underscores.","For example:","dependency: nitrite-fjall-adapter","import: use nitrite_fjall_adapter::FjallModule;","The same pattern applies to nitrite-spatial -> nitrite_spatial and nitrite-tantivy-fts -> nitrite_tantivy_fts."]},{"l":"Versioning guidance","p":["Keep the Nitrite crates on the same release line unless you have a specific compatibility reason not to. The current source tree uses 0.4.x across the core, derive, Fjall, spatial, and Tantivy FTS crates.","0.4.0 changes the on-disk index and key format (see Schema Migration). Rebuild a 0.3.x database before reading it with 0.4.x."]}],[{"i":"#","p":["This guide will help you get started with Nitrite database. It will show you how to create a database, create a collection, insert documents, and query documents in Flutter."]},{"l":"Getting Started in Flutter","p":["Nitrite is a pure Dart database. It does not depend on any native library. So it can be used in any platform where Dart is supported. It is a server-less embedded database ideal for desktop, mobile, or web applications. It is written in pure Dart and runs in Flutter, Dart VM, and the browser."]},{"l":"Add dependency","p":["To use Nitrite in you project, add the following package to your package:","To add the nitrite code generator to your project:","More details about the code generator can be found here.","To use the hive storage adapter to your project add the below package:","More details about the hive adapter can be found here.","Nitrite is null safe. So you can use it in your null safe project."]},{"i":"add-dependency-code-1","c":["dart pub add nitrite"]},{"i":"add-dependency-code-2","c":["dart pub add --dev build_runner\ndart pub add --dev nitrite_generator"]},{"i":"add-dependency-code-3","c":["dart pub add nitrite_hive_adapter"]}],[{"l":"Database","p":["Nitrite database is a serverless, embedded, and self-contained database for Flutter. It is an open-source project that provides a simple API for persistent data storage. Nitrite database is designed to be lightweight, fast, and easy to use."]},{"l":"Creating a Database","p":["Nitrite database can be created in-memory or on-disk. By default, Nitrite database is created in-memory. To create a database on-disk, you need to add a storage module dependency to your project. More details about storage modules can be found here.","To create a database, you need to use NitriteBuilder class. To get an instance of NitriteBuilder, you need to call builder() method on Nitrite class."]},{"i":"creating-a-database-code-1","c":["var builder = Nitrite.builder();"]},{"l":"In-memory Database","p":["If you don't load any on-disk storage module, then Nitrite will create an in-memory database. The below code snippet shows how to create a database in-memory."]},{"i":"in-memory-database-code-1","c":["var db = await Nitrite.builder()\n    .openOrCreate();"]},{"l":"On-disk Database","p":["The below code snippet shows how to create a database on-disk."]},{"l":"Hive Backed Database","p":["More details about Hive configuration can be found here."]},{"i":"hive-backed-database-code-1","c":["var storeModule = HiveModule.withConfig()\n    .crashRecovery(true)\n    .path(\"/path/to/my.db\")\n    .build();\n\nvar db = await Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate();"]},{"l":"NitriteBuilder","p":["NitriteBuilder is the builder class for Nitrite database. It provides methods to configure and create a Nitrite database instance."]},{"l":"Open or Create a Database","p":["To open or create a database, you need to call openOrCreate() method on NitriteBuilder instance. This method returns a FutureNitrite instance.","If no StoreModule is configured, then Nitrite will create an in-memory database. If a StoreModule is configured, then Nitrite will create an on-disk database. If the database file does not exist, then Nitrite will create a new database file. If the database file exists, then Nitrite will open the database file."]},{"i":"open-or-create-a-database-code-1","c":["var db = await Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate();"]},{"l":"Securing a Database","p":["To secure a database, you need to call openOrCreate() method with username and password on NitriteBuilder instance. This method returns a FutureNitrite instance with the given username and password.","If you are using a file-based database, then you need to use the same username and password to open the database again. Otherwise, you will get a NitriteSecurityException.","Both username and password must be provided or both must be null."]},{"i":"securing-a-database-code-1","c":["var db = await Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate(username: \"user\", password: \"password\");"]},{"l":"Registering an EntityConverter","p":["Nitrite database uses a mapper to map a Dart object to a document and vice versa. By default, Nitrite uses SimpleNitriteMapper as its mapper. This mapper uses EntityConverters to map a Dart object to a document and vice versa. To register an EntityConverter, you need to call registerEntityConverter() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","More details about EntityConverter can be found here."]},{"i":"registering-an-entityconverter-code-1","c":["var db = await Nitrite.builder()\n    .loadModule(storeModule)\n    .registerEntityConverter(MyEntityConverter())\n    .openOrCreate();"]},{"l":"Loading a Module","p":["Nitrite database is modular in nature. It provides various modules to extend its functionality. To load a module, you need to call loadModule() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance."]},{"l":"Loading a Storage Module","p":["More on the Nitrite's module system can be found here."]},{"i":"loading-a-storage-module-code-1","c":["var db = Nitrite.builder()\n    .loadModule(storeModule)\n    .openOrCreate();"]},{"l":"Adding Migration Steps","p":["Nitrite database supports schema migration. To configure a migration step, you need to call addMigrations() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","More on the schema migration can be found here."]},{"i":"adding-migration-steps-code-1","c":["var migration = Migration(\n    initialSchemaVersion,\n    2,\n    (instructionSet) {\n        instructionSet.forDatabase().addUser('test-user', 'test-password');\n\n        instructionSet\n            .forRepository<OldClass>(key: 'demo1')\n            .renameRepository('new')\n            .changeDataType('empId', (value) => int.parse(value))\n            .changeIdField(Fields.withNames(['uuid']), Fields.withNames(['empId']))\n            .deleteField('uuid')\n            .renameField('lastName', 'familyName')\n            .addField('fullName', generator: (document) =>\n                '${document['firstName']} ${document['familyName']}',\n            )\n            .dropIndex(['firstName'])\n            .dropIndex(['literature.text'])\n            .changeDataType('literature.ratings', (value) => (value as double).round());\n    },\n);\n\nvar db = await Nitrite.builder()\n    .loadModule(storeModule)\n    .addMigrations([migration])\n    .openOrCreate();"]},{"l":"Current Schema Version","p":["To get the current schema version of a database, you need to call schemaVersion() method on NitriteBuilder instance. This method returns the current schema version of the database.","By default, the initial schema version is set to 1."]},{"i":"current-schema-version-code-1","c":["var db = await Nitrite.builder()\n    .loadModule(storeModule)\n    .schemaVersion(2);\n    .openOrCreate();"]},{"l":"Field Separator Character","p":["To configure the field separator character, you need to call fieldSeparator() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","It is used to separate field names in a nested document. For example, if a document has a field address which is a nested document, then the field street of the nested document can be accessed using address.street syntax.","The default field separator character is set to .."]},{"i":"field-separator-character-code-1","c":["var db = await Nitrite.builder()\n    .loadModule(storeModule)\n    .fieldSeparator('.')\n    .openOrCreate();"]},{"l":"Disable Repository Type Validation","p":["To disable repository type validation, you need to call disableRepositoryTypeValidation() method on NitriteBuilder instance. This method returns the same NitriteBuilder instance.","Repository type validation is a feature in Nitrite that ensures the type of the objects stored in the repository can be converted to and from the document. By default, the repository type validation is enabled. If you disable it, and if you try to store an object that cannot be converted to a document, Nitrite will throw an exception during the operation."]},{"i":"disable-repository-type-validation-code-1","c":["var db = await Nitrite.builder()\n    .loadModule(storeModule)\n    .disableRepositoryTypeValidation()\n    .openOrCreate();"]}],[{"l":"Document","p":["Document is the basic unit of data in Nitrite database. It is a JSON like field-value pairs. The field is always a String and value can be anything including null. Document is schema-less, which means you can store any kind of data in a document.","Nitrite document supports nested document. That means, a value of a field can be another document. This allows you to create complex data structure."]},{"l":"Document Structure","p":["Nitrite document has the following structure."]},{"i":"document-structure-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"address\": {\n        \"street\": \"123 Main Street\",\n        \"city\": \"New York\",\n        \"state\": \"NY\",\n        \"zip\": \"10001\"\n    },\n    \"phone\": [\n        \"212-555-1234\",\n        \"646-555-4567\"\n    ]\n}"]},{"l":"Document Field","p":["Document field is always a String. It can be any valid string. The field cannot be null or empty string.","Below fields are reserved and cannot be used as key in a document.","_id : The unique identifier of a document. This field is auto-generated by Nitrite database during insertion.","_revision : The revision number of a document. This field is auto-generated by Nitrite database during insertion and update.","_source : The source collection name of a document.","_modified : The last modified timestamp of a document. This field is auto-generated by Nitrite database during insertion and update."]},{"l":"Document Value","p":["Document value can be any valid Dart object. It can be null or any of the below types.","String","int","double","bool","List","Map","Set","DateTime","NitriteId","Document"]},{"l":"Document Identifier","p":["It is a unique identifier of a document. It is auto-generated by Nitrite database during insertion. It is a NitriteId and is stored as a String in the document."]},{"l":"NitriteId","p":["NitriteId is a unique identifier across the Nitrite database. Each document in a nitrite collection is associated with a NitriteId.","During insertion if a unique String value representing a integer is supplied in the _id field of the document, then the value of the _id field will be used to generate the NitriteId. Otherwise, a new NitriteId will be generated and will be used in the _id field of the document.","The value of the NitriteId is a String representation of a 64-bit integer. The id generation is based on Twitter Snowflake algorithm. The id is composed of:","41 bits for time in milliseconds","10 bits for a machine id","12 bits for a sequence number","1 unused sign bit","The id is not guaranteed to be monotonically increasing. The id is sortable and the timestamp is stored in the id itself."]},{"l":"Retrieving a NitriteId from a Document","p":["The id can be retrieved from a document using Document.id getter. If the document does not have an id, then it will create a new NitriteId and will set it in the document and will return the id. If the document already has an id, then it will return the id."]},{"i":"retrieving-a-nitriteid-from-a-document-code-1","c":["var document = createDocument(\"firstName\", \"John\");\n\nvar id = document.id;"]},{"l":"Field Separator","p":["To access a field of a nested document, or an element of an array field, you need to use the field separator.","Field separator is configurable. You can change the field separator character by calling NitriteBuilder.fieldSeparator() method.","Nitrite uses . as field separator by default."]},{"i":"field-separator-code-1","c":["var db = await nitriteBuilder()\n    .fieldSeparator('.')\n    .openOrCreate();"]},{"l":"Nested Document","p":["To specify or access a field of a nested document, you need to use the field separator character. That means, if a document has a field address which is a nested document, then the field street of the nested document can be accessed using address.street syntax."]},{"l":"Array Field","p":["To specify or access an element of an array field, you need to use the index of the element. For example, if a document has a field phone which is an array, then the first element of the array can be accessed using phone.0 syntax."]},{"l":"Creating a Document","p":["To create a document, you need to use createDocument() function."]},{"l":"Creating an Empty Document"},{"i":"creating-an-empty-document-code-1","c":["var document = emptyDocument();"]},{"l":"Creating a Document with Initial Field-value Pair"},{"i":"creating-a-document-with-initial-field-value-pair-code-1","c":["var document = createDocument(\"firstName\", \"John\");"]},{"l":"Creating a Document with a Map"},{"i":"creating-a-document-with-a-map-code-1","c":["var map = {\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"address\": {\n        \"street\": \"123 Main Street\",\n        \"city\": \"New York\",\n        \"state\": \"NY\",\n        \"zip\": \"10001\"\n    },\n    \"phone\": [\n        \"212-555-1234\",\n        \"646-555-4567\"\n    ]\n};\n\nvar document = documentFromMap(map);"]},{"l":"Updating a Document","p":["To update a document, you need to use Document.put() method. This method takes two parameters, the field name and the value. If the field already exists in the document, then the value will be updated. If the field does not exist, then it will be created.","You can also use the [] operator to update a document."]},{"i":"updating-a-document-code-1","c":["var document = createDocument(\"firstName\", \"John\");\n\ndocument.put(\"lastName\", \"Doe\");\ndocument[\"address\"] = createDocument(\"street\", \"123 Main Street\");"]},{"l":"Retrieving a Value from Document","p":["To retrieve a value from document, you need to use Document.get() method. This method takes one parameter, the field name. If the field exists in the document, then the value will be returned. If the field does not exist, then it will return null.","You can also use the [] operator to retrieve a value from a document.","To retrieve a value from a nested document, use the field separator character.","To retrieve an element from an array field, use the index of the element."]},{"i":"retrieving-a-value-from-document-code-1","c":["var document = createDocument(\"firstName\", \"John\");\n\nvar firstName = document.get(\"firstName\");\nvar firstName = document[\"firstName\"];"]},{"i":"retrieving-a-value-from-document-code-2","c":["var document = createDocument(\"firstName\", \"John\")\n    .put(\"address\", createDocument(\"street\", \"123 Main Street\"));\n\nvar street = document.get<String>(\"address.street\");"]},{"i":"retrieving-a-value-from-document-code-3","c":["var document = createDocument(\"firstName\", \"John\")\n    .put(\"phone\", [\"212-555-1234\", \"646-555-4567\"]);\n\nvar phone = document.get<String>(\"phone.0\");"]},{"l":"Removing a Field from Document","p":["To remove a field from document, you need to use Document.remove() method. This method takes one parameter, the field name. If the field exists in the document, then it will be removed. If the field does not exist, then it will do nothing.","To remove a field from a nested document, use the field separator character.","To remove an element from an array field, use the index of the element."]},{"i":"removing-a-field-from-document-code-1","c":["var document = createDocument(\"firstName\", \"John\");\n\ndocument.remove(\"firstName\");"]},{"i":"removing-a-field-from-document-code-2","c":["var document = createDocument(\"firstName\", \"John\")\n    .put(\"address\", createDocument(\"street\", \"123 Main Street\"));\n\ndocument.remove(\"address.street\");"]},{"i":"removing-a-field-from-document-code-3","c":["var document = createDocument(\"firstName\", \"John\")\n    .put(\"phone\", [\"212-555-1234\", \"646-555-4567\"]);\n\ndocument.remove(\"phone.0\");"]},{"l":"Checking If a Field Exists in Document","p":["To check if a field exists in a document, you need to use Document.containsKey() method. This method takes one parameter, the field name. If the field exists in the document, then it will return true. If the field does not exist, then it will return false.","To check if a field exists in a nested document, use the field separator character.","It cannot check if an element exists in an array field."]},{"i":"checking-if-a-field-exists-in-document-code-1","c":["var document = createDocument(\"firstName\", \"John\");\n\nvar exists = document.containsKey(\"firstName\");"]},{"i":"checking-if-a-field-exists-in-document-code-2","c":["var document = createDocument(\"firstName\", \"John\")\n    .put(\"address\", createDocument(\"street\", \"123 Main Street\"));\n\nvar exists = document.containsKey(\"address.street\");"]}],[{"l":"Introduction","p":["NitriteCollection represents a named document collection stored in a Nitrite database. It persists documents in a Nitrite database. It is similar to a table in relational database or a collection in MongoDB.","Each document in a collection is associated with a unique NitriteId. It exposes a set of methods to perform CRUD operations on documents. It also supports indexing and querying. It also supports event based notification on document changes."]},{"l":"Creating a Collection","p":["A NitriteCollection can be created using Nitrite class. You need to call getCollection() method on Nitrite class to get an instance of a FutureNitriteCollection.","If the collection does not exist, then it will be created automatically. If a collection with the same name already exists, then it will return the existing collection."]},{"i":"creating-a-collection-code-1","c":["var db = await nitriteBuilder()\n    .openOrCreate();\n\nvar collection = await db.getCollection(\"myCollection\");"]},{"l":"Limitations on Collection Name","p":["A collection name cannot be null or empty string. It cannot contains any of the following characters:","| (pipe)",": (colon)","+ (plus)","The name also cannot be any of the following reserved words:","$nitrite_users","$nitrite_index_meta","$nitrite_index","$nitrite_meta_map","$nitrite_store_info","$nitrite_catalog"]}],[{"l":"Write Operations"},{"l":"Inserting Documents","p":["Documents can be inserted into a collection using insert() or insertMany() methods. It takes one or multiple Document objects as input parameter respectively. It returns a FutureWriteResult object.","If the document has a NitriteId already in it's _id field, then it will be used as a unique key to identify the document in the collection. Otherwise, a new NitriteId will be generated and inserted into the document.","If any of the field is already indexed in the collection, then the index will be updated accordingly.","This operation will notify all the registered CollectionEventListener with EventType.insert event."]},{"l":"Inserting a Single Document"},{"i":"inserting-a-single-document-code-1","c":["var doc = createDocument(\"firstName\", \"John\")\n    ..put(\"lastName\", \"Doe\")\n    ..put(\"age\", 30)\n    ..put(\"data\", Uint8List.fromList([1, 2, 3, 4, 5]));\n\nvar result = await collection.insert(doc);"]},{"l":"Inserting Multiple Documents"},{"i":"inserting-multiple-documents-code-1","c":["var doc1 = createDocument(\"firstName\", \"John\")\n    ..put(\"lastName\", \"Doe\")\n    ..put(\"age\", 30)\n    ..put(\"data\", Uint8List.fromList([1, 2, 3, 4, 5]));\n\nvar doc2 = createDocument(\"firstName\", \"Jane\")\n    ..put(\"lastName\", \"Doe\")\n    ..put(\"age\", 25)\n    ..put(\"data\", Uint8List.fromList([1, 2, 3, 4, 5]));\n\nvar result = await collection.insertMany([doc1, doc2]);"]},{"l":"Error Scenarios","p":["If the document contains invalid value in it's _id field, then it will throw a InvalidIdException.","If there is another document with the same _id value in the collection, then it will throw a UniqueConstraintException.","If a field of the document is unique indexed and it's value violates the index constraint, then it will throw a UniqueConstraintException."]},{"l":"WriteResult","p":["WriteResult contains the result of a write operation. It contains the following information:","Number of documents affected by the write operation. You can get this value using getAffectedCount() method.","List of NitriteId of the documents affected by the write operation. The WriteResults implements IterableNitriteId interface. So you can iterate over the WriteResult to get the NitriteId of the documents affected by the write operation."]},{"l":"Updating Documents","p":["Documents can be updated using any of the following methods:","updateOne() - Updates a single document.","update() - Update the filtered documents in the collection.","All update methods returns a FutureWriteResult object.","This operation will notify all the registered CollectionEventListener with EventType.update event."]},{"l":"Updating a Single Document","p":["You can update a single document using updateOne() method. It takes a Document object as input parameter. It returns a FutureWriteResult object. The document must contain a valid NitriteId in it's _id field.","If the document does not contain a valid NitriteId in it's _id field, then it will throw a NotIdentifiableException."]},{"i":"updating-a-single-document-code-1","c":["var doc = createDocument(\"_id\", existingDoc.id)\n    ..put(\"age\", 30);\n\nvar result = await collection.updateOne(doc);"]},{"l":"Upserting a Single Document","p":["You can also upsert a single document using updateOne() method. Along with the document parameter, you need to pass a named parameter insertIfAbsent with value true. If the document does not exist in the collection, then it will be inserted. Otherwise, it will be updated. The default value of insertIfAbsent is false."]},{"i":"upserting-a-single-document-code-1","c":["var doc = createDocument(\"_id\", existingDoc.id)\n    ..put(\"lastName\", \"Doe\")\n    ..put(\"age\", 30);\n\nvar result = await collection.updateOne(doc, insertIfAbsent: true);"]},{"l":"Updating Using a Filter","p":["You can update multiple documents using a filter. It takes a Filter object as the first input parameter. It takes a Document object as the second input parameter. It returns a FutureWriteResult object."]},{"i":"updating-using-a-filter-code-1","c":["var update = createDocument(\"_id\", existingDoc.id)\n    ..put(\"lastName\", \"Doe\")\n    ..put(\"age\", 30)\n    ..put(\"data\", Uint8List.fromList([1, 2, 3, 4, 5]));\n\nvar result = await collection.update(where(\"firstName\").eq(\"John\"), update);"]},{"l":"Updating Using a Filter and Options","p":["You can update multiple documents using a filter and options. It takes a Filter object as the first input parameter. It takes a Document object as the second input parameter. It takes a UpdateOptions object as the optional third input parameter. It returns a FutureWriteResult object."]},{"l":"UpdateOptions","p":["UpdateOptions is a class that contains several options for update operation. It has the following options:","insertIfAbsent: If this option is true, then it will insert the document if it does not exist in the collection. Otherwise, it will update the document if it exists in the collection.","justOnce: If this option is true, then it will update only the first document matched by the filter. Otherwise, it will update all the documents matched by the filter."]},{"i":"updateoptions-code-1","c":["var update = createDocument(\"_id\", existingDoc.id)\n    ..put(\"lastName\", \"Doe\")\n    ..put(\"age\", 30)\n    ..put(\"data\", Uint8List.fromList([1, 2, 3, 4, 5]));\n\nvar updateOptions = UpdateOptions();\nupdateOptions.insertIfAbsent = true;\nupdateOptions.justOnce = true;\n\nvar result = await collection.update(where(\"firstName\").eq(\"John\"), update, updateOptions);"]},{"l":"Removing Documents","p":["Documents can be removed from a collection using any of the following methods:","removeOne() - Removes a single document.","remove() - Removes the filtered documents from the collection.","All remove methods returns a FutureWriteResult object.","This operation will notify all the registered CollectionEventListener with EventType.remove event."]},{"l":"Removing a Single Document","p":["You can remove a single document using removeOne() method. It takes a Document object as input parameter. It returns a FutureWriteResult object. The document must contain a valid NitriteId in it's _id field.","If the document does not contain a valid NitriteId in it's _id field, then it will throw a NotIdentifiableException."]},{"i":"removing-a-single-document-code-1","c":["var doc = createDocument(\"_id\", existingDoc.id);\n\nvar result = await collection.removeOne(doc);"]},{"l":"Removing Using a Filter","p":["You can remove multiple documents using a filter. It takes a Filter object as the input parameter. It returns a FutureWriteResult object."]},{"i":"removing-using-a-filter-code-1","c":["var result = await collection.remove(where(\"firstName\").eq(\"John\"));"]},{"l":"Removing Using a Filter and Options","p":["You can remove multiple documents using a filter and options. It takes a Filter object as the first input parameter. It takes a named parameter justOne with value true or false. If the value is true, then it will remove only the first document matched by the filter. Otherwise, it will remove all the documents matched by the filter. The default value of justOne is false. It returns a FutureWriteResult object."]},{"i":"removing-using-a-filter-and-options-code-1","c":["var result = await collection.remove(where(\"firstName\").eq(\"John\"), justOne: true);"]}],[{"l":"Read Operations"},{"l":"Find Operations","p":["You can search documents in a collection using find() method. There are several ways of using find() method using a filter or find options or both. You can also search a document using it's NitriteId."]},{"l":"Filters","p":["Nitrite uses filters to find documents in a collection. A filter is a simple expression which evaluates to true or false. More information about filters can be found here."]},{"l":"Find All Documents","p":["You can find all documents in a collection by calling find(). It returns a DocumentCursor object."]},{"i":"find-all-documents-code-1","c":["var cursor = collection.find();"]},{"l":"Finding a Document Using NitriteId","p":["You can find a document using it's NitriteId by calling getById(). It takes a NitriteId as input parameter. It returns a FutureDocument? object if the document is found. Otherwise, it returns null."]},{"i":"finding-a-document-using-nitriteid-code-1","c":["var doc = await collection.getById(someNitriteId);"]},{"l":"Finding a Document Using a Filter","p":["You can find a document using a filter. It takes a Filter object as input parameter. It returns a DocumentCursor object.","If there is an index on the field specified in the filter, this operation will use the index to find the document. Otherwise, it will scan the entire collection to find the document."]},{"i":"finding-a-document-using-a-filter-code-1","c":["var cursor = collection.find(where(\"firstName\").eq(\"John\"));"]},{"l":"Finding a Document Using a Filter and Options","p":["You can find a document using a filter and options. It takes a Filter object as the first input parameter. It takes a FindOptions object as the second input parameter. It returns a DocumentCursor object."]},{"l":"FindOptions","p":["FindOptions is a class that contains several options for find operation. It has the following options:","limit: It specifies the maximum number of documents to be returned by the find operation.","skip: It specifies the number of documents to be skipped from the beginning of the result set.","orderBy: It specifies a collection of fields to be sorted by, along with sort order for each field. The sort order can be SortOrder.ascending or SortOrder.descending.","distinct: It specifies if the find operation should return distinct documents. If this option is true, then it will return only the distinct documents. Otherwise, it will return all the documents matched by the filter."]},{"i":"findoptions-code-1","c":["var findOptions = FindOptions();\nfindOptions.setSkip(10)\n    ..setLimit(10)\n    ..thenOrderBy(\"firstName\", SortOrder.descending)\n    ..withDistinct(true);\n\nvar cursor = collection.find(filter: where(\"firstName\").eq(\"John\"), findOptions: findOptions);"]},{"l":"DocumentCursor","p":["DocumentCursor represents a result set of a find operation. It provides methods to iterate over the result of a find operation and retrieve the documents. It also provides methods like projection, join etc. to get the desired result."]},{"l":"Iterating Over Documents","p":["The DocumentCursor extends StreamDocument. So, you can iterate over the documents using await for loop.","A DocumentCursor is a stream of document. It does not load all the documents in memory at once. It loads the documents in memory as needed. So, it is memory efficient."]},{"i":"iterating-over-documents-code-1","c":["var cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nawait for (var doc in cursor) {\n  // do something with the document\n}"]},{"l":"Getting the Documents","p":["You can get the documents from a DocumentCursor using toList() method. It returns a FutureListDocument object."]},{"i":"getting-the-documents-code-1","c":["var cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nvar docs = await cursor.toList();"]},{"l":"Getting the First Document","p":["You can get the first document from a DocumentCursor using first getter. It returns a FutureDocument? object."]},{"i":"getting-the-first-document-code-1","c":["var cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nvar doc = await cursor.first;"]},{"l":"Getting the Size of the Result Set","p":["You can get the size of the result set from a DocumentCursor using length getter. It returns a Futureint object."]},{"i":"getting-the-size-of-the-result-set-code-1","c":["var cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nvar size = await cursor.length;"]},{"l":"Projection","p":["You can project a field or a set of fields from a DocumentCursor using project() method. It takes a Document as input parameter. It returns a StreamDocument object.","The document must contain only the fields that needs to be projected. The field values must be null or a nested document. The condition holds true for nested documents as well.","Let's say you have a document like this:","And you want to project only lastName and address.street fields. Then you can do it like this:","The result set will contain only lastName and address.street fields."]},{"i":"projection-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"address\": {\n        \"street\": \"123 Main Street\",\n        \"city\": \"New York\"\n    }\n}"]},{"i":"projection-code-2","c":["var cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nvar projection = createDocument(\"lastName\", null)\n    ..put(\"address\", createDocument(\"street\", null));\n\nvar projectedCursor = cursor.project(projection);"]},{"i":"projection-code-3","c":["[\n    {\n        \"lastName\": \"Doe\",\n        \"address\": {\n            \"street\": \"123 Main Street\"\n        }\n    }\n]"]},{"l":"Join","p":["You can join two DocumentCursor using leftJoin() method. It takes another DocumentCursor as input parameter along with a Lookup object. It returns a StreamDocument object.","The join operation is similar to SQL left outer join operation. It takes two cursors and a lookup object. The lookup object contains the join condition.","Let's say you have two collections users and orders. The users collection contains the following documents:","And the orders collection contains the following documents:","And you want to join these two collections on userId field. Then you can do it like this:","The result set will contain the following documents:"]},{"i":"join-code-1","c":["{\n    \"userId\": 1,\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\"\n}"]},{"i":"join-code-2","c":["{\n    \"userId\": 2,\n    \"firstName\": \"Jane\",\n    \"lastName\": \"Doe\"\n}"]},{"i":"join-code-3","c":["{\n    \"orderId\": 1,\n    \"userId\": 1,\n    \"orderDate\": \"2018-01-01\"\n}"]},{"i":"join-code-4","c":["{\n    \"orderId\": 2,\n    \"userId\": 1,\n    \"orderDate\": \"2018-01-02\"\n}"]},{"i":"join-code-5","c":["{\n    \"orderId\": 3,\n    \"userId\": 2,\n    \"orderDate\": \"2018-01-03\"\n}"]},{"i":"join-code-6","c":["{\n    \"orderId\": 4,\n    \"userId\": 2,\n    \"orderDate\": \"2018-01-04\"\n}"]},{"i":"join-code-7","c":["var userCollection = await db.collection(\"users\");\nvar orderCollection = await db.collection(\"orders\");\n\nvar users = userCollection.find();\nvar orders = orderCollection.find();\n\nvar lookup = Lookup();\nlookup.setLocalField(\"userId\");\nlookup.setForeignField(\"userId\");\nlookup.setTargetField(\"orders\");\n\nvar joinedCursor = users.leftJoin(orders, lookup);"]},{"i":"join-code-8","c":["{\n    \"userId\": 1,\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"orders\": [\n        {\n            \"orderId\": 1,\n            \"userId\": 1,\n            \"orderDate\": \"2018-01-01\"\n        },\n        {\n            \"orderId\": 2,\n            \"userId\": 1,\n            \"orderDate\": \"2018-01-02\"\n        }\n    ]\n}"]},{"i":"join-code-9","c":["{\n    \"userId\": 2,\n    \"firstName\": \"Jane\",\n    \"lastName\": \"Doe\",\n    \"orders\": [\n        {\n            \"orderId\": 3,\n            \"userId\": 2,\n            \"orderDate\": \"2018-01-03\"\n        },\n        {\n            \"orderId\": 4,\n            \"userId\": 2,\n            \"orderDate\": \"2018-01-04\"\n        }\n    ]\n}"]},{"l":"FindPlan","p":["FindPlan is a class that contains the execution plan of a find operation. It has the following properties:","byIdFilter: It contains the filter for finding a document using NitriteId.","indexScanFilter: It contains the filter for finding a document using index.","collectionScanFilter: It contains the filter for finding a document using full scan.","indexDescriptor: It contains the index descriptor for finding a document using index.","indexScanOrder: It contains the sort order for finding a document using index.","blockingSortOrder: It contains the sort order for finding a document using full scan.","skip: It contains the number of documents to be skipped from the beginning of the result set.","limit: It contains the maximum number of documents to be returned by the find operation.","distinct: It specifies if the find operation returns distinct documents.","subPlans: It contains the sub plans for finding a document using or filter.","You can get the execution plan of a find operation using findPlan getter. It returns a FutureFindPlan object."]},{"i":"findplan-code-1","c":["var cursor = collection.find(where(\"firstName\").eq(\"John\"));\n\nvar findPlan = await cursor.findPlan;"]}],[{"l":"Indexing","p":["Indexing is a way to optimize the performance of a database by minimizing the number of disk accesses required when a query is processed. It is a data structure technique which is used to quickly locate and access the data in a database.","Nitrite supports indexing on a collection. It supports indexing on a single field or multiple fields. It also supports full-text indexing."]},{"l":"Index Types","p":["Nitrite supports the following types of index out of the box:","Unique Index","Non-Unique Index","Full-text Index"]},{"l":"Unique Index","p":["A unique index ensures that the indexed field contains unique value. It does not allow duplicate value in the indexed field. It also ensures that the indexed field is not null."]},{"l":"Non-unique Index","p":["A non-unique index does not ensure that the indexed field contains unique value. It allows duplicate value in the indexed field."]},{"l":"Full-text Index","p":["A full-text index is used to search text content in a document. It is useful when you want to search text content in a document. It is also useful when you want to search text content in a document in a language other than English.","Document's _id field is always indexed.","Indexing on non-comparable value is not supported."]},{"l":"Custom Index","p":["You can also create your own custom index. You need to implement NitriteIndexer interface to create your own custom index. NitriteIndexer is a NitritePlugin, so you need to register it using loadModule() method while opening a database. During index creation you need to pass the type of the custom index in IndexOptions object.","One of such custom index implementation can be found in spatial module. It provides spatial indexing on a collection. More on spatial indexing can be found here."]},{"l":"Creating an Index","p":["You can create an index on a collection using createIndex() method. There are several overloaded version of createIndex() method. You can create an index on a single field or multiple fields.","You cannot create a new index on a field or a set of fields which is already indexed with a different type of index.","For example, if you have a unique index on firstName field, then you cannot create a non-unique index on firstName field. But you can create a unique index on firstName and lastName fields. Similarly, if you have a unique index on firstName and lastName fields, then you cannot create a non-unique index on firstName and lastName fields. But you can create two indexes on firstName and lastName fields separately."]},{"l":"Creating a Unique Index","p":["You can create a unique index on a single field or multiple fields. It takes the name of the fields on which the index will be created as input parameter."]},{"i":"creating-a-unique-index-code-1","c":["// create a unique index on a single field\nawait collection.createIndex([\"firstName\"]);\n\n// create a unique index on multiple fields\nawait collection.createIndex([\"firstName\", \"lastName\"]);"]},{"l":"Creating a Non-unique Index","p":["You can create a non-unique index on a single field or multiple fields by passing the index type as IndexType.nonUnique in IndexOptions object and the name of the fields on which the index will be created as input parameters."]},{"i":"creating-a-non-unique-index-code-1","c":["// create a non-unique index on a single field\nawait collection.createIndex([\"firstName\"], indexOptions(IndexType.nonUnique));\n\n// create a non-unique index on multiple fields\nawait collection.createIndex([\"firstName\", \"lastName\"], indexOptions(IndexType.nonUnique));"]},{"l":"Creating a Full-text Index","p":["You can create a full-text index on a single field by passing the index type as IndexType.fullText in IndexOptions object and the name of the fields on which the index will be created as input parameters.","Full-text index is not supported on multiple fields."]},{"i":"creating-a-full-text-index-code-1","c":["// create a full-text index on a single field\nawait collection.createIndex([\"firstName\"], indexOptions(IndexType.fullText));"]},{"l":"Creating Index on Array Field","p":["Nitrite supports creating index on array field. It will create index on each element of the array. For example, if you have a document like this:","You can create index on phones field like this:"]},{"i":"creating-index-on-array-field-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"age\": 30,\n    \"address\": \"123 Street\",\n    \"phones\": [\"1234567890\", \"0987654321\"]\n}"]},{"i":"creating-index-on-array-field-code-2","c":["// create unique index on array field\nawait collection.createIndex([\"phones\"]);\n\n// create non-unique index on array field\nawait collection.createIndex([\"phones\"], indexOptions(IndexType.nonUnique));"]},{"l":"Creating Index on Nested Field","p":["You can create index on nested field. For example, if you have a document like this:","You can create index on street field like this:","You cannot create index on nested field if the parent field is an array."]},{"i":"creating-index-on-nested-field-code-1","c":["{\n    \"firstName\": \"John\",\n    \"lastName\": \"Doe\",\n    \"age\": 30,\n    \"phones\": [\"1234567890\", \"0987654321\"],\n    \"address\": {\n        \"street\": \"123 Street\",\n        \"city\": \"New York\",\n        \"state\": \"NY\",\n        \"zip\": \"10021\"\n    }\n}"]},{"i":"creating-index-on-nested-field-code-2","c":["// create unique index on nested field\nawait collection.createIndex([\"address.street\"]);"]},{"l":"Rebuilding an Index","p":["You can rebuild an index on a collection using rebuildIndex() method. It takes the name of the fields on which the index will be rebuilt as input parameter."]},{"i":"rebuilding-an-index-code-1","c":["// rebuild index on a single field\nawait collection.rebuildIndex([\"firstName\"]);\n\n// rebuild index on multiple fields\nawait collection.rebuildIndex([\"firstName\", \"lastName\"]);"]},{"l":"Dropping an Index","p":["You can drop an index on a collection using dropIndex() method. It takes the name of the fields on which the index will be dropped as input parameter."]},{"i":"dropping-an-index-code-1","c":["// drop index on a single field\nawait collection.dropIndex([\"firstName\"]);\n\n// drop index on multiple fields\nawait collection.dropIndex([\"firstName\", \"lastName\"]);"]},{"l":"Dropping All Indexes","p":["You can drop all indexes on a collection using dropAllIndices() method."]},{"i":"dropping-all-indexes-code-1","c":["await collection.dropAllIndices();"]},{"l":"Getting All Indexes","p":["You can get all indexes on a collection using listIndices() method. It returns a FutureCollection of IndexDescriptor object."]},{"i":"getting-all-indexes-code-1","c":["Collection<IndexDescriptor> indexes = await collection.listIndices();"]},{"l":"IndexDescriptor","p":["IndexDescriptor is a simple class which contains the following information about an index:","collectionName: The name of the collection on which the index is created.","indexType: The type of the index.","fields: A Fields object containing the name of the fields on which the index is created."]},{"l":"Checking If an Index Exists","p":["You can check if an index exists on a collection using hasIndex() method. It takes the name of the fields on which the index will be checked as input parameter."]},{"i":"checking-if-an-index-exists-code-1","c":["// check if an index exists on a single field\nbool exists = await collection.hasIndex([\"firstName\"]);\n\n// check if an index exists on multiple fields\nbool exists = await collection.hasIndex([\"firstName\", \"lastName\"]);"]},{"l":"Error Scenarios","p":["The following error scenarios are possible while creating an index:","If another index of any type is already created on the collection on the same field(s), then it will throw IndexingException.","If a unique index is created on a field and the field contains duplicate value, then it will throw UniqueConstraintException.","If a full-text index is created on multiple fields, then it will throw IndexingException.","If a full-text index is created on a field which is not a String, then it will throw IndexingException.","If you try to drop an index which does not exist, then it will throw IndexingException.","If you try to rebuild an index which does not exist, then it will throw IndexingException."]}],[{"l":"Other Operations"},{"l":"Size of a Collection","p":["You can get the size of a collection using size getter. It returns a future of the number of documents in the collection."]},{"i":"size-of-a-collection-code-1","c":["int size = await collection.size;"]},{"l":"Clearing a Collection","p":["You can clear all the documents from a collection using clear() method. It removes all the documents from the collection and index entries from the indexes. It does not drop the collection."]},{"i":"clearing-a-collection-code-1","c":["await collection.clear();"]},{"l":"Dropping a Collection","p":["You can drop a collection using drop() method. It removes all the documents from the collection and index entries from the indexes. It also drops all the indexes associated with the collection. It also removes the collection from the database.","You can call isDropped getter to check if the collection is dropped or not.","Any further operation on a dropped collection will throw NitriteIOException."]},{"i":"dropping-a-collection-code-1","c":["await collection.drop();"]},{"i":"dropping-a-collection-code-2","c":["bool isDropped = await collection.isDropped;"]},{"l":"Closing a Collection","p":["You can close a collection using close() method. Any further operation on a closed collection will throw NitriteIOException.","After closing a collection, you must re-open it via Nitrite.getCollection() method to perform any operation on it.","You can call isOpen getter to check if the collection is closed or not."]},{"i":"closing-a-collection-code-1","c":["await collection.close();"]},{"i":"closing-a-collection-code-2","c":["bool isOpen = await collection.isOpen;"]},{"l":"Event Listener","p":["You can register an event listener on a collection to get notified on document changes. The event listener must implement CollectionEventListener interface. It will receive CollectionEventInfo whenever a document is inserted, updated or removed from the collection.","You can also remove an event listener from a collection."]},{"i":"event-listener-code-1","c":["collection.subscribe((eventInfo) {\n  // do something\n});"]},{"i":"event-listener-code-2","c":["collection.unsubscribe(listener);"]},{"l":"CollectionEventInfo","p":["CollectionEventInfo contains the following information:","item - the document which is inserted, updated or removed.","originator - the name of the collection on which the event is fired.","eventType - the type of the event. It can be any of the following:","EventType.insert","EventType.update","EventType.remove","EventType.indexStart","EventType.indexEnd","timestamp - the timestamp of the event."]},{"l":"Attributes","p":["Attributes is a metadata information associated with a collection.","You can get/set attributes on a collection. The attributes are stored in the database and can be retrieved later. The attributes are stored in a special map named $nitrite_meta_map."]},{"i":"attributes-code-1","c":["// get the attributes\nvar attributes = await collection.getAttributes();\nattributes.set(\"key\", \"value\");\n\n// save the attributes\nawait collection.setAttributes(attributes);\n\n// get the attributes\nattributes = await collection.getAttributes();\n\n// get the value of a key\nvar value = attributes[\"key\"];"]},{"l":"Processors","p":["Processors are used to process documents before writing them into or after reading them from a collection.","Processors are useful when you want to add some additional information in a document or transform any field before inserting or updating it in a collection. Processors are also useful when you want to validate a document before inserting or updating it in a collection.","Processors are registered on a collection. A collection can have multiple processors. Processors are executed in the order they are registered."]},{"l":"Registering a Processor","p":["You can register a processor on a collection using addProcessor() method. It takes a Processor as input parameter."]},{"i":"registering-a-processor-code-1","c":["class MyProcessor extends Processor {\n    @override\n    Document processBeforeWrite(Document document) {\n        // do something\n    }\n\n    @override\n    Document processAfterRead(Document document) {\n        // do something\n    }\n}\n\n// create a processor\nvar processor = MyProcessor();\n\n// process existing documents, if the collection is not empty\nawait processor.process(collection);\n\n// register the processor\nawait collection.addProcessor(processor);"]},{"l":"Available Processors","p":["Nitrite provides a StringFieldEncryptionProcessor which can be used to encrypt a field before writing it into a collection and decrypt a field after reading it from a collection.","More on this is described in Support."]}],[{"l":"Introduction","p":["ObjectRepository provides a simple and type-safe API for storing and retrieving Dart objects in a Nitrite database. It is built on top of NitriteCollection and provides a similar API for CRUD operations. It also supports indexing and querying. It also supports event based notification on object changes."]},{"l":"Creating a Repository","p":["An ObjectRepository can be created using Nitrite class. You need to call getRepository() method on Nitrite class to get an instance of an ObjectRepository. If the repository does not exist, then it will be created automatically. If a repository with the same name already exists, then it will return the existing repository.","There are several options available to create a repository. You can pass a class type or an EntityDecorator along with an optional string key to create a repository."]},{"l":"Creating a Repository with Class Type","p":["You can create a ObjectRepository by passing a class type to getRepository() method."]},{"i":"creating-a-repository-with-class-type-code-1","c":["ObjectRepository<Employee> repository = await db.getRepository<Employee>();"]},{"l":"Creating a Repository with Class Type and Key","p":["You can create a keyed ObjectRepository by passing a class type and a key to getRepository() method.","One typical use case of this keyed repository is to create a repository for each user in a multi-user application. The key can be the user name or user id. This will ensure that each user will have a separate repository for storing objects."]},{"i":"creating-a-repository-with-class-type-and-key-code-1","c":["ObjectRepository<Employee> repository = await db.getRepository<Employee>(key: \"myKey\");"]},{"l":"Creating a Repository with EntityDecorator","p":["A ObjectRepository can be created using EntityDecorator. This is useful when you cannot modify the object class to add annotations.","More details about EntityDecorator can be found here."]},{"i":"creating-a-repository-with-entitydecorator-code-1","c":["ObjectRepository<Employee> repository = await db.getRepository<Employee>(entityDecorator: EmployeeDecorator());"]},{"l":"Creating a Repository with EntityDecorator and Key","p":["A keyed ObjectRepository can be created using EntityDecorator and a key. This is useful when you cannot modify the object class to add annotations.","More details about EntityDecorator can be found here."]},{"i":"creating-a-repository-with-entitydecorator-and-key-code-1","c":["ObjectRepository<Employee> repository = await db.getRepository<Employee>(entityDecorator: EmployeeDecorator(), key: \"myKey\");"]}],[{"l":"Code Generator","p":["Nitrite provides Dart build system builders to extract metadata and generate code for entity classes which is used by ObjectRepository. The builders generate code when they find a class annotated with some Nitrite specific annotations. The generated code is written to a file that is named after the source file, but with .no2.dart extension.","Flutter doesn't support reflection, so the generated code is used to extract metadata and generate code for entity classes.","There are two generators available:","Entity Generator - Extracts metadata from classes annotated with @Entity and generates code for entity classes.","Converter Generator - Scans the classes annotated with @Convertable and generates the code to convert the Dart classes to Nitrite documents and vice-versa.","Both of these generators are available in the nitrite_generator package."]},{"l":"Setup","p":["Add the following package as your dev dependency:","Once you have added the annotations to your code, you can run the generator using the build_runner command-line tool:"]},{"i":"setup-code-1","c":["dart pub add --dev build_runner\ndart pub add --dev nitrite_generator"]},{"i":"setup-code-2","c":["dart run build_runner build"]},{"l":"Annotations for Entity Generator","p":["The following annotations are used by the entity generator:","@Entity - Marks a class as an entity class.","@Id - Marks a field as the primary key of the entity.","@Index - Provides index information for entity fields.","More on each of these annotations is here."]},{"l":"Annotations for Converter Generator","p":["The following annotations are used by the converter generator:","@Convertable - Generates the EntityConverter for the class.","@DocumentKey - Specifies the name of the field in the document.","@IgnoredKey - Marks a field as ignored while converting to document.","More on each of these annotations is here."]},{"l":"Examples","p":["Consider a book entity class and it's generated code:"],"c":["import 'package:nitrite/nitrite.dart'; part 'book.no2.dart'; @Convertable(className: 'MyBookConverter') @Entity(name: 'books', indices: [ Index(fields: ['tags'], type: IndexType.nonUnique), Index(fields: ['description'], type: IndexType.fullText), Index(fields: ['price', 'publisher']), ]) class Book with _$BookEntityMixin { @Id(fieldName: 'book_id', embeddedFields: ['isbn', 'book_name']) @DocumentKey(alias: 'book_id') BookId? bookId; String? publisher; double? price; List<String> tags = []; String? description; Book( [this.bookId, this.publisher, this.price, this.tags = const [], this.description]); } @Convertable() class BookId { String? isbn; @DocumentKey(alias: \"book_name\") String? name; @IgnoredKey() String? author; }","// GENERATED CODE - DO NOT MODIFY BY HAND part of 'book.dart'; // ************************************************************************** // NitriteEntityGenerator // ************************************************************************** mixin _$BookEntityMixin implements NitriteEntity { @override String get entityName => \"books\"; @override List<EntityIndex> get entityIndexes => const [ EntityIndex([\"tags\"], IndexType.nonUnique), EntityIndex([\"description\"], IndexType.fullText), EntityIndex([\"price\", \"publisher\"], IndexType.unique), ]; @override EntityId get entityId => EntityId( \"book_id\", false, [\"isbn\", \"book_name\"], ); } // ************************************************************************** // ConverterGenerator // ************************************************************************** class MyBookConverter extends EntityConverter<Book> { @override Book fromDocument( Document document, NitriteMapper nitriteMapper, ) { var entity = Book(); entity.bookId = nitriteMapper.tryConvert<BookId, Document>(document['book_id']); entity.publisher = document['publisher']; entity.price = document['price']; entity.tags = EntityConverter.toList(document['tags'], nitriteMapper); entity.description = document['description']; return entity; } @override Document toDocument( Book entity, NitriteMapper nitriteMapper, ) { var document = emptyDocument(); document.put( 'book_id', nitriteMapper.tryConvert<Document, BookId>(entity.bookId)); document.put('publisher', entity.publisher); document.put('price', entity.price); document.put('tags', EntityConverter.fromList(entity.tags, nitriteMapper)); document.put('description', entity.description); return document; } } class BookIdConverter extends EntityConverter<BookId> { @override BookId fromDocument( Document document, NitriteMapper nitriteMapper, ) { var entity = BookId(); entity.isbn = document['isbn']; entity.name = document['book_name']; return entity; } @override Document toDocument( BookId entity, NitriteMapper nitriteMapper, ) { var document = emptyDocument(); document.put('isbn', entity.isbn); document.put('book_name', entity.name); return document; } }"]},{"l":"Limitations","p":["There are certain limitations of each of the generators as described below:"]},{"l":"Entity Generator","p":["@Entity annotation can only be used on a class.","@Id annotation can only be used on a field and once per class.","@Id field should be one of the following data types:","num","int","double","String","Runes","bool","DateTime","Duration","NitriteId","A class in case of embedded id.","@Id field should not be static or synthetic."]},{"l":"Converter Generator","p":["@Convertable annotation can only be used on a class and enum and not on an abstract class or mixin.","@Convertable can only be used on a class which has at least one public constructor which is either a default constructor or one with all the parameters named or optional.","@DocumentKey annotation can not be used on a private/static/synthetic field.","@DocumentKey, @IgnoredKey annotation can only be used on a field or property.","@IgnoredKey annotation can not be used on a field with the same name as a non-null required named parameter in the constructor.","A class with a constructor having all named parameters (optional/required) should have all the fields' names same as the parameter names.","A class with a constructor having all positional optional parameters should not have any final field.","A getter must be defined for corresponding setter or vice-versa.","Any field with user-defined class type should be nullable.","dynamic type is not supported.","Function types are not supported.","If any of the above limitations are not met, then the generator will throw an exception and the build will fail.","Nested collection is not supported.","Never type is not supported.","Symbol type is not supported.","There are certain limitations on the fields and its data types:","Void type is not supported."]}],[{"l":"Entity","p":["An entity is a Dart object that can be stored in a collection. An entity can be a simple class with a few fields or a complex class with nested objects. Every entity in an ObjectRepository is actually converted to a Document before storing in the underlying NitriteCollection. When an entity is converted to a Document, the fields of the entity are mapped to the fields of the Document. While retrieving an entity from the ObjectRepository, the Document is converted back to the entity.","Nitrite uses a NitriteMapper implementation to convert an entity to a Document and vice versa. By default, Nitrite uses an EntityConverter based implementation of NitriteMapper to convert an entity to a Document. You can also provide your own implementation of NitriteMapper to convert an entity to a Document.","More on NitriteMapper can be found here."]},{"l":"Annotations","p":["Nitrite uses annotations to define an entity. There are several annotations available to define an entity. These annotations are:","@Entity","@Id","@Index","Flutter does not support reflection. So, Nitrite uses code generators to process these annotations and generates the metadata for an entity. The entity generator generates a mixin for an entity class in a separate file that is named after the source file, but with .no2.dart extension.","The name of the mixin is like - _$ + ClassName + EntityMixin. For example, if the entity class name is Person, the mixin name will be _$PersonEntityMixin. The generated mixin also implements NitriteEntity interface which defines few getters to access the metadata of the entity. You need to add this mixin to your entity class to make it a Nitrite entity.","The entity generator is a separate package and more on the entity generator can be found here."]},{"i":"entity-1","l":"@Entity","p":["The @Entity annotation marks a class as an entity class. The annotation has the following properties:","name - The name of the collection to which the entity belongs. If not specified, the name of the class is used as the collection name.","indices - An array of @Index annotations. The indices are created on the fields specified in the @Index annotation.","The above code generates the following code in book.no2.dart:","Now you can use the generated mixin in your entity class:"],"c":["import 'package:nitrite/nitrite.dart'; @Entity() class Book { @Id() String? bookId; String? publisher; double? price; List<String> tags = []; String? description; Book([ this.bookId, this.publisher, this.price, this.tags = const [], this.description, ]); }","import 'package:nitrite/nitrite.dart'; @Entity(name: 'books', indices: [ Index(fields: ['tags'], type: IndexType.nonUnique), Index(fields: ['description'], type: IndexType.fullText), Index(fields: ['price', 'publisher']), ]) class Book { @Id() String? bookId; String? publisher; double? price; List<String> tags = []; String? description; Book([ this.bookId, this.publisher, this.price, this.tags = const [], this.description, ]); }","// GENERATED CODE - DO NOT MODIFY BY HAND part of 'book.dart'; // ************************************************************************** // NitriteEntityGenerator // ************************************************************************** mixin _$BookEntityMixin implements NitriteEntity { @override String get entityName => \"Book\"; @override List<EntityIndex> get entityIndexes => const []; @override EntityId get entityId => EntityId( \"bookId\", false, ); }","// GENERATED CODE - DO NOT MODIFY BY HAND part of 'book.dart'; // ************************************************************************** // NitriteEntityGenerator // ************************************************************************** mixin _$BookEntityMixin implements NitriteEntity { @override String get entityName => \"books\"; @override List<EntityIndex> get entityIndexes => const [ EntityIndex([\"tags\"], IndexType.nonUnique), EntityIndex([\"description\"], IndexType.fullText), EntityIndex([\"price\", \"publisher\"], IndexType.unique), ]; @override EntityId get entityId => EntityId( \"bookId\", false, ); }","import 'package:nitrite/nitrite.dart'; part 'book.no2.dart'; @Entity() class Book with _$BookEntityMixin { @Id() String? bookId; String? publisher; double? price; List<String> tags = []; String? description; Book([ this.bookId, this.publisher, this.price, this.tags = const [], this.description, ]); }","import 'package:nitrite/nitrite.dart'; part 'book.no2.dart'; @Entity(name: 'books', indices: [ Index(fields: ['tags'], type: IndexType.nonUnique), Index(fields: ['description'], type: IndexType.fullText), Index(fields: ['price', 'publisher']), ]) class Book with _$BookEntityMixin { @Id() String? bookId; String? publisher; double? price; List<String> tags = []; String? description; Book([ this.bookId, this.publisher, this.price, this.tags = const [], this.description, ]); }"]},{"l":"@Id","p":["The @Id annotation marks a field as the unique identifier of the entity. It is a field level annotation and takes optional fieldName parameter. The fieldName parameter is used to specify the name of the field in the document. If the fieldName parameter is not specified, then the name of the field in the class will be used as the name of the field in the document.","The above code generates the following code in book.no2.dart:"],"c":["import 'package:nitrite/nitrite.dart'; @Entity() class Book with _$BookEntityMixin { @Id() String? bookId; String? publisher; double? price; List<String> tags = []; String? description; Book([ this.bookId, this.publisher, this.price, this.tags = const [], this.description, ]); }","import 'package:nitrite/nitrite.dart'; @Entity() class Book with _$BookEntityMixin { @Id(fieldName: 'book_id') String? bookId; String? publisher; double? price; List<String> tags = []; String? description; Book([ this.bookId, this.publisher, this.price, this.tags = const [], this.description, ]); }","// GENERATED CODE - DO NOT MODIFY BY HAND part of 'book.dart'; // ************************************************************************** // NitriteEntityGenerator // ************************************************************************** mixin _$BookEntityMixin implements NitriteEntity { @override String get entityName => \"Book\"; @override List<EntityIndex> get entityIndexes => const []; @override EntityId get entityId => EntityId( \"bookId\", false, ); }","// GENERATED CODE - DO NOT MODIFY BY HAND part of 'book.dart'; // ************************************************************************** // NitriteEntityGenerator // ************************************************************************** mixin _$BookEntityMixin implements NitriteEntity { @override String get entityName => \"Book\"; @override List<EntityIndex> get entityIndexes => const []; @override EntityId get entityId => EntityId( \"book_id\", false, ); }"]},{"l":"Embedded Id","p":["Nitrite also supports embedded id. The embedded id is used when the entity has a composite primary key. The @Id annotation can also be used to mark a field as an embedded id. In case of embedded id, the field should be marked with @Id annotation and the fieldName and embeddedFields parameters should be specified. The fieldName parameter is used to specify the name of the field in the document. The embeddedFields parameter is used to specify the name of the fields in the embedded object.","The above code generates the following code in book.no2.dart:","The above @Id annotation will create a unique compound index on the fields - book_id.isbn and book_id.title."]},{"i":"embedded-id-code-1","c":["import 'package:nitrite/nitrite.dart';\n\n@Entity()\nclass Book with _$BookEntityMixin {\n  @Id(fieldName: 'book_id', embeddedFields: ['isbn', 'title'])\n  BookId? bookId;\n  String? publisher;\n  double? price;\n  List<String> tags = [];\n  String? description;\n\n  Book([\n    this.bookId,\n    this.publisher,\n    this.price,\n    this.tags = const [],\n    this.description,\n  ]);\n}\n\nclass BookId {\n  String? isbn;\n  String? title;\n  String? author;\n}"]},{"i":"embedded-id-code-2","c":["// GENERATED CODE - DO NOT MODIFY BY HAND\n\npart of 'book.dart';\n\n// **************************************************************************\n// NitriteEntityGenerator\n// **************************************************************************\n\nmixin _$BookEntityMixin implements NitriteEntity {\n  @override\n  String get entityName => \"Book\";\n  @override\n  List<EntityIndex> get entityIndexes => const [];\n  @override\n  EntityId get entityId => EntityId(\n        \"book_id\",\n        false,\n        embeddedFields: [\"isbn\", \"title\"],\n      );\n}"]},{"l":"Data Type","p":["The data type of the field marked with @Id annotation should be one of the following:","num","int","double","String","Runes","bool","DateTime","Duration","NitriteId","In case of embedded id, the data type of the field marked with @Id annotation should be a class."]},{"l":"@Index","p":["@Index annotation is used to declare an index on an entity field. It is a class level annotation and takes mandatory fields parameter and optional type parameter. The fields parameter is used to specify the names of the fields in the document to be indexed. The type parameter is used to specify the type of the index. If the type parameter is not specified, then the type of the index will be IndexType.unique.","The above code generates the following code in book.no2.dart:","The above @Index annotations will create the following indices:","tags - Non-unique simple index","description - Full-text index","price and publisher - Unique compound index","@Index annotation can be used on super class as well. When the entity class extends a super class, the @Index annotations of the super class are also processed by the entity generator."]},{"i":"index-code-1","c":["import 'package:nitrite/nitrite.dart';\n\n@Entity(indices: [\n  Index(fields: ['tags'], type: IndexType.nonUnique),\n  Index(fields: ['description'], type: IndexType.fullText),\n  Index(fields: ['price', 'publisher']),\n])\nclass Book with _$BookEntityMixin {\n  String? bookId;\n  String? publisher;\n  double? price;\n  List<String> tags = [];\n  String? description;\n\n   Book([\n    this.bookId,\n    this.publisher,\n    this.price,\n    this.tags = const [],\n    this.description,\n  ]);\n}"]},{"i":"index-code-2","c":["// GENERATED CODE - DO NOT MODIFY BY HAND\n\npart of 'book.dart';\n\n// **************************************************************************\n// NitriteEntityGenerator\n// **************************************************************************\n\nmixin _$BookEntityMixin implements NitriteEntity {\n  @override\n  String get entityName => \"Book\";\n  @override\n  List<EntityIndex> get entityIndexes => const [\n        EntityIndex([\"tags\"], IndexType.nonUnique),\n        EntityIndex([\"description\"], IndexType.fullText),\n        EntityIndex([\"price\", \"publisher\"], IndexType.unique),\n      ];\n  @override\n  EntityId get entityId => EntityId(\n        \"bookId\",\n        false,\n      );\n}"]},{"i":"index-code-3","c":["import 'package:nitrite/nitrite.dart';\n\n@Entity(indices: [\n  Index(fields: ['tags'], type: IndexType.nonUnique),\n  Index(fields: ['price', 'publisher']),\n])\nclass Book extends BaseEntity with _$BookEntityMixin {\n  String? bookId;\n  String? publisher;\n  double? price;\n  List<String> tags = [];\n  \n  Book([\n    this.bookId,\n    this.publisher,\n    this.price,\n    this.tags = const [],\n    super.description,\n  ]);\n}\n\n@Index(fields: ['description'], type: IndexType.fullText)\nabstract class BaseEntity {\n  String? description;\n\n  BaseEntity([this.description]);\n}"]},{"i":"index-code-4","c":["// GENERATED CODE - DO NOT MODIFY BY HAND\n\npart of 'book.dart';\n\n// **************************************************************************\n// NitriteEntityGenerator\n// **************************************************************************\n\nmixin _$BookEntityMixin implements NitriteEntity {\n  @override\n  String get entityName => \"Book\";\n  @override\n  List<EntityIndex> get entityIndexes => const [\n        EntityIndex([\"tags\"], IndexType.nonUnique),\n        EntityIndex([\"price\", \"publisher\"], IndexType.unique),\n        EntityIndex([\"description\"], IndexType.fullText),\n      ];\n  @override\n  EntityId? get entityId => null;\n}"]},{"l":"EntityDecorator","p":["EntityDecorator is used to add metadata to an entity. If you cannot modify the entity class to add annotations, then you can use EntityDecorator to add metadata to an entity. You can use EntityDecorator to add id, indices and collection name for an entity.","While creating or opening a repository, you can pass an instance of EntityDecorator to the getRepository() method on Nitrite class. Nitrite will extract the metadata from the EntityDecorator instance and use it to create the repository.","To write an EntityDecorator for an entity, you need to implement the EntityDecorator interface. Let's take an example of a Product entity.","The Product entity has an embedded id ProductId and two indices on a nested object Manufacturer. To write an EntityDecorator for the Product entity with collection name 'products', you need to implement the EntityDecorator interface as follows.","which is equivalent to the following entity class when code generator is used:"]},{"i":"entitydecorator-code-1","c":["ObjectRepository<Product> repository = await db.getRepository<Product>(entityDecorator: ProductDecorator());"]},{"i":"entitydecorator-code-2","c":["class Product {\n    ProductId? productId;\n    Manufacturer? manufacturer;\n    String? productName;\n    double? price;\n\n    Product([\n        this.productId,\n        this.manufacturer,\n        this.productName,\n        this.price,\n    ]);\n}\n\nclass ProductId {\n    String? uniqueId;\n    String? productCode;\n\n    ProductId([\n        this.uniqueId,\n        this.productCode,\n    ]);\n}\n\nclass Manufacturer {\n    String? name;\n    String? uniqueId;\n\n    Manufacturer([\n        this.name,\n        this.uniqueId,\n    ]);\n}"]},{"i":"entitydecorator-code-3","c":["class ProductDecorator extends EntityDecorator<Product> {\n  @override\n  String get entityName => \"products\";\n\n  @override\n  EntityId? get idField => EntityId(\n        \"productId\",\n        false,\n        embeddedFields: [\"uniqueId\", \"productCode\"],\n      );\n\n  @override\n  List<EntityIndex> get indexFields => const [\n        EntityIndex([\"manufacturer.name\"], IndexType.nonUnique),\n        EntityIndex([\"productName\", \"manufacturer.uniqueId\"]),\n      ];\n}"]},{"i":"entitydecorator-code-4","c":["@Entity(name: 'products', indices: [\n  Index(fields: ['manufacturer.name'], type: IndexType.nonUnique),\n  Index(fields: ['productName', 'manufacturer.uniqueId']),\n])\nclass Product with _$ProductEntityMixin {\n  @Id(fieldName: 'productId', embeddedFields: ['uniqueId', 'productCode'])\n  ProductId? productId;\n  Manufacturer? manufacturer;\n  String? productName;\n  double? price;\n\n  Product([\n    this.productId,\n    this.manufacturer,\n    this.productName,\n    this.price,\n  ]);\n}\n\nclass ProductId {\n  String? uniqueId;\n  String? productCode;\n\n  ProductId([\n    this.uniqueId,\n    this.productCode,\n  ]);\n}\n\nclass Manufacturer {\n  String? name;\n  String? uniqueId;\n\n  Manufacturer([\n    this.name,\n    this.uniqueId,\n  ]);\n}"]},{"l":"EntityId","p":["EntityId is used to specify the id field of an entity. It takes mandatory fieldName parameter and optional embeddedFields parameter in case of embedded id. The fieldName parameter is used to specify the name of the field in the document. The embeddedFields parameter is used to specify the name of the fields in the embedded object.","Here productId is the name of the field in the document and uniqueId and productCode are the names of the fields in the embedded object. This will create a unique compound index on the fields - productId.uniqueId and productId.productCode."]},{"i":"entityid-code-1","c":["@override\nEntityId? get idField =>\n    EntityId('productId', false, ['uniqueId', 'productCode']);"]},{"l":"EntityIndex","p":["EntityIndex is used to specify the indices on an entity. It takes mandatory type parameter and fields parameter. The type parameter is used to specify the type of the index. The fields parameter is used to specify the name of the fields in the document to be indexed.","Here manufacturer.name is the name of the field in the document and productName and manufacturer.uniqueId are the names of the fields in the document. This will create a non-unique index on the field manufacturer.name and a unique compound index on the fields - productName and manufacturer.uniqueId."]},{"i":"entityindex-code-1","c":["@override\nList<EntityIndex> get indexFields => const [\n    EntityIndex(['manufacturer.name'], IndexType.nonUnique),\n    EntityIndex(['productName', 'manufacturer.uniqueId']),\n    ];"]},{"l":"Entity Name","p":["Entity name is used to specify the name of the collection in which the entity will be stored. It is a string value and can be specified using entityName getter.","Here products is the name of the NitriteCollection in which the product document will be stored."]},{"i":"entity-name-code-1","c":["@override\nString get entityName => \"products\";"]}],[{"l":"NitriteMapper","p":["NitriteMapper is a simple and lightweight object mapper which can be used to map Dart objects to Nitrite documents and vice-versa. Nitrite uses a NitriteMapper implementation to map Dart entities to Nitrite documents and vice-versa while storing and retrieving objects from an ObjectRepository."]},{"l":"SimpleNitriteMapper","p":["Nitrite provides a default NitriteMapper implementation called SimpleNitriteMapper. This is a simple and lightweight mapper which uses EntityConverter to map a Dart object to Nitrite documents and vice-versa. This mapper is suitable for most of the use cases."]},{"l":"EntityConverter","p":["EntityConverter is a simple interface which provides methods to convert a Dart object to Nitrite document and vice-versa. For each Dart class, you need to provide an implementation of EntityConverter and register it with SimpleNitriteMapper. SimpleNitriteMapper will use this converter to map the Dart object to Nitrite document and vice-versa.","You can write your own implementation of EntityConverter or you can use the code generator to generate the implementation for you. More on this is discussed here.","Let's take an example of Product class.","To map to Nitrite document, we need to provide an implementation of EntityConverter for each class. Let's take a look at the converter for Product class.","Similarly, we need to provide converters for ProductId and Manufacturer classes.","Once the converters are ready, we need to register them with registerEntityConverter() method on NitriteBuilder instance.","we can also register the converters with SimpleNitriteMapper instance and then pass the instance to loadModule() method.","NitriteMapper is a NitritePlugin. So, you need to load it using loadModule() method on NitriteBuilder. More on Nitrite's module system can be found here.","If you have used the registerEntityConverter() method on NitriteBuilder instance, Nitrite will only use SimpleNitriteMapper to map the entities. It will ignore any other NitriteMapper implementation you have provided using loadModule() method."]},{"i":"entityconverter-code-1","c":["class Product {\n    ProductId? productId;\n    Manufacturer? manufacturer;\n    String? productName;\n    double? price;\n    \n    Product({this.productId, this.manufacturer, this.productName, this.price});\n}\n\nclass ProductId {\n    String? uniqueId;\n    String? productCode;\n    \n    ProductId({this.uniqueId, this.productCode});\n}\n\nclass Manufacturer {\n    String? name;\n    String? address;\n    int? uniqueId;\n    \n    Manufacturer({this.name, this.address, this.uniqueId});\n}"]},{"i":"entityconverter-code-2","c":["class ProductConverter extends EntityConverter<Product> {\n    @override\n    Document toDocument(Product entity, NitriteMapper nitriteMapper) {\n        Document productId = nitriteMapper.tryConvert<Document, ProductId>(entity.productId);\n        Document manufacturer = nitriteMapper.tryConvert<Document, Manufacturer>(entity.manufacturer);\n\n        return emptyDocument()\n            .put(\"productId\", productId)\n            .put(\"manufacturer\", manufacturer)\n            .put(\"productName\", entity.productName)\n            .put(\"price\", entity.price);\n    }\n\n    @override\n    Product fromDocument(Document document, NitriteMapper nitriteMapper) {\n        var product = Product();\n        product.productId = nitriteMapper.tryConvert<ProductId, Document>(document[\"productId\"]);\n        product.manufacturer = nitriteMapper.tryConvert<Manufacturer, Document>(document[\"manufacturer\"]);\n        product.productName = document[\"productName\"];\n        product.price = document[\"price\"];\n\n        return product;\n    }\n}"]},{"i":"entityconverter-code-3","c":["class ProductIdConverter extends EntityConverter<ProductId> {\n    @override\n    Document toDocument(ProductId entity, NitriteMapper nitriteMapper) {\n        return emptyDocument()\n            .put(\"uniqueId\", entity.uniqueId)\n            .put(\"productCode\", entity.productCode);\n    }\n\n    @override\n    ProductId fromDocument(Document document, NitriteMapper nitriteMapper) {\n        var productId = ProductId();\n        productId.uniqueId = document[\"uniqueId\"];\n        productId.productCode = document[\"productCode\"];\n\n        return productId;\n    }\n}\n\nclass ManufacturerConverter extends EntityConverter<Manufacturer> {\n    @override\n    Document toDocument(Manufacturer entity, NitriteMapper nitriteMapper) {\n        return emptyDocument()\n            .put(\"name\", entity.name)\n            .put(\"address\", entity.address)\n            .put(\"uniqueId\", entity.uniqueId);\n    }\n\n    @override\n    Manufacturer fromDocument(Document document, NitriteMapper nitriteMapper) {\n        var manufacturer = Manufacturer();\n        manufacturer.name = document[\"name\"];\n        manufacturer.address = document[\"address\"];\n        manufacturer.uniqueId = document[\"uniqueId\"];\n\n        return manufacturer;\n    }\n}"]},{"i":"entityconverter-code-4","c":["var db = await Nitrite.builder()\n    .registerEntityConverter(ProductConverter())\n    .registerEntityConverter(ProductIdConverter())\n    .registerEntityConverter(ManufacturerConverter())\n    .openOrCreate();"]},{"i":"entityconverter-code-5","c":["var nitriteMapper = SimpleNitriteMapper();\nnitriteMapper.registerEntityConverter(ProductConverter());\nnitriteMapper.registerEntityConverter(ProductIdConverter());\nnitriteMapper.registerEntityConverter(ManufacturerConverter());\n\nvar db = await Nitrite.builder()\n    .loadModule(module(nitriteMapper))\n    .openOrCreate();"]},{"l":"Mapping Collections","p":["The EntityConverter interface provides some static methods to convert a collection of Dart objects to a collection of Nitrite documents and vice-versa.","These methods are:","fromList() - Converts a List of Dart objects to a List of Nitrite documents. If the type of the elements is a registered value type, it will return the same list without any conversion.","fromIterable() - Converts an Iterable of Dart objects to a List of Nitrite documents. If the type of the elements is a registered value type, it will return the same list without any conversion.","fromSet() - Converts a Set of Dart objects to a Set of Nitrite documents. If the type of the elements is a registered value type, it will return the same set without any conversion.","fromMap() - Converts a Map of key-value pair to a Map of Nitrite documents. If the type of the key or the value is a registered value type, it will not convert those objects to Nitrite document and return as is.","toList() - Converts a List of Nitrite documents to a List of Dart objects.","toIterable() - Converts an Iterable of Nitrite documents to an List of Dart objects.","toSet() - Converts a Set of Nitrite documents to a Set of Dart objects.","toMap() - Converts a Map of Nitrite documents to a Map of key value pair.","These methods are useful when you have a collection of objects as a property of a Dart class."]},{"l":"Example","p":["Let's take an example of Company class which has a map of Employee as a property.","To map this to Nitrite document, we need to provide an implementation of EntityConverter for Company class."]},{"i":"example-code-1","c":["class Company {\n  final int companyId;\n  final String companyName;\n  final DateTime? dateCreated;\n  final List<String> departments;\n  final Map<String, List<Employee>> employeeRecord;\n\n  Company({\n    this.companyId = 0,\n    this.companyName = '',\n    this.dateCreated,\n    this.departments = const [],\n    this.employeeRecord = const {},\n  });\n}\n\nclass Employee {\n  int? empId;\n  DateTime? joinDate;\n  String address;\n  String emailAddress;\n  List<int> blob;\n  Company? company;\n  Note? employeeNote;\n\n  Employee({\n    this.empId,\n    this.joinDate,\n    this.address = '',\n    this.emailAddress = '',\n    this.blob = const [],\n    this.company,\n    this.employeeNote,\n  });\n}\n\nclass Note {\n  final int noteId;\n  final String text;\n\n  Note({\n    this.noteId = 0,\n    this.text = '',\n  });\n}"]},{"i":"example-code-2","c":["class CompanyConverter extends EntityConverter<Company> {\n  @override\n  Company fromDocument(\n    Document document,\n    NitriteMapper nitriteMapper,\n  ) {\n    var map = <String, List<Employee>>{};\n    var employeeRecords = document['employeeRecord'] == null\n        ? {}\n        : document['employeeRecord'] as Map;\n\n    for (var entry in employeeRecords.entries) {\n      var key = nitriteMapper.tryConvert<String, dynamic>(entry.key);\n      var value = EntityConverter.toList<Employee>(entry.value, nitriteMapper);\n      map[key] = value;\n    }\n\n    var entity = Company(\n      companyId: document['company_id'] ?? 0,\n      companyName: document['companyName'] ?? \"\",\n      dateCreated: document['dateCreated'],\n      departments:\n          EntityConverter.toList(document['departments'], nitriteMapper),\n      employeeRecord: map,\n    );\n\n    return entity;\n  }\n\n  @override\n  Document toDocument(\n    Company entity,\n    NitriteMapper nitriteMapper,\n  ) {\n    var document = emptyDocument();\n    document.put('company_id', entity.companyId);\n    document.put('companyName', entity.companyName);\n    document.put('dateCreated', entity.dateCreated);\n    document.put('departments',\n        EntityConverter.fromList(entity.departments, nitriteMapper));\n    document.put('employeeRecord',\n        EntityConverter.fromMap(entity.employeeRecord, nitriteMapper));\n    return document;\n  }\n}\n\nclass EmployeeConverter extends EntityConverter<Employee> {\n  @override\n  Employee fromDocument(\n    Document document,\n    NitriteMapper nitriteMapper,\n  ) {\n    var entity = Employee(\n      empId: document['empId'],\n      joinDate: document['joinDate'],\n      address: document['address'] ?? \"\",\n      emailAddress: document['emailAddress'] ?? \"\",\n      blob: EntityConverter.toList(document['blob'], nitriteMapper),\n      company: nitriteMapper.tryConvert<Company, Document>(document['company']),\n      employeeNote:\n          nitriteMapper.tryConvert<Note, Document>(document['employeeNote']),\n    );\n    return entity;\n  }\n\n  @override\n  Document toDocument(\n    Employee entity,\n    NitriteMapper nitriteMapper,\n  ) {\n    var document = emptyDocument();\n    document.put('empId', entity.empId);\n    document.put('joinDate', entity.joinDate);\n    document.put('address', entity.address);\n    document.put('emailAddress', entity.emailAddress);\n    document.put('blob', EntityConverter.fromList(entity.blob, nitriteMapper));\n    document.put('employeeNote',\n        nitriteMapper.tryConvert<Document, Note>(entity.employeeNote));\n    return document;\n  }\n}\n\nclass NoteConverter extends EntityConverter<Note> {\n  @override\n  Note fromDocument(\n    Document document,\n    NitriteMapper nitriteMapper,\n  ) {\n    var entity = Note(\n      noteId: document['noteId'] ?? 0,\n      text: document['text'] ?? \"\",\n    );\n    return entity;\n  }\n\n  @override\n  Document toDocument(\n    Note entity,\n    NitriteMapper nitriteMapper,\n  ) {\n    var document = emptyDocument();\n    document.put('noteId', entity.noteId);\n    document.put('text', entity.text);\n    return document;\n  }\n}"]},{"l":"Code Generation","p":["Nitrite provides a code generator to generate the EntityConverter implementation for you. You have to annotate the class with some specific annotations and then run the code generator. The generated code will be saved in a separate file. You still need to register the generated converter with Nitrite.","The code generator is a separate package and more on the entity generator can be found here.","Nitrite uses below annotations to generate the EntityConverter implementation.","@Convertable","@DocumentKey","@IgnoredKey"]},{"l":"@Convertable","p":["@Convertable annotation is used to mark a class as convertable. This annotation is mandatory for the code generator to work. This annotation specifies the code generator to generate the EntityConverter implementation for the class. It takes an optional parameter className which is used to specify the name of the converter class. If this parameter is not specified, then the code generator will use the class name with Converter suffix as the converter class name.","This will generate the following code:","You need to register the generated converters with Nitrite by calling registerEntityConverter() method on NitriteBuilder instance."],"c":["@Convertable() class Book { BookId? bookId; String? publisher; double? price; List<String>? tags; String? description; Book({this.bookId, this.publisher, this.price, this.tags, this.description}); } @Convertable() class BookId { String? isbn; String? name; String? author; }","@Convertable(className: 'MyBookConverter') class Book { BookId? bookId; String? publisher; double? price; List<String>? tags; String? description; Book({this.bookId, this.publisher, this.price, this.tags, this.description}); } @Convertable() class BookId { String? isbn; String? name; String? author; }","// GENERATED CODE - DO NOT MODIFY BY HAND part of 'book.dart'; // ************************************************************************** // ConverterGenerator // ************************************************************************** class BookConverter extends EntityConverter<Book> { @override Book fromDocument(Document document, NitriteMapper nitriteMapper) { var book = Book(); book.bookId = nitriteMapper.tryConvert<BookId, Document>(document[\"bookId\"]); book.publisher = document[\"publisher\"]; book.price = document[\"price\"]; book.tags = EntityConverter.toList<String>(document[\"tags\"], nitriteMapper); book.description = document[\"description\"]; return book; } @override Document toDocument(Book entity, NitriteMapper nitriteMapper) { return emptyDocument() .put(\"bookId\", nitriteMapper.tryConvert<Document, BookId>(entity.bookId)) .put(\"publisher\", entity.publisher) .put(\"price\", entity.price) .put(\"tags\", EntityConverter.fromList<String>(entity.tags, nitriteMapper)) .put(\"description\", entity.description); } } class BookIdConverter extends EntityConverter<BookId> { @override BookId fromDocument(Document document, NitriteMapper nitriteMapper) { var bookId = BookId(); bookId.isbn = document[\"isbn\"]; bookId.name = document[\"name\"]; bookId.author = document[\"author\"]; return bookId; } @override Document toDocument(BookId entity, NitriteMapper nitriteMapper) { return emptyDocument() .put(\"isbn\", entity.isbn) .put(\"name\", entity.name) .put(\"author\", entity.author); } }","// GENERATED CODE - DO NOT MODIFY BY HAND part of 'book.dart'; // ************************************************************************** // ConverterGenerator // ************************************************************************** class MyBookConverter extends EntityConverter<Book> { @override Book fromDocument(Document document, NitriteMapper nitriteMapper) { var book = Book(); book.bookId = nitriteMapper.tryConvert<BookId, Document>(document[\"bookId\"]); book.publisher = document[\"publisher\"]; book.price = document[\"price\"]; book.tags = EntityConverter.toList<String>(document[\"tags\"], nitriteMapper); book.description = document[\"description\"]; return book; } @override Document toDocument(Book entity, NitriteMapper nitriteMapper) { return emptyDocument() .put(\"bookId\", nitriteMapper.tryConvert<Document, BookId>(entity.bookId)) .put(\"publisher\", entity.publisher) .put(\"price\", entity.price) .put(\"tags\", EntityConverter.fromList<String>(entity.tags, nitriteMapper)) .put(\"description\", entity.description); } } class BookIdConverter extends EntityConverter<BookId> { @override BookId fromDocument(Document document, NitriteMapper nitriteMapper) { var bookId = BookId(); bookId.isbn = document[\"isbn\"]; bookId.name = document[\"name\"]; bookId.author = document[\"author\"]; return bookId; } @override Document toDocument(BookId entity, NitriteMapper nitriteMapper) { return emptyDocument() .put(\"isbn\", entity.isbn) .put(\"name\", entity.name) .put(\"author\", entity.author); } }"]},{"i":"convertable-code-1","c":["var db = await Nitrite.builder()\n    .registerEntityConverter(BookConverter())\n    .registerEntityConverter(BookIdConverter())\n    .openOrCreate();"]},{"l":"@DocumentKey","p":["@DocumentKey annotation is used to mark a field as a document key. This annotation provides an alias to the field. Normally the field name is used as the key in the Nitrite document. If you want to use a different name, then you can specify the alias using this annotation. This annotation can be used on a field or a getter/setter method.","This will generate the following code:"]},{"i":"documentkey-code-1","c":["@Convertable()\nclass Book {\n  @DocumentKey(alias: 'book_id')\n  BookId? bookId;\n  String? publisher;\n  double? price;\n  List<String>? tags;\n  String? description;\n\n  Book({this.bookId, this.publisher, this.price, this.tags, this.description});\n}\n\n@Convertable()\nclass BookId {\n  String? isbn;\n  @DocumentKey(alias: \"book_name\")\n  String? name;\n  String? author;\n}"]},{"i":"documentkey-code-2","c":["// GENERATED CODE - DO NOT MODIFY BY HAND\n\npart of 'book.dart';\n\n// **************************************************************************\n// ConverterGenerator\n// **************************************************************************\n\nclass BookConverter extends EntityConverter<Book> {\n  @override\n  Book fromDocument(Document document, NitriteMapper nitriteMapper) {\n    var book = Book();\n    book.bookId = nitriteMapper.tryConvert<BookId, Document>(document[\"book_id\"]);\n    book.publisher = document[\"publisher\"];\n    book.price = document[\"price\"];\n    book.tags = EntityConverter.toList<String>(document[\"tags\"], nitriteMapper);\n    book.description = document[\"description\"];\n    return book;\n  }\n\n  @override\n  Document toDocument(Book entity, NitriteMapper nitriteMapper) {\n    return emptyDocument()\n        .put(\"book_id\", nitriteMapper.tryConvert<Document, BookId>(entity.bookId))\n        .put(\"publisher\", entity.publisher)\n        .put(\"price\", entity.price)\n        .put(\"tags\", EntityConverter.fromList<String>(entity.tags, nitriteMapper))\n        .put(\"description\", entity.description);\n  }\n}\n\nclass BookIdConverter extends EntityConverter<BookId> {\n  @override\n  BookId fromDocument(Document document, NitriteMapper nitriteMapper) {\n    var bookId = BookId();\n    bookId.isbn = document[\"isbn\"];\n    bookId.name = document[\"book_name\"];\n    bookId.author = document[\"author\"];\n    return bookId;\n  }\n\n  @override\n  Document toDocument(BookId entity, NitriteMapper nitriteMapper) {\n    return emptyDocument()\n        .put(\"isbn\", entity.isbn)\n        .put(\"book_name\", entity.name)\n        .put(\"author\", entity.author);\n  }\n}"]},{"l":"@IgnoredKey","p":["@IgnoredKey annotation is used to mark a field as ignored. This annotation is useful when you want to ignore a field while mapping to Nitrite document. This annotation can be used on a field or a getter/setter method.","This will generate the following code:","The code generator imposes some limitations on the Dart classes. These limitations are discussed here."]},{"i":"ignoredkey-code-1","c":["@Convertable()\nclass BookId {\n  String? isbn;\n  @DocumentKey(alias: \"book_name\")\n  String? name;\n  @IgnoredKey()\n  String? author;\n}"]},{"i":"ignoredkey-code-2","c":["// GENERATED CODE - DO NOT MODIFY BY HAND\n\npart of 'book.dart';\n\n// **************************************************************************\n// ConverterGenerator\n// **************************************************************************\n\nclass BookIdConverter extends EntityConverter<BookId> {\n  @override\n  BookId fromDocument(Document document, NitriteMapper nitriteMapper) {\n    var bookId = BookId();\n    bookId.isbn = document[\"isbn\"];\n    bookId.name = document[\"book_name\"];\n    return bookId;\n  }\n\n  @override\n  Document toDocument(BookId entity, NitriteMapper nitriteMapper) {\n    return emptyDocument()\n        .put(\"isbn\", entity.isbn)\n        .put(\"book_name\", entity.name);\n  }\n}"]},{"l":"Custom NitriteMapper","p":["Apart from SimpleNitriteMapper, you can also provide your own implementation of NitriteMapper. You need to implement NitriteMapper interface and provide your own implementation. Once the implementation is ready, you need to load it using loadModule() method on NitriteBuilder while building the database."]},{"i":"custom-nitritemapper-code-1","c":["Nitrite db = Nitrite.builder()\n    .loadModule(module(new CustomNitriteMapper()))\n    .openOrCreate();"]}],[{"l":"Write Operations"},{"l":"Inserting Entities","p":["Entities can be inserted into a repository using insert() or insertMay() method. It takes one or multiple Dart entities as input parameter respectively. It returns a future of WriteResult object.","If the entity has a NitriteId field, then the field value would be populated with a new NitriteId before inserting into the repository.","If any of the field is already indexed in the repository, then the index will be updated accordingly.","This operation will notify all the registered CollectionEventListener with EventType.insert event."]},{"l":"Inserting a Single Entity"},{"i":"inserting-a-single-entity-code-1","c":["var product = Product()\n  ..productId = ProductId(1)\n  ..productName = 'Apple iPhone 6'\n  ..price = 600.0;\n\nvar result = await productRepository.insert(product);"]},{"l":"Inserting Multiple Entities"},{"i":"inserting-multiple-entities-code-1","c":["var product1 = Product()\n  ..productId = ProductId(1)\n  ..productName = 'Apple iPhone 6'\n  ..price = 600.0;\n\nvar product2 = Product()\n    ..productId = ProductId(2)\n    ..productName = 'Apple iPhone 6 Plus'\n    ..price = 700.0;\n\nvar result = await productRepository.insertMany([product1, product2]);"]},{"l":"Error Scenarios","p":["If a field of the entity is unique indexed and it's value violates the index constraint, then it will throw a UniqueConstraintException."]},{"l":"WriteResult","p":["More information about WriteResult can be found here."]},{"l":"Updating Entities","p":["Entities can be updated using any of the following methods:","updateOne() - updates a single entity","update() - updates multiple entities using a filter and update entity","updateDocument() - updates multiple entities using a filter and update document","All update methods returns a FutureWriteResult object.","This operation will notify all the registered CollectionEventListener with EventType.update event."]},{"l":"Updating a Single Entity","p":["You can update a single entity using updateOne() method. It takes a Dart entity as input parameter. It returns a FutureWriteResult object. The entity must have a valid id field.","The entity must have a valid id field marked with @Id annotation. In case an EntityDecorator is used, the idField getter must return a valid non-null EntityId object. Otherwise, it will throw a NotIdentifiableException."]},{"i":"updating-a-single-entity-code-1","c":["```dart\nvar product = Product()\n  ..productId = ProductId(1)\n  ..productName = 'Apple iPhone 6'\n  ..price = 600.0;\n\nvar result = await productRepository.insert(product);\n\nproduct.price = 700.0;\n\nresult = await productRepository.updateOne(product);"]},{"l":"Upserting a Single Entity","p":["You can also upsert a single entity using updateOne() method. Along with the entity parameter, you need to pass a named parameter insertIfAbsent with value true. If the entity does not exist in the repository, then it will be inserted. Otherwise, it will be updated. The default value of insertIfAbsent is false."]},{"i":"upserting-a-single-entity-code-1","c":["var product = Product()\n  ..productId = ProductId(1)\n  ..productName = 'Apple iPhone 6'\n  ..price = 600.0;\n\nvar result = await productRepository.updateOne(product, insertIfAbsent: true);"]},{"l":"Updating Using a Filter","p":["You can update multiple entities using a filter. It takes a Filter object as first input parameter. It takes a Dart entity as second input parameter. It returns a FutureWriteResult object.","If the filter result matches multiple entities, then all the entities will be updated."]},{"i":"updating-using-a-filter-code-1","c":["var product = Product()\n  ..productId = ProductId(1)\n  ..productName = 'Apple iPhone 6'\n  ..price = 650.0;\n\nvar result = await productRepository.update(where('productName').eq('Apple iPhone 6'), product);"]},{"l":"Updating Using a Filter and Options","p":["You can update multiple entities using a filter and options. It takes a Filter object as first input parameter. It takes a Dart entity as second input parameter. It takes a UpdateOptions object as third input parameter. It returns a FutureWriteResult object."]},{"l":"UpdateOptions","p":["More information about UpdateOptions can be found here."]},{"i":"updateoptions-code-1","c":["var product = Product()\n  ..productId = ProductId(1)\n  ..productName = 'Apple iPhone 6'\n  ..price = 650.0;\n\nvar updateOptions = UpdateOptions();\nupdateOptions.insertIfAbsent = true;\n\nvar result = await productRepository.update(where('productName').eq('Apple iPhone 6'), product, updateOptions);"]},{"l":"Updating Using a Filter and Document","p":["You can update multiple entities using a filter. It takes a Filter object as first input parameter. It takes a Document object as second input parameter. It returns a FutureWriteResult object.","If the filter result matches multiple entities, then all the entities will be updated. The document must contain only the fields that needs to be updated.","The document should not contain _id field."]},{"i":"updating-using-a-filter-and-document-code-1","c":["var update = createDocument('price', 700);\n\nvar result = await productRepository.updateDocument(where('productName').eq('Apple iPhone 6'), update);"]},{"l":"Updating Using a Filter, Document and Options","p":["You can update multiple entities using a filter, document and options. It takes a Filter object as first input parameter. It takes a Document object as second input parameter. It takes a boolean value as third input parameter. If the third input parameter is true, then it will only update the first entity matched by the filter. Otherwise, it will update all the entities matched by the filter. It returns a FutureWriteResult object.","The document must contain only the fields that needs to be updated.","The document should not contain _id field."]},{"i":"updating-using-a-filter-document-and-options-code-1","c":["var update = createDocument('price', 700);\n\nvar result = await productRepository.updateDocument(where('productName').eq('Apple iPhone 6'), update, justOnce: true);"]},{"l":"Removing Entities","p":["Entities can be removed using any of the following methods:","removeOne() - removes a single entity","remove() - removes multiple entities using a filter","All remove methods returns a FutureWriteResult object.","This operation will notify all the registered CollectionEventListener with EventType.remove event."]},{"l":"Removing a Single Entity","p":["You can remove a single entity using removeOne() method. It takes a Dart entity as input parameter. It returns a FutureWriteResult object.","The entity must have a valid id field marked with @Id annotation. In case an EntityDecorator is used, the idField getter must return a valid non-null EntityId object. Otherwise, it will throw a NotIdentifiableException."]},{"i":"removing-a-single-entity-code-1","c":["var product = Product()\n  ..productId = ProductId(1)\n  ..productName = 'Apple iPhone 6'\n  ..price = 600.0;\n\nvar result = await productRepository.insert(product);\n\nresult = await productRepository.removeOne(product);"]},{"l":"Removing Using a Filter","p":["You can remove multiple entities using a filter. It takes a Filter object as input parameter. It returns a FutureWriteResult object.","If the filter result matches multiple entities, then all the entities will be removed."]},{"i":"removing-using-a-filter-code-1","c":["var result = await productRepository.remove(where('productName').eq('Apple iPhone 6'));"]},{"l":"Removing Using a Filter and Options","p":["You can remove multiple entities using a filter and options. It takes a Filter object as first input parameter. It takes a boolean value as second input parameter. If the second input parameter is true, then it will remove only the first entity matched by the filter. Otherwise, it will remove all the entities matched by the filter. It returns a FutureWriteResult object."]},{"i":"removing-using-a-filter-and-options-code-1","c":["var result = await productRepository.remove(where('productName').eq('Apple iPhone 6'), justOne: true);"]}],[{"l":"Read Operations"},{"l":"Find Operations","p":["You can search entities in a repository using find() method. There are several ways of using find() method using a filter or find options or both. You can also search an entity using it's id."]},{"l":"Filters","p":["Nitrite uses filters to find entities in a repository. A filter is a simple expression which evaluates to true or false. More information about filters can be found here."]},{"l":"Find All Entities","p":["You can find all entities in a repository by calling find(). It returns a Cursor object."]},{"i":"find-all-entities-code-1","c":["Cursor<Product> cursor = productRepository.find();"]},{"l":"Finding an Entity Using Id","p":["You can find an entity using it's id by calling getById(). It takes an id as input parameter. It returns an entity if the entity is found. Otherwise, it returns null."]},{"i":"finding-an-entity-using-id-code-1","c":["var product = await productRepository.getById(ProductId(1));"]},{"l":"Finding an Entity Using a Filter","p":["You can find an entity using a filter. It takes a Filter object as input parameter. It returns a Cursor object.","If there is an index on the field specified in the filter, this operation will use the index to find the entity. Otherwise, it will scan the entire repository to find the entity."]},{"i":"finding-an-entity-using-a-filter-code-1","c":["Cursor<Product> cursor = productRepository.find(filter: where('productName').eq('Apple iPhone 6'));"]},{"l":"Finding an Entity Using a Filter and Options","p":["You can find an entity using a filter and options. It takes a Filter object as the first input parameter. It takes a FindOptions object as the second input parameter. It returns a Cursor object."]},{"l":"FindOptions","p":["More information about FindOptions can be found here."]},{"l":"Cursor","p":["Cursor represents a result set of a find operation. It provides methods to iterate over the result of a find operation and retrieve the entities. It also provides methods like projection, join etc. to get the desired result."]},{"l":"Iterating over Entities","p":["The Cursor extends Stream of entities. So, you can iterate over the entities using await for loop.","A Cursor is a stream of entities. It does not load all the entities in memory at once. It loads the entity in memory as needed. So, it is memory efficient."]},{"i":"iterating-over-entities-code-1","c":["Cursor<Product> cursor = productRepository.find();\n\nawait for (var product in cursor) {\n  // do something with product\n}"]},{"l":"Getting the Entities","p":["You can get the entities from a Cursor using toList() method. It returns a FutureListT object."]},{"i":"getting-the-entities-code-1","c":["Cursor<Product> cursor = productRepository.find();\n\nvar products = await cursor.toList();"]},{"l":"Getting the First Entity","p":["You can get the first entity from a Cursor using first getter. It returns a FutureT? object."]},{"i":"getting-the-first-entity-code-1","c":["Cursor<Product> cursor = productRepository.find();\n\nvar product = await cursor.first;"]},{"l":"Getting the Size of the Cursor","p":["You can get the size of the cursor using length getter. It returns a Futureint object."]},{"i":"getting-the-size-of-the-cursor-code-1","c":["Cursor<Product> cursor = productRepository.find();\n\nvar size = await cursor.length;"]},{"l":"Projection","p":["You can project a field or a set of fields from a Cursor using project() method. It takes another entity type as input parameter. It returns a Stream of projected entities.","The projected entity must contain only the fields that needs to be projected.","Let's say you have an entity like this:","Then you can project the lastName and address.street fields. Then you define a new entity like this:","And then you can project the cursor like this:"]},{"i":"projection-code-1","c":["@Entity()\n@Convertable()\nclass User {\n  String? firstName;\n  String? lastName;\n  Address? address;\n\n  User({this.firstName, this.lastName, this.address});\n}\n\n@Convertable()\nclass Address {\n  String? city;\n  String? state;\n  String? country;\n\n  Address({this.city, this.state, this.country});\n}"]},{"i":"projection-code-2","c":["@Entity()\n@Convertable()\nclass UserProjection {\n  String? lastName;\n  StreetAddress? address;\n\n  UserProjection({this.lastName, this.address});\n}\n\n@Convertable()\nclass StreetAddress {\n  String? street;\n\n  StreetAddress({this.street});\n}"]},{"i":"projection-code-3","c":["Cursor<User> cursor = userRepository.find(filter: where('firstName').eq('John'));\n\nvar projectedStream = cursor.project<UserProjection>();"]},{"l":"Join","p":["You can join two cursors using leftJoin() method. It takes another cursor as the first input parameter. It takes a Lookup as the second input parameter. The first type parameter is the type of the foreign entity. The second type parameter is the type of the joined entity. It returns a Stream of joined entities.","The join operation is similar to SQL left outer join operation. It takes two cursors and a lookup object. The lookup object contains the join condition.","Let's say you have two entities like this:","And you want to join these two entities using userId field. Then you can define a new entity like this:","And then you can join the cursors like this:"]},{"i":"join-code-1","c":["@Entity()\n@Convertable()\nclass User {\n  String? userId;\n  String? firstName;\n  String? lastName;\n\n  User({this.userId, this.firstName, this.lastName});\n}\n\n@Entity()\n@Convertable()\nclass Order {\n  String? orderId;\n  String? userId;\n  String? productName;\n\n  Order({this.orderId, this.userId, this.productName});\n}"]},{"i":"join-code-2","c":["@Entity()\n@Convertable()\nclass UserOrder {\n  String? userId;\n  String? firstName;\n  String? lastName;\n  List<Order>? orders;\n\n  UserOrder({this.userId, this.firstName, this.lastName, this.orders});\n}"]},{"i":"join-code-3","c":["Cursor<User> userCursor = userRepository.find();\nCursor<Order> orderCursor = orderRepository.find();\n\nvar lookup = Lookup()\n  ..localField = 'userId'\n  ..foreignField = 'userId'\n  ..alias = 'orders';\n\nvar joinedStream = userCursor.leftJoin<Order, UserOrder>(orderCursor, lookup);"]},{"l":"FindPlan","p":["You can get the FindPlan of a cursor using findPlan getter. It returns a future of FindPlan object.","More information about FindPlan can be found here."]},{"i":"findplan-code-1","c":["Cursor<Product> cursor = productRepository.find(filter: where('productName').eq('Apple iPhone 6'));\n\nvar findPlan = await cursor.findPlan;"]}],[{"l":"Indexing","p":["Indexing is a way to optimize the performance of a database by minimizing the number of disk accesses required when a query is processed. It is a data structure technique which is used to quickly locate and access the data in a database.","Nitrite supports indexing on a repository. It supports indexing on a single field or multiple fields. It also supports full-text indexing.","Indexes for an entity can be defined using various annotations like @Id, @Index etc. More information about annotations can be found here. It can also be managed using various methods of ObjectRepository interface."]},{"l":"Index Types","p":["Nitrite supports the following types of index out of the box:","Unique Index","Non-Unique Index","Full-text Index"]},{"l":"Unique Index","p":["A unique index ensures that the indexed field contains unique value. It does not allow duplicate value in the indexed field. It also ensures that the indexed field is not null."]},{"l":"Non-unique Index","p":["A non-unique index does not ensure that the indexed field contains unique value. It allows duplicate value in the indexed field."]},{"l":"Full-text Index","p":["A full-text index is used to search text content in an entity. It is useful when you want to search text content in an entity. It is also useful when you want to search text content in an entity in a language other than English.","Indexing on non-comparable value is not supported."]},{"l":"Custom Index","p":["You can also create your own custom index. More information about custom index can be found here."]},{"l":"Creating an Index","p":["You can define indexes for an entity using annotations. You can also create indexes using ObjectRepository interface.","You cannot create a new index on a field or a set of fields which is already indexed with a different type of index.","For example, if you have a unique index on firstName field, then you cannot create a non-unique index on firstName field. But you can create a unique index on firstName and lastName fields. Similarly, if you have a unique index on firstName and lastName fields, then you cannot create a non-unique index on firstName and lastName fields. But you can create two indexes on firstName and lastName fields separately."]},{"l":"Creating a Unique Index","p":["You can create a unique index on a single field or multiple fields. It takes the name of the fields on which the index will be created as input parameter."]},{"l":"Using Annotations","p":["You can create a unique index on a single field or multiple fields using annotations. You can use @Id annotation to create a unique index on a single field. You can use @Index annotation to create a unique index on multiple fields."]},{"i":"using-annotations-code-1","c":["@Entity(indices: [\n  Index(fields: ['tags'], type: IndexType.nonUnique),\n  Index(fields: ['description'], type: IndexType.fullText),\n  Index(fields: ['price', 'publisher']),\n])\nclass Book {\n  @Id()\n  int id;\n  String title;\n  String description;\n  String publisher;\n  List<String> tags;\n  double price;\n\n  Book(this.title, this.description, this.publisher, this.tags, this.price);\n}"]},{"l":"Using ObjectRepository","p":["You can create a unique index on a single field or multiple fields using createIndex() method. It takes the name of the fields on which the index will be created as input parameter."]},{"i":"using-objectrepository-code-1","c":["await bookRepository.createIndex(['tags']);\nawait bookRepository.createIndex(['price', 'publisher']);"]},{"l":"Creating a Non-unique Index","p":["You can create a non-unique index on a single field or multiple fields by passing the index type as IndexType.nonUnique."]},{"i":"using-annotations-1","l":"Using Annotations","p":["You can create a non-unique index on a single field or multiple fields using annotations. You can use @Index annotation to create a non-unique index on multiple fields."]},{"i":"using-annotations-1-code-1","c":["@Entity(indices: [\n  Index(fields: ['tags'], type: IndexType.nonUnique),\n  Index(fields: ['price', 'publisher'], type: IndexType.nonUnique),\n])\nclass Book {\n  @Id()\n  int id;\n  String title;\n  String description;\n  String publisher;\n  List<String> tags;\n  double price;\n\n  Book(this.title, this.description, this.publisher, this.tags, this.price);\n}"]},{"i":"using-objectrepository-1","l":"Using ObjectRepository","p":["You can create a non-unique index on a single field or multiple fields using createIndex() method. It takes the name of the fields on which the index will be created as input parameter and the index type as IndexType.nonUnique."]},{"i":"using-objectrepository-1-code-1","c":["await bookRepository.createIndex(['tags'], indexOptions(IndexType.nonUnique));\nawait bookRepository.createIndex(['price', 'publisher'], indexOptions(IndexType.nonUnique));"]},{"l":"Creating a Full-text Index","p":["You can create a full-text index on a single field or multiple fields by passing the index type as IndexType.fullText."]},{"i":"using-annotations-2","l":"Using Annotations","p":["You can create a full-text index on a single field using annotations. You can use @Index annotation to create a full-text index on a single field."]},{"i":"using-annotations-2-code-1","c":["@Entity(indices: [\n  Index(fields: ['description'], type: IndexType.fullText),\n])\nclass Book {\n  @Id()\n  int id;\n  String title;\n  String description;\n  String publisher;\n  List<String> tags;\n  double price;\n\n  Book(this.title, this.description, this.publisher, this.tags, this.price);\n}"]},{"i":"using-objectrepository-2","l":"Using ObjectRepository","p":["You can create a full-text index on a single field using createIndex() method. It takes the name of the fields on which the index will be created as input parameter and the index type as IndexType.fullText.","Full-text index is not supported on multiple fields."]},{"i":"using-objectrepository-2-code-1","c":["await bookRepository.createIndex(['description'], indexOptions(IndexType.fullText));"]},{"l":"Creating Index on Iterable Field","p":["Nitrite supports creating index on iterable field. It will create index on each element of the iterable. For example, if you have an entity like this:","Then it will create index on each element of the tags list. You can also create index on tags field like this:"]},{"i":"creating-index-on-iterable-field-code-1","c":["@Entity(indices: [\n  Index(fields: ['tags'], type: IndexType.nonUnique),\n])\nclass Book {\n  @Id()\n  int id;\n  String title;\n  String description;\n  String publisher;\n  List<String> tags;\n  double price;\n\n  Book(this.title, this.description, this.publisher, this.tags, this.price);\n}"]},{"i":"creating-index-on-iterable-field-code-2","c":["await bookRepository.createIndex(['tags'], indexOptions(IndexType.nonUnique));"]},{"l":"Creating Index on Embedded Field","p":["Nitrite supports creating index on embedded field. For example, if you have entities like this:","Then it will create index on city field of Address entity. You can also create index on city field of Address entity like this:","You cannot create index on nested field if the parent field is an array."]},{"i":"creating-index-on-embedded-field-code-1","c":["@Entity(indices: [\n  Index(fields: ['address.city'], type: IndexType.nonUnique),\n])\nclass Person {\n  @Id()\n  int id;\n  String name;\n  Address address;\n\n  Person(this.name, this.address);\n}\n\nclass Address {\n  String city;\n  String state;\n  String country;\n\n  Address(this.city, this.state, this.country);\n}"]},{"i":"creating-index-on-embedded-field-code-2","c":["await personRepository.createIndex(['address.city'], indexOptions(IndexType.nonUnique));"]},{"l":"Rebuilding an Index","p":["You can rebuild an index using rebuildIndex() method. It takes the name of the fields on which the index will be rebuilt as input parameter."]},{"i":"rebuilding-an-index-code-1","c":["// rebuild index on a single field\nawait bookRepository.rebuildIndex(['tags']);\n\n// rebuild index on multiple fields\nawait bookRepository.rebuildIndex(['price', 'publisher']);"]},{"l":"Dropping an Index","p":["You can drop an index using dropIndex() method. It takes the name of the fields on which the index will be dropped as input parameter."]},{"i":"dropping-an-index-code-1","c":["// drop index on a single field\nawait bookRepository.dropIndex(['tags']);\n\n// drop index on multiple fields\nawait bookRepository.dropIndex(['price', 'publisher']);"]},{"l":"Dropping All Indexes","p":["You can drop all indexes using dropAllIndices() method."]},{"i":"dropping-all-indexes-code-1","c":["await bookRepository.dropAllIndices();"]},{"l":"Getting All Indexes","p":["You can get all indexes using listIndices() method. It returns a FutureCollection of IndexDescriptor object."]},{"i":"getting-all-indexes-code-1","c":["Collection<IndexDescriptor> indexes = await bookRepository.listIndices();"]},{"l":"IndexDescriptor","p":["IndexDescriptor is a class which contains information about an index. It contains the following information:","collectionName: The name of the collection on which the index is created.","indexType: The type of the index.","fields: A Fields object containing the name of the fields on which the index is created."]},{"l":"Checking If an Index Exists","p":["You can check if an index exists using hasIndex() method. It takes the name of the fields on which the index will be checked as input parameter."]},{"i":"checking-if-an-index-exists-code-1","c":["// check if an index exists on a single field\nbool exists = await bookRepository.hasIndex(['tags']);\n\n// check if an index exists on multiple fields\nbool exists = await bookRepository.hasIndex(['price', 'publisher']);"]},{"l":"Error Scenarios","p":["The following error scenarios are possible while creating an index:","If another index of any type is already created on the repository on the same field(s), then it will throw IndexingException.","If a unique index is created on a field and the field contains duplicate value, then it will throw UniqueConstraintException.","If a full-text index is created on multiple fields, then it will throw IndexingException.","If a full-text index is created on a field which is not a String, then it will throw IndexingException.","If you try to drop an index which does not exist, then it will throw IndexingException.","If you try to rebuild an index which does not exist, then it will throw IndexingException."]}],[{"l":"Other Operations"},{"l":"Size of a Repository","p":["You can get the size of a repository using size getter. It returns a future of the number of entities in the repository."]},{"i":"size-of-a-repository-code-1","c":["int size = await productRepository.size;"]},{"l":"Clearing a Repository","p":["You can clear all the entities from a repository using clear() method. It removes all the entities from the repository and index entries from the indexes. It does not drop the repository."]},{"i":"clearing-a-repository-code-1","c":["await productRepository.clear();"]},{"l":"Dropping a Repository","p":["You can drop a repository using drop() method. It removes all the entities from the repository and index entries from the indexes. It also drops all the indexes associated with the repository. It also removes the repository from the database.","You can call isDropped getter to check if the repository is dropped or not.","Any further operation on a dropped repository will throw NitriteIOException."]},{"i":"dropping-a-repository-code-1","c":["await productRepository.drop();"]},{"i":"dropping-a-repository-code-2","c":["bool isDropped = productRepository.isDropped;"]},{"l":"Closing a Repository","p":["You can close a repository using close() method. Any further operation on a closed repository will throw NitriteIOException.","After closing a repository, you must re-open it via Nitrite.getRepository() method to perform any operation on it.","You can call isOpen getter to check if the repository is closed or not."]},{"i":"closing-a-repository-code-1","c":["await productRepository.close();"]},{"i":"closing-a-repository-code-2","c":["bool isOpen = productRepository.isOpen;"]},{"l":"Event Listener","p":["You can register an event listener on a repository to get notified on entity changes. The event listener is a function of type CollectionEventListener. It will receive CollectionEventInfo whenever an entity is inserted, updated or removed from the repository.","You can unsubscribe the event listener using unsubscribe() method."]},{"i":"event-listener-code-1","c":["productRepository.subscribe((eventInfo) {\n  // do something with eventInfo\n});"]},{"i":"event-listener-code-2","c":["productRepository.unsubscribe(listener);"]},{"l":"CollectionEventInfo","p":["More on CollectionEventInfo can be found here."]},{"l":"Attributes","p":["Attributes is a metadata information associated with a repository.","You can get/set attributes on a repository. The attributes are stored in the database and can be retrieved later. The attributes are stored in a special map named $nitrite_meta_map."]},{"i":"attributes-code-1","c":["// get the attributes\nvar attributes = await productRepository.getAttributes();\nattributes.set('key', 'value');\n\n// save the attributes\nawait productRepository.setAttributes(attributes);\n\n// get the attributes\nattributes = await productRepository.getAttributes();\n\n// get the value of a key\nvar value = attributes.get['key'];"]},{"l":"Processors","p":["Processor can be used to process the underlying documents of a repository. More on processors can be found here."]},{"l":"Registering a Processor","p":["You can register a processor on a repository using addProcessor() method. It takes a Processor as input parameter."]},{"i":"registering-a-processor-code-1","c":["// create a processor\nvar processor = MyProcessor();\n\n// process existing entities\nawait processor.process(productRepository);\n\n// register the processor\nproductRepository.addProcessor(processor);"]},{"l":"Available Processors","p":["Nitrite provides a StringFieldEncryptionProcessor which can be used to encrypt a field before writing it into a repository and decrypt a field after reading it from a repository.","More on this is described in Support."]}],[{"l":"Filters","p":["Filters are used to specify the criteria used to select documents from a collection or repository. It provides a way to specify conditions that the documents must meet to be included in the result set. Filters are used in conjunction with the find method. The find method returns all documents in a collection that match the specified filtering criteria.","Each filtering criteria is based on a field in the document. If the field is indexed, the find operation takes advantage of the index to speed up the operation. If the field is not indexed, the find operation scans the entire collection to find matching documents."]},{"l":"Fluent API","p":["Nitrite provides a fluent API to create filters via FluentFilter class. It provides a global method where to create a filter. The where method takes a field name as input parameter and returns a FluentFilter object. The FluentFilter object provides various methods to create a filter. Here is an example:","The above code will create a filter for the field name and then filter for equality. The find method will return all documents where the field name is equal to John.","For spatial filters, use the SpatialFluentFilter class for the fluent API. Similarly it also provides a global method where to create a filter. The where method takes a field name as input parameter and returns a SpatialFluentFilter object. The SpatialFluentFilter object provides various methods to create a filter. Here is an example:","More on spatial module can be found here."]},{"i":"fluent-api-code-1","c":["var clause = where('name');\n\n// filter for equality\nvar filter = clause.eq('John');\n\nvar cursor = collection.find(filter: filter);"]},{"i":"fluent-api-code-2","c":["import 'package:nitrite_spatial/nitrite_spatial.dart';\n\nvar clause = where('location');\n\n// filter for within\nvar filter = clause.within(polygon);\n\nvar cursor = collection.find(filter: filter);"]},{"l":"Usage","p":["Filters are used with the find method of NitriteCollection or ObjectRepository to retrieve documents or entities that match the filter. Here's an example:","In this example, the where and eq methods are used to create an equality filter that matches documents where the name field equals \"John\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"usage-code-1","c":["// find all documents where the field 'name' equals 'John'\nvar cursor = collection.find(filter: where('name').eq('John'));"]},{"l":"String Extensions","p":["Nitrite provides a String extension to create filters. It creates a filter for the field name specified in the string."]},{"i":"string-extensions-code-1","c":["// find all documents where the field 'name' equals 'John'\nvar cursor = collection.find(filter: 'name'.eq('John'));"]},{"l":"Operator Overloading","p":["Nitrite provides operator overloading to create filters. It creates a filter for the field name specified in the string.","There are various operators available for creating filters. Here is the list:",": Greater than filter","=: Greater than or equal to filter",": Less than filter","=: Less than or equal to filter","~: Not filter",": And filter","|: Or filter","These operators are also valid on the String extension of filter. More on this is discussed in the following sections."]},{"i":"operator-overloading-code-1","c":["// find all documents where the field 'age' is greater than 18\nvar cursor = collection.find(filter: where('age') > 18);\n\n// or using string extension\nvar cursor = collection.find(filter: 'age' > 18);"]},{"l":"Types of Filters","p":["Nitrite filters can be grouped into the following categories:","Comparison filters","Logical filters","Array filters","Evaluation filters","Spatial filters"]},{"l":"Comparison Filters","p":["Comparison filters are used to compare a field with a value. The following comparison filters are available:","Equality (eq): Matches all documents where the value of the field equals the specified value.","Inequality (notEq): Matches all documents where the value of the field is not equal to the specified value.","Greater than (gt): Matches all documents where the value of the field is greater than the specified value.","Greater than or equal to (gte): Matches all documents where the value of the field is greater than or equal to the specified value.","Less than (lt): Matches all documents where the value of the field is less than the specified value.","Less than or equal to (lte): Matches all documents where the value of the field is less than or equal to the specified value.","Within (within): Matches all documents where the value of the field equals any value in the specified array.","Not in (notIn): Matches all documents where the value of the field does not equal any value in the specified array.","Between (between): Matches all documents where the value of the field is between the specified values.","All (all): Matches all documents in the collection."]},{"l":"Equality Filter","p":["The equality filter is used to match documents where the value of a field equals the specified value. The following example shows how to use the equality filter:","In this example, the where() and eq() methods are used to create an equality filter that matches documents where the name field equals \"John\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"equality-filter-code-1","c":["// find all documents where the field 'name' equals 'John'\ncollection.find(filter: where('name').eq('John'));\n\n// or using string extension\ncollection.find(filter: 'name'.eq('John'));"]},{"l":"Inequality Filter","p":["The inequality filter is used to match documents where the value of a field is not equal to the specified value. The following example shows how to use the inequality filter:","In this example, the where() and notEq() methods are used to create an inequality filter that matches documents where the name field does not equal \"John\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"inequality-filter-code-1","c":["// find all documents where the field 'name' is not equal to 'John'\ncollection.find(filter: where('name').notEq('John'));\n\n// or using string extension\ncollection.find(filter: 'name'.notEq('John'));"]},{"l":"Greater Than Filter","p":["The greater than filter is used to match documents where the value of a field is greater than the specified value. The following example shows how to use the greater than filter:","In this example, the where() and gt() methods are used to create a greater than filter that matches documents where the age field is greater than 18. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"greater-than-filter-code-1","c":["// find all documents where the field 'age' is greater than 18\ncollection.find(filter: where('age').gt(18));\n\n// or using string extension\ncollection.find(filter: 'age'.gt(18));\n\n// or using operator overloading\ncollection.find(filter: where('age') > 18);\n\n// or using operator overloading with string extension\ncollection.find(filter: 'age' > 18);"]},{"l":"Greater Than or Equal To Filter","p":["The greater than or equal to filter is used to match documents where the value of a field is greater than or equal to the specified value. The following example shows how to use the greater than or equal to filter:","In this example, the where() and gte() methods are used to create a greater than or equal to filter that matches documents where the age field is greater than or equal to 18. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"greater-than-or-equal-to-filter-code-1","c":["// find all documents where the field 'age' is greater than or equal to 18\ncollection.find(filter: where('age').gte(18));\n\n// or using string extension\ncollection.find(filter: 'age'.gte(18));\n\n// or using operator overloading\ncollection.find(filter: where('age') >= 18);\n\n// or using operator overloading with string extension\ncollection.find(filter: 'age' >= 18);"]},{"l":"Less Than Filter","p":["The less than filter is used to match documents where the value of a field is less than the specified value. The following example shows how to use the less than filter:","In this example, the where() and lt() methods are used to create a less than filter that matches documents where the age field is less than 18. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"less-than-filter-code-1","c":["// find all documents where the field 'age' is less than 18\ncollection.find(filter: where('age').lt(18));\n\n// or using string extension\ncollection.find(filter: 'age'.lt(18));\n\n// or using operator overloading\ncollection.find(filter: where('age') < 18);\n\n// or using operator overloading with string extension\ncollection.find(filter: 'age' < 18);"]},{"l":"Less Than or Equal To Filter","p":["The less than or equal to filter is used to match documents where the value of a field is less than or equal to the specified value. The following example shows how to use the less than or equal to filter:","In this example, the where() and lte() methods are used to create a less than or equal to filter that matches documents where the age field is less than or equal to 18. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"less-than-or-equal-to-filter-code-1","c":["// find all documents where the field 'age' is less than or equal to 18\ncollection.find(filter: where('age').lte(18));\n\n// or using string extension\ncollection.find(filter: 'age'.lte(18));\n\n// or using operator overloading\ncollection.find(filter: where('age') <= 18);\n\n// or using operator overloading with string extension\ncollection.find(filter: 'age' <= 18);"]},{"l":"Within Filter","p":["The within filter is used to match documents where the value of a field equals any value in the specified array. The following example shows how to use the in filter:","In this example, the where() and within() methods are used to create an in filter that matches documents where the name field equals \"John\" or \"Jane\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"within-filter-code-1","c":["// find all documents where the field 'name' equals 'John' or 'Jane'\ncollection.find(filter: where('name').within(['John', 'Jane']));\n\n// or using string extension\ncollection.find(filter: 'name'.within(['John', 'Jane']));"]},{"l":"Not In Filter","p":["The not in filter is used to match documents where the value of a field does not equal any value in the specified array. The following example shows how to use the not in filter:","In this example, the where() and notIn() methods are used to create a not in filter that matches documents where the name field does not equal \"John\" or \"Jane\". The filter is then passed to the find method to retrieve the matching documents."]},{"i":"not-in-filter-code-1","c":["// find all documents where the field 'name' does not equal 'John' or 'Jane'\ncollection.find(filter: where('name').notIn(['John', 'Jane']));\n\n// or using string extension\ncollection.find(filter: 'name'.notIn(['John', 'Jane']));"]},{"l":"Between Filter","p":["The between filter is used to match documents where the value of a field is between the specified values. The following example shows how to use the between filter:","In this example, the where() and between() methods are used to create a between filter that matches documents where the age field is between 18 and 30. The filter is then passed to the find method to retrieve the matching documents.","There two other optional parameters available in the between method. The first parameter is lowerInclusive which is a boolean value to indicate whether the lower bound is inclusive or not. The default value is true. The second parameter is upperInclusive which is a boolean value to indicate whether the upper bound is inclusive or not. The default value is true."]},{"i":"between-filter-code-1","c":["// find all documents where the field 'age' is between 18 and 30\ncollection.find(filter: where('age').between(18, 30));\n\n// or using string extension\ncollection.find(filter: 'age'.between(18, 30));"]},{"i":"between-filter-code-2","c":["// find all documents where the field 'age' is between 18 and 30\n// both lower and upper bounds are inclusive\ncollection.find(filter: where('age').between(18, 30));\n\n// find all documents where the field 'age' is between 18 and 30\n// lower bound is exclusive and upper bound is inclusive\ncollection.find(filter: where('age').between(18, 30, lowerInclusive: false, upperInclusive: true));\n\n// find all documents where the field 'age' is between 18 and 30\n// both lower and upper bounds are exclusive\ncollection.find(filter: where('age').between(18, 30, lowerInclusive: false, upperInclusive: false));\n\n// or using string extension\n// find all documents where the field 'age' is between 18 and 30\n// both lower and upper bounds are inclusive\ncollection.find(filter: 'age'.between(18, 30));\n\n// find all documents where the field 'age' is between 18 and 30\n// lower bound is exclusive and upper bound is inclusive\ncollection.find(filter: 'age'.between(18, 30, lowerInclusive: false, upperInclusive: true));\n\n// find all documents where the field 'age' is between 18 and 30\n// both lower and upper bounds are exclusive\ncollection.find(filter: 'age'.between(18, 30, lowerInclusive: false, upperInclusive: false));"]},{"l":"All Filter","p":["The all filter is used to match all documents in the collection. The following example shows how to use the all filter:","In this example, the all constant is used to create an all filter that matches all documents in the collection. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"all-filter-code-1","c":["// find all documents in the collection\ncollection.find(filter: all);"]},{"l":"Logical Filters","p":["Logical filters are used to combine multiple filters into a single filter. The following logical filters are supported:","And (and): Matches all documents that satisfy all the specified filters.","Or (or): Matches all documents that satisfy at least one of the specified filters.","Not (not): Matches all documents that do not satisfy the specified filter."]},{"l":"And Filter","p":["The and filter is used to match documents that satisfy all the specified filters. The following example shows how to use the and filter:","In this example, the where() and eq() methods are used to create an equality filter that matches documents where the name field equals \"John\". The where() and gt() methods are used to create a greater than filter that matches documents where the age field is greater than 18. The two filters are then combined using the and() method to create an and filter that matches documents where the name field equals \"John\" and the age field is greater than 18. The filter is then passed to the find method to retrieve the matching documents.","The and() method can be used to combine any number of filters. The following example shows how to combine three filters:","Operators can also be used to combine filters. The following example shows how to combine three filters using operators:","The global and() method can also be used to combine filters. The following example shows how to combine three filters using the global and() method:","In this example, the and() method is used to combine three filters into a single filter. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"and-filter-code-1","c":["// find all documents where the field 'name' equals 'John' and 'age' is greater than 18\ncollection.find(filter: where('name').eq('John').and('age').gt(18));\n\n// or using string extension and operator overloading\ncollection.find(filter: 'name'.eq('John') & 'age'.gt(18));"]},{"i":"and-filter-code-2","c":["// find all documents where the field 'name' equals 'John' and 'age' is greater than 18 and less than 30\ncollection.find(filter: where('name').eq('John').and('age').gt(18).and('age').lt(30));"]},{"i":"and-filter-code-3","c":["// find all documents where the field 'name' equals 'John' and 'age' is greater than 18 and less than 30\ncollection.find(filter: 'name'.eq('John') & (('age' > 18) & ('age' < 30)));"]},{"i":"and-filter-code-4","c":["// find all documents where the field 'name' equals 'John' and 'age' is greater than 18 and less than 30\ncollection.find(filter: and(where('name').eq('John'), where('age').gt(18), where('age').lt(30)));"]},{"l":"Or Filter","p":["The or filter is used to match documents that satisfy at least one of the specified filters. The following example shows how to use the or filter:","In this example, the where() and eq() methods are used to create an equality filter that matches documents where the name field equals \"John\". The where() and gt() methods are used to create a greater than filter that matches documents where the age field is greater than 18. The two filters are then combined using the or() method to create an or filter that matches documents where the name field equals \"John\" or the age field is greater than 18. The filter is then passed to the find method to retrieve the matching documents.","The or() method can be used to combine any number of filters. The following example shows how to combine three filters:","Operators can also be used to combine filters. The following example shows how to combine three filters using operators:","The global or() method can also be used to combine filters. The following example shows how to combine three filters using the global or() method:","In this example, the or() method is used to combine three filters into a single filter. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"or-filter-code-1","c":["// find all documents where the field 'name' equals 'John' or 'age' is greater than 18\ncollection.find(filter: where('name').eq('John').or('age').gt(18));\n\n// or using string extension and operator overloading\ncollection.find(filter: 'name'.eq('John') | 'age'.gt(18));"]},{"i":"or-filter-code-2","c":["// find all documents where the field 'name' equals 'John' or 'age' is greater than 18 or less than 30\ncollection.find(filter: where('name').eq('John').or('age').gt(18).or('age').lt(30));"]},{"i":"or-filter-code-3","c":["// find all documents where the field 'name' equals 'John' or 'age' is greater than 18 or less than 30\ncollection.find(filter: 'name'.eq('John') | (('age' > 18) | ('age' < 30)));"]},{"i":"or-filter-code-4","c":["// find all documents where the field 'name' equals 'John' or 'age' is greater than 18 or less than 30\ncollection.find(filter: or(where('name').eq('John'), where('age').gt(18), where('age').lt(30)));"]},{"l":"Not Filter","p":["The not filter is used to match documents that do not satisfy the specified filter. The following example shows how to use the not filter:","In this example, the where() and eq() methods are used to create an equality filter that matches documents where the name field equals \"John\". The not() method is then used to create a not filter that matches documents where the name field does not equal \"John\". The filter is then passed to the find method to retrieve the matching documents.","The not() method can be used to negate any filter. The following example shows how to negate a greater than filter:"]},{"i":"not-filter-code-1","c":["// find all documents where the field 'name' does not equal 'John'\ncollection.find(filter: where('name').eq('John').not());\n\n// or using operator overloading\ncollection.find(filter: ~('name'.eq('John')));"]},{"i":"not-filter-code-2","c":["// find all documents where the field 'age' is not greater than 18\ncollection.find(filter: where('age').gt(18).not());\n\n// or using operator overloading\ncollection.find(filter: ~('age' > 18));"]},{"l":"Array Filters","p":["Array filters are used to match documents based on the values in an array field. The following array filters are supported:","Element match (elemMatch): Matches all documents where the array field contains at least one element that matches the specified filter."]},{"l":"Element Match Filter","p":["The element match filter is used to match documents where the array field contains at least one element that matches the specified filter. The following example shows how to use the element match filter:","Let's say we have a collection that contains documents with the following structure:","The following example shows how to use the element match filter to find all documents where the addresses field contains at least one element that matches the filter where the city field equals \"New York\":","In this example, the where() and elemMatch() methods are used to create an element match filter that matches documents where the addresses field contains at least one element that matches the filter where the city field equals \"New York\". The filter is then passed to the find method to retrieve the matching documents.","The elemMatch filter can be used to search an array of elements for a specific value. The following example shows how to use the elemMatch filter to find all documents where the data field contains at least one element that is greater than 2 or less than equal to 5:","The global $ variable is used to create a filter for the current element in the array. The $.gt(2).or($.lte(5)) filter is used to match documents where the data field contains at least one element that is greater than 2 or less than equal to 5. The filter is then passed to the find method to retrieve the matching documents."]},{"i":"element-match-filter-code-1","c":["{\n  \"name\": \"John\",\n  \"addresses\": [\n    {\n      \"city\": \"New York\",\n      \"state\": \"NY\"\n    },\n    {\n      \"city\": \"Los Angeles\",\n      \"state\": \"CA\"\n    }\n  ]\n}"]},{"i":"element-match-filter-code-2","c":["// find all documents where the field 'addresses' contains at least one element where the field 'city' equals 'New York'\ncollection.find(filter: where('addresses').elemMatch(where('city').eq('New York'))));"]},{"i":"element-match-filter-code-3","c":["// find all documents where the field 'data' contains at least one element that is greater than 2 or less than equal to 5\ncollection.find(filter: where('data').elemMatch($.gt(2).or($.lte(5))));"]},{"l":"Evaluation Filters","p":["Evaluation filters are used to match documents based on evaluating the value of any field in a document. The following evaluation filters are supported:","Text (text): Matches all documents which contain a specified full-text search expression.","Regex (regex): Matches all documents where values contain a specified regular expression."]},{"l":"Text Filter","p":["The text filter is used to match documents which contain a specified full-text search expression. The following example shows how to use the text filter:","In this example, the where() and text() methods are used to create a text filter that matches documents where the name field contains the word \"John\". The filter is then passed to the find method to retrieve the matching documents.","The text filter supports glob patterns. The following example shows how to use the text filter with glob patterns:","The text filter can only be used with a field that has a full-text index."]},{"i":"text-filter-code-1","c":["// find all documents where the field 'name' contains the word 'John'\ncollection.find(filter: where('name').text('John'));"]},{"i":"text-filter-code-2","c":["// find all documents where the field 'name' starts with the word 'Jo'\ncollection.find(filter: where('name').text('Jo*'));\n\n// find all documents where the field 'name' ends with the word 'hn'\ncollection.find(filter: where('name').text('*hn'));\n\n// find all documents where the field 'name' contains the word 'oh'\ncollection.find(filter: where('name').text('*oh*'));"]},{"l":"Regex Filter","p":["The regex filter is used to match documents where values contain a specified regular expression. The following example shows how to use the regex filter:","In this example, the where() and regex() methods are used to create a regex filter that matches documents where the name field matches the regular expression \"John.*\". The filter is then passed to the find method to retrieve the matching documents.","This filter scans the entire collection to find matching documents. It cannot take advantage of an index."]},{"i":"regex-filter-code-1","c":["// find all documents where the field 'name' contains the word 'John'\ncollection.find(filter: where('name').regex('John.*'));"]},{"l":"Spatial Filters","p":["Spatial filters are used to match documents based on the values in a spatial field. The following spatial filters are supported:","Near (near): Matches all documents where the spatial field is within the specified distance from the specified point.","Within (within): Matches all documents where the spatial field is within the specified shape.","Intersects (intersects): Matches all documents where the spatial field intersects the specified shape.","To use spatial filters, you need create a spatial index on the field, which needs the nitrite-spatial module to be loaded. More on this can be found here.","Spatial filters can only be used with a field that has a spatial index."]},{"l":"Near Filter","p":["The near filter is used to match documents where the value of the spatial field is near the specified point. The following example shows how to use the near filter:","In this example, the where() and near() methods are used to create a near filter that matches documents where the location field is within 1000 meters of the point (40.730610, -73.935242). The filter is then passed to the find method to retrieve the matching documents."]},{"i":"near-filter-code-1","c":["import 'package:nitrite_spatial/nitrite_spatial.dart';\n\n// find all documents where the field 'location' is within 1000 meters of the point (40.730610, -73.935242)\nvar reader = WKTReader();\nvar point = reader.read('POINT(40.730610 -73.935242)') as Point;\n\ncollection.find(filter: where('location').near(Center.fromPoint(point), 1000));\n\n// or using Center.fromCoordinates()\ncollection.find(filter: where('location').near(Center.fromCoordinate(point.getCoordinate()!), 1000));"]},{"i":"within-filter-1","l":"Within Filter","p":["The within filter is used to match documents where the value of the spatial field is within the specified shape. The following example shows how to use the within filter:","In this example, the where() and within() methods are used to create a within filter that matches documents where the location field is within the polygon ((0 0, 0 3, 3 3, 3 0, 0 0)). The filter is then passed to the find method to retrieve the matching documents."]},{"i":"within-filter-1-code-1","c":["import 'package:nitrite_spatial/nitrite_spatial.dart';\n\n// find all documents where the field 'location' is within the polygon ((0 0, 0 3, 3 3, 3 0, 0 0))\nvar reader = WKTReader();\nvar polygon = reader.read('POLYGON((0 0, 0 3, 3 3, 3 0, 0 0))') as Polygon;\n\ncollection.find(filter: where('location').within(polygon));"]},{"l":"Intersects Filter","p":["The intersects filter is used to match documents where the value of the spatial field intersects the specified shape. The following example shows how to use the intersects filter:","In this example, the where() and intersects() methods are used to create an intersects filter that matches documents where the location field intersects the polygon ((0 0, 0 3, 3 3, 3 0, 0 0)). The filter is then passed to the find method to retrieve the matching documents."]},{"i":"intersects-filter-code-1","c":["import 'package:nitrite_spatial/nitrite_spatial.dart';\n\n// find all documents where the field 'location' intersects the polygon ((0 0, 0 3, 3 3, 3 0, 0 0))\nvar reader = WKTReader();\nvar polygon = reader.read('POLYGON((0 0, 0 3, 3 3, 3 0, 0 0))') as Polygon;\n\ncollection.find(filter: where('location').intersects(polygon));"]}],[{"l":"Transaction","p":["A transaction is a single logical unit of work which accesses and possibly modifies the contents of a database. Transactions access data using read and write operations.","Nitrite supports transactional operations on its collections and repositories. A transaction can be committed or rolled back. Once a transaction is committed, all the changes are persisted to the disk. If a transaction is rolled back, all the changes are discarded."]},{"l":"Transaction on NitriteCollection","p":["A transaction can be started from a session using the Session.beginTransaction() method. To start a transactional operation on a NitriteCollection, the Transaction.getCollection() method can be used. All the operations performed on the collection will be part of the transaction.","Nitrite also provides a Session.executeTransaction() method to execute a transactional operation. The Session.executeTransaction() method takes a callback function as an argument. The callback function will be executed inside a transaction.","If any exception occurs inside the transaction, the transaction will be rolled back. If you want to rollback a transaction only for certain exceptions, you can use the Session.executeTransaction() method with rollbackFor parameter. The rollbackFor parameter takes a list of exception types for which the transaction will be rolled back. For any other exceptions, the transaction will be committed.","Any find operations performed inside a transaction will return all the documents including the uncommitted ones.","Any find operations performed outside a transaction will return only the committed documents."]},{"i":"transaction-on-nitritecollection-code-1","c":["// start a transaction\nvar transaction = await session.beginTransaction();\n\n// get a collection\nvar collection = await transaction.getCollection(\"test\");\n\n// perform operations on the collection\nawait collection.insert(doc1);\n\n// commit the transaction\nawait transaction.commit();"]},{"i":"transaction-on-nitritecollection-code-2","c":["await session.executeTransaction((transaction) async {\n  var collection = await transaction.getCollection(\"test\");\n  await collection.insert(doc1);\n});"]},{"i":"transaction-on-nitritecollection-code-3","c":["await session.executeTransaction((transaction) async {\n  var collection = await transaction.getCollection(\"test\");\n  await collection.insert(doc1);\n}, rollbackFor: [NitriteException]);"]},{"l":"Auto-commit Operations","p":["Certain operations are auto-committed in Nitrite. Those operations are not part of a transaction and cannot be rolled back. The following operations are auto-committed:","NitriteCollection.createIndex()","NitriteCollection.rebuildIndex()","NitriteCollection.dropIndex()","NitriteCollection.dropAllIndices()","NitriteCollection.drop()","NitriteCollection.clear()","NitriteCollection.close()"]},{"l":"Transaction on ObjectRepository","p":["A transaction can be started from a session using the Session.beginTransaction() method. To start a transactional operation on a ObjectRepository, the Transaction.getRepository() method can be used. All the operations performed on the repository will be part of the transaction.","Nitrite also provides a Session.executeTransaction() method to execute a transactional operation. The Session.executeTransaction() method takes a callback function as an argument. The callback function will be executed inside a transaction.","If any exception occurs inside the transaction, the transaction will be rolled back. If you want to rollback a transaction only for certain exceptions, you can use the Session.executeTransaction() method with rollbackFor parameter. The rollbackFor parameter takes a list of exception types for which the transaction will be rolled back. For any other exceptions, the transaction will be committed.","Any find operations performed inside a transaction will return all the entities including the uncommitted ones.","Any find operations performed outside a transaction will return only the committed entities."]},{"i":"transaction-on-objectrepository-code-1","c":["// start a transaction\nvar transaction = await session.beginTransaction();\n\n// get a repository\nvar repository = await transaction.getRepository<Employee>();\n\n// perform operations on the repository\nawait repository.insert(employee);\n\n// commit the transaction\nawait transaction.commit();"]},{"i":"transaction-on-objectrepository-code-2","c":["await session.executeTransaction((transaction) async {\n  var repository = await transaction.getRepository<Employee>();\n  await repository.insert(employee);\n});"]},{"i":"transaction-on-objectrepository-code-3","c":["await session.executeTransaction((transaction) async {\n  var repository = await transaction.getRepository<Employee>();\n  await repository.insert(employee);\n}, rollbackFor: [NitriteException]);"]},{"i":"auto-commit-operations-1","l":"Auto-commit Operations","p":["Certain operations are auto-committed in Nitrite. Those operations are not part of a transaction and cannot be rolled back. The following operations are auto-committed:","ObjectRepository.createIndex()","ObjectRepository.rebuildIndex()","ObjectRepository.dropIndex()","ObjectRepository.dropAllIndices()","ObjectRepository.drop()","ObjectRepository.clear()","ObjectRepository.close()"]},{"l":"Session","p":["A session represents a transactional context for a Nitrite database. Session is used to create a new transaction. A session should be closed after use to release any resources held by it. If a session is closed and the transaction is not committed, all opened transactions will be rolled back."]},{"l":"Create a Session","p":["A session can be created using the Nitrite.createSession() method. Multiple sessions can be created for a Nitrite database."]},{"i":"create-a-session-code-1","c":["// create a session\nvar session = db.createSession();"]},{"l":"Close a Session","p":["A session can be closed using the Session.close() method. If a session is closed and the transaction is not committed, all opened transactions will be rolled back."]},{"i":"close-a-session-code-1","c":["// close a session\nawait session.close();"]},{"l":"Checking If Session is Active","p":["A session can be checked if it is active or not using the Session.isActive getter."]},{"i":"checking-if-session-is-active-code-1","c":["// check if session is active\nif (session.isActive) {\n  // do something\n}"]},{"l":"Managing Transactions","p":["A transaction can be started using the Session.beginTransaction() method.","A transaction can be committed using the Transaction.commit() method. If a transaction is committed, all the changes are persisted to the disk.","A transaction can be rolled back using the Transaction.rollback() method. If a transaction is rolled back, all the changes are discarded.","A transaction can be closed using the Transaction.close() method. If a transaction is closed and the transaction is not committed, all opened transactions will be rolled back."]},{"i":"managing-transactions-code-1","c":["// start a transaction\nvar transaction = await session.beginTransaction();"]},{"i":"managing-transactions-code-2","c":["// commit a transaction\nawait transaction.commit();"]},{"i":"managing-transactions-code-3","c":["// rollback a transaction\nawait transaction.rollback();"]},{"i":"managing-transactions-code-4","c":["// close a transaction\nawait transaction.close();"]},{"l":"Querying Transaction State","p":["The current state of a transaction can be retrieved using the Transaction.getState() method. It returns an enum of type TransactionState.","Possible values for TransactionState are:","TransactionState.active - The transaction is active.","TransactionState.committed - The transaction is committed.","TransactionState.partiallyCommitted - The transaction is partially committed.","TransactionState.closed - The transaction is closed.","TransactionState.failed - The transaction is failed.","TransactionState.aborted - The transaction is aborted."]},{"i":"querying-transaction-state-code-1","c":["// get transaction state\nvar state = transaction.getState();"]}],[{"l":"Schema Migration","p":["A migration is a set of changes to the schema that can be applied to a database. Migrations are used to keep the database schema up to date with the codebase. It contains a queue of instructions that are executed in order to update the database schema from one version to the next.","The migration is executed only once for a specific schema version.ni If you want to execute the migration again, you need to change the schema version of the database.","For example, if you have a database with the schema version 1 and you want to update it to version 2, you need to apply the migration steps from version 1 and version 2.","The migration instructions are executed in the order they are added to the migration. The order of the instructions is important. For example, if you want to rename a field, you need to add the renameField instruction before the deleteField instruction. Otherwise, the deleteField instruction will fail.","Once a migration is applied to a database, it cannot be reverted. If you want to revert a migration, you need to create a new migration that will revert the changes.","Nitrite provides a set of instructions that can be used to update the database schema. These instructions can be grouped into three categories:","Database Instruction","Collection Instruction","Repository Instruction"]},{"i":"schema-migration-code-1","c":["// create a migration\n\nvar migration = Migration(1, 2, (instructionSet) {\n   instructionSet\n        .forDatabase()\n        .addUser('test-user', 'test-password');\n\n   instructionSet\n        .forRepository<OldClass>(key: 'demo1')\n        .renameRepository('new')\n        .changeDataType('empId', (value) => int.parse(value))\n        .changeIdField(Fields.withNames(['uuid']), Fields.withNames(['empId']))\n        .deleteField('uuid')\n        .renameField('lastName', 'familyName')\n        .addField('fullName', generator: (document) => '${document['firstName']} ${document['familyName']}')\n        .dropIndex(['firstName'])\n        .dropIndex(['literature.text'])\n        .changeDataType('literature.ratings', (value) => (value as double).round());\n    },\n);\n\n// apply the migration\nvar db = Nitrite.builder()\n    .loadModule(storeModule)\n    .schemaVersion(1)\n    .addMigration(migration)\n    .openOrCreate('test-user', 'test-password');"]},{"l":"Database Instruction","p":["Database instructions are used to perform operations on the database. The following instructions are available:"]},{"l":"Add User","p":["Adds an instruction to set a user authentication to the database. The user will be used to open the database.","Nitrite database supports only one user authentication per database. If you try to add a new user when there is already a user authentication present, the migration will fail throwing a NitriteSecurityException."]},{"i":"add-user-code-1","c":["instruction.forDatabase()\n    .addUser(\"test-user\", \"test-password\");"]},{"l":"Change Password","p":["Adds an instruction to change the password for the user authentication to the database.","The user authentication must be present in the database. If you try to change the password for a user that does not exist, the migration will fail throwing a NitriteSecurityException.","If you try to change the password for a user with a wrong password, the migration will also fail throwing a NitriteSecurityException."]},{"i":"change-password-code-1","c":["instruction.forDatabase()\n    .changePassword(\"test-user\", \"test-password\", \"new-password\");"]},{"l":"Drop Collection","p":["Adds an instruction to drop a NitriteCollection from the database."]},{"i":"drop-collection-code-1","c":["instruction.forDatabase()\n    .dropCollection(\"collection-name\");"]},{"l":"Drop Repository","p":["Adds an instruction to drop a ObjectRepository from the database. There are several ways to drop a repository:"]},{"l":"Drop by Type"},{"i":"drop-by-type-code-1","c":["instruction.forDatabase()\n    .dropRepository<OldClass>();"]},{"l":"Drop by Type and Key Name"},{"i":"drop-by-type-and-key-name-code-1","c":["instruction.forDatabase()\n    .dropRepository<OldClass>(key: \"demo1\");"]},{"l":"Drop by EntityDecorator"},{"i":"drop-by-entitydecorator-code-1","c":["instruction.forDatabase()\n    .dropRepository(entityDecorator: OldClassEntityDecorator());"]},{"l":"Drop by EntityDecorator and Key Name"},{"i":"drop-by-entitydecorator-and-key-name-code-1","c":["instruction.forDatabase()\n    .dropRepository(entityDecorator: OldClassEntityDecorator(),  key: \"demo1\");"]},{"l":"Drop by Entity Name"},{"i":"drop-by-entity-name-code-1","c":["instruction.forDatabase()\n    .dropRepository(entityName: \"OldClass\");"]},{"l":"Drop by Entity Name and Key Name"},{"i":"drop-by-entity-name-and-key-name-code-1","c":["instruction.forDatabase()\n    .dropRepository(entityName: \"OldClass\", key: \"demo1\");"]},{"l":"Custom Instruction","p":["Adds a custom instruction to the migration. The custom instruction is a callback function that takes a Nitrite instance as an argument. The callback function can be used to perform any operation on the database."]},{"i":"custom-instruction-code-1","c":["instruction.forDatabase()\n    .customInstruction((db) {\n        // perform any operation on the database\n    });"]},{"l":"Collection Instruction","p":["Collection instructions are used to perform operations on a NitriteCollection. The following instructions are available:"]},{"l":"Rename Collection","p":["Adds an instruction to rename a NitriteCollection."]},{"i":"rename-collection-code-1","c":["instruction.forCollection(\"collection-name\")\n    .rename(\"new-collection-name\");"]},{"l":"Add Field","p":["Adds an instruction to add new field to the documents of a NitriteCollection."]},{"l":"Add Field with Null Value","p":["The new field will be added to all the documents of the collection. The value of the new field will be null."]},{"i":"add-field-with-null-value-code-1","c":["instruction.forCollection(\"collection-name\")\n    .addField(\"new-field\");"]},{"l":"Add Field with Default Value","p":["The new field will be added to all the documents of the collection. The value of the new field will be new-value."]},{"i":"add-field-with-default-value-code-1","c":["instruction.forCollection(\"collection-name\")\n    .addField(\"new-field\", defaultValue: \"new-value\");"]},{"l":"Add Field with Generator","p":["The new field will be added to all the documents of the collection. The value of the new field will be the value returned by the Generator."]},{"i":"add-field-with-generator-code-1","c":["instruction.forCollection(\"collection-name\")\n    .addField(\"new-field\", generator: (document) => \"new-value\");"]},{"l":"Generator","p":["A Generator is a function that takes a Document as input and returns a value. The value returned by the Generator will be used as the value of the new field."]},{"i":"generator-code-1","c":["Generator generator = (document) => \"new-value\";"]},{"l":"Rename Field","p":["Adds an instruction to rename a field of the documents of a NitriteCollection."]},{"i":"rename-field-code-1","c":["instruction.forCollection(\"collection-name\")\n    .renameField(\"old-field\", \"new-field\");"]},{"l":"Delete Field","p":["Adds an instruction to delete a field from the documents of a NitriteCollection."]},{"i":"delete-field-code-1","c":["instruction.forCollection(\"collection-name\")\n    .deleteField(\"field-name\");"]},{"l":"Drop Index","p":["Adds an instruction to drop an index from a NitriteCollection.","The drop index instruction can be used to drop a single field index or a compound index."]},{"i":"drop-index-code-1","c":["instruction.forCollection(\"collection-name\")\n    .dropIndex([\"field-name-1\", \"field-name-2\"]);"]},{"l":"Drop All Indexes","p":["Adds an instruction to drop all the indexes from a NitriteCollection."]},{"i":"drop-all-indexes-code-1","c":["instruction.forCollection(\"collection-name\")\n    .dropAllIndices();"]},{"l":"Create Index","p":["Adds an instruction to create an index on a NitriteCollection.","The create index instruction can be used to create a single field index or a compound index."]},{"i":"create-index-code-1","c":["instruction.forCollection(\"collection-name\")\n    .createIndex(IndexType.nonUnique, [\"field-name-1\", \"field-name-2\"]);"]},{"l":"Repository Instruction","p":["Repository instructions are used to perform operations on a ObjectRepository. The following instructions are available:"]},{"l":"Rename Repository","p":["Adds an instruction to rename a ObjectRepository."]},{"i":"rename-repository-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .renameRepository(\"newName\");"]},{"i":"add-field-1","l":"Add Field","p":["Adds an instruction to add new field to the entity of a ObjectRepository."]},{"i":"add-field-with-null-value-1","l":"Add Field with Null Value","p":["The new field will be added to all the entities of the repository. The value of the new field will be null."]},{"i":"add-field-with-null-value-1-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .addField(\"new-field\");"]},{"i":"add-field-with-default-value-1","l":"Add Field with Default Value","p":["The new field will be added to all the entities of the repository. The value of the new field will be new-value."]},{"i":"add-field-with-default-value-1-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .addField(\"new-field\", defaultValue: \"new-value\");"]},{"l":"Add Field with Generator Function","p":["The new field will be added to all the entities of the repository. The value of the new field will be the value returned by the Generator function.","More information about the Generator can be found here."]},{"i":"add-field-with-generator-function-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .addField(\"new-field\", generator: (entity) => \"new-value\");"]},{"i":"rename-field-1","l":"Rename Field","p":["Adds an instruction to rename a field of the entity of a ObjectRepository."]},{"i":"rename-field-1-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .renameField(\"old-field\", \"new-field\");"]},{"i":"delete-field-1","l":"Delete Field","p":["Adds an instruction to delete a field from the entity of a ObjectRepository."]},{"i":"delete-field-1-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .deleteField(\"field-name\");"]},{"l":"Change Data Type","p":["Adds an instruction to change the data type of a field of the entity of a ObjectRepository."]},{"i":"change-data-type-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .changeDataType(\"field-name\", (value) => int.parse(value));"]},{"l":"Type Converter","p":["A TypeConverter is a function that takes a value of one type as input and returns a value of another type. The value returned by the TypeConverter will be used as the value of the new field."]},{"i":"type-converter-code-1","c":["// convert String to int\nTypeConverter typeConverter = (value) => int.parse(value);\n\n// convert double to int\nTypeConverter typeConverter = (value) => (value as double).round();"]},{"l":"Change Id Field","p":["Adds an instruction to change the id field of the entity of a ObjectRepository."]},{"i":"change-id-field-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .changeIdField(Fields.withNames([\"uuid\"]), Fields.withNames([\"empId\"]));"]},{"i":"drop-index-1","l":"Drop Index","p":["Adds an instruction to drop an index from a ObjectRepository.","The drop index instruction can be used to drop a single field index or a compound index."]},{"i":"drop-index-1-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .dropIndex([\"field-name-1\", \"field-name-2\"]);"]},{"i":"drop-all-indexes-1","l":"Drop All Indexes","p":["Adds an instruction to drop all the indexes from a ObjectRepository."]},{"i":"drop-all-indexes-1-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .dropAllIndices();"]},{"i":"create-index-1","l":"Create Index","p":["Adds an instruction to create an index on a ObjectRepository.","The create index instruction can be used to create a single field index or a compound index."]},{"i":"create-index-1-code-1","c":["instruction.forRepository<OldClass>(key: \"demo1\")\n    .createIndex(IndexType.nonUnique, [\"field-name-1\", \"field-name-2\"]);"]}],[{"l":"Module System","p":["Nitrite is a modular database engine. The core functionality of Nitrite is provided by the nitrite module. The nitrite module is the only mandatory module for Nitrite. All other modules are optional and can be added to the project as per the requirement.","Nitrite's module system is built on top of NitritePlugin and NitriteModule interfaces. A module is a collection of plugins. While opening a database, all the modules must be loaded. Each module then load and initialize all the plugins it contains.","The nitrite module provides default implementation of all the interfaces. For example, the nitrite module provides in-memory storage implementation. If you want to use on-disk storage, you need to add a storage module to your project.","The main advantage of Nitrite's module system is that it allows you to extend the functionality of Nitrite without adding all the dependencies at once in your project. You only need to add dependencies that you want to use. This helps to keep the application size small.","You can write your own module and plugin and add it to the project. The module system also allows you to replace the default implementation of any plugin. For example, if you want to use a different storage engine, you can write your own storage module and add it to the project."]},{"l":"NitriteModule","p":["The NitriteModule interface is the base interface for all the modules. It encapsulates a set of plugins. A module must be loaded before opening a database.","To create a module, you need to implement the NitriteModule interface. The NitriteModule interface has a single getter plugins which returns a set of plugins."]},{"i":"nitritemodule-code-1","c":["var module = MyModule();\n\nvar db = await Nitrite.builder()\n    .loadModule(module)\n    .openOrCreate();"]},{"i":"nitritemodule-code-2","c":["class MyModule implements NitriteModule {\n  @override\n  Set<NitritePlugin> get plugins => {MyPlugin()};\n}"]},{"l":"Dynamic Module","p":["A dynamic module can be created using the global module() method. A dynamic module is a module which is not loaded from any package, instead it is created dynamically.","A dynamic module is useful when you want to create a module from a set of plugins at runtime."]},{"i":"dynamic-module-code-1","c":["var module = module([MyPlugin()]);\n\nvar db = await Nitrite.builder()\n    .loadModule(module)\n    .openOrCreate();"]},{"l":"Available Modules","p":["The following modules are available from Nitrite.","Storage Module","Spatial Module"]},{"l":"NitritePlugin","p":["The NitritePlugin interface is the base interface for all the plugins. A plugin is a single unit of functionality. A plugin must be loaded via a NitriteModule before opening a database."]},{"i":"nitriteplugin-code-1","c":["var plugin = MyPlugin();\nvar module = MyModule(plugin);\nvar db = await Nitrite.builder()\n    .loadModule(module)\n    .openOrCreate();"]},{"l":"Initializing Plugin","p":["A plugin can be initialized by implementing the initialize() method of the NitritePlugin interface. The initialize() method is called by the module when the plugin is loaded."]},{"i":"initializing-plugin-code-1","c":["class MyPlugin implements NitritePlugin {\n  @override\n  Future<void> initialize(NitriteConfig nitriteConfig) async {\n    // do something\n  }\n}"]},{"l":"Closing Plugin","p":["A plugin can be closed by implementing the close() method of the NitritePlugin interface. The close() method is called by the module when the database is closed."]},{"i":"closing-plugin-code-1","c":["class MyPlugin implements NitritePlugin {\n  @override\n  Future<void> close() async {\n    // do something\n  }\n}"]},{"l":"Available Plugins","p":["Following are the available plugins in Nitrite which can be used to extend the functionality of Nitrite:","NitriteStore - A plugin to provide storage functionality.","NitriteMapper - A plugin to provide object mapping functionality.","NitriteIndexer - A plugin to provide indexing functionality.","EntityConverter - A plugin to provide entity conversion functionality.","You can implement any of the above plugins to extend the functionality of Nitrite."]},{"l":"NitriteStore","p":["The NitriteStore interface is the base interface for all the storage plugins. A storage plugin is responsible for storing and retrieving data from the underlying storage. The NitriteStore interface extends the NitritePlugin interface.","A reference implementation of the NitriteStore interface can be found here."]},{"i":"nitritestore-code-1","c":["class MyStore implements NitriteStore {\n    // implement the methods  \n}"]},{"l":"NitriteMapper","p":["The NitriteMapper interface is the base interface for all the object mapping plugins. A mapper plugin is responsible for mapping an object to a document and vice-versa. The NitriteMapper interface extends the NitritePlugin interface."]},{"i":"nitritemapper-code-1","c":["class MyMapper extends NitriteMapper {\n    // implement the methods\n}"]},{"l":"NitriteIndexer","p":["The NitriteIndexer interface is the base interface for all the indexing plugins. An indexer plugin is responsible for indexing a document. The NitriteIndexer interface extends the NitritePlugin interface.","While creating a new index, Nitrite uses the indexType getter to determine the type of the index. The indexType getter must return a unique string for each type of index. So when you create a new index, you need to pass the same string to the IndexOptions.indexType."]},{"i":"nitriteindexer-code-1","c":["class CustomIndexer implements NitriteIndexer {\n    static final String customIndex = 'custom';\n\n    @override\n    String get indexType => customIndex;\n\n    // implement the methods\n}"]},{"i":"nitriteindexer-code-2","c":["var index = await collection.createIndex(['myField'], indexOptions(CustomIndexer.customIndex);"]},{"l":"EntityConverter","p":["An EntityConverter is a plugin which is responsible for converting an object to a document and vice-versa. The EntityConverter interface extends the NitritePlugin interface.","If Nitrite is using the default SimpleNitriteMapper, then all EntityConverters from all the loaded modules are automatically registered with the mapper. If you are using a custom mapper, then you need to register the EntityConverter with the mapper manually.","One of the available EntityConverter in Nitrite is GeometryConverter from the spatial module. It is responsible for converting a Geometry object of JTS to a document and vice-versa. Once you load the spatial module, the GeometryConverter is automatically registered with the mapper. You can find more information about GeometryConverter here.","If you want to load multiple EntityConverters, while opening the database, you can also create a dynamic module and load it instead of using the NitriteBuilder.registerEntityConverter() method multiple times."]},{"i":"entityconverter-code-1","c":["var module = module([MyConverter(), MyOtherConverter()]);\n\nvar db = await Nitrite.builder()\n    .loadModule(module)\n    .openOrCreate();"]}],[{"l":"Storage Module","p":["Nitrite provides a default storage module which is in-memory. It means all the data is stored in memory and is volatile. Once the application is closed, all the data is lost. If you want to persist the data, you want to use on-disk storage, you need to add a storage module to your project. There are choices of storage modules available for Nitrite. You can choose from below as per your requirement.","Hive Module","You can also write your own storage module and add it to the project. More details about writing your own storage module is available here."]}],[{"l":"Hive Modules","p":["Nitrite provides a persistent storage module based on Hive. Hive is a lightweight and blazing fast, file based key-value store written in pure Dart."]},{"l":"Adding Hive Module","p":["To use Hive module, you need add below dependency to your project:"]},{"i":"adding-hive-module-code-1","c":["dart pub add nitrite\ndart pub add nitrite_hive_adapter"]},{"l":"Using Hive Module","p":["To use Hive as your persistent storage, you need to load the HiveModule while opening the database. You can also configure the module as per your requirement.","Once the module is loaded, you can use the database as usual. All the data will be persisted in the file you specified."]},{"i":"using-hive-module-code-1","c":["import 'package:nitrite/nitrite.dart';\nimport 'package:nitrite_hive_adapter/nitrite_hive_adapter.dart';\n\n// configure the module\nvar storeModule = HiveModule.withConfig()\n            .path(filePath)\n            .build();\n\nvar db = await Nitrite.builder()\n            .loadModule(storeModule)\n            .openOrCreate();"]},{"l":"Configuring Hive Module","p":["You can configure the Hive module as per your requirement. The following configuration options are available:","path - the file path where the database will be stored. It is a directory path.","backendPreference - the preference for the backend to use. It takes an enum HiveStorageBackendPreference.","encryptionCipher - the encryption cipher used to encrypt the database. If not specified, the database will not be encrypted. It takes a HiveCipher instance.","compactionStrategy - the compaction strategy to use. It takes a function of type CompactionStrategy.","crashRecovery - if set to true, the database will be recovered from crash. The default value is false.","addTypeAdapter() - you can add your own type adapter to the Hive database. It takes a TypeAdapter instance.","addStoreEventListener() - you can add your own store event listener to the Hive database. It takes a StoreEventListener function as argument.","Nitrite provides a builder pattern to configure the module. You can use the HiveModule.withConfig() method to get the builder instance. The builder has a build() method which returns the module instance.","For more details about Hive configuration, please visit Hive Documentation."]},{"i":"configuring-hive-module-code-1","c":["var storeModule = HiveModule.withConfig()\n            .path(filePath)\n            .backendPreference(HiveStorageBackendPreference.native)\n            .encryptionCipher(StandardAESEncryption(password))\n            .compactionStrategy((entries, deletedEntries) => true)\n            .crashRecovery(true)\n            .addTypeAdapter(MyTypeAdapter())\n            .addStoreEventListener((event) => print(event))\n            .build();"]}],[{"l":"Custom Storage Modules","p":["The beauty of Nitrite is that it is highly extensible. You can write your own storage module and use it with Nitrite. Nitrite provides a simple interface StoreModule to write your own storage module."]},{"l":"StoreModule Interface","p":["To write a custom storage module, you need to implement the StoreModule interface. The interface has only one method getStore() which returns an implementation of NitriteStore interface.","Optionally, you can also implement the StoreConfig interface to provide configuration options for your storage module."]},{"l":"NitriteStore Interface","p":["The NitriteStore is the storage abstraction layer for Nitrite. It provides the basic operations required by Nitrite to store and retrieve data. A NitriteStore is responsible for managing NitriteMap and NitriteRTree instances which are the main building blocks of database collections."]},{"l":"StoreConfig Interface","p":["The StoreConfig interface provides configuration options for your storage module. You can use this interface to provide configuration options for your storage module."]},{"l":"NitriteMap Interface","p":["The NitriteMap interface is the abstraction layer for Nitrite's key-value store. It provides the basic operations required by a collection to store and retrieve data. A NitriteMap is responsible for managing NitriteId and Document instances which are the main unit of data storage in Nitrite."]},{"l":"NitriteRTree Interface","p":["The NitriteRTree interface is the abstraction layer for Nitrite's R-Tree. It provides the basic operations required by a spatial index to store and retrieve data."]},{"l":"Example","p":["Let's write a simple storage module which stores data in a Map object. The module will be a simple in-memory storage module. The module will be configured with a Map object and will use it to store data."]},{"l":"Store Module","p":["The following code snippet shows the implementation of the storage module."]},{"i":"store-module-code-1","c":["import 'package:nitrite/nitrite.dart';\n\nclass InMemoryStoreModule extends StoreModule {\n  InMemoryConfig _storeConfig = InMemoryConfig();\n\n  static InMemoryModuleBuilder withConfig() => InMemoryModuleBuilder._();\n\n  @override\n  NitriteStore<Config> getStore<Config extends StoreConfig>() {\n    var store = InMemoryStore(_storeConfig);\n    return store as NitriteStore<Config>;\n  }\n\n  @override\n  Set<NitritePlugin> get plugins => <NitritePlugin>{getStore()};\n}"]},{"l":"Store Config","p":["The following code snippet shows the implementation of the store configuration.","And the builder class for the configuration."]},{"i":"store-config-code-1","c":["class InMemoryConfig extends StoreConfig {\n  Set<StoreEventListener> _eventListeners = <StoreEventListener>{};\n\n  @override\n  void addStoreEventListener(StoreEventListener listener) {\n    _eventListeners.add(listener);\n  }\n\n  @override\n  String? get filePath => null;\n\n  @override\n  bool get isReadOnly => false;\n\n  @override\n  Set<StoreEventListener> get eventListeners =>\n      Set.unmodifiable(_eventListeners);\n}"]},{"i":"store-config-code-2","c":["class InMemoryModuleBuilder {\n  final Set<StoreEventListener> _eventListeners = <StoreEventListener>{};\n  final InMemoryConfig _dbConfig = InMemoryConfig();\n\n  InMemoryModuleBuilder._();\n\n  /// Adds a [StoreEventListener] to the in-memory module builder.\n  InMemoryModuleBuilder addStoreEventListener(StoreEventListener listener) {\n    _eventListeners.add(listener);\n    return this;\n  }\n\n  /// Builds an in-memory store module.\n  InMemoryStoreModule build() {\n    var module = InMemoryStoreModule();\n    _dbConfig._eventListeners = _eventListeners;\n    module._storeConfig = _dbConfig;\n    return module;\n  }\n}"]},{"l":"Nitrite Store","p":["The following code snippet shows the implementation of the NitriteStore interface."]},{"i":"nitrite-store-code-1","c":["class InMemoryStore extends AbstractNitriteStore<InMemoryConfig> {\n  final Map<String, dynamic> _nitriteMapRegistry;\n  final Map<String, dynamic> _nitriteRTreeMapRegistry;\n  bool _closed = false;\n\n  InMemoryStore(super._storeConfig)\n      : _nitriteMapRegistry = <String, dynamic>{},\n        _nitriteRTreeMapRegistry = <String, dynamic>{};\n\n  @override\n  bool get isClosed => _closed;\n\n  @override\n  Future<bool> get hasUnsavedChanges async => false;\n\n  @override\n  bool get isReadOnly => false;\n\n  @override\n  String get storeVersion => 'InMemory/$nitriteVersion';\n\n  @override\n  Future<void> openOrCreate() async {\n    _initEventBus();\n    alert(StoreEvents.opened);\n  }\n\n  @override\n  Future<void> close() async {\n    // close all maps and rtree\n    close(MapEntry entry) => entry.value.close();\n    _closed = true;\n\n    // to avoid concurrent modification exception\n    var tempMap = Map.from(_nitriteMapRegistry);\n    tempMap.entries.forEach(close);\n\n    tempMap = Map.from(_nitriteRTreeMapRegistry);\n    tempMap.entries.forEach(close);\n\n    _nitriteMapRegistry.clear();\n    _nitriteRTreeMapRegistry.clear();\n    await super.close();\n  }\n\n  @override\n  Future<void> commit() async {\n    alert(StoreEvents.commit);\n  }\n\n  @override\n  Future<bool> hasMap(String mapName) async {\n    return _nitriteMapRegistry.containsKey(mapName) ||\n        _nitriteRTreeMapRegistry.containsKey(mapName);\n  }\n\n  @override\n  Future<NitriteMap<Key, Value>> openMap<Key, Value>(String mapName) async {\n    if (_nitriteMapRegistry.containsKey(mapName)) {\n      var nitriteMap = _nitriteMapRegistry[mapName]!;\n      if (nitriteMap.isClosed) {\n        _nitriteMapRegistry.remove(mapName);\n      } else {\n        return nitriteMap as InMemoryMap<Key, Value>;\n      }\n    }\n\n    var nitriteMap = InMemoryMap<Key, Value>(mapName, this);\n    _nitriteMapRegistry[mapName] = nitriteMap;\n    return nitriteMap;\n  }\n\n  @override\n  Future<NitriteRTree<Key, Value>> openRTree<Key extends BoundingBox, Value>(\n      String rTreeName) async {\n    if (_nitriteRTreeMapRegistry.containsKey(rTreeName)) {\n      return _nitriteRTreeMapRegistry[rTreeName]! as InMemoryRTree<Key, Value>;\n    }\n\n    var nitriteRTree = InMemoryRTree<Key, Value>(rTreeName, this);\n    _nitriteRTreeMapRegistry[rTreeName] = nitriteRTree;\n    return nitriteRTree;\n  }\n\n  @override\n  Future<void> closeMap(String mapName) async {\n    _nitriteMapRegistry.remove(mapName);\n  }\n\n  @override\n  Future<void> closeRTree(String rTreeName) async {\n    _nitriteRTreeMapRegistry.remove(rTreeName);\n  }\n\n  @override\n  Future<void> removeMap(String mapName) async {\n    if (_nitriteMapRegistry.containsKey(mapName)) {\n      var map = _nitriteMapRegistry[mapName]!;\n\n      if (!map.isClosed && !map.isDropped) {\n        await map.close();\n      }\n\n      _nitriteMapRegistry.remove(mapName);\n      var catalog = await getCatalog();\n      await catalog.remove(mapName);\n    }\n  }\n\n  @override\n  Future<void> removeRTree(String rTreeName) async {\n    if (_nitriteRTreeMapRegistry.containsKey(rTreeName)) {\n      var rTree = _nitriteRTreeMapRegistry[rTreeName]!;\n      await rTree.close();\n      _nitriteRTreeMapRegistry.remove(rTreeName);\n      var catalog = await getCatalog();\n      await catalog.remove(rTreeName);\n    }\n  }\n\n  void _initEventBus() {\n    if (storeConfig!.eventListeners.isNotEmpty) {\n      for (var listener in storeConfig!.eventListeners) {\n        subscribe(listener);\n      }\n    }\n  }\n}"]},{"l":"Nitrite Map","p":["The following code snippet shows the implementation of the NitriteMap interface."]},{"i":"nitrite-map-code-1","c":["class InMemoryMap<Key, Value> extends NitriteMap<Key, Value> {\n  final SplayTreeMap<Key, Value> _backingMap;\n  final NitriteStore _nitriteStore;\n  final String _mapName;\n\n  bool _droppedFlag = false;\n  bool _closedFlag = false;\n\n  InMemoryMap(this._mapName, this._nitriteStore)\n      : _backingMap = SplayTreeMap<Key, Value>(_comp);\n\n  @override\n  String get name => _mapName;\n\n  @override\n  Future<bool> containsKey(Key key) async {\n    _checkOpened();\n    return _backingMap.containsKey(key);\n  }\n\n  @override\n  Future<Value?> operator [](Key key) async {\n    _checkOpened();\n    return _backingMap[key];\n  }\n\n  @override\n  NitriteStore<Config> getStore<Config extends StoreConfig>() {\n    return _nitriteStore as NitriteStore<Config>;\n  }\n\n  @override\n  Stream<Value> values() {\n    _checkOpened();\n    return Stream.fromIterable(_backingMap.values);\n  }\n\n  @override\n  Future<Value?> remove(Key key) async {\n    _checkOpened();\n    var val = _backingMap.remove(key);\n    await updateLastModifiedTime();\n    return val;\n  }\n\n  @override\n  Stream<Key> keys() {\n    _checkOpened();\n    return Stream.fromIterable(_backingMap.keys);\n  }\n\n  @override\n  Future<void> put(Key key, Value value) {\n    _checkOpened();\n    _backingMap[key] = value;\n    return updateLastModifiedTime();\n  }\n\n  @override\n  Future<int> size() async {\n    _checkOpened();\n    return _backingMap.length;\n  }\n\n  @override\n  Future<Value?> putIfAbsent(Key key, Value value) async {\n    _checkOpened();\n    if (await containsKey(key)) {\n      return _backingMap[key];\n    } else {\n      _backingMap[key] = value;\n      await updateLastModifiedTime();\n      return null;\n    }\n  }\n\n  @override\n  Stream<(Key, Value)> entries() {\n    _checkOpened();\n    return Stream.fromIterable(\n        _backingMap.entries.map((e) => (e.key, e.value)));\n  }\n\n  @override\n  Stream<(Key, Value)> reversedEntries() {\n    _checkOpened();\n    return Stream.fromIterable(\n        _backingMap.reversedEntries.map((e) => (e.key, e.value)));\n  }\n\n  @override\n  Future<Key?> higherKey(Key key) async {\n    _checkOpened();\n    if (key == null) return null;\n    return _backingMap.higherKey(key);\n  }\n\n  @override\n  Future<Key?> ceilingKey(Key key) async {\n    _checkOpened();\n    if (key == null) return null;\n    return _backingMap.ceilingKey(key);\n  }\n\n  @override\n  Future<Key?> lowerKey(Key key) async {\n    _checkOpened();\n    if (key == null) return null;\n    return _backingMap.lowerKey(key);\n  }\n\n  @override\n  Future<Key?> floorKey(Key key) async {\n    _checkOpened();\n    if (key == null) return null;\n    return _backingMap.floorKey(key);\n  }\n\n  @override\n  Future<bool> isEmpty() async {\n    _checkOpened();\n    return _backingMap.isEmpty;\n  }\n\n  @override\n  Future<void> drop() async {\n    if (!_droppedFlag) {\n      _backingMap.clear();\n      await getStore().removeMap(_mapName);\n      _droppedFlag = true;\n      _closedFlag = true;\n    }\n  }\n\n  @override\n  bool get isDropped => _droppedFlag;\n\n  @override\n  Future<void> close() async {\n    _closedFlag = true;\n    await _nitriteStore.closeMap(_mapName);\n  }\n\n  @override\n  bool get isClosed => _closedFlag;\n\n  @override\n  Future<void> clear() async {\n    _checkOpened();\n    _backingMap.clear();\n    await _nitriteStore.closeMap(_mapName);\n    await updateLastModifiedTime();\n  }\n\n  static int _comp(k1, k2) {\n    if (k1 is Comparable && k2 is Comparable) {\n      return compare(k1, k2);\n    }\n    return Comparable.compare(k1, k2);\n  }\n\n  void _checkOpened() {\n    if (_closedFlag) {\n      throw InvalidOperationException('Map $_mapName is closed');\n    }\n    if (_droppedFlag) {\n      throw InvalidOperationException('Map $_mapName is dropped');\n    }\n  }\n\n  @override\n  Future<void> initialize() async {}\n}"]},{"l":"Nitrite RTree","p":["The following code snippet shows the implementation of the NitriteRTree interface."]},{"i":"nitrite-rtree-code-1","c":["class InMemoryRTree<Key extends BoundingBox, Value>\n    extends NitriteRTree<Key, Value> {\n  final Map<SpatialKey, Key?> _backingMap = <SpatialKey, Key?>{};\n  final NitriteStore _nitriteStore;\n  final String _mapName;\n\n  bool _droppedFlag = false;\n  bool _closedFlag = false;\n\n  InMemoryRTree(this._mapName, this._nitriteStore);\n\n  @override\n  Future<int> size() async {\n    _checkOpened();\n    return _backingMap.length;\n  }\n\n  @override\n  Future<void> add(Key? key, NitriteId? value) async {\n    _checkOpened();\n    if (value != null) {\n      var spatialKey = _getKey(key, int.parse(value.idValue));\n      _backingMap[spatialKey] = key;\n    }\n  }\n\n  @override\n  Future<void> remove(Key? key, NitriteId? value) async {\n    _checkOpened();\n    if (value != null) {\n      var spatialKey = _getKey(key, int.parse(value.idValue));\n      _backingMap.remove(spatialKey);\n    }\n  }\n\n  @override\n  Stream<NitriteId> findIntersectingKeys(Key? key) async* {\n    _checkOpened();\n    var spatialKey = _getKey(key, 0);\n\n    for (var sk in _backingMap.keys) {\n      if (_isOverlap(sk, spatialKey)) {\n        yield NitriteId.createId(sk.id.toString());\n      }\n    }\n  }\n\n  @override\n  Stream<NitriteId> findContainedKeys(Key? key) async* {\n    _checkOpened();\n    var spatialKey = _getKey(key, 0);\n\n    for (var sk in _backingMap.keys) {\n      if (_isInside(sk, spatialKey)) {\n        yield NitriteId.createId(sk.id.toString());\n      }\n    }\n  }\n\n  @override\n  Future<void> clear() async {\n    _checkOpened();\n    _backingMap.clear();\n    await _nitriteStore.closeRTree(_mapName);\n  }\n\n  @override\n  Future<void> close() async {\n    _closedFlag = true;\n    await _nitriteStore.closeRTree(_mapName);\n  }\n\n  @override\n  Future<void> drop() async {\n    _checkOpened();\n    _droppedFlag = true;\n    _backingMap.clear();\n    await _nitriteStore.removeRTree(_mapName);\n  }\n\n  SpatialKey _getKey(Key? key, int id) {\n    if (key == null || key == BoundingBox.empty) {\n      return SpatialKey(id, []);\n    }\n    return SpatialKey(id, [key.minX, key.maxX, key.minY, key.maxY]);\n  }\n\n  bool _isOverlap(SpatialKey a, SpatialKey b) {\n    if (a.isNull() || b.isNull()) {\n      return false;\n    }\n\n    for (var i = 0; i < 2; i++) {\n      if (a.max(i) < b.min(i) || a.min(i) > b.max(i)) {\n        return false;\n      }\n    }\n\n    return true;\n  }\n\n  bool _isInside(SpatialKey a, SpatialKey b) {\n    if (a.isNull() || b.isNull()) {\n      return false;\n    }\n\n    for (var i = 0; i < 2; i++) {\n      if (a.min(i) <= b.min(i) || a.max(i) >= b.max(i)) {\n        return false;\n      }\n    }\n\n    return true;\n  }\n\n  void _checkOpened() {\n    if (_closedFlag) {\n      throw NitriteException('RTreeMap is closed');\n    }\n    if (_droppedFlag) {\n      throw NitriteException('RTreeMap is dropped');\n    }\n  }\n\n  @override\n  Future<void> initialize() async {}\n}"]}],[{"l":"Spatial Module","p":["Nitrite Spatial module provides support for spatial queries. The module uses JTS port of the dart package dart_jts for spatial operations."]},{"l":"Adding Spatial Module","p":["To use Spatial module to your project, you need to add below dependency to your project:"]},{"i":"adding-spatial-module-code-1","c":["dart pub add nitrite\ndart pub add nitrite_spatial"]},{"l":"Using Spatial Module","p":["To use Spatial module, you need to load the SpatialModule while opening the database.","If you are using nitrite_hive_adapter as your storage module, you need to register the GeometryAdapter with the Hive database.","If Nitrite is using the default SimpleNitriteMapper, then the SpatialModule will automatically register the GeometryConverter with the mapper. If you are using your own custom mapper, then you need to register the GeometryConverter with the mapper."]},{"i":"using-spatial-module-code-1","c":["import 'package:nitrite/nitrite.dart';\nimport 'package:nitrite_spatial/nitrite_spatial.dart';\n\nvar db = await Nitrite.builder()\n            .loadModule(SpatialModule())\n            .openOrCreate();"]},{"i":"using-spatial-module-code-2","c":["import 'package:nitrite_hive_adapter/nitrite_hive_adapter.dart';\n\nvar storeModule = HiveModule.withConfig()\n            .path(filePath)\n            .addTypeAdapter(GeometryAdapter())\n            .build();\n\nvar db = await Nitrite.builder()\n            .loadModule(storeModule)\n            .loadModule(SpatialModule())\n            .openOrCreate();"]},{"l":"GeometryConverter","p":["GeometryConverter is an EntityConverter which is used to convert Geometry object of Dart JTS to Document and vice-versa. It is used to store the Geometry object in the database."]},{"l":"Spatial Index","p":["Spatial module uses R-Tree index to store the spatial data.","To create a spatial index, you need to pass the index type as spatialIndex while creating the index. spatialIndex is a global constant defined in nitrite_spatial package.","Spatial index is not supported on multiple fields."]},{"i":"spatial-index-code-1","c":["await collection.createIndex([\"location\"], indexOptions(spatialIndex));"]},{"l":"Spatial Filter","p":["Spatial module supports several filters to query spatial data. To know more about filters, please refer to Spatial Filters."]}],[{"l":"Usage","p":["Nitrite provides some additional functionalities via nitrite-support library. You can use the library to enable encryption, import/export database etc."]},{"l":"Adding nitrite-support","p":["To use nitrite-support to your project, add the following dependency to your project:"]},{"i":"adding-nitrite-support-code-1","c":["dart pub add nitrite\ndart pub add nitrite_support"]}],[{"l":"Import/Export","p":["Nitrite provides import/export functionality via nitrite-support library. You can import/export your database to/from a file in JSON format. You can choose to import/export the entire database or a specific collection."]},{"l":"Exporting Database","p":["To export the entire database in JSON format, you can use the Exporter class of nitrite-support library. You can use the Exporter.withOptions() method to construct an instance of Exporter.","The database must be in closed state before exporting."]},{"i":"exporting-database-code-1","c":["// create an exporter with export options\nvar exporter = Exporter.withOptions(\n    dbFactory: () async => createDb('nitrite_source.db'),\n    collections: ['first'],\n    repositories: ['Employee'],\n    keyedRepositories: {\n        'key': {'Employee'},\n    },\n);\n\n// export the database to a file\nawait exporter.exportTo(dataFile);"]},{"l":"Export Options","p":["collections - the list of collections to export. The rules for specifying the collection names are as follows:","dbFactory - the NitriteFactory function to use for export. It is used to create the Nitrite instance for export. It's a mandatory field.","exportData - whether to export data or not. It's an optional field, if not provided, it will be set to true.","exportIndices - whether to export indices or not. It's an optional field, if not provided, it will be set to true.","If a non-empty list is specified, only the collections in the list will be exported.","If a non-empty list is specified, only the repositories in the list will be exported.","If a non-empty map is specified, only the keyed repositories in the map will be exported.","If an empty list is specified, no collection will be exported.","If an empty list is specified, no repository will be exported.","If an empty map is specified, no keyed repository will be exported.","If null is specified, all collections will be exported.","If null is specified, all keyed repositories will be exported.","If null is specified, all repositories will be exported.","keyedRepositories - the map of keyed repositories to export. The rules for specifying the keyed repository names are as follows:","repositories - the list of repositories to export. The rules for specifying the repository names are as follows:","The Exporter.withOptions() method provides various options to configure the export process. You can set the following options:"]},{"l":"Example","p":["First create a method to create a Nitrite instance, which will be used as the nitriteFactory.","Then create the Exporter instance and export the database.","The source.json file will contain the exported data in JSON format."]},{"i":"example-code-1","c":["Future<Nitrite> createDb(String filePath) async {\n    // create a Hive based file store\n    var storeModule = Hive.withConfig()\n        .path(filePath)\n        .build();\n\n    // open the database\n    return Nitrite.builder()\n        .loadModule(storeModule)\n        .build();\n}"]},{"i":"example-code-2","c":["// create an exporter with export options\nvar exporter = Exporter.withOptions(\n    dbFactory: () async => createDb('nitrite_source.db'),\n    collections: ['first'],\n    repositories: ['Employee'],\n    keyedRepositories: {\n        'key': {'Employee'},\n    },\n);\n\n// export the database to a file\nawait exporter.exportTo('source.json');"]},{"l":"Importing Database","p":["To import the entire database from an exported JSON data, you can use the Importer class of nitrite-support library. You can use the Importer.withOptions() method to construct an instance of Importer.","The database must be in closed state before importing."]},{"i":"importing-database-code-1","c":["// create an importer with import options\nvar importer = Importer.withOptions(\n    dbFactory: () async => createDb(getTempPath('nitrite_dest.db')),\n);\n\n// import the database from a file\nawait importer.importFrom('source.json');"]},{"l":"Import Options","p":["The Importer.withOptions() method provides various options to configure the import process. You can set the following options:","dbFactory - the NitriteFactory function to use for import. It is used to create the Nitrite instance for import. It's a mandatory field."]},{"i":"example-1","l":"Example","p":["First create the Importer instance and configure it.","The nitrite_dest.db file will contain the imported data. You can open the database and use it."]},{"i":"example-1-code-1","c":["// create an importer with import options\nvar importer = Importer.withOptions(\n    dbFactory: () async => createDb('nitrite_dest.db'),\n);\n\n// import the database from a file\nawait importer.importFrom('source.json');"]}],[{"l":"Encryption","p":["Nitrite provides field level encryption support via nitrite-support module. You can encrypt your data using with or without a password."]},{"l":"Field Level Encryption","p":["Nitrite provides a StringFieldEncryptionProcessor utility class to encrypt and decrypt a field of a document. It is a Processor implementation. It uses AES to encrypt and decrypt data.","While initializing the StringFieldEncryptionProcessor, you can either provide a password or not. If you provide a password, the processor will use the password to encrypt and decrypt data. If you do not provide a password, the processor will use a random key to encrypt and decrypt data."]},{"i":"field-level-encryption-code-1","c":["// create a processor with a password\nvar processor = StringFieldEncryptionProcessor(\"my-password\");\n\n// or, create a processor without a password\nvar processor = StringFieldEncryptionProcessor();\n\n// add fields to encrypt\nprocessor.addFields([\"field1\", \"field2\"]);\n\n// use the processor\ncollection.addProcessor(processor);\n\n// use the collection\nawait collection.insert(doc);"]}],[{"l":"Rust Examples","p":["Here we discuss a Rust project tracker example that exercises most of Nitrite Rust's current feature set. It uses a Fjall-backed database for persistence, a typed repository for structured task data, a document collection for flexible activity records, Tantivy full-text search for text discovery, the spatial module for location-based lookups, transactions for batched writes, projection for lightweight reads, and sorted queries for reporting. The full runnable source code is available here."]},{"l":"Setup","p":["Add the following dependencies to your Cargo.toml file:"]},{"i":"setup-code-1","c":["[dependencies]\nnitrite = \"0.3\"\nnitrite_derive = \"0.3\"\nnitrite_fjall_adapter = \"0.3\"\nnitrite_spatial = \"0.3\"\nnitrite_tantivy_fts = \"0.3\"\nuuid = { version = \"1\", features = [\"v4\"] }"]},{"l":"Domain Model","p":["The example keeps structured project data in a typed repository and uses entity-derived indexes for the common access paths:"]},{"i":"domain-model-code-1","c":["use nitrite_derive::{Convertible, NitriteEntity};\n\n#[derive(Debug, Clone, Convertible, NitriteEntity, Default)]\n#[entity(\n    name = \"tasks\",\n    id(field = \"id\"),\n    index(type = \"unique\", fields = \"slug\"),\n    index(type = \"non-unique\", fields = \"status\"),\n    index(type = \"non-unique\", fields = \"owner\")\n)]\nstruct Task {\n    pub id: i64,\n    pub slug: String,\n    pub title: String,\n    pub owner: String,\n    pub status: String,\n    pub priority: i64,\n    pub estimate_hours: i64,\n    pub tags: Vec<String>,\n}\n\n#[derive(Debug, Clone, Convertible, NitriteEntity, Default)]\nstruct TaskSummary {\n    pub title: Option<String>,\n    pub status: Option<String>,\n    pub priority: Option<i64>,\n    pub owner: Option<String>,\n}"]},{"l":"Database Initialization","p":["The database is opened with the Fjall storage adapter and both optional search modules loaded:","The example also creates a flexible document collection with dedicated FTS and spatial indexes:"]},{"i":"database-initialization-code-1","c":["use nitrite::nitrite::Nitrite;\nuse nitrite_fjall_adapter::FjallModule;\nuse nitrite_spatial::SpatialModule;\nuse nitrite_tantivy_fts::TantivyFtsModule;\n\nlet fjall_module = FjallModule::with_config()\n    .db_path(db_path)\n    .build();\n\nlet db = Nitrite::builder()\n    .load_module(fjall_module)\n    .load_module(TantivyFtsModule::default())\n    .load_module(SpatialModule)\n    .open_or_create(None, None)?;"]},{"i":"database-initialization-code-2","c":["use nitrite_tantivy_fts::fts_index;\nuse nitrite_spatial::spatial_index;\n\nlet activity = db.collection(\"task_activity\")?;\nactivity.create_index(vec![\"summary\"], &fts_index())?;\nactivity.create_index(vec![\"location\"], &spatial_index())?;"]},{"l":"Transactional Writes","p":["Initial task data is written inside a session transaction so the structured repository changes commit together before the indexed activity documents are added:","On the current 0.3 line, that Fjall-backed transaction commit and its repository index updates are crash-atomic: after a reopen you see either the whole logical write or none of it.","The indexed activity collection is then populated through the normal collection API:","Those Tantivy-backed activity writes are buffered and committed on the next full-text search or on db.close(), which keeps bulk inserts fast while still making the later search in this example observe its own writes."]},{"i":"transactional-writes-code-1","c":["use nitrite::doc;\nuse nitrite::repository::ObjectRepository;\n\ndb.with_session(|session| {\n    let tx = session.begin_transaction()?;\n    let tx_tasks: ObjectRepository<Task> = tx.repository()?;\n\n    tx_tasks.insert(Task::new(\n        1,\n        \"release-dashboard\",\n        \"Prepare the release dashboard\",\n        \"alice\",\n        \"open\",\n        3,\n        8,\n        &[\"release\", \"dashboard\"],\n    ))?;\n\n    tx.commit()\n})?;"]},{"i":"transactional-writes-code-2","c":["use nitrite::doc;\n\nlet activity = db.collection(\"task_activity\")?;\nactivity.insert(doc! {\n    \"task_slug\": \"release-dashboard\",\n    \"summary\": \"Release dashboard shipped with offline sync metrics\",\n    \"location\": {\n        \"x\": (-122.335167f64),\n        \"y\": 47.608013f64\n    }\n})?;"]},{"l":"Queries, Projection, and Reporting","p":["After the seed write, the example demonstrates repository filtering, projection, sorted reads, updates, full-text search, and spatial queries:"]},{"i":"queries-projection-and-reporting-code-1","c":["use nitrite::collection::order_by;\nuse nitrite::common::SortOrder;\nuse nitrite::filter::{all, and, field};\nuse nitrite_tantivy_fts::fts_field;\nuse nitrite_spatial::{spatial_field, Geometry};\n\nlet tasks: ObjectRepository<Task> = db.repository()?;\nlet high_priority_open = tasks.find(and(vec![\n    field(\"status\").eq(\"open\"),\n    field(\"priority\").gte(2i64),\n]))?;\n\nlet mut owner_cursor = tasks.find(field(\"owner\").eq(\"alice\"))?;\nlet summaries = owner_cursor.project::<TaskSummary>()?;\n\nlet ordered = tasks.find_with_options(all(), &order_by(\"priority\", SortOrder::Descending))?;\n\nlet activity = db.collection(\"task_activity\")?;\nlet text_matches = activity.find(fts_field(\"summary\").matches(\"offline sync\"))?;\n\nlet seattle = Geometry::envelope(-122.5, 47.5, -122.2, 47.7);\nlet nearby = activity.find(spatial_field(\"location\").within(seattle))?;"]},{"l":"Run the Example","p":["The source lives in the integration-test crate because it already depends on the optional Nitrite Rust modules used by the showcase example.","When the command finishes, it prints counts and summaries for the repository, full-text, and spatial queries, then closes and removes the temporary Fjall database directory."]},{"i":"run-the-example-code-1","c":["cd nitrite-rust\ncargo run -p nitrite_int_test --example rust_feature_showcase"]}],[{"l":"Java Examples","p":["Here we discuss about an Android todo application using Nitrite database. It uses nitrite as a file based storage engine. It demonstrates the use of Nitrite database in an Android application. The full source code is available here. This tutorial assumes that you have basic knowledge of Android development."]},{"l":"Setup","p":["To use Nitrite in your Android application, you need to add the following dependency in your app's build.gradle file.","Also add these pro-guard rules in your proguard-rules.pro file."]},{"i":"setup-code-1","c":["dependencies {\n    implementation platform('org.dizitart:nitrite-bom:[latest-version]')\n    implementation 'org.dizitart:nitrite'\n    implementation 'org.dizitart:nitrite-mvstore-adapter'\n}"]},{"i":"setup-code-2","c":["-keep class org.dizitart.no2.** { *; }\n-keep class org.slf4j.** { *; }\n-keep class org.h2.** { *; }\n-keep class org.objenesis.** { *; }\n-keep class com.fasterxml.jackson.** { *; }\n\n-keepnames class * implements java.io.Serializable\n\n-keepclassmembers class * implements java.io.Serializable {\n    static final long serialVersionUID;\n    private static final java.io.ObjectStreamField[] serialPersistentFields;\n    !static !transient <fields>;\n    private void writeObject(java.io.ObjectOutputStream);\n    private void readObject(java.io.ObjectInputStream);\n    java.lang.Object writeReplace();\n    java.lang.Object readResolve();\n}"]},{"l":"Entity Classes","p":["Define a simple Todo entity class to hold your todo data:","And, a list of TodoItem can be represented as:"]},{"i":"entity-classes-code-1","c":["import org.dizitart.no2.collection.Document;\nimport org.dizitart.no2.common.mapper.EntityConverter;\nimport org.dizitart.no2.common.mapper.NitriteMapper;\nimport org.dizitart.no2.repository.annotations.Entity;\n\n@Entity\npublic class TodoItem {\n    @Id\n    private Integer id;\n    private String taskName;\n    private Boolean status;\n    private String color;\n\n    public Integer getId() {\n        return id;\n    }\n\n    public void setId(Integer id) {\n        this.id = id;\n    }\n\n    public String getTaskName() {\n        return taskName;\n    }\n\n    public void setTaskName(String taskName) {\n        this.taskName = taskName;\n    }\n\n    public Boolean getStatus() {\n        return status;\n    }\n\n    public void setStatus(Boolean status) {\n        this.status = status;\n    }\n\n    public String getColor() {\n        return color;\n    }\n\n    public void setColor(String color) {\n        this.color = color;\n    }\n\n    public static class Converter implements EntityConverter<TodoItem> {\n\n        @Override\n        public Class<TodoItem> getEntityType() {\n            return TodoItem.class;\n        }\n\n        @Override\n        public Document toDocument(TodoItem entity, NitriteMapper nitriteMapper) {\n            return Document.createDocument()\n                    .put(\"id\", entity.getId())\n                    .put(\"taskName\", entity.getTaskName())\n                    .put(\"status\", entity.getStatus())\n                    .put(\"color\", entity.getColor());\n        }\n\n        @Override\n        public TodoItem fromDocument(Document document, NitriteMapper nitriteMapper) {\n            TodoItem item = new TodoItem();\n            item.id = document.get(\"id\", Integer.class);\n            item.taskName = document.get(\"taskName\", String.class);\n            item.status = document.get(\"status\", Boolean.class);\n            item.color = document.get(\"color\", String.class);\n            return item;\n        }\n    }\n}"]},{"i":"entity-classes-code-2","c":["public class TodoList {\n    private String name;\n    private String color;\n\n    public TodoList(String name, String color) {\n        this.name = name;\n        this.color = color;\n    }\n\n    public String getName() {\n        return name;\n    }\n\n    public void setName(String name) {\n        this.name = name;\n    }\n\n    public String getColor() {\n        return color;\n    }\n\n    public void setColor(String color) {\n        this.color = color;\n    }\n}"]},{"l":"Database Initialization","p":["To initialize the database and to maintain a singleton instance of the database, you need to create a singleton class NitriteManager as follows:","Next create a data access layer DataBaseManager for CRUD operations:"]},{"i":"database-initialization-code-1","c":["public class NitriteManager {\n    private static NitriteManager _instance = new NitriteManager();\n    private static final String dbName = \"task.db\";\n    private static Nitrite db;\n\n    private NitriteManager() {}\n\n    public static NitriteManager getInstance() {\n        return _instance;\n    }\n\n    private void openDb(Context context) {\n        if (db != null) {\n            db.close();\n        }\n\n        MVStoreModule storeModule = MVStoreModule.withConfig()\n                .filePath(context.getDatabasePath(dbName))\n                .build();\n        SimpleDocumentMapper documentMapper = new SimpleDocumentMapper();\n        documentMapper.registerEntityConverter(new TodoItem.Converter());\n\n        db = Nitrite.builder()\n                .loadModule(storeModule)\n                .loadModule(() -> setOf(documentMapper))\n                .openOrCreate();\n    }\n\n    public ObjectRepository<TodoItem> getTodoRepository(Context context, String label) {\n        if (db == null) {\n            openDb(context);\n        }\n\n        return db.getRepository(TodoItem.class, label);\n    }\n}"]},{"i":"database-initialization-code-2","c":["public class DataBaseManager {\n\n    private final NitriteManager nitriteManager;\n    private final String label;\n\n    public DataBaseManager(String label) {\n        this.nitriteManager = NitriteManager.getInstance();\n        this.label = label;\n    }\n\n    public void addTask(Context context, int id, boolean status, String taskName, String taskColor) {\n        TodoItem todoItem = new TodoItem();\n        todoItem.setId(id);\n        todoItem.setColor(taskColor);\n        todoItem.setStatus(status);\n        todoItem.setTaskName(taskName);\n        nitriteManager.getTodoRepository(context, label).insert(todoItem);\n    }\n\n    public void removeTask(Context context, int id) {\n        nitriteManager.getTodoRepository(context, label).remove(where(\"id\").eq(id));\n    }\n\n    public void updateTask(Context context, Boolean taskStatus, int id, String taskName) {\n        Document updateDocument = Document.createDocument()\n                .put(\"status\", taskStatus)\n                .put(\"taskName\", taskName);\n        nitriteManager.getTodoRepository(context, label).update(where(\"id\").eq(id), updateDocument);\n    }\n\n    public List<TodoItem> readFromDB(Context context) {\n        return nitriteManager.getTodoRepository(context, label).find().toList();\n    }\n\n    public int getCurrentBiggestId(Context context) {\n        TodoItem item = nitriteManager.getTodoRepository(context, label).find(\n                FindOptions.orderBy(\"id\", SortOrder.Descending)).firstOrNull();\n        if (item == null) return 0;\n        return item.getId();\n    }\n}"]},{"l":"Activity","p":["Now you need to create two activities, one for the todo list and another for the menu."]},{"l":"Todo List Activity"},{"i":"todo-list-activity-code-1","c":["public class ToDoListActivity extends AppCompatActivity {\n\n    DataBaseManager manager;\n    ListView listView;\n    CustomAdapter customAdapter;\n    TextView activityTitle;\n    EditText addTask;\n    int currentBiggerId = 0;\n\n    @Override\n    protected void onCreate(Bundle savedInstanceState) {\n        super.onCreate(savedInstanceState);\n        setContentView(R.layout.activity_todo_list);\n        //naming the activity\n        activityTitle = (TextView) findViewById(R.id.activityTitle);\n        activityTitle.setText(getIntent().getStringExtra(\"listName\"));\n        //getting list color\n        String color = getIntent().getStringExtra(\"listColor\");\n\n        addTask = (EditText) findViewById(R.id.editTextAddTask);\n\n        listView = (ListView) findViewById(R.id.listTodo);\n        manager = new DataBaseManager(activityTitle.getText().toString());\n        listView.setOnItemLongClickListener((parent, view, position, id) -> {\n            Log.e(\"Item Long Click\", \"Removing the item\");\n            manager.removeTask(getApplicationContext(), (customAdapter.todoList.get(position)).getId());\n            try {\n                printDB(true);\n            } catch (ExecutionException | InterruptedException e) {\n                e.printStackTrace();\n            }\n            return false;\n        });\n        try {\n            printDB(true);\n        } catch (ExecutionException | InterruptedException e) {\n            e.printStackTrace();\n        }\n    }\n\n    public void addTask(View v) {\n        Runnable runnable = () -> {\n            currentBiggerId = manager.getCurrentBiggestId(getApplicationContext());\n            int randomInt = new Random().nextInt(3);\n            String color = \"\";\n            switch (randomInt) {\n                case 0:\n                    color = \"blue\";\n                    break;\n                case 1:\n                    color = \"green\";\n                    break;\n                case 2:\n                    color = \"violet\";\n                    break;\n            }\n            manager.addTask(getApplicationContext(), new Random().nextInt(), false, addTask.getText().toString(), color);\n            try {\n                printDB(true);\n            } catch (ExecutionException | InterruptedException e) {\n                e.printStackTrace();\n            }\n        };\n        runnable.run();\n    }\n\n    public void printDB(boolean updateFromDb) throws ExecutionException, InterruptedException {\n        if (updateFromDb) {\n            customAdapter = new CustomAdapter(manager.readFromDB(getApplicationContext()));\n            listView.setAdapter(customAdapter);\n        }\n        customAdapter.notifyDataSetChanged();\n        currentBiggerId = manager.getCurrentBiggestId(getApplicationContext());\n        addTask.setText(\"\");\n    }\n\n    @Override\n    public boolean onCreateOptionsMenu(Menu menu) {\n        getMenuInflater().inflate(R.menu.menu, menu);\n        return true;\n    }\n\n    @Override\n    public boolean onOptionsItemSelected(MenuItem item) {\n        int id = item.getItemId();\n        if (id == R.id.about) {\n            Toast.makeText(this, \"Nitrite Database Demo\", Toast.LENGTH_LONG).show();\n        }\n        return super.onOptionsItemSelected(item);\n    }\n\n    @Override\n    protected void onResume() {\n        super.onResume();\n        try {\n            printDB(true);\n        } catch (ExecutionException | InterruptedException e) {\n            e.printStackTrace();\n        }\n        System.out.println(customAdapter.todoList.size());\n    }\n\n    public class CustomAdapter extends BaseAdapter {\n        List<TodoItem> todoList;\n\n        CustomAdapter(List<TodoItem> todoList) {\n            this.todoList = todoList;\n        }\n\n        @Override\n        public int getCount() {\n            return todoList.size();\n        }\n\n        @Override\n        public Object getItem(int i) {\n            return null;\n        }\n\n        @Override\n        public long getItemId(int i) {\n            return i;\n        }\n\n        @Override\n        public View getView(final int i, View view, ViewGroup viewGroup) {\n            view = getLayoutInflater().inflate(R.layout.task_todo_item, null);\n\n            final TextView title = view.findViewById(R.id.todoName);\n            title.setText(todoList.get(i).getTaskName());\n            CheckBox button = view.findViewById(R.id.checkButton);\n            button.setChecked(todoList.get(i).getStatus());\n\n            //region setting color states\n            int[][] states = new int[][]{\n                    new int[]{-android.R.attr.state_checked}, //disabled\n                    new int[]{android.R.attr.state_checked} //enabled\n            };\n            @SuppressLint(\"ResourceType\") int[] colorBlue = new int[]{Color.parseColor(getString(R.color.colorBlue)),\n                    Color.parseColor(getString(R.color.colorBlue))};\n            @SuppressLint(\"ResourceType\") int[] colorGreen = new int[]{Color.parseColor(getString(R.color.colorGreen)),\n                    Color.parseColor(getString(R.color.colorGreen))};\n            @SuppressLint(\"ResourceType\") int[] colorViolet = new int[]{Color.parseColor(getString(R.color.colorViolet)),\n                    Color.parseColor(getString(R.color.colorViolet))};\n            //endregion\n\n            //region setting UI colors\n            RelativeLayout layout = view.findViewById(R.id.itemBackground);\n            String color = todoList.get(i).getColor();\n            final int taskId = todoList.get(i).getId();\n            final String taskName = todoList.get(i).getTaskName();\n            if (color.matches(\"blue\")) {\n                layout.setBackground(ContextCompat.getDrawable(getApplicationContext(), R.drawable.list_item_background_blue));\n                button.setButtonTintList(new ColorStateList(states, colorBlue));\n            } else if (color.matches(\"green\")) {\n                layout.setBackground(ContextCompat.getDrawable(getApplicationContext(), R.drawable.list_item_background_green));\n                button.setButtonTintList(new ColorStateList(states, colorGreen));\n            } else {\n                layout.setBackground(ContextCompat.getDrawable(getApplicationContext(), R.drawable.list_item_background_violet));\n                button.setButtonTintList(new ColorStateList(states, colorViolet));\n            }\n            //endregion\n            button.setOnCheckedChangeListener((compoundButton, b) -> itemChecked(b, taskId, taskName));\n\n            return view;\n        }\n\n        void itemChecked(final boolean taskStatus, final int taskId, final String taskName) {\n            Runnable runnable = () -> manager.updateTask(getApplicationContext(), taskStatus, taskId, taskName);\n            runnable.run();\n        }\n    }\n}"]},{"l":"Menu Activity","p":["The other resources are available in the source code."]},{"i":"menu-activity-code-1","c":["public class ListMenuActivity extends AppCompatActivity {\n    ListView listView;\n\n    @Override\n    protected void onCreate(Bundle savedInstanceState) {\n        super.onCreate(savedInstanceState);\n        setContentView(R.layout.activity_list_menu);\n        listView = (ListView) findViewById(R.id.listMenu);\n        ArrayList<TodoList> lists = new ArrayList<>();\n        lists.add(new TodoList(\"Home\", \"blue\"));\n        lists.add(new TodoList(\"Work\", \"green\"));\n        lists.add(new TodoList(\"School\", \"violet\"));\n        CustomAdapter customAdapter = new CustomAdapter(lists);\n        listView.setAdapter(customAdapter);\n    }\n\n    public class CustomAdapter extends BaseAdapter {\n        ArrayList<TodoList> lists;\n\n        public CustomAdapter(ArrayList<TodoList> lists) {\n            this.lists = lists;\n        }\n\n        @Override\n        public int getCount() {\n            return lists.size();\n        }\n\n        @Override\n        public Object getItem(int i) {\n            return null;\n        }\n\n        @Override\n        public long getItemId(int i) {\n            return i;\n        }\n\n        @Override\n        public View getView(int i, View view, ViewGroup viewGroup) {\n            view = getLayoutInflater().inflate(R.layout.task_menu_item, null);\n\n            //region setting background color\n            RelativeLayout layout = view.findViewById(R.id.itemBackground);\n            final String color = lists.get(i).getColor();\n            if (color.matches(\"blue\"))\n                layout.setBackground(ContextCompat.getDrawable(getApplicationContext(), R.drawable.list_item_background_blue));\n            else if (color.matches(\"green\"))\n                layout.setBackground(ContextCompat.getDrawable(getApplicationContext(), R.drawable.list_item_background_green));\n            else\n                layout.setBackground(ContextCompat.getDrawable(getApplicationContext(), R.drawable.list_item_background_violet));\n            //endregion\n\n            final TextView title = view.findViewById(R.id.listName);\n            title.setText(lists.get(i).getName());\n            ImageButton button = view.findViewById(R.id.selectList);\n            button.setOnClickListener(view1 -> listSelected(title.getText().toString(), color));\n\n            return view;\n        }\n\n        void listSelected(String listName, String listColor) {\n            Intent intent = new Intent(getApplicationContext(), ToDoListActivity.class);\n            intent.putExtra(\"listName\", listName);\n            intent.putExtra(\"listColor\", listColor);\n            startActivity(intent);\n        }\n    }\n}"]}],[{"l":"Flutter Examples","p":["Here we discuss about a flutter todo application using Nitrite database. It uses nitrite as a file based storage engine. It also uses Riverpod for state management. It demonstrates the use of Nitrite database in a flutter application. The full source code is available here. This tutorial assumes that you have basic knowledge of flutter and riverpod."]},{"l":"Setup","p":["Add the following Nitrite dependencies in your pubspec.yaml file along with path_provider and riverpod_generator:"]},{"i":"setup-code-1","c":["dependencies:\n  nitrite: ^[latest-version]\n  nitrite_hive_adapter: ^[latest-version]\n  path_provider: ^2.0.15\n  riverpod_annotation: ^2.1.1\n\ndev_dependencies:\n  build_runner: ^2.4.6\n  riverpod_generator: ^2.2.3\n  nitrite_generator: ^[latest-version]"]},{"l":"Entity Classes","p":["Define a simple Todo entity class to hold your todo data:","And run the following command to generate the _$TodoEntityMixin:","This command will generate the models.no2.dart file in the same directory."]},{"i":"entity-classes-code-1","c":["import 'package:nitrite/nitrite.dart';\n\npart 'models.no2.dart';\n\n@Entity(name: 'todo', indices: [\n  Index(fields: ['title'], type: IndexType.fullText),\n])\n@Convertable()\nclass Todo with _$TodoEntityMixin {\n  @Id(fieldName: 'id')\n  final String id;\n  final String title;\n  bool completed = false;\n\n  Todo({\n    required this.id,\n    required this.title,\n    required this.completed,\n  });\n\n  @override\n  bool operator ==(Object other) =>\n      identical(this, other) ||\n      other is Todo &&\n          runtimeType == other.runtimeType &&\n          id == other.id &&\n          title == other.title &&\n          completed == other.completed;\n\n  @override\n  int get hashCode => id.hashCode ^ title.hashCode ^ completed.hashCode;\n\n  @override\n  String toString() {\n    return 'Todo{id: $id, title: $title, completed: $completed}';\n  }\n}"]},{"i":"entity-classes-code-2","c":["dart run build_runner build"]},{"l":"Database Initialization","p":["Next create a Nitrite database provider using riverpod:","Now using the dbProvider, create a todo ObjectRepository provider:","And other required providers for listing and searching:","Now again run the following command to generate the providers:"]},{"i":"database-initialization-code-1","c":["import 'package:flutter_riverpod/flutter_riverpod.dart';\nimport 'package:nitrite/nitrite.dart';\nimport 'package:nitrite_hive_adapter/nitrite_hive_adapter.dart';\nimport 'package:path_provider/path_provider.dart';\nimport 'package:riverpod_annotation/riverpod_annotation.dart';\n\npart 'providers.g.dart';\n\n@riverpod\nFuture<Nitrite> db(DbRef ref) async {\n  var docPath = await getApplicationDocumentsDirectory();\n  var dbDir = await Directory('${docPath.path}${Platform.pathSeparator}db')\n      .create(recursive: true);\n  var storeModule =\n      HiveModule.withConfig().crashRecovery(true).path(dbDir.path).build();\n\n  var db = await Nitrite.builder()\n      .loadModule(storeModule)\n      .fieldSeparator('.')\n      .registerEntityConverter(TodoConverter())\n      .openOrCreate(username: 'demo', password: 'demo123');\n\n  return db;\n}"]},{"i":"database-initialization-code-2","c":["@riverpod\nFuture<ObjectRepository<Todo>> todoRepository(TodoRepositoryRef ref) async {\n  var db = await ref.read(dbProvider.future);\n  return await db.getRepository<Todo>();\n}"]},{"i":"database-initialization-code-3","c":["@riverpod\nclass Todos extends _$Todos {\n  Future<List<Todo>> _fetchTodo() async {\n    var repository = await ref.read(todoRepositoryProvider.future);\n    var filter = ref.watch(filterProvider);\n    var findOptions = ref.watch(findOptionStateProvider);\n    return repository.find(filter: filter, findOptions: findOptions).toList();\n  }\n\n  @override\n  Future<List<Todo>> build() async {\n    return _fetchTodo();\n  }\n\n  Future<void> addTodo(Todo todo) async {\n    state = const AsyncValue.loading();\n\n    try {\n      var repository = await ref.read(todoRepositoryProvider.future);\n      await repository.insert(todo);\n      state = AsyncValue.data(await _fetchTodo());\n    } catch (e, s) {\n      state = AsyncValue.error(e, s);\n    }\n  }\n\n  Future<void> removeTodo(String todoId) async {\n    state = const AsyncValue.loading();\n    try {\n      var repository = await ref.read(todoRepositoryProvider.future);\n      await repository.remove(where('id').eq(todoId));\n      state = AsyncValue.data(await _fetchTodo());\n    } catch (e, s) {\n      state = AsyncValue.error(e, s);\n    }\n  }\n\n  Future<void> toggle(String todoId) async {\n    state = const AsyncValue.loading();\n    try {\n      var repository = await ref.read(todoRepositoryProvider.future);\n      var byId = await repository.getById(todoId);\n      if (byId != null) {\n        byId.completed = !byId.completed;\n        await repository.updateOne(byId);\n      }\n      state = AsyncValue.data(await _fetchTodo());\n    } catch (e, s) {\n      state = AsyncValue.error(e, s);\n    }\n  }\n}\n\n@riverpod\nclass FindOptionState extends _$FindOptionState {\n  @override\n  FindOptions build() {\n    return FindOptions(\n      orderBy: SortableFields.from([('title', SortOrder.ascending)]),\n      skip: 0,\n      limit: 10,\n    );\n  }\n}\n\nfinal filterProvider = StateProvider<Filter>((ref) => all);\nfinal todoTextProvider = StateProvider<String>((ref) => '');\n\n@riverpod\nint pendingCounter(PendingCounterRef ref) {\n  var todos = ref.watch(todosProvider);\n  return todos.when(\n    data: (todoList) => todoList.where((todo) => !todo.completed).length,\n    loading: () => 0,\n    error: (err, stack) => 0,\n  );\n}\n\n@riverpod\nint completedCounter(CompletedCounterRef ref) {\n  var todos = ref.watch(todosProvider);\n  return todos.when(\n    data: (todoList) => todoList.where((todo) => todo.completed).length,\n    loading: () => 0,\n    error: (err, stack) => 0,\n  );\n}"]},{"i":"database-initialization-code-4","c":["dart run build_runner build"]},{"l":"UI","p":["Now define a todo widget to display a single time and define different actions on it:","And a todo list widget to display the list of todos:","Now you can use these widgets in your app and other widgets to add new todo, search, etc."]},{"i":"ui-code-1","c":["class TodoWidget extends ConsumerWidget {\n  final Todo todo;\n\n  const TodoWidget({super.key, required this.todo});\n\n  bool _isDesktop() =>\n      Platform.isLinux || Platform.isMacOS || Platform.isWindows;\n\n  @override\n  Widget build(BuildContext context, WidgetRef ref) {\n    if (_isDesktop()) {\n      return Card(\n        color: Theme.of(context).colorScheme.surface,\n        child: ListTile(\n          title: Text(\n            todo.title,\n            style: TextStyle(\n              decoration: todo.completed ? TextDecoration.lineThrough : null,\n            ),\n          ),\n          trailing: Row(\n            mainAxisSize: MainAxisSize.min,\n            children: [\n              IconButton(\n                onPressed: () =>\n                    ref.read(todosProvider.notifier).toggle(todo.id),\n                icon: Icon(\n                  todo.completed ? Icons.task_alt : Icons.check_box_outlined,\n                  color: todo.completed ? Colors.green : Colors.grey,\n                ),\n              ),\n              IconButton(\n                onPressed: () =>\n                    ref.read(todosProvider.notifier).removeTodo(todo.id),\n                icon: const Icon(\n                  Icons.delete,\n                  color: Colors.red,\n                ),\n              ),\n            ],\n          ),\n        ),\n      );\n    } else {\n      return Slidable(\n        key: ValueKey(todo.id),\n        startActionPane: ActionPane(\n          motion: const ScrollMotion(),\n          children: [\n            SlidableAction(\n              borderRadius: BorderRadius.circular(5),\n              spacing: 10,\n              onPressed: (context) =>\n                  ref.read(todosProvider.notifier).toggle(todo.id),\n              backgroundColor: Colors.green,\n              foregroundColor: Colors.white,\n              icon: todo.completed ? Icons.task_alt : Icons.check_box_outlined,\n            ),\n          ],\n        ),\n        endActionPane: ActionPane(\n          motion: const ScrollMotion(),\n          children: [\n            SlidableAction(\n              borderRadius: BorderRadius.circular(5),\n              spacing: 10,\n              onPressed: (context) =>\n                  ref.read(todosProvider.notifier).removeTodo(todo.id),\n              backgroundColor: Colors.red,\n              foregroundColor: Colors.white,\n              icon: Icons.delete,\n            ),\n          ],\n        ),\n        child: ListTile(\n          leading: const Icon(Icons.adjust, color: Colors.black26),\n          shape: RoundedRectangleBorder(\n            borderRadius: BorderRadius.circular(5),\n          ),\n          title: Text(\n            todo.title,\n            style: TextStyle(\n              decoration: todo.completed ? TextDecoration.lineThrough : null,\n            ),\n          ),\n        ),\n      );\n    }\n  }\n}"]},{"i":"ui-code-2","c":["class TodoList extends ConsumerWidget {\n  const TodoList({super.key});\n\n  @override\n  Widget build(BuildContext context, WidgetRef ref) {\n    // Get the todos from the provider.\n    var todos = ref.watch(todosProvider);\n\n    return todos.when(\n      data: (todoList) => ListView.builder(\n        itemCount: todoList.length,\n        itemBuilder: (context, index) {\n          Todo todo = todoList[index];\n          return Padding(\n            padding: const EdgeInsets.only(left: 30.0, right: 30.0),\n            child: TodoWidget(todo: todo),\n          );\n        },\n      ),\n      error: (err, stack) => Text('Error: $err\\n$stack'),\n      loading: () => const Center(\n        child: CircularProgressIndicator(),\n      ),\n    );\n  }\n}"]}],[{"l":"Showcase"},{"l":"Showcase Your Application","p":["If you are using Nitrite Database in your application, submit your showcase through the hosted Google Form below. This keeps the documentation site static, does not require a GitHub account, and does not expose a maintainer email address on the page."]}],[{"l":"Frequently Asked Questions"},{"l":"What is Nitrite?","p":["Nitrite is a server-less embedded database ideal for desktop, mobile or small web applications. It's an open source, self-contained database. It supports both in-memory and file based persistent store."]},{"l":"Is Nitrite an RDBMS?","p":["No, Nitrite is not an RDBMS. It's a NoSQL database. It's a document store with support for indexing, full-text search, event listeners, embedded and in-memory modes, encryption, and many other features."]},{"l":"What is the difference between Nitrite and SQLite?","p":["Nitrite is a NoSQL document store, whereas SQLite is an RDBMS. Nitrite is a document store, whereas SQLite is a relational store. Nitrite has pure Java, Dart implementations, whereas SQLite has C/C++ implementation and native bindings are needed for other languages."]},{"l":"Which platforms are supported by Nitrite?","p":["Nitrite Java is supported on all platforms where Java is supported. Nitrite Flutter is supported on all platforms where Dart is supported."]},{"l":"When should I use Nitrite?","p":["Nitrite is a good choice for desktop, mobile or small web applications. It's a good choice for applications where you don't want to install a separate database server. It's a good choice for applications where you want to store data in-memory."]},{"l":"What is the performance of Nitrite?","p":["Nitrite is highly performant, though it heavily depends on the underlying storage backend implementation. A JMH benchmark of Nitrite for Java is available here where you can find its performance amongst various storage backends against SQLite."]},{"l":"Does Nitrite support replication over network?","p":["No, Nitrite doesn't support replication over network. It's a server-less embedded database. If you are looking for replication, you can subscribe to collection events using CollectionEventListener and replicate the data over network."]},{"l":"What happened to Nitrite DataGate Server?","p":["Nitrite DataGate Server is now deprecated. It's no longer maintained due to lack of interest from the community. If you are looking for it to be revived, please vote here. If enough people are interested, it will be revived."]},{"l":"What happened to Nitrite Explorer?","p":["Nitrite Explorer is now deprecated. It's no longer maintained due to lack of interest from the community. If you are looking for it to be revived, please vote here. If enough people are interested, it will be revived."]},{"l":"What if I find any issues in the documentation?","p":["If you find any issues in the documentation, please raise an issue here."]},{"l":"What if I had any suggestions/questions?","p":["If you have any suggestions or questions about Nitrite, please start a discussion here."]},{"l":"What is the license of Nitrite?","p":["Nitrite is licensed under Apache License 2.0. It's free to use in both commercial and non-commercial applications. If you are using Nitrite in your commercial application, please consider donating to the project."]},{"l":"How can I donate to Nitrite?","p":["If you like Nitrite and want to support the project, please consider donating to the project. You can donate via GitHub Sponsors."]}]];